INSERT INTO grammar_points VALUES(1,'n5-da','だ','da','is; am; are (casual form of です)',unistr('Noun + だ\u000aな-adjective + だ'),unistr('「だ」 (da) is the casual form of the copula 「です」 (desu), meaning "to be" (am, is, are). It is used to state facts or make assertions in informal contexts.\u000a\u000aIt directly follows nouns and な-adjectives. For example, 「学生だ」 (gakusei da - "(I) am a student") or 「きれいだ」 (kirei da - "(It) is clean"). Note that for い-adjectives and verbs, 「だ」 is not typically used directly after them to form a simple statement; they already have their own casual forms.\u000a\u000a「だ」 is primarily used in casual conversations among friends, family, or people of equal status. It should be avoided in formal situations or when speaking to superiors, where 「です」 would be more appropriate.'),'N5',1,'Crucial Sentence Elements','[{"ja":"これはペンだ。","romaji":"kore wa pen da.","en":"This is a pen."},{"ja":"彼は学生だ。","romaji":"kare wa gakusei da.","en":"He is a student."},{"ja":"この部屋はきれいだ。","romaji":"kono heya wa kirei da.","en":"This room is clean."},{"ja":"彼女は日本人だ。","romaji":"kanojo wa nihonjin da.","en":"She is Japanese."}]','["n5-desu"]','["copula","casual"]',1);
INSERT INTO grammar_points VALUES(2,'n5-desu','です','desu','is; am; are (polite form of だ)',unistr('Noun + です\u000aい-adjective + です\u000a な-adjective + です'),unistr('「です」 (desu) is the polite form of the copula, meaning "to be" (am, is, are). It is used to state facts or make assertions in polite contexts.\u000a\u000aIt is commonly used after nouns and な-adjectives. For example, 「先生です」 (sensei desu - "(I) am a teacher") or 「元気です」 (genki desu - "(I) am fine"). For い-adjectives, 「です」 is added directly after the adjective to make the sentence polite, such as 「寒いです」 (samui desu - "It is cold").\u000a\u000a「です」 is essential for polite communication in Japanese and is used when speaking to strangers, superiors, or in formal situations. It softens the tone of a statement compared to its casual counterpart, 「だ」.'),'N5',1,'Crucial Sentence Elements','[{"ja":"私は学生です。","romaji":"watashi wa gakusei desu.","en":"I am a student."},{"ja":"これは本です。","romaji":"kore wa hon desu.","en":"This is a book."},{"ja":"このかばんはきれいです。","romaji":"kono kaban wa kirei desu.","en":"This bag is clean."},{"ja":"今日は寒いです。","romaji":"kyou wa samui desu.","en":"It is cold today."}]','["n5-da"]','["copula","polite"]',2);
INSERT INTO grammar_points VALUES(3,'n5-wa','は','wa','topic marker particle','Noun/Phrase + は',unistr('「は」 (wa) is a topic-marking particle. It indicates what the sentence is about, often introducing new information or contrasting it with something else.\u000a\u000aThe element preceding 「は」 is the topic of the sentence. While it often coincides with the grammatical subject, it''s important to remember that 「は」 marks the topic, not necessarily the grammatical subject. For example, in 「私は学生です。」 (Watashi wa gakusei desu.), "私" (watashi) is both the topic and the subject.\u000a\u000aWhen 「は」 is used, it often implies a contrast or a general statement about the topic. It sets the stage for the information that follows, telling the listener what the speaker intends to discuss.'),'N5',1,'Crucial Sentence Elements','[{"ja":"私は田中です。","romaji":"watashi wa tanaka desu.","en":"I am Tanaka."},{"ja":"これは日本語の本です。","romaji":"kore wa nihongo no hon desu.","en":"This is a Japanese book."},{"ja":"富士山は高いです。","romaji":"fujisan wa takai desu.","en":"Mount Fuji is tall."},{"ja":"魚は好きですが、肉は好きではありません。","romaji":"sakana wa suki desu ga, niku wa suki dewa arimasen.","en":"I like fish, but I don''t like meat."}]','["n5-ga-identifier"]','["particle","topic marker"]',3);
INSERT INTO grammar_points VALUES(4,'n5-mo','も','mo','too; also; as well; either (in negative sentences)','Noun/Pronoun + も',unistr('「も」 (mo) is a particle that means "too," "also," or "as well." It indicates that the preceding noun or pronoun shares a characteristic or action with something previously mentioned or implied.\u000a\u000aWhen used in a negative sentence, 「も」 means "not... either" or "not... at all." For example, 「私も行きません。」 (Watashi mo ikimasen.) means "I won''t go either."\u000a\u000a「も」 can also be used multiple times in a sentence to list several items that share a commonality, often translated as "both... and..." or "neither... nor..." (in negative contexts). It emphasizes the inclusion of additional items.'),'N5',1,'Crucial Sentence Elements','[{"ja":"私は学生です。彼も学生です。","romaji":"watashi wa gakusei desu. kare mo gakusei desu.","en":"I am a student. He is also a student."},{"ja":"日本語も英語も話せます。","romaji":"nihongo mo eigo mo hanasemasu.","en":"I can speak Japanese and English."},{"ja":"私はコーヒーを飲みません。お茶も飲みません。","romaji":"watashi wa koohii o nomimasen. ocha mo nomimasen.","en":"I don''t drink coffee. I don''t drink tea either."},{"ja":"この本もあの本も面白いです。","romaji":"kono hon mo ano hon mo omoshiroi desu.","en":"Both this book and that book are interesting."}]','[]','["particle","addition"]',4);
INSERT INTO grammar_points VALUES(5,'n5-ga-identifier','が (Identifier)','ga','subject marker particle; but; however',unistr('Noun + が (subject marker)\u000aClause A + が + Clause B (conjunction)'),unistr('The particle 「が」 (ga) has two primary uses at the N5 level. First, it marks the grammatical subject of a sentence, especially when introducing new information or when the subject is the focus of the statement. Unlike 「は」, 「が」 specifically identifies the doer of an action or the entity described by a state.\u000a\u000aSecond, 「が」 can function as a conjunction meaning "but" or "however," connecting two clauses. When used this way, it provides a contrast or a mild opposition between the two parts of the sentence.\u000a\u000aWhen 「が」 marks the subject, it often answers the question "who?" or "what?". For example, 「誰が来ましたか？」 (Dare ga kimashita ka?) "Who came?" - 「私が来ました。」 (Watashi ga kimashita.) "I came." It highlights the subject as the specific entity performing the action or being described.'),'N5',1,'Crucial Sentence Elements','[{"ja":"誰が来ましたか。私が来ました。","romaji":"dare ga kimashita ka. watashi ga kimashita.","en":"Who came? I came."},{"ja":"猫が好きです。","romaji":"neko ga suki desu.","en":"I like cats."},{"ja":"日本語は難しいですが、面白いです。","romaji":"nihongo wa muzukashii desu ga, omoshiroi desu.","en":"Japanese is difficult, but it''s interesting."},{"ja":"窓が開いています。","romaji":"mado ga aite imasu.","en":"The window is open."}]','["n5-wa"]','["particle","subject marker","conjunction"]',5);
INSERT INTO grammar_points VALUES(6,'n5-ka','か','ka','Sentence-ending particle to form a question.','Sentence + か',unistr('The particle `か` is placed at the end of a sentence to turn it into a question. In Japanese, unlike English, you don''t change the word order for questions; you simply add `か`.\u000a\u000aWhen using `か` in formal speech (e.g., with `です` or `ます`), it is always included. In casual speech, especially among friends, `か` is often omitted, and the question is indicated by rising intonation at the end of the sentence, similar to how we might ask a question in English without changing word order.\u000a\u000aRemember to use a rising intonation when asking a question with `か` to make it sound natural.'),'N5',1,'Crucial Sentence Elements','[{"ja":"これは本ですか。","romaji":"kore wa hon desu ka.","en":"Is this a book?"},{"ja":"田中さんは学生ですか。","romaji":"tanaka-san wa gakusei desu ka.","en":"Is Mr. Tanaka a student?"},{"ja":"お元気ですか。","romaji":"o-genki desu ka.","en":"How are you? (Are you well?)"},{"ja":"これはあなたの傘ですか。","romaji":"kore wa anata no kasa desu ka.","en":"Is this your umbrella?"}]','[]','["particle"]',6);
INSERT INTO grammar_points VALUES(7,'n5-no-possessive','の (Possessive)','no','Indicates possession or modifies a noun with another noun.','Noun1 + の + Noun2',unistr('The particle `の` connects two nouns, indicating a relationship between them. Its most common use is to show possession, similar to the English apostrophe ''s'' or the word ''of''. For example, `私のかばん` (watashi no kaban) means ''my bag'' or ''bag of mine''.\u000a\u000a`の` can also be used to describe Noun2 using Noun1. In this case, Noun1 specifies what kind of Noun2 it is, or where Noun2 is from. For instance, `日本語の先生` (nihongo no sensei) means ''Japanese language teacher'' (a teacher of Japanese), and `日本の車` (nihon no kuruma) means ''Japanese car'' (a car from Japan).\u000a\u000aAlways remember that `の` comes *after* the possessor or the modifying noun and *before* the noun being possessed or modified.'),'N5',1,'Crucial Sentence Elements','[{"ja":"これは私の本です。","romaji":"kore wa watashi no hon desu.","en":"This is my book."},{"ja":"彼は日本の学生です。","romaji":"kare wa nihon no gakusei desu.","en":"He is a Japanese student."},{"ja":"これは誰のペンですか。","romaji":"kore wa dare no pen desu ka.","en":"Whose pen is this?"},{"ja":"私の友達は医者です。","romaji":"watashi no tomodachi wa isha desu.","en":"My friend is a doctor."}]','[]','["particle"]',7);
INSERT INTO grammar_points VALUES(8,'n5-kore-sore-are','これ・それ・あれ','kore sore are','This, that, that over there (referring to objects).','これ/それ/あれ + は + Noun + です',unistr('`これ`, `それ`, and `あれ` are demonstrative pronouns used to refer to objects. They are part of the `ko-so-a-do` system, which indicates proximity to the speaker and listener.\u000a\u000a`これ` (kore) refers to something near the speaker. `それ` (sore) refers to something near the listener (but not the speaker). `あれ` (are) refers to something far from both the speaker and the listener.\u000a\u000aThese words function as pronouns, meaning they can stand alone in a sentence and do not need to be followed by a noun. They are typically used to point out or identify specific items.'),'N5',1,'Crucial Sentence Elements','[{"ja":"これは私の辞書です。","romaji":"kore wa watashi no jisho desu.","en":"This is my dictionary."},{"ja":"それは何ですか。","romaji":"sore wa nan desu ka.","en":"What is that (near you)?"},{"ja":"あれは富士山です。","romaji":"are wa fuji-san desu.","en":"That over there is Mt. Fuji."},{"ja":"これは美味しいです。","romaji":"kore wa oishii desu.","en":"This is delicious."}]','["n5-kono-sono-ano"]','["demonstrative","pronoun"]',8);
INSERT INTO grammar_points VALUES(9,'n5-kono-sono-ano','この・その・あの','kono sono ano','This, that, that over there (modifying nouns).','この/その/あの + Noun',unistr('`この`, `その`, and `あの` are demonstrative adjectives used to modify nouns. Like `これ`, `それ`, `あれ`, they follow the `ko-so-a-do` system to indicate proximity.\u000a\u000a`この` (kono) modifies a noun near the speaker. `その` (sono) modifies a noun near the listener (but not the speaker). `あの` (ano) modifies a noun far from both the speaker and the listener.\u000a\u000aUnlike `これ`, `それ`, `あれ`, these words *must* be followed immediately by a noun. They cannot stand alone. They specify which particular noun is being referred to based on its location relative to the speaker and listener.'),'N5',1,'Crucial Sentence Elements','[{"ja":"この本は面白いです。","romaji":"kono hon wa omoshiroi desu.","en":"This book is interesting."},{"ja":"そのカバンは誰のですか。","romaji":"sono kaban wa dare no desu ka.","en":"Whose bag is that (near you)?"},{"ja":"あの建物は病院です。","romaji":"ano tatemono wa byouin desu.","en":"That building over there is a hospital."},{"ja":"このりんごは甘いです。","romaji":"kono ringo wa amai desu.","en":"This apple is sweet."}]','["n5-kore-sore-are"]','["demonstrative","adjective"]',9);
INSERT INTO grammar_points VALUES(10,'n5-ni-location','に (Location)','ni','Indicates a destination, specific point in time, or location of existence.','Noun (place/time) + に',unistr('The particle `に` has several important uses in Japanese, particularly for indicating location and time. One primary use is to mark the destination of movement verbs like `行く` (iku - to go), `来る` (kuru - to come), and `帰る` (kaeru - to return).\u000a\u000aIt is also used to specify a particular point in time when an event occurs, such as `7時に` (shichi-ji ni - at 7 o''clock) or `日曜日に` (nichiyoubi ni - on Sunday). However, `に` is generally omitted when referring to relative times like `今日` (kyou - today) or `明日` (ashita - tomorrow).\u000a\u000aFurthermore, `に` marks the location where something or someone exists, when used with `あります` (arimasu - to exist, for inanimate objects) and `います` (imasu - to exist, for animate beings). This is different from `で` (de), which marks the location where an action takes place. For example, `部屋に本があります` (heya ni hon ga arimasu - There is a book in the room) vs. `部屋で本を読みます` (heya de hon o yomimasu - I read a book in the room).'),'N5',2,'Things About Nouns','[{"ja":"私は日本に行きます。","romaji":"watashi wa nihon ni ikimasu.","en":"I will go to Japan."},{"ja":"彼は公園にいます。","romaji":"kare wa kouen ni imasu.","en":"He is in the park."},{"ja":"会議は3時に始まります。","romaji":"kaigi wa san-ji ni hajimarimasu.","en":"The meeting starts at 3 o''clock."},{"ja":"机の上に本があります。","romaji":"tsukue no ue ni hon ga arimasu.","en":"There is a book on the desk."}]','["n5-de-location-of-action","n5-ni-time"]','["particle"]',10);
INSERT INTO grammar_points VALUES(11,'n5-de-location','で (Location)','de','At; In (location of action)','場所 (Place) + で + 動詞 (Verb)',unistr('The particle 「で」 marks the location where an action or event takes place. It indicates the *venue* or *setting* of an activity, rather than just a static location or destination.\u000a\u000aThis is distinct from 「に」, which often marks the destination of movement verbs (e.g., 「学校に行きます」 - I go to school) or the location of existence (e.g., 「部屋にいます」 - I am in the room). When using 「で」, there is an active verb describing an action performed at that location.\u000a\u000aCommon verbs used with 「で」 include 食べます (tabemasu - to eat), 飲みます (nomimasu - to drink), 勉強します (benkyou shimasu - to study), 買います (kaimasu - to buy), します (shimasu - to do), etc.'),'N5',2,'Things About Nouns','[{"ja":"図書館で本を読みます。","romaji":"toshokan de hon o yomimasu.","en":"I read books at the library."},{"ja":"駅で友達と会いました。","romaji":"eki de tomodachi to aimashita.","en":"I met my friend at the station."},{"ja":"このレストランで美味しい料理を食べました。","romaji":"kono resutoran de oishii ryouri o tabemashita.","en":"I ate delicious food at this restaurant."},{"ja":"公園でサッカーをします。","romaji":"kouen de sakkaa o shimasu.","en":"I play soccer in the park."}]','["n5-ni-location"]','["particle"]',11);
INSERT INTO grammar_points VALUES(12,'n5-wo','を','wo','Direct object marker','名詞 (Noun) + を + 他動詞 (Transitive Verb)',unistr('The particle 「を」 (pronounced ''o'') is primarily used to mark the direct object of a transitive verb. The direct object is the noun that directly receives the action of the verb.\u000a\u000aFor example, in the sentence 「水を飲みます」 (mizu o nomimasu - I drink water), 「水」 (mizu - water) is the direct object, and 「を」 indicates that it is what is being drunk. Most verbs that take a direct object are transitive verbs.\u000a\u000aAdditionally, 「を」 can also indicate the place through which one moves (e.g., 「道を歩きます」 - michi o arukimasu - I walk along the road) or the starting point from which one departs (e.g., 「家を出ます」 - ie o demasu - I leave the house).'),'N5',2,'Things About Nouns','[{"ja":"日本語を勉強しています。","romaji":"nihongo o benkyou shiteimasu.","en":"I am studying Japanese."},{"ja":"パンを食べます。","romaji":"pan o tabemasu.","en":"I eat bread."},{"ja":"公園を散歩します。","romaji":"kouen o sanpo shimasu.","en":"I take a walk through the park."},{"ja":"会社を出ます。","romaji":"kaisha o demasu.","en":"I leave the company."}]','[]','["particle"]',12);
INSERT INTO grammar_points VALUES(13,'n5-to-and','と (And)','to','And; With (exhaustive list, companion)','名詞 (Noun) + と + 名詞 (Noun)',unistr('The particle 「と」 has two main uses at the N5 level. Firstly, it connects two or more nouns to form an exhaustive list, meaning that only the items mentioned are included. For example, 「ペンとノート」 (pen to nooto) means "a pen and a notebook," and implies that these are the only items being referred to.\u000a\u000aSecondly, 「と」 is used to indicate a companion or partner with whom an action is performed. In this case, it translates to "with." For instance, 「友達と映画を見ます」 (tomodachi to eiga o mimasu) means "I watch a movie with my friend."\u000a\u000aIt''s important to remember that 「と」 creates a complete list. If you want to give a non-exhaustive list (e.g., "apples, bananas, and *other things*"), you should use 「や」 instead.'),'N5',2,'Things About Nouns','[{"ja":"私と弟は学生です。","romaji":"watashi to otouto wa gakusei desu.","en":"My younger brother and I are students."},{"ja":"コーヒーとパンを買いました。","romaji":"koohii to pan o kaimashita.","en":"I bought coffee and bread."},{"ja":"家族と旅行に行きます。","romaji":"kazoku to ryokou ni ikimasu.","en":"I go on a trip with my family."},{"ja":"先生と話しました。","romaji":"sensei to hanashimashita.","en":"I talked with the teacher."}]','["n5-ya"]','["particle","conjunction"]',13);
INSERT INTO grammar_points VALUES(14,'n5-ya','や','ya','And; Such as (non-exhaustive list)','名詞 (Noun) + や + 名詞 (Noun) (など)',unistr('The particle 「や」 is used to list a few examples of items, implying that there are other similar items not mentioned. It translates to "and," "such as," or "among other things." Unlike 「と」, which creates an exhaustive list, 「や」 indicates that the list is not complete.\u000a\u000aIt is often followed by 「など」 (nado), which means "etc." or "and so on," further emphasizing the non-exhaustive nature of the list. Even without 「など」, the implication of other items still exists.\u000a\u000aUse 「や」 when you want to give a few representative examples without listing every single item. For instance, if you say 「りんごやバナナを買いました」 (ringo ya banana o kaimashita), it means you bought apples, bananas, and other fruits or items, but you''re only mentioning these two as examples.'),'N5',2,'Things About Nouns','[{"ja":"机の上に本やペンがあります。","romaji":"tsukue no ue ni hon ya pen ga arimasu.","en":"There are books, pens, and other things on the desk."},{"ja":"日本で寿司やラーメンを食べたいです。","romaji":"nihon de sushi ya raamen o tabetai desu.","en":"I want to eat sushi, ramen, and other things in Japan."},{"ja":"私の趣味は読書や映画鑑賞などです。","romaji":"watashi no shumi wa dokusho ya eiga kanshou nado desu.","en":"My hobbies are reading, watching movies, and so on."},{"ja":"かばんの中に財布や鍵が入っています。","romaji":"kaban no naka ni saifu ya kagi ga haitte imasu.","en":"There''s a wallet, keys, and other things in my bag."}]','["n5-to-and"]','["particle","conjunction"]',14);
INSERT INTO grammar_points VALUES(15,'n5-kara-from','から (From)','kara','From (starting point in time or space)','場所 (Place) + から\n時間 (Time) + から',unistr('The particle 「から」 is used to indicate a starting point, either in terms of location or time. When used with a place, it means "from" that location. For example, 「東京から来ました」 (toukyou kara kimashita) means "I came from Tokyo."\u000a\u000aWhen used with time, 「から」 indicates the starting time of an event or period. For instance, 「9時から働きます」 (kuji kara hatarakimasu) means "I work from 9 o''clock." It can also be used to indicate the origin of something, like a gift from someone.\u000a\u000aWhile 「から」 also means "because" or "since" (indicating a reason), this entry focuses on its usage as a starting point. The context usually makes it clear which meaning is intended. When paired with 「まで」 (made - until/to), it forms the common phrase 「〜から〜まで」 (kara made - from ~ to ~).'),'N5',2,'Things About Nouns','[{"ja":"大阪から来ました。","romaji":"oosaka kara kimashita.","en":"I came from Osaka."},{"ja":"朝9時から仕事です。","romaji":"asa kuji kara shigoto desu.","en":"Work starts from 9 AM."},{"ja":"このバスは駅前から出発します。","romaji":"kono basu wa ekimae kara shuppatsu shimasu.","en":"This bus departs from in front of the station."},{"ja":"先週から日本語を勉強しています。","romaji":"senshuu kara nihongo o benkyou shiteimasu.","en":"I have been studying Japanese since last week."}]','["n5-made"]','["particle"]',15);
INSERT INTO grammar_points VALUES(16,'n5-made','まで','made','until; as far as; to (a place/time)','Noun + まで',unistr('「まで」 (made) is a particle that indicates a limit or extent. It can refer to a point in time, meaning "until" or "by," or a point in space, meaning "as far as" or "to."\u000a\u000aWhen used with time, it specifies the end point of an action or state. For example, 「明日まで」 (ashita made) means "until tomorrow." When combined with 「に」 (ni), as in 「来週までに」 (raishū made ni), it means "by next week," indicating a deadline.\u000a\u000aWhen used with a place, it indicates the destination or the extent of a journey. For example, 「駅まで」 (eki made) means "to the station" or "as far as the station." It can also imply "up to" a certain level or degree.'),'N5',2,'Things About Nouns','[{"ja":"図書館は午後5時までです。","romaji":"Toshokan wa gogo goji made desu.","en":"The library is open until 5 PM."},{"ja":"東京から大阪まで新幹線で行きます。","romaji":"Tōkyō kara Ōsaka made shinkansen de ikimasu.","en":"I will go from Tokyo to Osaka by bullet train."},{"ja":"この仕事は来週までに終わらせます。","romaji":"Kono shigoto wa raishū made ni owarasemasu.","en":"I will finish this work by next week."},{"ja":"彼は昨日まで日本にいました。","romaji":"Kare wa kinō made Nihon ni imashita.","en":"He was in Japan until yesterday."}]','["n5-kara"]','["particle","time","place"]',16);
INSERT INTO grammar_points VALUES(17,'n5-ni-time','に (Time)','ni','at (a specific time); on (a specific day)','Specific Time/Date + に',unistr('The particle 「に」 (ni) is used to mark a specific point in time when an action occurs. This includes specific hours (例: 「3時に」 - at 3 o''clock), days of the week (例: 「日曜日に」 - on Sunday), dates (例: 「10月1日に」 - on October 1st), and years (例: 「2024年に」 - in 2024).\u000a\u000aIt is generally used with quantifiable or specific time expressions. For example, you would say 「7時に起きます」 (shichiji ni okimasu - I wake up at 7 o''clock).\u000a\u000aHowever, 「に」 is *not* used with relative time expressions like 「今日」 (kyō - today), 「明日」 (ashita - tomorrow), 「昨日」 (kinō - yesterday), 「来週」 (raishū - next week), 「先月」 (sengetsu - last month), 「毎日」 (mainichi - every day), or 「いつ」 (itsu - when). These expressions inherently refer to a specific time in relation to the present, so 「に」 is omitted.'),'N5',2,'Things About Nouns','[{"ja":"私は毎朝6時に起きます。","romaji":"Watashi wa maiasa rokuji ni okimasu.","en":"I wake up at 6 AM every morning."},{"ja":"会議は月曜日にあります。","romaji":"Kaigi wa getsuyōbi ni arimasu.","en":"The meeting is on Monday."},{"ja":"日本へは2024年に行きます。","romaji":"Nihon e wa nisen nijūyonen ni ikimasu.","en":"I will go to Japan in 2024."},{"ja":"誕生日は7月15日です。","romaji":"Tanjōbi wa shichigatsu jūgonichi desu.","en":"My birthday is on July 15th."}]','["n5-ni-place","n5-ni-purpose"]','["particle","time"]',17);
INSERT INTO grammar_points VALUES(18,'n5-ne','ね','ne','isn''t it?; right?; you know (seeking agreement/confirmation)','Sentence (casual/polite) + ね',unistr('The sentence-ending particle 「ね」 (ne) is used to seek agreement or confirmation from the listener. It implies that the speaker expects the listener to agree with what they are saying, similar to "right?" or "isn''t it?" in English.\u000a\u000aIt can also be used to share information or an observation, inviting the listener to acknowledge or respond. For example, 「このケーキ、美味しいですね」 (Kono kēki, oishii desu ne - This cake is delicious, isn''t it?).\u000a\u000a「ね」 creates a softer, more friendly tone and is often used in casual conversation. It can also be used to confirm information that both the speaker and listener are aware of.'),'N5',2,'Things About Nouns','[{"ja":"この映画、面白いですね。","romaji":"Kono eiga, omoshiroi desu ne.","en":"This movie is interesting, isn''t it?"},{"ja":"今日は暑いですね。","romaji":"Kyō wa atsui desu ne.","en":"It''s hot today, isn''t it?"},{"ja":"そうですね。","romaji":"Sō desu ne.","en":"That''s right, isn''t it? (Often used as a filler or to agree)"},{"ja":"また明日ね！","romaji":"Mata ashita ne!","en":"See you tomorrow, okay?"}]','["n5-yo"]','["particle","sentence-ending"]',18);
INSERT INTO grammar_points VALUES(19,'n5-yo','よ','yo','I tell you; you know (emphasizing information)','Sentence (casual/polite) + よ',unistr('The sentence-ending particle 「よ」 (yo) is used to emphasize a statement or to inform the listener of something new or something they might not know. It adds a sense of conviction or assertion to the speaker''s words.\u000a\u000aIt can be used to give advice, make a strong suggestion, or correct a misunderstanding. For example, 「それは違うよ」 (Sore wa chigau yo - That''s wrong, you know).\u000a\u000aWhile 「ね」 seeks agreement, 「よ」 provides information or expresses the speaker''s strong opinion. Using 「よ」 too frequently or in certain contexts can sound assertive or even slightly confrontational, so it''s important to use it appropriately.'),'N5',2,'Things About Nouns','[{"ja":"この本、とても面白いですよ。","romaji":"Kono hon, totemo omoshiroi desu yo.","en":"This book is very interesting, I tell you."},{"ja":"明日は雨が降るそうですよ。","romaji":"Ashita wa ame ga furu sō desu yo.","en":"I hear it''s going to rain tomorrow, you know."},{"ja":"もう時間がないよ！","romaji":"Mō jikan ga nai yo!","en":"There''s no more time!"},{"ja":"大丈夫だよ。心配しないで。","romaji":"Daijōbu da yo. Shinpai shinaide.","en":"It''s okay. Don''t worry."}]','["n5-ne"]','["particle","sentence-ending"]',19);
INSERT INTO grammar_points VALUES(20,'n5-masu','ます','masu','polite verb ending (present/future affirmative)','Verb Stem + ます',unistr('「ます」 (masu) is a polite verb ending used primarily in formal or polite speech. It attaches to the stem of verbs to form the present affirmative tense. For example, 「食べます」 (tabemasu - eat), 「行きます」 (ikimasu - go), 「します」 (shimasu - do).\u000a\u000aThis form is essential for N5 learners as it is the standard way to speak politely in Japanese. It indicates actions that happen regularly, are currently happening, or will happen in the future.\u000a\u000aThe 「ます」 form can be conjugated into other polite forms: 「ません」 (masen - negative), 「ました」 (mashita - past affirmative), and 「ませんでした」 (masen deshita - past negative). Mastering these forms is fundamental for basic communication.'),'N5',3,'Basic Verb Conjugation','[{"ja":"私は毎日日本語を勉強します。","romaji":"Watashi wa mainichi Nihongo o benkyō shimasu.","en":"I study Japanese every day."},{"ja":"田中さんは会社で働きます。","romaji":"Tanaka-san wa kaisha de hatarakimasu.","en":"Mr. Tanaka works at a company."},{"ja":"来週、友達と映画を見ます。","romaji":"Raishū, tomodachi to eiga o mimasu.","en":"I will watch a movie with my friend next week."},{"ja":"朝ごはんを食べます。","romaji":"Asagohan o tabemasu.","en":"I eat breakfast."}]','["n5-masen","n5-mashita","n5-masendeshita"]','["verb","polite form"]',20);
INSERT INTO grammar_points VALUES(21,'n5-masen-ka','ませんか','masen ka','Won''t you?; Shall we?; Would you like to?','Verb (ます-form, drop ます) + ませんか',unistr('「ませんか」 is used to make a polite invitation or suggestion. It literally means "won''t you do X?" but is understood as "would you like to do X?" or "shall we do X?". It''s a very common and polite way to invite someone to join an activity or offer something.\u000a\u000aThis form is more polite than the casual 「〜ない？」 or 「〜よう」 forms for invitations. It implies a slight expectation or hope that the other person will agree, but it''s still a question, allowing them to decline politely. It''s often used when you are proposing an activity to someone you don''t know very well or in a formal setting.\u000a\u000aFor example, 「コーヒーを飲みませんか？」 (Would you like to drink coffee?) is a polite way to offer coffee. When used with an action, like 「一緒に映画を見ませんか？」 (Shall we watch a movie together?), it''s a direct invitation.'),'N5',3,'Basic Verb Conjugation','[{"ja":"今日一緒に食べませんか？","romaji":"Kyou isshoni tabemasen ka?","en":"Do you want to eat together today?"},{"ja":"うちで映画を見ませんか。","romaji":"Uchi de eiga o mimasen ka.","en":"Would you like to watch a movie at my place?"},{"ja":"お茶にしませんか？","romaji":"Ocha ni shimasen ka?","en":"Would you care for some tea?"},{"ja":"日曜日にテニスをしませんか。","romaji":"Nichiyoubi ni tenisu o shimasen ka.","en":"Shall we play tennis on Sunday?"}]','["n5-mashou"]','["verb conjugation","invitation","question","polite form"]',21);
INSERT INTO grammar_points VALUES(22,'n5-mashita','ました','mashita','Polite past tense verb ending (affirmative).','Verb (ます-form, drop ます) + ました',unistr('「ました」 is the polite past affirmative ending for Japanese verbs. It indicates that an action was completed in the past in a polite context. It is formed by taking the ます-form of a verb, dropping ます, and adding ました.\u000a\u000aFor example, the ます-form of 「食べる」 (to eat) is 「食べます」. To make it past tense polite, you drop ます and add ました, becoming 「食べました」 (ate). Similarly, 「行きます」 (to go) becomes 「行きました」 (went).\u000a\u000aThis form is essential for polite conversations when talking about past events. It contrasts with 「ます」 (polite present/future affirmative) and 「ませんでした」 (polite past negative).'),'N5',3,'Basic Verb Conjugation','[{"ja":"昨日、映画を見ました。","romaji":"Kinou, eiga o mimashita.","en":"I watched a movie yesterday."},{"ja":"先週、東京に行きました。","romaji":"Senshuu, Toukyou ni ikimashita.","en":"I went to Tokyo last week."},{"ja":"新しい本を買いました。","romaji":"Atarashii hon o kaimashita.","en":"I bought a new book."},{"ja":"私たちは日本語を勉強しました。","romaji":"Watashitachi wa nihongo o benkyoushimashita.","en":"We studied Japanese."}]','["n5-masu","n5-masen","n5-masen-deshita"]','["verb conjugation","past tense","polite form"]',22);
INSERT INTO grammar_points VALUES(23,'n5-masen-deshita','ませんでした','masen deshita','Polite past tense verb ending (negative).','Verb (ます-form, drop ます) + ませんでした',unistr('「ませんでした」 is the polite past negative ending for Japanese verbs. It indicates that an action did not occur or was not completed in the past, in a polite context. It is formed by taking the ます-form of a verb, dropping ます, and adding ませんでした.\u000a\u000aFor example, the ます-form of 「食べる」 (to eat) is 「食べます」. To make it past tense negative polite, you drop ます and add ませんでした, becoming 「食べませんでした」 (did not eat). Similarly, 「行きます」 (to go) becomes 「行きませんでした」 (did not go).\u000a\u000aThis form is crucial for polite conversations when stating that something did not happen in the past. It contrasts with 「ません」 (polite present/future negative) and 「ました」 (polite past affirmative).'),'N5',3,'Basic Verb Conjugation','[{"ja":"昨日は何も食べませんでした。","romaji":"Kinou wa nani mo tabemasen deshita.","en":"I didn''t eat anything yesterday."},{"ja":"パーティーに行きませんでした。","romaji":"Paatii ni ikimasen deshita.","en":"I didn''t go to the party."},{"ja":"今日は仕事に行きませんでした。","romaji":"Kyou wa shigoto ni ikimasen deshita.","en":"I didn''t go to work today."},{"ja":"彼らは説明を理解しませんでした。","romaji":"Karera wa setsumei o rikai shimasen deshita.","en":"They didn''t understand the explanation."}]','["n5-masu","n5-masen","n5-mashita"]','["verb conjugation","past tense","negative form","polite form"]',23);
INSERT INTO grammar_points VALUES(24,'n5-ru-verb-plain','る-Verb (Dictionary)','ru verb','Dictionary form of Group 2 (Ichidan) verbs.','Verb stem + る',unistr('「る-Verb (Dictionary)」 refers to the dictionary form of Group 2 verbs, also known as Ichidan verbs. These verbs are characterized by ending in 「る」, and the syllable immediately preceding 「る」 is either an ''e'' sound (e-dan) or an ''i'' sound (i-dan).\u000a\u000aExamples include 「食べる」 (taberu - to eat), 「見る」 (miru - to see), 「寝る」 (neru - to sleep), and 「教える」 (oshieru - to teach). The dictionary form is the basic, plain form of the verb, used for dictionary lookup and in casual speech.\u000a\u000aTo conjugate Ichidan verbs, you typically drop the final 「る」 and add various endings. Understanding the dictionary form is fundamental for learning other verb conjugations and for identifying verb groups.'),'N5',3,'Basic Verb Conjugation','[{"ja":"毎朝6時に起きる。","romaji":"Maiasa rokuji ni okiru.","en":"I wake up at 6 every morning."},{"ja":"テレビを見る。","romaji":"Terebi o miru.","en":"I watch TV."},{"ja":"夜は早く寝る。","romaji":"Yoru wa hayaku neru.","en":"I sleep early at night."},{"ja":"先生が日本語を教える。","romaji":"Sensei ga nihongo o oshieru.","en":"The teacher teaches Japanese."}]','["n5-u-verb-plain"]','["verb conjugation","dictionary form","plain form","ichidan verb"]',24);
INSERT INTO grammar_points VALUES(25,'n5-u-verb-plain','う-Verb (Dictionary)','u verb','Dictionary form of Group 1 (Godan) verbs.','Verb stem + う-ending (e.g., -う, -く, -す, -つ, -ぬ, -ぶ, -む, -る)',unistr('「う-Verb (Dictionary)」 refers to the dictionary form of Group 1 verbs, also known as Godan verbs. These verbs are characterized by their dictionary form ending in a ''u'' sound (う, く, す, つ, ぬ, ぶ, む, る) and do not fit the Ichidan verb pattern.\u000a\u000aExamples include 「話す」 (hanasu - to talk), 「読む」 (yomu - to read), 「書く」 (kaku - to write), and 「行く」 (iku - to go). The dictionary form is the basic, plain form of the verb, used for dictionary lookup and in casual speech.\u000a\u000aGodan verbs undergo more complex sound changes when conjugated compared to Ichidan verbs. Understanding their dictionary form is crucial for correctly applying various grammatical patterns and for identifying verb groups.'),'N5',3,'Basic Verb Conjugation','[{"ja":"友達と話す。","romaji":"Tomodachi to hanasu.","en":"I talk with friends."},{"ja":"本を読む。","romaji":"Hon o yomu.","en":"I read books."},{"ja":"手紙を書く。","romaji":"Tegami o kaku.","en":"I write letters."},{"ja":"毎日学校に行く。","romaji":"Mainichi gakkou ni iku.","en":"I go to school every day."}]','["n5-ru-verb-plain"]','["verb conjugation","dictionary form","plain form","godan verb"]',25);
INSERT INTO grammar_points VALUES(26,'n5-ru-verb-negative','る-Verb (Negative)','ru verb negative','Don''t do (ru-verb); will not do (ru-verb)','る-Verb (stem) + ない',unistr('The negative casual form for る-verbs (also known as Group 2 verbs or Ichidan verbs) is formed by dropping the final る and adding ない. This form is used in casual conversations and in various grammatical structures.\u000a\u000aFor example, 食べる (taberu - to eat) becomes 食べない (tabenai - don''t eat). 見る (miru - to see/watch) becomes 見ない (minai - don''t see/watch).\u000a\u000aThis form expresses a negative action or state in the present or future, similar to "don''t" or "won''t" in English. It is the plain form equivalent of the polite negative form, Verb (ます-stem) + ません.'),'N5',3,'Basic Verb Conjugation','[{"ja":"朝ごはんを食べない。","romaji":"Asagohan wo tabenai.","en":"I don''t eat breakfast."},{"ja":"テレビを見ない。","romaji":"Terebi wo minai.","en":"I don''t watch TV."},{"ja":"今日は早く起きない。","romaji":"Kyou wa hayaku okinai.","en":"I won''t wake up early today."},{"ja":"ここに猫がいない。","romaji":"Koko ni neko ga inai.","en":"There is no cat here."}]','["n5-ru-verb-masu","n5-u-verb-negative"]','["verb conjugation","negative form","casual form"]',26);
INSERT INTO grammar_points VALUES(27,'n5-u-verb-negative','う-Verb (Negative)','u verb negative','Don''t do (u-verb); will not do (u-verb)',unistr('う-Verb (u-ending changes to a-ending) + ない\u000a*Special case: う -> わない'),unistr('The negative casual form for う-verbs (also known as Group 1 verbs or Godan verbs) is formed by changing the final う-sound to its corresponding あ-sound and then adding ない. For example, 飲む (nomu - to drink) becomes 飲まない (nomanai - don''t drink).\u000a\u000aThere is a special rule for verbs ending in う (e.g., 買う - kau - to buy). In this case, う changes to わ, so 買わない (kawanai - don''t buy). This is to avoid an awkward ''あわない'' sound.\u000a\u000aThis form expresses a negative action or state in the present or future, similar to "don''t" or "won''t" in English. It is the plain form equivalent of the polite negative form, Verb (ます-stem) + ません.'),'N5',3,'Basic Verb Conjugation','[{"ja":"お酒を飲まない。","romaji":"Osake wo nomanai.","en":"I don''t drink alcohol."},{"ja":"手紙を書かない。","romaji":"Tegami wo kakanai.","en":"I don''t write letters."},{"ja":"今日は学校に行かない。","romaji":"Kyou wa gakkou ni ikanai.","en":"I won''t go to school today."},{"ja":"新しい車を買わない。","romaji":"Atarashii kuruma wo kawanai.","en":"I won''t buy a new car."}]','["n5-u-verb-masu","n5-ru-verb-negative"]','["verb conjugation","negative form","casual form"]',27);
INSERT INTO grammar_points VALUES(28,'n5-mashou','ましょう','mashou','Let''s ~; Shall we ~ (polite suggestion)','Verb (ます-stem) + ましょう',unistr('The `ましょう` form is a polite volitional expression used to make suggestions, invite someone to do something together, or express the speaker''s polite intention to do something.\u000a\u000aTo form it, simply take the ます-stem of any verb (the part before ます) and add ましょう. For example, 食べます (tabemasu - to eat) becomes 食べましょう (tabemashou - let''s eat). 行きます (ikimasu - to go) becomes 行きましょう (ikimashou - let''s go).\u000a\u000aThis form is commonly used in polite social situations and when addressing someone you want to be respectful towards. It''s a very useful phrase for initiating activities with others.'),'N5',3,'Basic Verb Conjugation','[{"ja":"行きましょう！","romaji":"Ikimashou!","en":"Let''s go!"},{"ja":"駅で会いましょう！","romaji":"Eki de aimashou!","en":"Let''s meet at the station!"},{"ja":"もうご飯の時間だよ、早く食べましょう！","romaji":"Mou gohan no jikan dayo, hayaku tabemashou!","en":"It''s already dinner time, let''s hurry up and eat!"},{"ja":"帰る前に教室をきれいにしましょう。","romaji":"Kaeru mae ni kyoushitsu o kirei ni shimashou.","en":"Before we go home, let''s clean up the classroom."}]','["n5-masu"]','["volitional form","polite form","suggestion"]',28);
INSERT INTO grammar_points VALUES(29,'n5-ru-verb-past','る-Verb (Past)','ru verb past','Did (ru-verb); (ru-verb)ed (casual past)','る-Verb (stem) + た',unistr('The casual past tense for る-verbs (Group 2 verbs) is formed by dropping the final る and adding た. This is often referred to as the た-form, which is a fundamental conjugation used in many other grammar patterns.\u000a\u000aFor example, 食べる (taberu - to eat) becomes 食べた (tabeta - ate). 見る (miru - to see/watch) becomes 見た (mita - saw/watched).\u000a\u000aThis form expresses an action that was completed in the past and is used in casual conversation. It is the plain form equivalent of the polite past tense, Verb (ます-stem) + ました.'),'N5',4,'More Verb Forms','[{"ja":"昨日、早く起きた。","romaji":"Kinou, hayaku okita.","en":"I woke up early yesterday."},{"ja":"全部食べた。","romaji":"Zenbu tabeta.","en":"I ate everything."},{"ja":"映画を見た。","romaji":"Eiga wo mita.","en":"I watched a movie."},{"ja":"彼はもう家にいた。","romaji":"Kare wa mou ie ni ita.","en":"He was already home."}]','["n5-ru-verb-masu","n5-u-verb-past"]','["verb conjugation","past tense","casual form"]',29);
INSERT INTO grammar_points VALUES(30,'n5-u-verb-past','う-Verb (Past)','u verb past','Did (u-verb); (u-verb)ed (casual past)',unistr('う-Verb (changes based on ending) + た/だ\u000a* う, つ, る -> った\u000a* む, ぶ, ぬ -> んだ\u000a* く -> いた\u000a* ぐ -> いだ\u000a* す -> した'),unistr('The casual past tense for う-verbs (Group 1 verbs) involves various sound changes (音便 - onbin) before adding た or だ. This is also known as the た-form and is crucial for casual speech and forming other grammar patterns.\u000a\u000aThe specific changes depend on the consonant preceding the final う-sound:\u000a*   Verbs ending in う, つ, る change to った (e.g., 買う → 買った, 待つ → 待った, 帰る → 帰った).\u000a*   Verbs ending in む, ぶ, ぬ change to んだ (e.g., 飲む → 飲んだ, 遊ぶ → 遊んだ, 死ぬ → 死んだ).\u000a*   Verbs ending in く change to いた (e.g., 書く → 書いた).\u000a*   Verbs ending in ぐ change to いだ (e.g., 泳ぐ → 泳いだ).\u000a*   Verbs ending in す change to した (e.g., 話す → 話した).\u000a\u000aThis form expresses an action that was completed in the past and is used in casual conversation. It is the plain form equivalent of the polite past tense, Verb (ます-stem) + ました.'),'N5',4,'More Verb Forms','[{"ja":"友達と話した。","romaji":"Tomodachi to hanashita.","en":"I talked with my friend."},{"ja":"本を読んだ。","romaji":"Hon wo yonda.","en":"I read a book."},{"ja":"昨日、手紙を書いた。","romaji":"Kinou, tegami wo kaita.","en":"I wrote a letter yesterday."},{"ja":"公園で遊んだ。","romaji":"Kouen de asonda.","en":"I played in the park."}]','["n5-u-verb-masu","n5-ru-verb-past","n5-te-form"]','["verb conjugation","past tense","casual form","sound change"]',30);
INSERT INTO grammar_points VALUES(31,'n5-naide-kudasai','〜ないでください','naide kudasai','Please don''t do ~','Verb (ない-form) + でください',unistr('The grammar pattern `〜ないでください` is used to make a polite negative request, asking someone *not* to do something. It is formed by taking the plain negative (ない-form) of a verb, dropping the final `い`, and adding `でください`.\u000a\u000aFor example, `行く (iku)` becomes `行かない (ikanai)`, then `行かないでください (ikanaide kudasai)`. For `食べる (taberu)`, it becomes `食べない (tabenai)`, then `食べないでください (tabenaide kudasai)`.\u000a\u000aYou can also use `〜ないで` on its own for a more casual or direct negative request, often used among friends or family. This pattern is essential for expressing prohibitions or asking others to refrain from certain actions.'),'N5',4,'More Verb Forms','[{"ja":"泣かないでください。","romaji":"nakanaide kudasai.","en":"Please don''t cry."},{"ja":"このパソコンを使わないでください。","romaji":"kono pasokon o tsukawanaide kudasai.","en":"Please don''t use this computer."},{"ja":"明日の予定を忘れないでください。","romaji":"ashita no yotei o wasurenaide kudasai.","en":"Please don''t forget about tomorrow''s plans."},{"ja":"私のことを心配しないでください。","romaji":"watashi no koto o shinpai shinaide kudasai.","en":"Please don''t worry about me."}]','["n5-te-kudasai"]','["verb form","request","negative"]',31);
INSERT INTO grammar_points VALUES(32,'n5-nakatta','〜なかった','nakatta','was not; did not (past negative plain form)',unistr('Verb (ない-form, drop い) + かった\u000aい-adjective (drop い) + くなかった\u000aな-adjective (drop な) + じゃなかった\u000aNoun + じゃなかった'),'`〜なかった` is the plain past negative form used for verbs, い-adjectives, な-adjectives, and nouns. It expresses that something ','N5',4,'More Verb Forms','[{"ja":"昨日は雨が降らなかった。","romaji":"kinou wa ame ga furanakatta.","en":"It didn''t rain yesterday."},{"ja":"その映画は面白くなかった。","romaji":"sono eiga wa omoshirokunakatta.","en":"That movie was not interesting."},{"ja":"彼は学生じゃなかった。","romaji":"kare wa gakusei janakatta.","en":"He was not a student."},{"ja":"テストは簡単じゃなかったです。","romaji":"tesuto wa kantan janakatta desu.","en":"The test was not easy."}]','["n5-nai","n5-masen-deshita"]','["verb form","adjective form","negative","past tense","plain form"]',32);
INSERT INTO grammar_points VALUES(33,'n5-ga-but','が','ga','but; however; although','Sentence A + が + Sentence B',unistr('The particle `が` can be used as a conjunction to connect two clauses, indicating a contrast or a gentle opposition between them. It functions similarly to "but" or "however" in English.\u000a\u000aUnlike `けど` or `けれど`, `が` can sometimes be used to introduce a topic politely before stating a request or a problem, softening the statement. For example, `すみませんが、... (sumimasen ga, ...)` means "Excuse me, but...".\u000a\u000aWhen `が` connects two sentences, the first sentence provides background or a contrasting idea to the second. It''s a versatile particle for creating more complex sentences in Japanese.'),'N5',4,'More Verb Forms','[{"ja":"日本語は難しいですが、面白いです。","romaji":"nihongo wa muzukashii desu ga, omoshiroi desu.","en":"Japanese is difficult, but interesting."},{"ja":"この本は高いですが、買いたいです。","romaji":"kono hon wa takai desu ga, kaitai desu.","en":"This book is expensive, but I want to buy it."},{"ja":"雨が降っていますが、出かけましょう。","romaji":"ame ga futte imasu ga, dekakemashou.","en":"It''s raining, but let''s go out."},{"ja":"すみませんが、もう一度お願いします。","romaji":"sumimasen ga, mou ichido onegai shimasu.","en":"Excuse me, but please do it one more time."}]','["n5-kedo"]','["particle","conjunction"]',33);
INSERT INTO grammar_points VALUES(34,'n5-kedo','けど・けれど','kedo keredo','but; however; although',unistr('Verb (Plain form) + けど/けれど\u000aい-adjective (Plain form) + けど/けれど\u000aな-adjective (Plain form, drop な) + だけど/ですけど\u000aNoun + だけど/ですけど'),unistr('`けど` and `けれど` are conjunctions that mean "but," "however," or "although." They are used to connect two clauses where the second clause presents a contrasting or somewhat unexpected idea compared to the first.\u000a\u000a`けれど` is slightly more formal than `けど`, but both are commonly used in everyday conversation. They can also be used to soften a statement or a request, or to provide background information before making a main point, similar to `が` but generally more casual.\u000a\u000aWhen connecting a な-adjective or a noun, `だ` is often added before `けど/けれど` in plain form (e.g., `きれいだけど`, `学生だけど`). In polite form, `ですけど` is used (e.g., `きれいですけど`, `学生ですけど`).'),'N5',4,'More Verb Forms','[{"ja":"仕事は辛いけど楽しい。","romaji":"shigoto wa tsurai kedo tanoshii.","en":"Work is tough, but fun."},{"ja":"金はないけど夢はある。","romaji":"kane wa nai kedo yume wa aru.","en":"I don''t have money, but I have dreams."},{"ja":"スポーツは上手じゃないけど、好きです。","romaji":"supootsu wa jouzu janai kedo, suki desu.","en":"I''m not good at sports, but I like them."},{"ja":"悪いけど、明日のパーティーに行けません。","romaji":"warui kedo, ashita no paatii ni ikemasen.","en":"Sorry, but I can''t make it to tomorrow''s party."}]','["n5-ga-but"]','["conjunction"]',34);
INSERT INTO grammar_points VALUES(35,'n5-ni-direction','に','ni','to; toward (direction/destination)','Place/Direction + に + Movement Verb',unistr('The particle `に` is used to indicate the destination or direction of a movement. It marks the specific place or point that the subject is moving towards or arriving at. It is typically used with verbs of movement such as `行く (iku - to go)`, `来る (kuru - to come)`, `帰る (kaeru - to return)`, `入る (hairu - to enter)`, etc.\u000a\u000aWhile `へ (e)` can also indicate direction, `に` often implies a more specific destination or arrival point. For example, `学校に行く (gakkou ni iku)` means "to go to school," emphasizing the school as the destination. It''s a fundamental particle for expressing movement in Japanese.'),'N5',4,'More Verb Forms','[{"ja":"右に曲がってください。","romaji":"migi ni magatte kudasai.","en":"Please turn right."},{"ja":"日本に行きたいです。","romaji":"nihon ni ikitai desu.","en":"I want to go to Japan."},{"ja":"家に帰ります。","romaji":"uchi ni kaerimasu.","en":"I will go home."},{"ja":"駅に友達を迎えに行きます。","romaji":"eki ni tomodachi o mukae ni ikimasu.","en":"I''m going to the station to pick up a friend."}]','["n5-e"]','["particle","direction"]',35);
INSERT INTO grammar_points VALUES(36,'n5-ru-verb-neg-past','る-Verb (Neg-Past)','ru verb neg past','Didn''t do (ru-verb)','る-Verb (ます-form stem) + なかった',unistr('This grammar point explains how to form the negative past tense for る-verbs (Group 2 verbs). To do this, you take the verb''s ます-form stem (the part before ます) and attach なかった.\u000a\u000aFor example, 食べる (taberu, to eat) becomes 食べます (tabemasu) in the ます-form. The stem is 食べ (tabe). Adding なかった makes it 食べなかった (tabenakatta), meaning "didn''t eat."\u000a\u000aThis form is used to describe actions that did not occur in the past.'),'N5',5,'Linking Structures','[{"ja":"昨日は何も食べなかった。","romaji":"Kinou wa nani mo tabenakatta.","en":"I didn''t eat anything yesterday."},{"ja":"その映画は面白くなかったので、見なかった。","romaji":"Sono eiga wa omoshirokunakatta node, minakatta.","en":"That movie wasn''t interesting, so I didn''t watch it."},{"ja":"昨夜は忙しくて、寝なかった。","romaji":"Sakuya wa isogashikute, nenakatta.","en":"I was busy last night, so I didn''t sleep."},{"ja":"今朝は早く起きなかった。","romaji":"Kesa wa hayaku okinakatta.","en":"I didn''t wake up early this morning."}]','["n5-ru-verb-neg","n5-ru-verb-past"]','["verb conjugation","negative form","past tense"]',36);
INSERT INTO grammar_points VALUES(37,'n5-u-verb-neg-past','う-Verb (Neg-Past)','u verb neg past','Didn''t do (u-verb)',unistr('う-Verb (dictionary form, drop う, change to あ-sound) + なかった\u000a*Exception: 行く (iku) → 行かなかった (ikanakatta)'),unistr('This grammar point explains how to form the negative past tense for う-verbs (Group 1 verbs). To do this, you change the final う-sound of the verb''s dictionary form to its corresponding あ-sound, and then attach なかった.\u000a\u000aFor example, 飲む (nomu, to drink) becomes 飲まなかった (nomanakatta), meaning "didn''t drink." 話す (hanasu, to speak) becomes 話さなかった (hanasanakatta), meaning "didn''t speak."\u000a\u000aAn important exception is the verb 行く (iku, to go), which becomes 行かなかった (ikanakatta), not 行かかった. This form is used to describe actions that did not occur in the past.'),'N5',5,'Linking Structures','[{"ja":"昨日は水を飲まなかった。","romaji":"Kinou wa mizu o nomanakatta.","en":"I didn''t drink water yesterday."},{"ja":"先週、図書館へ行かなかった。","romaji":"Senshuu, toshokan e ikanakatta.","en":"I didn''t go to the library last week."},{"ja":"彼はそのことについて話さなかった。","romaji":"Kare wa sono koto ni tsuite hanasanakatta.","en":"He didn''t talk about that."},{"ja":"お金がなかったので、何も買わなかった。","romaji":"Okane ga nakatta node, nani mo kawanakatta.","en":"I didn''t have money, so I didn''t buy anything."}]','["n5-u-verb-neg","n5-u-verb-past"]','["verb conjugation","negative form","past tense"]',37);
INSERT INTO grammar_points VALUES(38,'n5-te-conjunction','て (Conjunction)','te conjunction','And; then; linking actions/states',unistr('Verb (て-form) + Verb/Adjective/Noun\u000aい-Adjective (drop い) + くて + Verb/Adjective/Noun\u000aな-Adjective (drop な) + で + Verb/Adjective/Noun\u000aNoun + で + Verb/Adjective/Noun'),unistr('The て-form serves as a versatile conjunction to link multiple clauses or phrases. Its primary uses at the N5 level are to connect actions that happen in sequence, or to list multiple qualities or states.\u000a\u000aWhen connecting actions, the て-form indicates that the actions occur in the order they are stated. The tense of the entire sentence is determined by the final verb. For example, 「朝起きて、顔を洗います」 (Asa okite, kao wo araimasu) means "I wake up in the morning, and then wash my face."\u000a\u000aIt can also link adjectives and nouns to describe multiple characteristics or states. For い-adjectives, drop the final い and add くて (e.g., 楽しい → 楽しくて). For な-adjectives and nouns, add で (e.g., 静か → 静かで, 学生 → 学生で). This allows you to combine descriptions like 「この本は面白くて、読みやすいです」 (Kono hon wa omoshirokute, yomiyasui desu - This book is interesting and easy to read).'),'N5',5,'Linking Structures','[{"ja":"朝起きて、顔を洗います。","romaji":"Asa okite, kao wo araimasu.","en":"I wake up in the morning and wash my face."},{"ja":"デパートへ行って、服を買いました。","romaji":"Depaato e itte, fuku o kaimashita.","en":"I went to the department store and bought clothes."},{"ja":"この部屋は広くて、明るいです。","romaji":"Kono heya wa hirokute, akarui desu.","en":"This room is spacious and bright."},{"ja":"彼は学生で、毎日日本語を勉強します。","romaji":"Kare wa gakusei de, mainichi nihongo o benkyou shimasu.","en":"He is a student, and he studies Japanese every day."}]','["n5-te-form"]','["particle","conjunction","te-form"]',38);
INSERT INTO grammar_points VALUES(39,'n5-te-iru-1','ている①','te iru','Is doing (ongoing action); is in a state of','Verb (て-form) + いる',unistr('The `ている` form is a fundamental N5 grammar point with two primary uses: indicating an ongoing action and describing a current state resulting from a past action.\u000a\u000a1.  **Ongoing Action**: This is similar to the English progressive tense (e.g., "-ing"). It describes an action that is currently happening. For example, 「今、本を読んでいます」 (Ima, hon o yonde imasu) means "I am reading a book now." It can also describe habitual actions, such as 「彼は毎日日本語を勉強しています」 (Kare wa mainichi nihongo o benkyou shite imasu - He studies Japanese every day).\u000a\u000a2.  **Current State**: This use describes a state that began in the past and continues into the present. For example, 「田中さんは結婚しています」 (Tanaka-san wa kekkon shite imasu) means "Mr. Tanaka is married" (he got married in the past, and is still in that state). Similarly, 「窓が開いています」 (Mado ga aite imasu) means "The window is open" (it was opened, and is still open). The tense of the sentence is determined by the form of `いる` (e.g., います for present/future, いました for past).'),'N5',5,'Linking Structures','[{"ja":"今、ご飯を食べています。","romaji":"Ima, gohan o tabete imasu.","en":"I am eating a meal now."},{"ja":"彼は日本語を勉強しています。","romaji":"Kare wa nihongo o benkyou shite imasu.","en":"He is studying Japanese."},{"ja":"田中さんは結婚しています。","romaji":"Tanaka-san wa kekkon shite imasu.","en":"Mr. Tanaka is married."},{"ja":"窓が開いています。","romaji":"Mado ga aite imasu.","en":"The window is open."}]','["n5-te-form"]','["verb form","progressive","state","te-form"]',39);
INSERT INTO grammar_points VALUES(40,'n5-he','へ','e','To; toward (direction of movement)','Place Noun + へ',unistr('The particle へ (pronounced "e", not "he") indicates the direction of movement. It is attached to a noun that represents a destination or a general direction. It emphasizes the path or the general orientation of movement rather than the precise arrival point.\u000a\u000aWhile へ can often be used interchangeably with the particle に (ni) when indicating a destination, へ places more emphasis on the ''toward'' aspect or the journey itself. For example, 「学校へ行きます」 (Gakkou e ikimasu) means "I go toward/to school," highlighting the direction of travel. If you use に, 「学校に行きます」 (Gakkou ni ikimasu), it emphasizes the destination as the point of arrival.\u000a\u000aIt is commonly used with verbs of movement such as 行く (iku - to go), 来る (kuru - to come), 帰る (kaeru - to return), and 向かう (mukau - to head toward).'),'N5',5,'Linking Structures','[{"ja":"日本へ行きます。","romaji":"Nihon e ikimasu.","en":"I go to Japan."},{"ja":"駅へ向かっています。","romaji":"Eki e mukatte imasu.","en":"I am heading toward the station."},{"ja":"友達の家へ遊びに行きます。","romaji":"Tomodachi no ie e asobi ni ikimasu.","en":"I''m going to my friend''s house to play."},{"ja":"どちらへ行きますか。","romaji":"Dochira e ikimasu ka.","en":"Where are you going? (Which direction are you heading?)"}]','["n5-ni-destination"]','["particle","direction"]',40);
INSERT INTO grammar_points VALUES(41,'n5-ni-iku','Verb + にいく','ni iku','to go to do (something)','Verb (stem form) + に + 行く (いく)',unistr('The grammar pattern `Verb (stem form) + に + 行く (いく)` is used to express the purpose for which one is going somewhere. The particle `に` in this context indicates the purpose or objective of the movement.\u000a\u000aTo form this pattern, take a verb and remove the `-masu` ending (e.g., 食べます -> 食べ, 読みます -> 読み). Then, attach `に` followed by `行く` (or `来る` for coming, `帰る` for returning, etc.). This structure literally means "to go for the purpose of [doing the verb]".\u000a\u000aThis pattern is very common in daily conversation and is essential for N5 learners to express intentions related to movement.'),'N5',5,'Linking Structures','[{"ja":"友だちの家に遊びに行く。","romaji":"Tomodachi no ie ni asobi ni iku.","en":"I''m going to my friend''s house to hang out."},{"ja":"日本に勉強しに行くつもりです。","romaji":"Nihon ni benkyou shi ni iku tsumori desu.","en":"I''m planning to go to Japan to study."},{"ja":"東京へ何しに行くの？","romaji":"Toukyou e nani shi ni iku no?","en":"What are you going to Tokyo for?"},{"ja":"私たちは公園にサッカーをしに行く。","romaji":"Watashitachi wa kouen ni sakkaa o shi ni iku.","en":"We''re going to the park to play soccer."}]','["n5-ni"]','["verb","purpose","movement"]',41);
INSERT INTO grammar_points VALUES(42,'n5-dare','誰','dare','who; whom','誰 (だれ)',unistr('`誰 (だれ)` is an interrogative pronoun meaning "who" or "whom." It is used to ask about a person''s identity. Like other nouns, `誰` can be followed by various particles to indicate its grammatical role in a sentence.\u000a\u000aWhen `誰` is the subject of a sentence, it is typically followed by the particle `が` (e.g., 誰が来ましたか - Who came?). When it is the object, it is followed by `を` (e.g., 誰を見ましたか - Whom did you see?). It can also be used with `の` to indicate possession (e.g., 誰の本ですか - Whose book is this?).\u000a\u000a`誰` is a fundamental word for asking questions about people and is frequently used in daily conversation.'),'N5',6,'Knowledge Gaps','[{"ja":"あの人は誰ですか？","romaji":"Ano hito wa dare desu ka?","en":"Who is that person?"},{"ja":"誰が来ましたか？","romaji":"Dare ga kimashita ka?","en":"Who came?"},{"ja":"これは誰の本ですか？","romaji":"Kore wa dare no hon desu ka?","en":"Whose book is this?"},{"ja":"あなたは誰に会いましたか？","romaji":"Anata wa dare ni aimashita ka?","en":"Who did you meet?"}]','["n5-nani","n5-itsu","n5-doko"]','["interrogative","pronoun"]',42);
INSERT INTO grammar_points VALUES(43,'n5-naze','なぜ','naze','why (formal)','なぜ',unistr('`なぜ` is an interrogative adverb meaning "why." It is used to ask for a reason or cause. Among the various ways to ask "why" in Japanese, `なぜ` is generally considered the most formal and objective.\u000a\u000aIt is often used in written language, formal speeches, or when asking for a logical explanation. While it can be used in conversation, `どうして` or `なんで` are more common in casual, everyday speech. `なぜ` directly precedes the verb or predicate it modifies.\u000a\u000aWhen using `なぜ`, the answer often includes `からです` or `ためです` to provide the reason.'),'N5',6,'Knowledge Gaps','[{"ja":"なぜ日本語を勉強していますか？","romaji":"Naze nihongo o benkyou shite imasu ka?","en":"Why are you studying Japanese?"},{"ja":"なぜ彼女は来なかったのですか？","romaji":"Naze kanojo wa konakatta no desu ka?","en":"Why didn''t she come?"},{"ja":"なぜこの問題は難しいのですか？","romaji":"Naze kono mondai wa muzukashii no desu ka?","en":"Why is this problem difficult?"},{"ja":"なぜ彼はいつも遅れるのですか？","romaji":"Naze kare wa itsumo okureru no desu ka?","en":"Why is he always late?"}]','["n5-doushite","n5-nande"]','["interrogative","adverb","formal"]',43);
INSERT INTO grammar_points VALUES(44,'n5-doushite','どうして','doushite','why; how','どうして',unistr('`どうして` is an interrogative adverb that can mean both "why" and "how." It is a very versatile and commonly used word in Japanese, especially in everyday conversation.\u000a\u000aWhen asking "why," `どうして` is less formal than `なぜ` but more polite than `なんで`. It seeks a reason or cause for an action or situation. When asking "how," it inquires about the manner or method by which something occurred or is done.\u000a\u000aThe context of the sentence usually makes it clear whether `どうして` means "why" or "how." It can be used with both polite (`です/ます`) and casual (`だ/である`) forms of verbs and adjectives.'),'N5',6,'Knowledge Gaps','[{"ja":"どうして来ないの？","romaji":"Doushite konai no?","en":"Why aren''t you coming?"},{"ja":"どうしてそうなったの？","romaji":"Doushite sou natta no?","en":"How/Why did that happen?"},{"ja":"どうしてそれを知っている？","romaji":"Doushite sore o shitteiru?","en":"How/Why do you know that?"},{"ja":"どうして日本に来たんですか？","romaji":"Doushite Nihon ni kitan desu ka?","en":"Why did you come to Japan?"}]','["n5-naze","n5-nande"]','["interrogative","adverb"]',44);
INSERT INTO grammar_points VALUES(45,'n5-nande','なんで','nande','why (casual); by what means','なんで',unistr('`なんで` is an interrogative adverb that primarily means "why" in a casual context. It is the most informal way to ask for a reason, typically used among close friends, family, or in very relaxed situations.\u000a\u000aIn addition to asking "why," `なんで` can also mean "by what means" or "how." This usage is less common than its "why" meaning but is important to recognize. For example, `なんで来たの？` could mean "Why did you come?" or "How did you come?" (e.g., by what transportation).\u000a\u000aDue to its casual nature, `なんで` is often used with casual verb forms and can sometimes sound abrupt or demanding if used in formal settings or with strangers.'),'N5',6,'Knowledge Gaps','[{"ja":"なんで遅れたの？","romaji":"Nande okureta no?","en":"Why were you late? (casual)"},{"ja":"なんでそんなこと言うの？","romaji":"Nande sonna koto iu no?","en":"Why do you say such a thing?"},{"ja":"なんでここにいるの？","romaji":"Nande koko ni iru no?","en":"Why are you here?"},{"ja":"なんで電車で行くの？","romaji":"Nande densha de iku no?","en":"How come you''re going by train? / By what means are you going by train?"}]','["n5-naze","n5-doushite"]','["interrogative","adverb","casual"]',45);
INSERT INTO grammar_points VALUES(46,'n5-i-adj-predicate','い-Adjective (Predicate)','i-adj predicate','To be [i-adjective]','い-Adjective',unistr('い-adjectives are a type of adjective in Japanese that end with the hiragana い (i) in their dictionary form (e.g., 寒い samui - cold, 楽しい tanoshii - fun). When an い-adjective is used as a predicate, it directly describes the subject of the sentence without needing a copula like だ or です.\u000a\u000aThis is the simplest form of using an い-adjective to state a quality or condition. For example, to say "The weather is good," you would simply say 「天気は良い。」 (Tenki wa ii.). The adjective itself carries the meaning of "is good."\u000a\u000aTo make an い-adjective polite, you add です after it (e.g., 良いです ii desu). To make it negative, you change い to くない (e.g., 良くない yokunai). To make it past tense, you change い to かった (e.g., 良かった yokatta).'),'N5',6,'Knowledge Gaps','[{"ja":"この映画は面白い。","romaji":"Kono eiga wa omoshiroi.","en":"This movie is interesting."},{"ja":"今日は暑い。","romaji":"Kyou wa atsui.","en":"Today is hot."},{"ja":"あの本は高い。","romaji":"Ano hon wa takai.","en":"That book is expensive."},{"ja":"このりんごは甘い。","romaji":"Kono ringo wa amai.","en":"This apple is sweet."}]','["n5-na-adj-predicate"]','["adjective","predicate"]',46);
INSERT INTO grammar_points VALUES(47,'n5-na-adj-predicate','な-Adjective (Predicate)','na-adj predicate','To be [na-adjective]',unistr('な-Adjective + だ (casual)\u000a な-Adjective + です (polite)'),unistr('な-adjectives are a type of adjective in Japanese that typically require な when modifying a noun (e.g., 静かな部屋 shizuka na heya - a quiet room). However, when a な-adjective is used as a predicate, it needs a copula (だ or です) to complete the sentence.\u000a\u000aFor casual speech, you use だ after the な-adjective (e.g., 静かだ shizuka da - It is quiet). For polite speech, you use です (e.g., 静かです shizuka desu - It is quiet).\u000a\u000aUnlike い-adjectives, な-adjectives cannot stand alone as predicates. They always need だ or です (or their negative/past forms) to function as the main verb of a sentence. For example, to say "This room is quiet," you would say 「この部屋は静かだ。」 or 「この部屋は静かです。」'),'N5',6,'Knowledge Gaps','[{"ja":"この部屋は静かだ。","romaji":"Kono heya wa shizuka da.","en":"This room is quiet."},{"ja":"彼女は元気です。","romaji":"Kanojo wa genki desu.","en":"She is well/energetic."},{"ja":"日本語は簡単です。","romaji":"Nihongo wa kantan desu.","en":"Japanese is easy."},{"ja":"彼はハンサムだ。","romaji":"Kare wa hansamu da.","en":"He is handsome."}]','["n5-i-adj-predicate"]','["adjective","predicate"]',47);
INSERT INTO grammar_points VALUES(48,'n5-datta-deshita','だった・でした','datta deshita','Was; Were (past tense of だ/です)',unistr('Noun + だった (casual)\u000a Noun + でした (polite)\u000a な-Adjective + だった (casual)\u000a な-Adjective + でした (polite)\u000a い-Adjective (remove い) + かった (casual)\u000a い-Adjective (remove い) + かったです (polite)'),unistr('だった and でした are the past tense forms of the copulas だ and です, respectively. They are used to state that something ''was'' or ''were'' a certain way in the past. だった is the casual form, while でした is the polite form.\u000a\u000aThese forms are primarily used with nouns and な-adjectives. For example, to say "It was a student," you would use 「学生だった」 (casual) or 「学生でした」 (polite). For な-adjectives, you attach だった or でした directly after the adjective stem (e.g., 静かだった shizuka datta - it was quiet).\u000a\u000aFor い-adjectives, the past tense is formed differently by changing the final い to かった (casual) or かったです (polite). For instance, 暑い (atsui - hot) becomes 暑かった (atsukatta - it was hot) or 暑かったです (atsukatta desu - it was hot, polite). It''s important to distinguish these formation rules.'),'N5',6,'Knowledge Gaps','[{"ja":"昨日は日曜日だった。","romaji":"Kinou wa nichiyoubi datta.","en":"Yesterday was Sunday."},{"ja":"あのレストランは静かでした。","romaji":"Ano resutoran wa shizuka deshita.","en":"That restaurant was quiet."},{"ja":"テストは難しかった。","romaji":"Tesuto wa muzukashikatta.","en":"The test was difficult."},{"ja":"子供の時、私は学生でした。","romaji":"Kodomo no toki, watashi wa gakusei deshita.","en":"When I was a child, I was a student."}]','["n5-da-desu","n5-i-adj-predicate","n5-na-adj-predicate"]','["past tense","copula"]',48);
INSERT INTO grammar_points VALUES(49,'n5-janai','じゃない','janai','Is not; Am not; Are not (casual)',unistr('Noun + じゃない\u000a な-Adjective + じゃない'),unistr('じゃない is the casual negative form of the copula だ (da), meaning "is not," "am not," or "are not." It is used with nouns and な-adjectives to express a negative statement in informal contexts.\u000a\u000aFor example, to say "It is not a student," you would use 「学生じゃない」 (gakusei janai). For な-adjectives, you attach じゃない directly after the adjective stem (e.g., 静かじゃない shizuka janai - it is not quiet).\u000a\u000aWhile じゃない is very common in spoken Japanese, ではない (dewa nai) is a slightly more formal or written equivalent, though still casual. For polite negative statements, you would use じゃありません (ja arimasen) or ではありません (dewa arimasen).'),'N5',6,'Knowledge Gaps','[{"ja":"これは私の本じゃない。","romaji":"Kore wa watashi no hon janai.","en":"This is not my book."},{"ja":"彼は学生じゃない。","romaji":"Kare wa gakusei janai.","en":"He is not a student."},{"ja":"この部屋は静かじゃない。","romaji":"Kono heya wa shizuka janai.","en":"This room is not quiet."},{"ja":"それは本当じゃない。","romaji":"Sore wa hontou janai.","en":"That is not true."}]','["n5-da-desu","n5-janakatta"]','["negative","copula","casual"]',49);
INSERT INTO grammar_points VALUES(50,'n5-janakatta','じゃなかった','janakatta','Was not; Wasn''t (casual past negative)',unistr('Noun + じゃなかった\u000a な-Adjective + じゃなかった'),unistr('じゃなかった is the casual past negative form of the copula だ (da), meaning "was not" or "were not." It is used with nouns and な-adjectives to express a negative statement about a past event or condition in informal contexts.\u000a\u000aFor example, to say "It wasn''t a student," you would use 「学生じゃなかった」 (gakusei janakatta). For な-adjectives, you attach じゃなかった directly after the adjective stem (e.g., 便利じゃなかった benri janakatta - it wasn''t convenient).\u000a\u000aThis form is the casual equivalent of ではありませんでした (dewa arimasen deshita), which is the polite past negative. Remember that い-adjectives have their own past negative form, which is formed by changing い to くなかった (e.g., 暑い (atsui) -> 暑くなかった (atsukunakatta) - it wasn''t hot).'),'N5',6,'Knowledge Gaps','[{"ja":"昨日は休みじゃなかった。","romaji":"Kinou wa yasumi janakatta.","en":"Yesterday wasn''t a day off."},{"ja":"彼は医者じゃなかった。","romaji":"Kare wa isha janakatta.","en":"He wasn''t a doctor."},{"ja":"あの店は便利じゃなかった。","romaji":"Ano mise wa benri janakatta.","en":"That store wasn''t convenient."},{"ja":"そのニュースは本当じゃなかった。","romaji":"Sono nyuusu wa hontou janakatta.","en":"That news wasn''t true."}]','["n5-janai","n5-datta-deshita"]','["past tense","negative","copula","casual"]',50);
INSERT INTO grammar_points VALUES(51,'n5-i-adj-kunakatta','い-Adj くなかった','kunakatta','was not (i-adjective)','い-Adjective (stem) + くなかった',unistr('This grammar pattern is used to express the past negative form of い-adjectives. To form it, you remove the final い from the い-adjective and replace it with くなかった.\u000a\u000aFor example, 暑い (atsui - hot) becomes 暑くなかった (atsukunakatta - was not hot). This is a fundamental conjugation for describing past states or qualities that did not hold true.\u000a\u000aNote that the adjective 良い (yoi - good) is an exception; its past negative form is 良くなかった (yokunakatta).'),'N5',6,'Knowledge Gaps','[{"ja":"昨日は寒くなかった。","romaji":"Kinou wa samukunakatta.","en":"It wasn''t cold yesterday."},{"ja":"この本は面白くなかった。","romaji":"Kono hon wa omoshirokunakatta.","en":"This book wasn''t interesting."},{"ja":"その映画は良くなかった。","romaji":"Sono eiga wa yokunakatta.","en":"That movie wasn''t good."},{"ja":"彼の部屋は広くなかった。","romaji":"Kare no heya wa hirokunakatta.","en":"His room wasn''t spacious."}]','["n5-i-adj-desu","n5-i-adj-kunai"]','["adjective","conjugation","negative","past tense"]',51);
INSERT INTO grammar_points VALUES(52,'n5-to-quotation','と (Quotation)','to quotation','quoting; saying that; thinking that','Sentence (casual form) + と + 言う/思う/聞く etc.',unistr('The particle と is used to introduce direct or indirect quotations. It follows the quoted speech or thought and precedes verbs like 言う (iu - to say), 思う (omou - to think), 聞く (kiku - to hear), etc.\u000a\u000aWhen quoting direct speech, the quoted part is often enclosed in quotation marks (「」). For indirect speech or thoughts, the sentence before と is usually in its casual (plain) form.\u000a\u000aThis particle is essential for reporting what someone said or thought, allowing you to embed a full sentence within another sentence.'),'N5',6,'Knowledge Gaps','[{"ja":"彼は「明日行きます」と言いました。","romaji":"Kare wa ''ashita ikimasu'' to iimashita.","en":"He said, \"I will go tomorrow.\""},{"ja":"私は「これは難しい」と思った。","romaji":"Watashi wa ''kore wa muzukashii'' to omotta.","en":"I thought, \"This is difficult.\""},{"ja":"友達は「もう食べた」と言っていた。","romaji":"Tomodachi wa ''mou tabeta'' to itteita.","en":"My friend said, \"I already ate.\""},{"ja":"先生は「宿題を忘れないで」と注意した。","romaji":"Sensei wa ''shukudai wo wasurenai de'' to chuui shita.","en":"The teacher warned, \"Don''t forget your homework.\""}]','["n5-tte"]','["particle","quotation","reporting"]',52);
INSERT INTO grammar_points VALUES(53,'n5-tte','って','tte','casual quotation; I heard that; they say that','Sentence (casual form) + って',unistr('って is a casual and informal version of the quotation particle と言う (to iu) or と聞きました (to kikimashita). It is used to report what someone said or what you heard, often implying that the information is secondhand or a rumor.\u000a\u000aIt can also be used to introduce a topic or to ask for confirmation in a casual setting. Because of its informal nature, って is primarily used in conversations among friends, family, or close acquaintances.\u000a\u000aWhile と is more formal and versatile, って offers a quick and natural way to convey reported speech in everyday Japanese.'),'N5',6,'Knowledge Gaps','[{"ja":"彼は明日来ないって。","romaji":"Kare wa ashita konai tte.","en":"He said he''s not coming tomorrow."},{"ja":"ジョンさん、日本に行ったって？","romaji":"Jon-san, Nihon ni itta tte?","en":"John, I heard you went to Japan?"},{"ja":"この映画、面白いって聞いたよ。","romaji":"Kono eiga, omoshiroi tte kiita yo.","en":"I heard this movie is interesting."},{"ja":"彼女、結婚するって言ってたよ。","romaji":"Kanojo, kekkon suru tte itteta yo.","en":"She said she''s getting married."}]','["n5-to-quotation"]','["particle","quotation","casual","reporting"]',53);
INSERT INTO grammar_points VALUES(54,'n5-verb-non-past','Verb (Non-Past)','verb non-past','verb dictionary form; plain present/future','Verb (dictionary form)',unistr('The non-past form of a verb, also known as the dictionary form or plain form, is the basic, unconjugated form of a verb found in dictionaries. It is used to express actions or states in the present or future, or general truths and habits.\u000a\u000aThis form is considered casual speech and is used when speaking with close friends or family. It also serves as the base for many other grammar patterns and conjugations in Japanese.\u000a\u000aUnderstanding the non-past form is crucial as it''s the foundation for more complex sentence structures and is often contrasted with the more polite ます-form.'),'N5',6,'Knowledge Gaps','[{"ja":"毎日日本語を勉強する。","romaji":"Mainichi Nihongo wo benkyou suru.","en":"I study Japanese every day."},{"ja":"来週、友達と映画を見る。","romaji":"Raishuu, tomodachi to eiga wo miru.","en":"I will watch a movie with my friend next week."},{"ja":"彼はよく本を読む。","romaji":"Kare wa yoku hon wo yomu.","en":"He often reads books."},{"ja":"私はコーヒーを飲む。","romaji":"Watashi wa koohii wo nomu.","en":"I drink coffee."}]','["n5-verb-masu","n5-verb-ta"]','["verb","conjugation","plain form","dictionary form"]',54);
INSERT INTO grammar_points VALUES(55,'n5-verb-ta-noun','Verb[た] + Noun','verb ta noun','noun modified by a past tense verb','Verb (た-form) + Noun',unistr('This pattern allows a verb in its た-form (past tense plain form) to directly modify a noun, functioning similarly to a relative clause in English. The verb describes an action that has already occurred and is directly related to the noun that follows it.\u000a\u000aThis structure is very common in Japanese for creating more descriptive and specific noun phrases. It helps to specify which noun is being referred to by providing past context about it.\u000a\u000aFor example, instead of just saying 「本」 (hon - book), you can say 「昨日読んだ本」 (kinou yonda hon - the book I read yesterday) to give more information.'),'N5',6,'Knowledge Gaps','[{"ja":"昨日食べたケーキは美味しかった。","romaji":"Kinou tabeta keeki wa oishikatta.","en":"The cake I ate yesterday was delicious."},{"ja":"彼女が書いた手紙を読んだ。","romaji":"Kanojo ga kaita tegami wo yonda.","en":"I read the letter she wrote."},{"ja":"去年行った旅行は楽しかった。","romaji":"Kyonen itta ryokou wa tanoshikatta.","en":"The trip I went on last year was fun."},{"ja":"友達にもらったプレゼントはこれです。","romaji":"Tomodachi ni moratta purezento wa kore desu.","en":"This is the present I received from my friend."}]','["n5-verb-dictionary-noun"]','["verb","noun modification","relative clause","ta-form"]',55);
INSERT INTO grammar_points VALUES(56,'n5-no-omission','の (Noun Omission)','no noun omission','one; ones (replacing a noun)',unistr('い-adjective + の\u000aな-adjective + な + の\u000aVerb (Casual) + の\u000aNoun + の'),unistr('The particle 「の」 can be used to replace a noun when the noun is clear from context or has already been mentioned. This helps to avoid repetition and makes sentences sound more natural. It essentially functions as a pronoun meaning "one" or "ones."\u000a\u000aWhen used after an い-adjective, the い-adjective directly attaches to 「の」 (e.g., 赤いの - the red one). For な-adjectives, the 「な」 particle is required before 「の」 (e.g., 好きなの - the one I like). It can also follow verbs in their casual forms or nouns, often implying possession or a specific item related to the preceding word.'),'N5',6,'Knowledge Gaps','[{"ja":"赤いのをください。","romaji":"Akai no o kudasai.","en":"Please give me the red one."},{"ja":"大きいのはどれですか？","romaji":"Ookii no wa dore desu ka?","en":"Which one is the big one?"},{"ja":"このカバンは私のです。","romaji":"Kono kaban wa watashi no desu.","en":"This bag is mine (my one)."},{"ja":"新しいのと古いのが両方あります。","romaji":"Atarashii no to furui no ga ryouhou arimasu.","en":"There are both new ones and old ones."}]','["n5-no-possessive"]','["particle","pronoun","noun substitute"]',56);
INSERT INTO grammar_points VALUES(57,'n5-na-prohibitive','な (Prohibitive)','na prohibitive','Don''t; Do not (casual prohibition)','Verb (Dictionary Form) + な',unistr('The particle 「な」, when attached to the dictionary form of a verb, expresses a casual and direct prohibition or command not to do something. It is a strong form of negative imperative.\u000a\u000aThis grammar point is typically used in informal contexts, such as by parents to children, among close friends, or in written warnings. It can sound impolite or harsh if used towards superiors or strangers. For a more polite way to express prohibition, one might use 「～てはいけません」 or 「～ないでください」.'),'N5',6,'Knowledge Gaps','[{"ja":"ここに座るな。","romaji":"Koko ni suwaru na.","en":"Don''t sit here."},{"ja":"嘘をつくな。","romaji":"Uso o tsuku na.","en":"Don''t lie."},{"ja":"危ないから、走るな。","romaji":"Abunai kara, hashiru na.","en":"It''s dangerous, so don''t run."},{"ja":"遅れるなよ！","romaji":"Okureru na yo!","en":"Don''t be late!"}]','["n5-te-wa-ikenai","n5-naide-kudasai"]','["verb form","prohibition","casual"]',57);
INSERT INTO grammar_points VALUES(58,'n5-dake','だけ','dake','only; just; merely',unistr('Noun + だけ\u000aVerb (Casual) + だけ\u000aい-adjective + だけ\u000aな-adjective + な + だけ'),unistr('「だけ」 is a particle that expresses limitation, meaning "only," "just," or "merely." It emphasizes that nothing more or less than the specified item or amount is involved. It can follow nouns, verbs (in their casual forms), and adjectives.\u000a\u000aWhen used with a な-adjective, the particle 「な」 is required before 「だけ」 (e.g., 好きなだけ - only the one I like). It can also be used with numbers to specify a precise quantity, such as 「一人だけ」 (only one person) or 「これだけ」 (only this much).'),'N5',7,'Advanced Linking','[{"ja":"私の持っているお金はこれだけだ。","romaji":"Watashi no motteiru okane wa kore dake da.","en":"This is the only money I have."},{"ja":"ちょっと見ているだけです。","romaji":"Chotto miteiru dake desu.","en":"I''m just looking around."},{"ja":"好きじゃない食べ物はトマトだけだ。","romaji":"Suki janai tabemono wa tomato dake da.","en":"The only food I dislike is tomatoes."},{"ja":"ただ話していただけです。","romaji":"Tada hanashiteita dake desu.","en":"I was just speaking."}]','["n5-shika"]','["particle","limitation"]',58);
INSERT INTO grammar_points VALUES(59,'n5-dore','どれ','dore','Which one (among three or more)','どれ',unistr('「どれ」 is an interrogative pronoun used to ask "which one?" when there are three or more items or options to choose from. It functions as a standalone word and does not directly modify a noun.\u000a\u000aIf you need to ask "which (noun)?" (e.g., "which book?"), you would use 「どの」 followed by the noun (e.g., どの本). 「どれ」 is used when the noun is omitted or understood from context, referring to one specific item out of a group.'),'N5',7,'Advanced Linking','[{"ja":"どれが好きですか？","romaji":"Dore ga suki desu ka?","en":"Which one do you like?"},{"ja":"この中で、どれが一番高いですか？","romaji":"Kono naka de, dore ga ichiban takai desu ka?","en":"Among these, which one is the most expensive?"},{"ja":"あなたのカバンはどれですか？","romaji":"Anata no kaban wa dore desu ka?","en":"Which one is your bag?"},{"ja":"どれも美味しいですね。","romaji":"Dore mo oishii desu ne.","en":"All of them are delicious, aren''t they?"}]','["n5-dono","n5-dochira"]','["interrogative","pronoun"]',59);
INSERT INTO grammar_points VALUES(60,'n5-doko','どこ','doko','Where',unistr('どこ\u000aどこ + Particle (e.g., に, へ, で)'),unistr('「どこ」 is an interrogative pronoun meaning "where." It is used to inquire about a location or place. It can be used by itself or in conjunction with various particles to specify the nuance of the question.\u000a\u000aCommon particles used with 「どこ」 include 「に」 (indicating existence at a location or destination), 「へ」 (indicating direction or destination), and 「で」 (indicating the location where an action takes place).'),'N5',7,'Advanced Linking','[{"ja":"トイレはどこですか？","romaji":"Toire wa doko desu ka?","en":"Where is the bathroom?"},{"ja":"どこに住んでいますか？","romaji":"Doko ni sunde imasu ka?","en":"Where do you live?"},{"ja":"駅はどこですか？","romaji":"Eki wa doko desu ka?","en":"Where is the station?"},{"ja":"どこへ行きたいですか？","romaji":"Doko e ikitai desu ka?","en":"Where do you want to go?"}]','["n5-kochira"]','["interrogative","pronoun"]',60);
INSERT INTO grammar_points VALUES(61,'n5-dono','どの','dono','which (of three or more options)','どの + Noun',unistr('「どの」 (dono) is an interrogative adjective used to ask "which" when referring to three or more items or people. It always directly precedes a noun.\u000a\u000aIt is similar to 「どれ」 (dore), which means "which one" and is used when the noun is omitted, and 「どちら」 (dochira), which means "which (of two)" or "which way". Remember that 「どの」 must always be followed by a noun.'),'N5',7,'Advanced Linking','[{"ja":"どの本が好きですか。","romaji":"dono hon ga suki desu ka.","en":"Which book do you like?"},{"ja":"どの電車に乗りますか。","romaji":"dono densha ni norimasu ka.","en":"Which train will you take?"},{"ja":"どのりんごが一番大きいですか。","romaji":"dono ringo ga ichiban ookii desu ka.","en":"Which apple is the biggest?"},{"ja":"どの道を行けばいいですか。","romaji":"dono michi o ikeba ii desu ka.","en":"Which road should I take?"}]','["n5-dore","n5-dochira"]','["interrogative","adjective"]',61);
INSERT INTO grammar_points VALUES(62,'n5-te-iru-2','ている②','te iru 2','state of being; resulting state; habitual action; occupation','Verb て-form + いる',unistr('The `~ている` form has several important uses in Japanese. While `~ている①` typically describes an ongoing action (e.g., 読んでいます - I am reading), `~ている②` covers other crucial aspects.\u000a\u000aOne common use is to describe a **resulting state**. This means an action has occurred, and its result is still ongoing or observable. It''s often used with intransitive verbs (verbs that don''t take a direct object). For example, 「窓が開いている」 (mado ga aite iru) means "The window is open" (as a result of someone having opened it).\u000a\u000aAnother use is to describe **habitual actions** or **repeated events**. This indicates something that happens regularly or is a part of one''s routine (e.g., 毎日日本語を勉強している - I study Japanese every day). It can also describe one''s **occupation or status** (e.g., 先生をしている - I am a teacher; 結婚している - I am married).'),'N5',7,'Advanced Linking','[{"ja":"窓が開いている。","romaji":"mado ga aite iru.","en":"The window is open."},{"ja":"私は東京に住んでいる。","romaji":"watashi wa tōkyō ni sunde iru.","en":"I live in Tokyo."},{"ja":"彼は毎日新聞を読んでいる。","romaji":"kare wa mainichi shinbun o yonde iru.","en":"He reads the newspaper every day."},{"ja":"私の父は医者をしている。","romaji":"watashi no chichi wa isha o shite iru.","en":"My father is a doctor."}]','["n5-te-iru-1"]','["verb conjugation","aspect"]',62);
INSERT INTO grammar_points VALUES(63,'n5-te-kara','てから','te kara','after doing; once done','Verb て-form + から',unistr('「てから」 (te kara) is used to indicate a sequence of events, specifically that one action is completed, and *then* another action begins. It clearly marks the completion of the first action before the second one starts.\u000a\u000aThis pattern emphasizes the temporal order and the completion of the preceding action. The tense of the entire sentence is determined by the final verb. It''s a very common way to link actions in Japanese, providing a clear sense of ''after X, then Y''.'),'N5',7,'Advanced Linking','[{"ja":"トイレを使ってから、手を洗わないといけません。","romaji":"toire o tsukatte kara, te o arawanai to ikemasen.","en":"We must wash our hands after using the restroom."},{"ja":"買い物をしてから家に帰ります。","romaji":"kaimono o shite kara ie ni kaerimasu.","en":"I''ll come home after I finish shopping."},{"ja":"ご飯を食べてから散歩しました。","romaji":"gohan o tabete kara sanpo shimashita.","en":"After eating I went for a walk."},{"ja":"今日は、起きてからまだ何も食べていません。","romaji":"kyou wa, okite kara mada nanimo tabeteimasen.","en":"I haven''t eaten anything today since waking up."}]','["n5-te-sequence"]','["conjunction","sequence"]',63);
INSERT INTO grammar_points VALUES(64,'n5-te-sequence','て (Sequence)','te sequence','and; then; connecting actions sequentially','Verb て-form + Verb',unistr('The `て` form of a verb can be used to connect multiple actions or states in a sequence. It indicates that the actions occur one after another, or that multiple qualities apply to a single subject. This is a fundamental way to create longer, more complex sentences in Japanese.\u000a\u000aWhen connecting verbs, the `て` form implies a temporal sequence, meaning the first action happens, and then the second action happens. The tense of the entire sentence is determined by the final verb. For example, if the last verb is in the past tense, all preceding actions are understood to have occurred in the past. This form is simpler than `~てから` as it doesn''t always emphasize the completion of the first action as strongly, but rather just the order.'),'N5',7,'Advanced Linking','[{"ja":"朝ごはんを食べて、学校に行きます。","romaji":"asagohan o tabete, gakkō ni ikimasu.","en":"I eat breakfast and then go to school."},{"ja":"本を読んで、寝ました。","romaji":"hon o yonde, nemashita.","en":"I read a book and then went to sleep."},{"ja":"デパートに行って、服を買いました。","romaji":"depāto ni itte, fuku o kaimashita.","en":"I went to the department store and bought clothes."},{"ja":"シャワーを浴びて、ご飯を食べます。","romaji":"shawā o abite, gohan o tabemasu.","en":"I''ll take a shower and then eat."}]','["n5-te-kara"]','["verb conjugation","conjunction","sequence"]',64);
INSERT INTO grammar_points VALUES(65,'n5-mou','もう','mou','already; anymore; again; more','もう + [Verb/Noun/Adjective/Sentence]',unistr('「もう」 (mou) is a versatile adverb in Japanese with several key meanings, primarily indicating a change in state or quantity.\u000a\u000aIts most common use is to express "already" or "by now," often used with verbs in the past tense or forms indicating completion. It signifies that an action or state has occurred sooner than expected or has been completed. When used with negative forms, it can mean "no longer" or "not anymore," indicating that a previous state or action has ceased.\u000a\u000aAdditionally, 「もう」 can mean "more" or "another," used when requesting or referring to an additional quantity or item. The specific meaning is usually clear from the context of the sentence.'),'N5',7,'Advanced Linking','[{"ja":"もう昼ご飯の時間だ。早く食べましょう！","romaji":"mou hiru gohan no jikan da. hayaku tabe mashou!.","en":"It''s lunch time already, let''s hurry up and eat."},{"ja":"宿題はもう終わった？","romaji":"shukudai wa mou owatta?.","en":"Did you already finish your homework?."},{"ja":"ビールもう一杯ください！","romaji":"biiru mou ippai kudasai!.","en":"One more beer please!."},{"ja":"飲み物は全部飲みました。もうありません。","romaji":"nomimono wa zenbu nomimashita. mou arimasen.","en":"We drank all of the drinks. There aren''t any left."}]','[]','["adverb"]',65);
INSERT INTO grammar_points VALUES(66,'n5-mada','まだ','mada','still; not yet',unistr('まだ + Verb (て-form) + います\u000aまだ + Verb (て-form) + いません\u000aまだ + Adjective / Noun + です'),unistr('「まだ」 is an adverb used to express that a state or action is continuing, or that an expected action or state has not yet occurred. When used with positive verb forms (e.g., 〜ています), it means "still" or "yet."\u000a\u000aWhen used with negative verb forms (e.g., 〜ていません), it means "not yet." It indicates that something has not happened up to the present moment, but it is expected to happen or is in the process of happening. It can also be used with adjectives and nouns to express a continuing state.\u000a\u000aFor emphasis, you can sometimes hear 「まだまだ」, which intensifies the meaning of "still" or "not yet," suggesting a longer duration or a greater degree of incompleteness.'),'N5',7,'Advanced Linking','[{"ja":"田中さんはまだ寝ています。","romaji":"tanaka-san wa mada neteimasu.","en":"Mr. Tanaka is still sleeping."},{"ja":"宿題はまだ終わっていません。","romaji":"shukudai wa mada owatteimasen.","en":"My homework is not yet finished."},{"ja":"この仕事はまだ難しいです。","romaji":"kono shigoto wa mada muzukashii desu.","en":"This job is still difficult."},{"ja":"電車はまだ来ていませんか。","romaji":"densha wa mada kiteimasen ka.","en":"Has the train not come yet?"}]','["n5-mada-te-imasen"]','["adverb"]',66);
INSERT INTO grammar_points VALUES(67,'n5-mada-te-imasen','まだ〜ていません','mada te imasen','have not yet ~; still haven''t ~','まだ + Verb (て-form) + いません',unistr('The phrase 「まだ〜ていません」 is used to express that an action or state has not yet occurred or been completed up to the present moment. It implies that the action is expected to happen or is still pending.\u000a\u000aThis structure is commonly used when talking about tasks that are incomplete, events that haven''t happened, or skills that haven''t been acquired. It directly contrasts with 「もう〜ました」, which means "already did."\u000a\u000aFor example, if someone asks if you''ve eaten breakfast, and you haven''t, you would say 「まだ食べていません。」 (I haven''t eaten yet.). It''s a fundamental N5 expression for discussing incomplete actions.'),'N5',7,'Advanced Linking','[{"ja":"バスはまだ来ていません。","romaji":"basu wa mada kiteimasen.","en":"The bus has not come yet."},{"ja":"私はまだ朝ごはんを食べていません。","romaji":"watashi wa mada asagohan o tabete imasen.","en":"I still haven''t eaten breakfast yet."},{"ja":"新しい仕事はまだ決まっていません。","romaji":"atarashii shigoto wa mada kimatteimasen.","en":"My new job has not been decided yet."},{"ja":"この本はまだ読んでいません。","romaji":"kono hon wa mada yondeimasen.","en":"I haven''t read this book yet."}]','["n5-mada","n5-te-imasu"]','["verb conjugation","negation"]',67);
INSERT INTO grammar_points VALUES(68,'n5-te-mo-ii','てもいい','te mo ii','may; it''s okay to; you can',unistr('Verb (て-form) + もいい\u000aい-Adjective (く-form) + てもいい\u000aな-Adjective (で-form) + もいい\u000aNoun (で-form) + もいい'),unistr('The grammar pattern 「〜てもいい」 is used to express permission or to state that something is permissible. It translates to "may," "it''s okay to," or "you can." It indicates that there is no problem with performing a certain action or being in a certain state.\u000a\u000aTo form this, you attach 「もいい」 to the て-form of a verb. For い-adjectives, change the final い to く and add てもいい (e.g., 暑い → 暑くてもいい). For な-adjectives and nouns, add で to the stem/noun, then もいい (e.g., 静か → 静かでもいい, 学生 → 学生でもいい).\u000a\u000aThis pattern is often used in questions to ask for permission (e.g., 「入ってもいいですか。」 - "May I come in?"). Its negative counterpart, 「〜てはいけません」, means "must not do" or "it is forbidden to do."'),'N5',7,'Advanced Linking','[{"ja":"ここに座ってもいいですか。","romaji":"koko ni suwatte mo ii desu ka.","en":"May I sit here?"},{"ja":"もう帰ってもいいですよ。","romaji":"mou kaette mo ii desu yo.","en":"You may go home now."},{"ja":"この辞書を使ってもいいです。","romaji":"kono jisho o tsukatte mo ii desu.","en":"You can use this dictionary."},{"ja":"辛くてもいいから、もっと食べたい。","romaji":"karakute mo ii kara, motto tabetai.","en":"Even if it''s spicy, I want to eat more."}]','["n5-te-wa-ikemasen"]','["permission","verb conjugation"]',68);
INSERT INTO grammar_points VALUES(69,'n5-tai','たい','tai','want to do ~','Verb (ます-stem) + たい',unistr('The suffix 「〜たい」 is used to express the speaker''s desire to perform an action. It attaches directly to the ます-stem of a verb. For example, 食べます (tabemasu) becomes 食べたい (tabetai - want to eat), and 行きます (ikimasu) becomes 行きたい (ikitai - want to go).\u000a\u000aOnce 「〜たい」 is attached, the resulting form behaves like an い-adjective. This means it can be conjugated for tense and negation in the same way as い-adjectives (e.g., 食べたくない - don''t want to eat, 食べたかった - wanted to eat, 食べたくなかった - didn''t want to eat).\u000a\u000aWhen the object of the desired action is a noun, the particle 「が」 is often used instead of 「を」, especially when expressing a general desire (e.g., 水が飲みたい - I want to drink water). However, 「を」 can also be used, particularly when emphasizing the action itself.'),'N5',7,'Advanced Linking','[{"ja":"私は日本へ行きたいです。","romaji":"watashi wa nihon e ikitai desu.","en":"I want to go to Japan."},{"ja":"何か温かいものが飲みたい。","romaji":"nanika atatakai mono ga nomitai.","en":"I want to drink something warm."},{"ja":"今日は何もしたくないです。","romaji":"kyou wa nani mo shitakunai desu.","en":"I don''t want to do anything today."},{"ja":"子供の時、医者になりたかったです。","romaji":"kodomo no toki, isha ni naritakatta desu.","en":"When I was a child, I wanted to be a doctor."}]','[]','["desire","verb conjugation"]',69);
INSERT INTO grammar_points VALUES(70,'n5-tari-tari','たり〜たりする','tari tari suru','do such things as A and B; do A, B, and so on','Verb (た-form) + り、Verb (た-form) + りする',unistr('The grammar pattern 「〜たり〜たりする」 is used to list a few representative actions or states among many, implying that other similar things also happen or could happen. It does not list all possible actions, but rather gives examples of what occurs.\u000a\u000aTo form this, you take the past tense (た-form) of a verb, add 「り」, and repeat this for another verb, finally ending with 「する」. The verb 「する」 at the end can be conjugated to reflect the tense of the overall sentence (e.g., 「〜たり〜たりしました」 for past tense, 「〜たり〜たりします」 for present/future).\u000a\u000aThis pattern can also be used with nouns and adjectives by changing them to their past tense forms (e.g., Noun + だったり, い-Adjective + かったり, な-Adjective + だったり). It conveys a sense of variety or a non-exhaustive list of activities or conditions.'),'N5',7,'Advanced Linking','[{"ja":"休みの日は本を読んだり、音楽を聴いたりします。","romaji":"yasumi no hi wa hon o yondari, ongaku o kiitari shimasu.","en":"On my days off, I do things like read books and listen to music."},{"ja":"週末は友達と会ったり、映画を見たりしました。","romaji":"shuumatsu wa tomodachi to attari, eiga o mitari shimashita.","en":"On the weekend, I did things like meet friends and watch movies."},{"ja":"このレストランは美味しかったり、安かったりします。","romaji":"kono resutoran wa oishikattari, yasukattari shimasu.","en":"This restaurant is sometimes delicious and sometimes cheap."},{"ja":"彼は歌ったり踊ったりするのが好きです。","romaji":"kare wa uttari odottari suru no ga suki desu.","en":"He likes doing things like singing and dancing."}]','[]','["listing","verb conjugation"]',70);
INSERT INTO grammar_points VALUES(71,'n5-i-adj-ku','い-Adj + く','i-adj ku','Adverbial form of i-adjectives','い-Adjective (remove い) + く',unistr('The particle 「く」 is attached to the stem of an い-adjective (after removing the final 「い」) to transform it into an adverb. This adverbial form is used to modify verbs, describing *how* an action is performed, or to modify other adjectives/adverbs.\u000a\u000aFor example, 「早い (hayai)」 (early/fast) becomes 「早く (hayaku)」 (early/fast, adverbially). When used with a verb like 「起きる (okiru)」 (to wake up), 「早く起きる (hayaku okiru)」 means "to wake up early".\u000a\u000aAn important exception is 「良い (ii)」 (good), which becomes 「良く (yoku)」 in its adverbial form. This form is also used in negative conjugations (e.g., 良くない).'),'N5',8,'Counting and Comparisons','[{"ja":"早く起きてください。","romaji":"Hayaku okite kudasai.","en":"Please wake up early."},{"ja":"大きく書いてください。","romaji":"Ookiku kaite kudasai.","en":"Please write it big."},{"ja":"楽しく勉強しましょう。","romaji":"Tanoshiku benkyou shimashou.","en":"Let''s study enjoyably."},{"ja":"部屋を明るくしてください。","romaji":"Heya wo akaruku shite kudasai.","en":"Please make the room bright."}]','["n5-na-adj-ni"]','["adjective","adverbial form"]',71);
INSERT INTO grammar_points VALUES(72,'n5-i-adj-katta','い-Adj + かった','i-adj katta','Past tense of i-adjectives','い-Adjective (remove い) + かった',unistr('To form the past tense of an い-adjective, you remove the final 「い」 and replace it with 「かった」. This indicates that the state described by the adjective was true in the past.\u000a\u000aFor example, 「寒い (samui)」 (cold) becomes 「寒かった (samukatta)」 (was cold). This form can be used informally on its own or formally by adding 「です (desu)」 at the end (e.g., 「寒かったです (samukatta desu)」).\u000a\u000aThe irregular い-adjective 「良い (ii)」 (good) becomes 「良かった (yokatta)」 in the past tense, not 「いかった」. This is an important exception to remember.'),'N5',8,'Counting and Comparisons','[{"ja":"昨日は楽しかった。","romaji":"Kinou wa tanoshikatta.","en":"Yesterday was fun."},{"ja":"そのラーメンはおいしかった。","romaji":"Sono raamen wa oishikatta.","en":"That ramen was delicious."},{"ja":"この本は面白かったです。","romaji":"Kono hon wa omoshirokatta desu.","en":"This book was interesting."},{"ja":"昨日のテストは難しかった。","romaji":"Kinou no tesuto wa muzukashikatta.","en":"Yesterday''s test was difficult."}]','["n5-i-adj-kunakatta","n5-na-adj-datta"]','["adjective","past tense"]',72);
INSERT INTO grammar_points VALUES(73,'n5-i-adj-kunai','い-Adj + くない','i-adj kunai','Negative form of i-adjectives','い-Adjective (remove い) + くない',unistr('To form the negative of an い-adjective, you remove the final 「い」 and replace it with 「くない」. This indicates that the state described by the adjective is *not* true.\u000a\u000aFor example, 「高い (takai)」 (expensive/tall) becomes 「高くない (takakunai)」 (not expensive/not tall). This form is the casual negative. To make it polite, you add 「です (desu)」 at the end (e.g., 「高くないです (takakunai desu)」).\u000a\u000aThe irregular い-adjective 「良い (ii)」 (good) becomes 「良くない (yokunai)」 in the negative form, not 「いくない」. This is a crucial exception to remember.'),'N5',8,'Counting and Comparisons','[{"ja":"このコーヒーは熱くない。","romaji":"Kono koohii wa atsukunai.","en":"This coffee isn''t hot."},{"ja":"今日は寒くないです。","romaji":"Kyou wa samukunai desu.","en":"It''s not cold today."},{"ja":"その映画は面白くない。","romaji":"Sono eiga wa omoshirokunai.","en":"That movie is not interesting."},{"ja":"このかばんは重くないですか。","romaji":"Kono kaban wa omokunai desu ka.","en":"Isn''t this bag heavy?"}]','["n5-i-adj-kunakatta","n5-na-adj-ja-nai"]','["adjective","negative form"]',73);
INSERT INTO grammar_points VALUES(74,'n5-na-adj-ni','な-Adj + に','na-adj ni','Adverbial form of na-adjectives','な-Adjective (remove な) + に',unistr('The particle 「に」 is attached to the stem of a な-adjective (after removing the final 「な」) to transform it into an adverb. This adverbial form is primarily used to modify verbs, describing *how* an action is performed.\u000a\u000aFor example, 「静か (shizuka)」 (quiet) becomes 「静かに (shizuka ni)」 (quietly). When used with a verb like 「歩く (aruku)」 (to walk), 「静かに歩く (shizuka ni aruku)」 means "to walk quietly".\u000a\u000aUnlike い-adjectives, な-adjectives use 「に」 to form their adverbial form. This distinction is fundamental in Japanese grammar. Remember that the 「な」 particle is only used when a な-adjective directly modifies a noun (e.g., 静かな部屋 - a quiet room).'),'N5',8,'Counting and Comparisons','[{"ja":"静かに歩いてください。","romaji":"Shizuka ni aruite kudasai.","en":"Please walk quietly."},{"ja":"きれいに書きましょう。","romaji":"Kirei ni kakimashou.","en":"Let''s write neatly."},{"ja":"丁寧に説明します。","romaji":"Teinei ni setsumei shimasu.","en":"I will explain politely."},{"ja":"彼は上手に日本語を話します。","romaji":"Kare wa jouzu ni nihongo wo hanashimasu.","en":"He speaks Japanese skillfully."}]','["n5-i-adj-ku"]','["adjective","adverbial form"]',74);
INSERT INTO grammar_points VALUES(75,'n5-counter','Counter + の + Noun','counter no noun','Specifying quantity of a noun using a counter','Number + Counter + の + Noun',unistr('This structure is used to specify the quantity of a noun by placing a counter directly before the noun, connected by the particle 「の (no)」. While it''s more common to place the counter after the noun and before the verb (e.g., りんごを３つ買いました - I bought 3 apples), this construction emphasizes the quantity as an attribute of the noun.\u000a\u000aFor example, instead of saying 「りんごを３つ買いました (ringo wo mittsu kaimashita)」, you can say 「３つのりんごを買いました (mittsu no ringo wo kaimashita)」. Both mean "I bought 3 apples," but the latter explicitly describes "three apples" as a single unit.\u000a\u000aThis pattern is particularly useful when the counter phrase acts as a noun phrase itself, such as when it''s the subject of a sentence or directly modifies another noun. It''s important to use the correct counter for the specific type of noun.'),'N5',8,'Counting and Comparisons','[{"ja":"3つのりんごを買いました。","romaji":"Mittsu no ringo wo kaimashita.","en":"I bought 3 apples."},{"ja":"2枚の切符をください。","romaji":"Nimai no kippu wo kudasai.","en":"Please give me 2 tickets."},{"ja":"1匹の猫がいます。","romaji":"Ippiki no neko ga imasu.","en":"There is one cat."},{"ja":"5本のペンがあります。","romaji":"Gohon no pen ga arimasu.","en":"There are five pens."}]','[]','["counter","particle"]',75);
INSERT INTO grammar_points VALUES(76,'n5-yori','より','yori','More than; Rather than; From (a point in time/space)','Noun + より',unistr('「より」 is a particle primarily used for comparisons, meaning "more than" or "rather than." It indicates the point of comparison, with the item *before* より being the one that is less or the standard against which something else is superior. It is very commonly paired with 「のほうが」 to explicitly state which item is superior.\u000a\u000aFor example, in 「AよりBのほうが好きです」, B is preferred over A. The item following 「より」 is the one being surpassed or compared against. While its main use is comparison, 「より」 can also indicate a starting point in time or space, similar to 「から」, though this usage is less common in N5.\u000a\u000aWhen used in comparisons, the structure is typically `[Item 2] + より + [Item 1] + のほうが + [Adjective/Verb]`. This highlights that `[Item 1]` possesses the quality `[Adjective/Verb]` to a greater degree than `[Item 2]`.'),'N5',8,'Counting and Comparisons','[{"ja":"私は猫より、犬のほうが好きです。","romaji":"watashi wa neko yori, inu no hou ga suki desu.","en":"I like dogs more than cats."},{"ja":"昨日より今日の方が暑いです。","romaji":"kinou yori kyou no hou ga atsui desu.","en":"It''s hotter today than it was yesterday."},{"ja":"彼女より、君の方がきれいだよ。","romaji":"kanojo yori kimi no hou ga kirei da yo.","en":"You''re more beautiful than she is."},{"ja":"日本語を読むより、話す方が上手だ。","romaji":"nihongo o yomu yori, hanasu hou ga jouzu da.","en":"I''m better at speaking Japanese than I am at reading it."}]','["n5-no-hou-ga"]','["particle","comparison"]',76);
INSERT INTO grammar_points VALUES(77,'n5-no-hou-ga','のほうが','no hou ga','X is more ~ (than Y); X is preferable',unistr('Noun + のほうが + Adjective/Verb\u000aVerb (Casual) + のほうが + Adjective/Verb\u000a[Item 2] + より + [Item 1] + のほうが + Adjective/Verb'),unistr('「のほうが」 is a phrase used to indicate that one item or option is superior, preferable, or possesses a certain quality to a greater degree than another. It literally means "the side of ~" or "the direction of ~," emphasizing one choice over others.\u000a\u000aIt is most commonly used in comparative sentences, often in conjunction with 「より」. The structure `[Item 2] + より + [Item 1] + のほうが + [Adjective/Verb]` means that `[Item 1]` is more `[Adjective/Verb]` than `[Item 2]`.\u000a\u000aEven without 「より」, 「のほうが」 can be used when the comparison is implied or understood from context. For example, if you''re choosing between two items, you might simply say 「こっちのほうがいいです」 (This one is better). It clearly marks the preferred or superior option.'),'N5',8,'Counting and Comparisons','[{"ja":"私は猫より、犬のほうが好きです。","romaji":"watashi wa neko yori, inu no hou ga suki desu.","en":"I like dogs more than cats."},{"ja":"昨日より今日の方が暑いです。","romaji":"kinou yori kyou no hou ga atsui desu.","en":"It''s hotter today than it was yesterday."},{"ja":"彼女より、君の方がきれいだよ。","romaji":"kanojo yori kimi no hou ga kirei da yo.","en":"You''re more beautiful than she is."},{"ja":"日本語を読むより、話す方が上手だ。","romaji":"nihongo o yomu yori, hanasu hou ga jouzu da.","en":"I''m better at speaking Japanese than I am at reading it."}]','["n5-yori"]','["particle","comparison"]',77);
INSERT INTO grammar_points VALUES(78,'n5-ichiban','一番','ichiban','The most; The best; Number one',unistr('Noun + が + 一番 + Adjective/Verb\u000a(Among X) + で + 一番 + Adjective/Verb'),unistr('「一番 (いちばん)」 is an adverb used to express the superlative degree, meaning "the most," "the best," "the worst," or "number one." It is placed before an adjective, adverb, or verb to indicate that something possesses a quality or performs an action to the highest degree within a given group or context.\u000a\u000aWhen using 「一番」, the item being described as the most/best/worst is typically marked with the particle 「が」. If you want to specify the group or category within which something is the most, you can use the particle 「で」 (e.g., 「世界で一番」 - the most in the world, 「クラスで一番」 - the most in the class).\u000a\u000aThis grammar point is essential for making superlative statements and expressing preferences or rankings. It can be used with various types of words, including i-adjectives, na-adjectives (without な), and verbs.'),'N5',8,'Counting and Comparisons','[{"ja":"彼がいちばん働いた。","romaji":"kare ga ichiban hataraita.","en":"He worked the hardest."},{"ja":"秋が一番好きな季節です。","romaji":"aki ga ichiban suki na kisetsu desu.","en":"Fall is my favorite season."},{"ja":"私はブロッコリーが一番嫌いだ。","romaji":"watashi wa burokkorii ga ichiban kirai da.","en":"I hate broccoli the most."},{"ja":"午前中が一番調子がいい。","romaji":"gozen chuu ga ichiban choushi ga ii.","en":"I feel best in the morning."}]','[]','["adverb","superlative"]',78);
INSERT INTO grammar_points VALUES(79,'n5-ga-aru','がある','ga aru','There is; To have (for inanimate objects)',unistr('Noun + が + ある (polite: あります)\u000aPlace + に + Noun + が + ある'),unistr('「がある」 uses the verb 「ある」 (to exist) to indicate the existence or presence of inanimate objects. This includes things like tables, books, money, time, events, and abstract concepts. The particle 「が」 marks the subject, which is the inanimate object that exists.\u000a\u000aWhen stating where an inanimate object exists, the location is marked with the particle 「に」. For example, 「部屋にテレビがあります」 (There is a TV in the room). It can also express possession or having something, such as 「お金があります」 (I have money) or 「時間があります」 (I have time).\u000a\u000aIt''s crucial to distinguish 「ある」 from 「いる」. 「ある」 is exclusively for inanimate objects, plants, and abstract concepts, while 「いる」 is for animate beings (people and animals). Using the wrong verb is a common mistake for beginners.'),'N5',8,'Counting and Comparisons','[{"ja":"部屋にテレビがあります。","romaji":"heya ni terebi ga arimasu.","en":"There is a TV in the room."},{"ja":"私はお金があります。","romaji":"watashi wa okane ga arimasu.","en":"I have money."},{"ja":"明日、テストがあります。","romaji":"ashita, tesuto ga arimasu.","en":"There will be a test tomorrow."},{"ja":"何か問題がありますか。","romaji":"nanika mondai ga arimasu ka.","en":"Is there any problem?"}]','["n5-ga-iru"]','["verb","existence"]',79);
INSERT INTO grammar_points VALUES(80,'n5-ga-iru','がいる','ga iru','There is; To have (for animate objects)',unistr('Noun + が + いる (polite: います)\u000aPlace + に + Noun + が + いる'),unistr('「がいる」 uses the verb 「いる」 (to exist) to indicate the existence or presence of animate objects. This includes people, animals, and other living beings. The particle 「が」 marks the subject, which is the animate object that exists.\u000a\u000aWhen stating where an animate object exists, the location is marked with the particle 「に」. For example, 「部屋に猫がいます」 (There is a cat in the room). It can also express having family members or friends, such as 「兄弟がいます」 (I have siblings) or 「友達がいます」 (I have friends).\u000a\u000aIt''s crucial to distinguish 「いる」 from 「ある」. 「いる」 is exclusively for animate objects (people and animals), while 「ある」 is for inanimate objects, plants, and abstract concepts. Using the wrong verb is a fundamental point in N5 grammar.'),'N5',8,'Counting and Comparisons','[{"ja":"テーブルの下に猫がいます。","romaji":"teeburu no shita ni neko ga imasu.","en":"There is a cat under the table."},{"ja":"あなたは彼氏がいますか。","romaji":"anata wa kareshi ga imasu ka.","en":"Do you have a boyfriend?"},{"ja":"私には兄弟がいないんだ。","romaji":"watashi ni wa kyoudai ga inai nda.","en":"I don''t have any siblings."},{"ja":"公園に子供たちがいます。","romaji":"kouen ni kodomotachi ga imasu.","en":"There are children in the park."}]','["n5-ga-aru"]','["verb","existence"]',80);
INSERT INTO grammar_points VALUES(81,'n5-te-kudasai','てください','te kudasai','Please do (a polite request).','Verb (て-form) + ください',unistr('「てください」 is a fundamental N5 grammar pattern used to make polite requests or commands. It directly translates to "Please do X." This pattern is versatile and commonly used in everyday conversations.\u000a\u000aTo form this, you take a verb, change it to its て-form, and then attach 「ください」. For example, 食べます (tabemasu - to eat) becomes 食べて (tabete), so 食べてください means "Please eat." The politeness level is generally appropriate for most situations, but for very formal contexts, more honorific expressions might be preferred.'),'N5',9,'Suggesting and Requesting','[{"ja":"日本語で話してください。","romaji":"nihongo de hanashite kudasai.","en":"Please speak in Japanese."},{"ja":"この本を読んでください。","romaji":"kono hon o yonde kudasai.","en":"Please read this book."},{"ja":"ここに座ってください。","romaji":"koko ni suwatte kudasai.","en":"Please sit here."},{"ja":"ちょっと待ってください。","romaji":"chotto matte kudasai.","en":"Please wait a moment."}]','["n5-naide-kudasai"]','["request","verb form"]',81);
INSERT INTO grammar_points VALUES(82,'n5-naide-kudasai-1','ないでください','naide kudasai','Please don''t do (a polite negative request).','Verb (ない-form) + でください',unistr('「ないでください」 is used to make a polite negative request, meaning "Please don''t do X." It is the negative counterpart to 「てください」 and is essential for expressing prohibitions or asking someone to refrain from an action.\u000a\u000aTo form this, you take a verb, change it to its ない-form (negative plain form), and then attach 「でください」. For example, 行きます (ikimasu - to go) becomes 行かない (ikanai), so 行かないでください means "Please don''t go." While generally polite, this expression can be made more casual by dropping 「ください」 to just 「ないで」. It''s important not to confuse this 「ないで」 (negative request) with the 「ないで」 that means "without doing X" (e.g., 何も食べないで寝た - I slept without eating anything). Context usually clarifies the meaning.'),'N5',9,'Suggesting and Requesting','[{"ja":"ここで写真を撮らないでください。","romaji":"koko de shashin o toranaide kudasai.","en":"Please don''t take pictures here."},{"ja":"遅刻しないでください。","romaji":"chikoku shinaide kudasai.","en":"Please don''t be late."},{"ja":"このドアを開けないでください。","romaji":"kono doa o akenaide kudasai.","en":"Please don''t open this door."},{"ja":"私に触らないでください。","romaji":"watashi ni sawaranaide kudasai.","en":"Please don''t touch me."}]','["n5-te-kudasai"]','["request","negative","verb form"]',82);
INSERT INTO grammar_points VALUES(83,'n5-te-wa-ikenai','てはいけない','te wa ikenai','Must not; May not; Should not. (Prohibition)','Verb (て-form) + は + いけない',unistr('「てはいけない」 expresses prohibition or a strong warning, meaning "You must not do X" or "You may not do X." It indicates that an action is forbidden, inappropriate, or against rules. The literal meaning is "doing X is not good."\u000a\u000aTo form this, you combine the て-form of a verb with the particle 「は」 (pronounced "wa" here) and 「いけない」 (ikenai), which is the negative form of 良い (ii - good). For example, 飲んで (nonde - drinking) + は + いけない becomes 飲んではいけない (nonde wa ikenai - must not drink).\u000a\u000aThis pattern is often used by superiors to subordinates, parents to children, or in rules and regulations, and can sound quite strong. A slightly softer alternative for "should not" is 「ないほうがいい」. In casual speech, 「てはいけない」 often contracts to 「ちゃいけない」 (for verbs ending in て) or 「じゃいけない」 (for verbs ending in で). For example, 食べてはいけない becomes 食べちゃいけない.'),'N5',9,'Suggesting and Requesting','[{"ja":"ここでタバコを吸ってはいけません。","romaji":"koko de tabako o sutte wa ikemasen.","en":"You must not smoke here."},{"ja":"子供は夜遅くまで起きていてはいけない。","romaji":"kodomo wa yoru osoku made okite ite wa ikenai.","en":"Children must not stay up late at night."},{"ja":"試験中に携帯電話を使ってはいけない。","romaji":"shiken-chuu ni keitai denwa o tsukatte wa ikenai.","en":"You must not use mobile phones during the exam."},{"ja":"嘘をついてはいけない。","romaji":"uso o tsuite wa ikenai.","en":"You must not tell lies."}]','["n5-nakereba-naranai","n5-ta-hou-ga-ii"]','["prohibition","verb form","restriction"]',83);
INSERT INTO grammar_points VALUES(84,'n5-nakereba-naranai','なければならない','nakereba naranai','Must do; Have to do; Need to do. (Obligation)','Verb (ない-form, drop い) + なければならない',unistr('「なければならない」 expresses a strong obligation or necessity, meaning "must do," "have to do," or "need to do." It indicates that an action is unavoidable or required, often due to rules, circumstances, or personal responsibility.\u000a\u000aTo form this, take the ない-form of a verb, drop the final い, and add 「なければならない」. For example, 行かない (ikanai - not go) becomes 行かなければならない (ikanakereba naranai - must go). This pattern is commonly used in both formal and informal contexts, though more casual variations exist.\u000a\u000aThis pattern can also be seen in variations like 「なければいけない」 (nakereba ikenai), 「なくてはいけない」 (nakute wa ikenai), and 「なくてはならない」 (nakute wa naranai). All convey a similar meaning of obligation. In casual speech, these forms often contract; for instance, 「なければならない」 can become 「なきゃならない」 or 「なきゃいけない」, and 「なくてはいけない」 can become 「なくちゃいけない」.'),'N5',9,'Suggesting and Requesting','[{"ja":"明日は早く起きなければなりません。","romaji":"ashita wa hayaku okinakereba narimasen.","en":"I have to wake up early tomorrow."},{"ja":"宿題をしなければならない。","romaji":"shukudai o shinakereba naranai.","en":"I must do my homework."},{"ja":"パスポートを更新しなければならない。","romaji":"pasupōto o kōshin shinakereba naranai.","en":"I need to renew my passport."},{"ja":"もっと日本語を勉強しなければならない。","romaji":"motto nihongo o benkyō shinakereba naranai.","en":"I must study more Japanese."}]','["n5-te-wa-ikenai","n5-ta-hou-ga-ii"]','["obligation","necessity","verb form"]',84);
INSERT INTO grammar_points VALUES(85,'n5-ta-hou-ga-ii','たほうがいい','ta hou ga ii','Had better; It would be better to; Should. (Suggestion/Advice)',unistr('Verb (た-form) + ほうがいい (Positive suggestion)\u000aVerb (ない-form) + ほうがいい (Negative suggestion)'),unistr('「たほうがいい」 is used to give advice or make a suggestion, meaning "It would be better to do X" or "You should do X." It implies that the suggested action is preferable or beneficial. The phrase 「ほうがいい」 literally means "the direction/side is good," indicating that choosing that action is the better option.\u000a\u000aFor positive suggestions, use the た-form of the verb (e.g., 食べたほうがいい - It''s better to eat). For negative suggestions, use the ない-form of the verb (e.g., 食べないほうがいい - It''s better not to eat). This structure is very common for offering guidance or recommendations.\u000a\u000aThis expression is a gentle way to offer advice, but it can sound a bit strong if used directly to someone of much higher status or in a very formal setting. It''s commonly used among friends, family, or when giving advice to someone younger or of equal status.'),'N5',9,'Suggesting and Requesting','[{"ja":"風邪をひいたから、早く寝たほうがいいですよ。","romaji":"kaze o hiita kara, hayaku neta hou ga ii desu yo.","en":"You caught a cold, so you should go to bed early."},{"ja":"もっと野菜を食べたほうがいい。","romaji":"motto yasai o tabeta hou ga ii.","en":"You should eat more vegetables."},{"ja":"危ないから、一人で行かないほうがいい。","romaji":"abunai kara, hitori de ikanai hou ga ii.","en":"It''s dangerous, so you shouldn''t go alone."},{"ja":"日本語のニュースを見たほうがいいと思います。","romaji":"nihongo no nyūsu o mita hou ga ii to omoimasu.","en":"I think it''s better to watch Japanese news."}]','["n5-nakereba-naranai","n5-te-wa-ikenai"]','["suggestion","advice","verb form"]',85);
INSERT INTO grammar_points VALUES(86,'n5-deshou','でしょう','deshou','probably; right?; I wonder',unistr('Verb (casual form) + でしょう\u000aい-adjective + でしょう\u000aな-adjective (stem) + でしょう\u000aNoun + でしょう'),unistr('「でしょう」 (deshou) is a versatile expression in Japanese with two primary uses. Firstly, it expresses conjecture or probability, similar to "probably" or "I think" in English. The speaker is making an educated guess or expressing their opinion about a future event or current situation. It indicates a degree of certainty, but not 100%.\u000a\u000aSecondly, 「でしょう」 can be used to seek agreement or confirmation from the listener, much like adding "right?" or "isn''t it?" to the end of a sentence. When used in this way, it implies that the speaker expects the listener to agree with their statement. The intonation typically rises at the end of the sentence when asking for confirmation.\u000a\u000aIt is the polite form of 「だろう」 (darou). When used in questions, it can also convey a sense of wonder or speculation, as in "I wonder what..." or "Who could that be?". In casual speech, it is often shortened to 「でしょ」 (desho).'),'N5',9,'Suggesting and Requesting','[{"ja":"明日は晴れるでしょう。","romaji":"ashita wa hareru deshou.","en":"It will probably be sunny tomorrow."},{"ja":"このケーキは美味しいでしょう？","romaji":"kono keeki wa oishii deshou?","en":"This cake is delicious, isn''t it?"},{"ja":"あの人は誰でしょう。","romaji":"ano hito wa dare deshou.","en":"I wonder who that person is."},{"ja":"田中さんはもう家に着いたでしょう。","romaji":"tanaka-san wa mou ie ni tsuita deshou.","en":"Mr. Tanaka has probably already arrived home."}]','["n5-darou"]','["auxiliary","conjecture","confirmation"]',86);
INSERT INTO grammar_points VALUES(87,'n5-kara-reason','から (Because)','kara reason','because; since',unistr('Verb (casual form) + から\u000aい-adjective + から\u000aな-adjective (stem) + だから\u000aNoun + だから'),unistr('「から」 (kara) is a conjunction used to express a reason or cause for an action or situation. It connects two clauses, with the reason or cause preceding 「から」, and the result or consequence following it. It directly translates to "because" or "since" in English.\u000a\u000aThis grammar point can be attached to various parts of speech. For verbs and い-adjectives, you use their casual forms directly before 「から」. For な-adjectives and nouns, you must add 「だ」 before 「から」 (e.g., 暇だから, 学生だから). This structure clearly indicates a cause-and-effect relationship.\u000a\u000aWhile 「から」 is widely used, it can sometimes sound more direct or assertive when stating a reason compared to 「ので」 (node). It''s a fundamental grammar point for explaining why something is the way it is or why an action is taken.'),'N5',9,'Suggesting and Requesting','[{"ja":"雨が降っているから、傘を持っていきます。","romaji":"ame ga futte iru kara, kasa o motte ikimasu.","en":"Because it''s raining, I will take an umbrella."},{"ja":"この本は面白いから、読んでみてください。","romaji":"kono hon wa omoshiroi kara, yonde mite kudasai.","en":"This book is interesting, so please try reading it."},{"ja":"彼は日本人だから、日本語が上手です。","romaji":"kare wa nihonjin dakara, nihongo ga jouzu desu.","en":"Because he is Japanese, he is good at Japanese."},{"ja":"忙しいから、パーティーに行けません。","romaji":"isogashii kara, paatii ni ikemasen.","en":"I''m busy, so I can''t go to the party."}]','["n5-node"]','["conjunction","reason"]',87);
INSERT INTO grammar_points VALUES(88,'n5-node','ので','node','because; since; given that (polite reason)',unistr('Verb (casual form) + ので\u000aい-adjective + ので\u000aな-adjective (stem) + なので\u000aNoun + なので'),unistr('「ので」 (node) is a conjunction used to state a reason or cause, similar to 「から」 (kara). However, 「ので」 often implies a more objective, softer, or less assertive reason. It is generally considered more polite and formal than 「から」, making it suitable for situations where you want to sound less direct or when making requests or apologies.\u000a\u000aThe conjugation rules for 「ので」 are important to remember. For verbs and い-adjectives, you attach 「ので」 directly to their casual forms. For な-adjectives and nouns, you must insert 「な」 before 「ので」 (e.g., 静かなので, 病気なので). This 「な」 is crucial and differentiates it from 「から」.\u000a\u000a「ので」 is frequently used when providing an explanation for a situation, making a polite request, or offering an apology. It softens the tone and presents the reason as a natural consequence, rather than a strong justification. For example, when asking for permission, using 「ので」 makes the request sound more considerate.'),'N5',10,'Final Concepts','[{"ja":"頭が痛いので、今日は早く帰ります。","romaji":"atama ga itai node, kyou wa hayaku kaerimasu.","en":"Because I have a headache, I will go home early today."},{"ja":"道が混んでいたので、遅れてしまいました。","romaji":"michi ga konde ita node, okurete shimaimashita.","en":"Since the road was crowded, I ended up being late."},{"ja":"ここは静かなので、勉強しやすいです。","romaji":"koko wa shizuka na node, benkyou shi yasui desu.","en":"Because it''s quiet here, it''s easy to study."},{"ja":"先生は忙しいので、後で話しましょう。","romaji":"sensei wa isogashii node, ato de hanashimashou.","en":"Since the teacher is busy, let''s talk later."}]','["n5-kara-reason"]','["conjunction","reason","polite"]',88);
INSERT INTO grammar_points VALUES(89,'n5-no-desu','のです・んです','no desu','it is that; the reason is; to explain/emphasize',unistr('Verb (casual form) + のです / んです\u000aい-adjective + のです / んです\u000aな-adjective (stem) + なのです / なんです\u000aNoun + なのです / なんです'),unistr('「のです」 (no desu) and its contracted form 「んです」 (n desu) are used to provide an explanation, give a reason, or add emphasis to a statement. It often implies that the speaker is clarifying something, responding to an unstated question, or providing background information. It makes a statement sound more explanatory or inquisitive.\u000a\u000aThe conjugation rules are as follows: for verbs and い-adjectives, you attach 「のです」 or 「んです」 directly to their casual forms. For な-adjectives and nouns, you must insert 「な」 before 「のです」 or 「んです」 (e.g., 好きなのです, 学生なのです). The contracted form 「んです」 is very common in spoken Japanese and carries the same meaning.\u000a\u000aThis grammar point adds a nuance of seeking or providing a deeper explanation. When used in questions (e.g., 「どうしたんですか」), it asks for the reason or circumstances. When used in statements, it explains the reason behind a situation or emphasizes a point, often with a sense of conviction or clarification.'),'N5',10,'Final Concepts','[{"ja":"どうして日本語を勉強しているのですか。","romaji":"doushite nihongo o benkyou shite iru no desu ka.","en":"Why are you studying Japanese? (Asking for an explanation)"},{"ja":"昨日、熱があったので、学校を休んだんです。","romaji":"kinou, netsu ga atta node, gakkou o yasunda n desu.","en":"I had a fever yesterday, so I took a day off from school. (Explaining the reason)"},{"ja":"この本はとても面白いんですよ。","romaji":"kono hon wa totemo omoshiroi n desu yo.","en":"This book is really interesting, you know. (Adding emphasis/explanation)"},{"ja":"私は医者なのです。","romaji":"watashi wa isha na no desu.","en":"I am a doctor. (Stating a fact with emphasis/explanation)"}]','[]','["explanatory","emphasis","auxiliary"]',89);
INSERT INTO grammar_points VALUES(90,'n5-tsumori','つもり','tsumori','intend to; plan to; mean to',unistr('Verb (dictionary form) + つもりだ\u000aVerb (ない form) + つもりだ\u000aNoun + の + つもりだ'),unistr('「つもり」 (tsumori) expresses the speaker''s intention, plan, or resolution to do something. It indicates a firm decision or a strong personal will regarding a future action. It''s a more definite statement of intent than simply using the plain form of a verb or the ~ます form, which can sometimes just indicate a future action without strong personal resolve.\u000a\u000aTo form a sentence with 「つもり」, you attach it to the dictionary form of a verb for affirmative intentions (e.g., 食べるつもりだ - I intend to eat). For negative intentions, you use the ない form of the verb (e.g., 食べないつもりだ - I don''t intend to eat). This clearly distinguishes between planning to do something and planning not to do something.\u000a\u000a「つもり」 can also be used with nouns, in the form 「Noun + の + つもりだ」, to mean "intend to be (a noun)" or "consider oneself to be (a noun)". This usage often implies a role or status. It''s a crucial expression for communicating personal plans and intentions in Japanese.'),'N5',10,'Final Concepts','[{"ja":"来年、日本へ行くつもりです。","romaji":"rainen, nihon e iku tsumori desu.","en":"I intend to go to Japan next year."},{"ja":"今日は残業しないつもりです。","romaji":"kyou wa zangyou shinai tsumori desu.","en":"I don''t intend to work overtime today."},{"ja":"彼は医者になるつもりだ。","romaji":"kare wa isha ni naru tsumori da.","en":"He plans to become a doctor."},{"ja":"私はもう子供じゃないつもりです。","romaji":"watashi wa mou kodomo ja nai tsumori desu.","en":"I don''t consider myself a child anymore."}]','[]','["intention","plan"]',90);
INSERT INTO grammar_points VALUES(91,'n5-you-ni-naru','ようになる','you ni naru','to reach the point that; to become able to; to start to',unistr('Verb (dictionary form) + ようになる\u000aVerb (negative form) + ようになる'),unistr('The grammar pattern 「ようになる」 (you ni naru) expresses a gradual change or the acquisition of a new ability or habit. It indicates that a state or action that was not previously possible or habitual has now become so.\u000a\u000aThis pattern is often used to describe a process of learning or adaptation. For example, if you couldn''t speak Japanese before but now you can, you would use 「話せるようになる」. It implies a transition over time, rather than an immediate or direct change.\u000a\u000aIt differs from 「～になる」 (ni naru), which describes a direct change of state (e.g., 「医者になる」 - to become a doctor). 「ようになる」 specifically highlights the *process* of becoming able to do something or starting a new habit.'),'N5',10,'Final Concepts','[{"ja":"毎日、運動するようになりました。","romaji":"mainichi, undou suru you ni narimashita.","en":"I started exercising every day."},{"ja":"日本語が話せるようになりました。","romaji":"nihongo ga hanaseru you ni narimashita.","en":"I became able to speak Japanese."},{"ja":"朝早く起きるようになりました。","romaji":"asa hayaku okiru you ni narimashita.","en":"I started waking up early in the morning."},{"ja":"パソコンで漢字が打てるようになりました。","romaji":"pasokon de kanji ga uteru you ni narimashita.","en":"I became able to type kanji on the computer."}]','["n5-ni-naru"]','["verb conjugation","change of state"]',91);
INSERT INTO grammar_points VALUES(92,'n5-shi','し','shi','and; also; in addition; because (listing reasons)',unistr('Verb (casual form) + し\u000aい-Adjective (casual form) + し\u000aな-Adjective (casual form) + だし\u000aNoun + だし'),unistr('The particle 「し」 (shi) is used to list multiple reasons or facts, often implying a causal or supportive relationship between them. It''s similar to saying "and... and also..." in English, but it carries the nuance that the listed items contribute to a certain conclusion or situation.\u000a\u000aUnlike a simple conjunction like 「と」 (to) or 「そして」 (soshite), 「し」 suggests that there might be other unstated reasons, or it can be used to soften a statement or provide an excuse. The final conclusion or action is often stated after the list of reasons, but it can also be implied.\u000a\u000aEach clause ending with 「し」 takes the casual form of the verb, い-adjective, な-adjective (with だ), or noun (with だ).'),'N5',10,'Final Concepts','[{"ja":"このレストランは美味しいし、値段も安いし、よく行きます。","romaji":"kono resutoran wa oishii shi, nedan mo yasui shi, yoku ikimasu.","en":"This restaurant is delicious, and the prices are cheap, so I often go there."},{"ja":"今日は雨だし、寒いし、出かけたくない。","romaji":"kyou wa ame da shi, samui shi, dekaketakunai.","en":"It''s raining today, and it''s cold, so I don''t want to go out."},{"ja":"彼は頭もいいし、優しいし、人気があります。","romaji":"kare wa atama mo ii shi, yasashii shi, ninki ga arimasu.","en":"He is smart, and kind, so he is popular."},{"ja":"宿題も終わったし、ご飯も食べたし、もう寝てもいいですか。","romaji":"shukudai mo owatta shi, gohan mo tabeta shi, mou nete mo ii desu ka.","en":"I finished my homework, and I ate dinner, so can I go to bed now?"}]','["n5-to","n5-soshite"]','["conjunction","listing"]',92);
INSERT INTO grammar_points VALUES(93,'n5-ga-hoshii','が欲しい','ga hoshii','to want (a noun)','Noun + が + 欲しい (ほしい)',unistr('The expression 「が欲しい」 (ga hoshii) is used to state one''s desire for a specific noun or object. 「欲しい」 is an い-adjective, meaning "wanted" or "desired," and it always takes the particle 「が」 (ga) to mark the object of desire.\u000a\u000aThis pattern is exclusively for wanting *things* (nouns). When you want *to do* something, you would use the 「～たい」 (tai) form of a verb (e.g., 「食べたい」 - want to eat). You can only use 「が欲しい」 to express your own desire; to express someone else''s desire, you would typically use 「欲しがっている」 (hoshigatte iru) or 「～たいと言っている」 (tai to itte iru).\u000a\u000aIt''s a fundamental N5 grammar point for expressing personal wants and needs.'),'N5',10,'Final Concepts','[{"ja":"新しいパソコンが欲しいです。","romaji":"atarashii pasokon ga hoshii desu.","en":"I want a new computer."},{"ja":"今、一番欲しいものは時間です。","romaji":"ima, ichiban hoshii mono wa jikan desu.","en":"What I want most right now is time."},{"ja":"何か飲み物が欲しいですか。","romaji":"nanika nomimono ga hoshii desu ka.","en":"Do you want something to drink?"},{"ja":"子供の時、犬が欲しかったです。","romaji":"kodomo no toki, inu ga hoshikatta desu.","en":"When I was a child, I wanted a dog."}]','["n5-tai"]','["adjective","desire"]',93);
INSERT INTO grammar_points VALUES(94,'n5-nagara','ながら','nagara','while; during; doing (two actions simultaneously)','Verb (stem form) + ながら',unistr('The grammar pattern 「ながら」 (nagara) is used to express that two actions are happening at the same time, performed by the same subject. It is attached to the stem form of the first verb, and the second verb describes the main action.\u000a\u000aThe action described by the verb before 「ながら」 is usually considered the secondary or accompanying action, while the action described by the verb after 「ながら」 is the primary or more important action. For example, in 「音楽を聴きながら勉強します」, studying is the main activity, and listening to music is the accompanying one.\u000a\u000aIt''s important that both actions are performed by the same person or entity. This pattern is very common for describing everyday activities where multitasking occurs.'),'N5',10,'Final Concepts','[{"ja":"音楽を聴きながら勉強します。","romaji":"ongaku o kikinagara benkyou shimasu.","en":"I study while listening to music."},{"ja":"歩きながら話しましょう。","romaji":"arukinagara hanashimashou.","en":"Let''s talk while walking."},{"ja":"テレビを見ながらご飯を食べます。","romaji":"terebi o minagara gohan o tabemasu.","en":"I eat dinner while watching TV."},{"ja":"歌いながら料理をするのが好きです。","romaji":"utainagara ryouri o suru no ga suki desu.","en":"I like cooking while singing."}]','[]','["conjunction","simultaneous actions"]',94);
INSERT INTO grammar_points VALUES(95,'n5-ni-suru','にする','ni suru','to decide on; to choose; to make (something into something)',unistr('Noun + にする\u000aVerb (dictionary form) + ことにする'),unistr('The grammar pattern 「にする」 (ni suru) has two main uses. Firstly, it expresses a decision or choice, often made by the speaker. This is commonly seen when ordering food or selecting an option, where you are actively making a choice (e.g., 「コーヒーにする」 - I''ll have coffee).\u000a\u000aSecondly, it can mean to *make* something into a certain state or form. For example, 「部屋をきれいにする」 means "to make the room clean." When deciding *to do* something, the pattern 「Verb (dictionary form) + ことにする」 is used, indicating a personal decision to perform an action.\u000a\u000aThis pattern emphasizes a volitional act or a conscious decision, distinguishing it from 「～になる」 (ni naru), which describes a natural or unintentional change of state.'),'N5',10,'Final Concepts','[{"ja":"飲み物はコーヒーにします。","romaji":"nomimono wa koohii ni shimasu.","en":"I''ll have coffee (I''ll decide on coffee)."},{"ja":"和食にしましょう。","romaji":"washoku ni shimashou.","en":"Let''s go with Japanese food."},{"ja":"来年、日本へ留学することにしました。","romaji":"rainen, nihon e ryuugaku suru koto ni shimashita.","en":"I decided to study abroad in Japan next year."},{"ja":"部屋をきれいにします。","romaji":"heya o kirei ni shimasu.","en":"I will make the room clean."}]','["n5-ni-naru"]','["decision","choice","change of state"]',95);
INSERT INTO grammar_points VALUES(96,'n5-sou-hearsay','そう (Hearsay)','sou hearsay','I heard that; They say',unistr('Verb (casual form) + そうだ\u000aい-adjective (full form) + そうだ\u000aな-adjective (remove な) + だ + そうだ\u000aNoun + だ + そうだ'),unistr('The grammar pattern 「そう (そうだ)」 is used to report information that you have heard from someone else or from a source like the news. It indicates that the speaker is not stating their own opinion or observation, but rather relaying information.\u000a\u000aIt attaches to the casual form of verbs, the full form of い-adjectives, and to な-adjectives and nouns followed by 「だ」. When used in polite speech, 「そうだ」 becomes 「そうです」. This pattern is distinct from 「そう (Appearance)」, which expresses an observation based on how something looks.'),'N5',10,'Final Concepts','[{"ja":"明日は雨だそうです。","romaji":"Ashita wa ame da sou desu.","en":"I heard it will rain tomorrow."},{"ja":"彼は忙しいそうだ。","romaji":"Kare wa isogashii sou da.","en":"I heard he''s busy."},{"ja":"田中さんは来週日本へ行くそうです。","romaji":"Tanaka-san wa raishuu Nihon e iku sou desu.","en":"I heard Mr. Tanaka is going to Japan next week."},{"ja":"このレストランは美味しいそうだ。","romaji":"Kono resutoran wa oishii sou da.","en":"They say this restaurant is delicious."}]','[]','["hearsay","reporting"]',96);
INSERT INTO grammar_points VALUES(97,'n5-sou-appearance','そう (Appearance)','sou appearance','Looks like; Seems like',unistr('Verb (ます-stem) + そうだ\u000aい-adjective (remove い) + そうだ\u000aな-adjective (remove な) + そうだ\u000a*Exception*: 良い -> よさそうだ'),unistr('The grammar pattern 「そう (そうだ)」 is used to express a judgment or impression based on what you see or perceive. It indicates that something ''looks like'' or ''seems like'' a certain way. This is a direct observation by the speaker.\u000a\u000aIt attaches to the ます-stem of verbs, the stem of い-adjectives (by removing the final い), and the stem of な-adjectives (by removing the final な). A common exception is 「良い (ii)」 which becomes 「よさそうだ」. When used in polite speech, 「そうだ」 becomes 「そうです」. This pattern is different from 「そう (Hearsay)」, which reports information heard from others.'),'N5',10,'Final Concepts','[{"ja":"これはおいしそうです。","romaji":"Kore wa oishisou desu.","en":"This looks delicious."},{"ja":"雨が降りそうだ。","romaji":"Ame ga furisou da.","en":"It looks like it''s going to rain."},{"ja":"彼は元気そうだ。","romaji":"Kare wa genki sou da.","en":"He looks energetic."},{"ja":"このケーキは甘そうだ。","romaji":"Kono keeki wa amasou da.","en":"This cake looks sweet."}]','[]','["appearance","conjecture"]',97);
INSERT INTO grammar_points VALUES(98,'n5-to-omou','と思う','to omou','I think that...',unistr('Verb (casual form) + と思う\u000aい-adjective (casual form) + と思う\u000aな-adjective (remove な, add だ) + と思う\u000aNoun (add だ) + と思う'),unistr('The grammar pattern 「と思う (to omou)」 is used to express one''s own thoughts, opinions, or beliefs. It directly translates to "I think that..." and is a fundamental way to share your perspective in Japanese.\u000a\u000aIt is always preceded by the casual form of verbs, い-adjectives, な-adjectives (which take 「だ」), and nouns (which also take 「だ」). The polite form of 「思う」 is 「思います」. This pattern is crucial for engaging in conversations where you need to state your personal viewpoint.'),'N5',10,'Final Concepts','[{"ja":"日本に行きたいと思います。","romaji":"Nihon ni ikitai to omoimasu.","en":"I think I want to go to Japan."},{"ja":"明日は暑いと思う。","romaji":"Ashita wa atsui to omou.","en":"I think it''ll be hot tomorrow."},{"ja":"この本は面白いと思います。","romaji":"Kono hon wa omoshiroi to omoimasu.","en":"I think this book is interesting."},{"ja":"彼は学生だと思います。","romaji":"Kare wa gakusei da to omoimasu.","en":"I think he is a student."}]','[]','["opinion","thought"]',98);
INSERT INTO grammar_points VALUES(99,'n5-sugiru','すぎる','sugiru','Too much; Excessively',unistr('Verb (ます-stem) + すぎる\u000aい-adjective (remove い) + すぎる\u000aな-adjective (remove な) + すぎる'),unistr('The grammar pattern 「すぎる (sugiru)」 is used to indicate that an action or state is excessive or "too much." It often carries a negative connotation, implying that the degree is beyond what is appropriate or desirable.\u000a\u000aIt attaches to the ます-stem of verbs, the stem of い-adjectives (by removing the final い), and the stem of な-adjectives (by removing the final な). 「すぎる」 itself conjugates like a regular る-verb (e.g., すぎます, すぎない, すぎた). This pattern is useful for expressing dissatisfaction or a problem with an extreme quantity or quality.'),'N5',10,'Final Concepts','[{"ja":"このシャツは大きすぎる。","romaji":"Kono shatsu wa ookisugiru.","en":"This shirt is too big."},{"ja":"今年の夏は暑すぎた。","romaji":"Kotoshi no natsu wa atsusugita.","en":"This year''s summer was too hot."},{"ja":"食べすぎるとお腹が痛くなる。","romaji":"Tabesugiru to onaka ga itaku naru.","en":"If you eat too much, your stomach will hurt."},{"ja":"この問題は簡単すぎます。","romaji":"Kono mondai wa kantansugimasu.","en":"This problem is too easy."}]','[]','["degree","excess"]',99);
INSERT INTO grammar_points VALUES(100,'n4-demo','でも','demo','...or something; how about~','Noun + でも',unistr('The particle 「でも」, when used after a noun, suggests an example or a casual option among many possibilities. It often implies "...or something like that," or "how about..." and is used to make a gentle suggestion or offer.\u000a\u000aIt can also be used with interrogative words (e.g., 誰でも - anyone, 何でも - anything, どこでも - anywhere) to mean "any/every." However, in its basic N4 usage, it''s commonly seen in suggestions. This usage conveys a sense of not being particular or being open to various choices.'),'N4',1,'Ways of Doing and Being','[{"ja":"水でも飲みますか？","romaji":"Mizu demo nomimasu ka?","en":"Would you care for some water or something to drink?"},{"ja":"牛丼でも食べに行きませんか？","romaji":"Gyuudon demo tabe ni ikimasen ka?","en":"How about going to eat a beef bowl or something?"},{"ja":"寒いから、暖かいものでも飲みませんか。","romaji":"Samui kara, atatakai mono demo nomimasen ka.","en":"It''s cold, so how about drinking something warm?"},{"ja":"晩ご飯ならサラダでも作りましょうか？","romaji":"Bangohan nara sarada demo tsukurimashou ka?","en":"If it''s dinner, shall I make a salad or something?"}]','[]','["particle","suggestion"]',100);
INSERT INTO grammar_points VALUES(101,'n4-yasui','～易（やす）い','yasui','Easy to do; likely to do','Verb (ます-stem) + 易い',unistr('The grammar pattern `～易い` (yasui) attaches to the ます-stem of a verb to indicate that an action is easy to perform or that something is prone to happening. It functions grammatically like an い-adjective, meaning it can directly modify nouns or be conjugated for tense and politeness.\u000a\u000aThis pattern expresses an inherent quality or characteristic that makes an action simple or straightforward. For example, if a book is `読みやすい` (yomiyasui), it means the book itself is structured or written in a way that facilitates easy reading.\u000a\u000aIt is the opposite of `～にくい` (nikui) and `～づらい` (zurai), which both express difficulty. While `～にくい` often implies objective difficulty, `～易い` implies objective ease.'),'N4',1,'Ways of Doing and Being','[{"ja":"この本は読みやすいです。","romaji":"Kono hon wa yomiyasui desu.","en":"This book is easy to read."},{"ja":"この椅子は座りやすい。","romaji":"Kono isu wa suwariyasui.","en":"This chair is easy to sit in."},{"ja":"このペンはとても書きやすいです。","romaji":"Kono pen wa totemo kakiyasui desu.","en":"This pen is very easy to write with."},{"ja":"この道は広くて歩きやすい。","romaji":"Kono michi wa hirokute arukiyasui.","en":"This road is wide and easy to walk on."}]','["n4-nikui","n4-zurai"]','["verb suffix","adjective"]',101);
INSERT INTO grammar_points VALUES(102,'n4-nikui','にくい','nikui','Difficult to do; hard to do','Verb (ます-stem) + にくい',unistr('The grammar pattern `～にくい` (nikui) attaches to the ます-stem of a verb to indicate that an action is difficult to perform. It functions grammatically like an い-adjective, meaning it can directly modify nouns or be conjugated for tense and politeness.\u000a\u000aThis pattern expresses an objective difficulty, often due to external factors or the inherent nature of the object or situation. For example, if a book is `読みにくい` (yominikui), it might be because the font is too small, or the content is complex, making it objectively hard to read.\u000a\u000a`～にくい` is the opposite of `～易い` (yasui). While `～づらい` (zurai) also expresses difficulty, `～にくい` tends to focus on the physical or objective challenges, whereas `～づらい` often implies a more personal, emotional, or psychological discomfort.'),'N4',1,'Ways of Doing and Being','[{"ja":"この質問には答えにくいです。","romaji":"Kono shitsumon niwa kotaenikui desu.","en":"This question is difficult to answer."},{"ja":"この本は字が小さくて読みにくいです。","romaji":"Kono hon wa ji ga chiisakute yominikui desu.","en":"This book''s print is too small, it''s difficult to read."},{"ja":"この漢字は覚えにくいです。","romaji":"Kono kanji wa oboenikui desu.","en":"This kanji is difficult to remember."},{"ja":"この自転車は古くて乗りにくいです。","romaji":"Kono jitensha wa furukute norinikui desu.","en":"This bicycle is old and difficult to ride."}]','["n4-yasui","n4-zurai"]','["verb suffix","adjective"]',102);
INSERT INTO grammar_points VALUES(103,'n4-zurai','づらい','zurai','Difficult/painful to do (often due to psychological or physical discomfort)','Verb (ます-stem) + づらい',unistr('The grammar pattern `～づらい` (zurai) attaches to the ます-stem of a verb to indicate that an action is difficult or painful to perform. It functions grammatically like an い-adjective. While similar to `～にくい`, `～づらい` often carries a nuance of emotional, psychological, or physical discomfort, making the action personally challenging or unpleasant.\u000a\u000aThis pattern is typically used when the speaker feels reluctant, uncomfortable, or finds it hard to do something due to internal feelings or a sense of burden. For example, `話しづらい` (hanashizurai) might mean it''s hard to talk about a sensitive topic, not necessarily that the act of speaking itself is physically difficult.\u000a\u000aIn contrast, `～にくい` (nikui) often describes objective difficulty (e.g., a door is `開けにくい` because it''s stuck), whereas `～づらい` emphasizes a subjective or internal struggle (e.g., it''s `開けづらい` because you''re nervous about what''s behind it).'),'N4',1,'Ways of Doing and Being','[{"ja":"この質問には答えづらいです。","romaji":"Kono shitsumon niwa kotaezurai desu.","en":"This question is difficult to answer (due to discomfort/reluctance)."},{"ja":"この本は字が小さくて読みづらいです。","romaji":"Kono hon wa ji ga chiisakute yomizurai desu.","en":"This book''s print is too small, it''s difficult to read (causing eye strain/discomfort)."},{"ja":"彼女はつき合いづらい人だ。","romaji":"Kanojo wa tsukiaizurai hito da.","en":"She''s a difficult person to get along with (due to her personality)."},{"ja":"彼の説明がむずかしくて分かりづらいだった。","romaji":"Kare no setsumei ga muzukashikute wakarizurai datta.","en":"His explanation was complicated and difficult to understand (causing mental strain)."}]','["n4-yasui","n4-nikui"]','["verb suffix","adjective"]',103);
INSERT INTO grammar_points VALUES(104,'n4-dandan','段々（だんだん）','dandan','Gradually; little by little; step by step','だんだん + Verb / Adjective',unistr('`だんだん` (dandan) is an adverb used to describe a gradual change or progression over time. It implies a steady, step-by-step increase or decrease in a state or action, suggesting a slow but continuous development.\u000a\u000aIt is often used with verbs that indicate change, such as `なる` (to become), or with adjectives to show a state that is slowly transforming. The change described by `だんだん` is typically smooth and observable over a period.\u000a\u000a`だんだん` contrasts with `どんどん` (dondon), which implies a more rapid or sudden change. While `だんだん` focuses on the slow, incremental nature of change, `どんどん` emphasizes speed and intensity.'),'N4',1,'Ways of Doing and Being','[{"ja":"段々日本語が上手になりました。","romaji":"Dandan nihongo ga jouzu ni narimashita.","en":"I gradually got better at Japanese."},{"ja":"朝から段々暖かくなってきましたね。","romaji":"Asa kara dandan atatakaku natte kimashita ne.","en":"It''s gradually gotten warmer since morning, hasn''t it?"},{"ja":"子供は段々大きくなります。","romaji":"Kodomo wa dandan ookiku narimasu.","en":"Children gradually grow bigger."},{"ja":"仕事を覚えるのは段々楽しくなってきた。","romaji":"Shigoto o oboeru no wa dandan tanoshiku natte kita.","en":"Learning the job gradually became more enjoyable."}]','["n4-dondon"]','["adverb"]',104);
INSERT INTO grammar_points VALUES(105,'n4-dondon','どんどん','dondon','Rapidly; progressively; quickly; without hesitation','どんどん + Verb / Adjective',unistr('`どんどん` (dondon) is an adverb that indicates rapid, continuous, or unhesitating action or change. It suggests a quick progression, an increase in speed or intensity, or an encouragement to proceed without reservation.\u000a\u000aThis adverb is used when something is happening quickly, without interruption, or at an accelerating pace. It can also be used to urge someone to do something promptly or without holding back, implying a sense of urgency or encouragement.\u000a\u000a`どんどん` differs from `だんだん` (dandan) in its emphasis on speed. While `だんだん` describes a slow, gradual change, `どんどん` highlights a fast, energetic, or progressive change.'),'N4',1,'Ways of Doing and Being','[{"ja":"どんどん寒くなってきた。","romaji":"Dondon samuku natte kita.","en":"It''s getting colder and colder (rapidly)."},{"ja":"質問があったら、どんどん聞いてください。","romaji":"Shitsumon ga attara, dondon kiite kudasai.","en":"If you have any questions, please ask away (without hesitation)."},{"ja":"彼はどんどん日本語が上達している。","romaji":"Kare wa dondon nihongo ga joutatsu shite iru.","en":"His Japanese is improving rapidly."},{"ja":"雨がどんどん強くなってきた。","romaji":"Ame ga dondon tsuyoku natte kita.","en":"The rain has been getting stronger and stronger (rapidly)."}]','["n4-dandan"]','["adverb"]',105);
INSERT INTO grammar_points VALUES(106,'n4-ra','等（ら）','ra','Plural suffix for people/pronouns.','Noun (person/pronoun) + ら',unistr('「～ら」 is a suffix used to create the plural form of certain nouns, especially pronouns and names of people. It indicates "and others" or "they/them" when attached to a person''s name or a pronoun.\u000a\u000aCommonly seen with pronouns like 「彼 (かれ)」 (he) → 「彼ら (かれら)」 (they/them) and 「彼女 (かのじょ)」 (she) → 「彼女ら (かのじょら)」 (they/them). It can also be attached to names, e.g., 「田中さん (たなかさん)」 → 「田中さんら (たなかさんら)」 (Mr. Tanaka and others), or general nouns referring to people like 「子供 (こども)」 → 「子供ら (こどもら)」 (children).\u000a\u000aWhile 「～たち」 is a more general and polite pluralizer for people, 「～ら」 can sometimes carry a slightly more casual or even slightly derogatory nuance depending on context, especially when used with names. However, with pronouns like 「彼ら」 and 「彼女ら」, it is standard. For 「私ら」, 「私たち」 is generally preferred in formal or polite contexts.'),'N4',1,'Ways of Doing and Being','[{"ja":"彼らは昨日、映画を見に行きました。","romaji":"karera wa kinou, eiga o mi ni ikimashita.","en":"They went to see a movie yesterday."},{"ja":"彼女らはいつも一緒に勉強しています。","romaji":"kanojo-ra wa itsumo issho ni benkyou shiteimasu.","en":"They (females) are always studying together."},{"ja":"先生と生徒らで話し合いました。","romaji":"sensei to seito-ra de hanashiaimashita.","en":"The teacher and the students discussed it."},{"ja":"子供らが公園で遊んでいます。","romaji":"kodomo-ra ga kouen de asondeimasu.","en":"The children are playing in the park."}]','["n5-tachi"]','["suffix","plural"]',106);
INSERT INTO grammar_points VALUES(107,'n4-teiku','～ていく','teiku','To go on; to continue; to start moving away; to change over time.','Verb て-form + いく',unistr('「～ていく」 is a compound verb formed by combining the て-form of a verb with 「いく」 (to go). It expresses movement away from the speaker, a change that progresses into the future, or the continuation of an action.\u000a\u000aThere are generally three main nuances:\u000a1.  **Movement away**: The action is performed, and the subject moves away from the speaker. For example, 「歩いていく」 (to walk away).\u000a2.  **Change over time**: The action or state changes gradually into the future. For example, 「暖かくなっていく」 (to get warmer and warmer).\u000a3.  **Continuation into the future**: An action starts now and continues into the future. For example, 「これからも頑張っていく」 (I will continue to do my best from now on).\u000a\u000aThis grammar point emphasizes the direction of the action or change *away* from the current point in time or location. It contrasts with 「～てくる」, which implies movement *towards* the speaker or a change that has been happening up to the present.'),'N4',1,'Ways of Doing and Being','[{"ja":"これから日本語を勉強していきます。","romaji":"kore kara nihongo o benkyou shite ikimasu.","en":"I will continue to study Japanese from now on."},{"ja":"彼は駅まで歩いていきました。","romaji":"kare wa eki made aruite ikimashita.","en":"He walked to the station (and went away)."},{"ja":"船は港を出ていきました。","romaji":"fune wa minato o dete ikimashita.","en":"The ship left the harbor (and went away)."},{"ja":"日本の経済はこれからどうなっていくでしょうか。","romaji":"nihon no keizai wa kore kara dou natte iku deshou ka.","en":"What will happen to Japan''s economy from now on?"}]','["n4-tekuru"]','["compound verb","direction","change"]',107);
INSERT INTO grammar_points VALUES(108,'n4-tekuru','～てくる','tekuru','To come to; to become; to continue up to now; to start (towards speaker).','Verb て-form + くる',unistr('「～てくる」 is a compound verb formed by combining the て-form of a verb with 「くる」 (to come). It expresses movement towards the speaker, a change that has been progressing up to the present, or an action that started in the past and continues to the present.\u000a\u000aThere are generally three main nuances:\u000a1.  **Movement towards**: The action is performed, and the subject moves towards the speaker or a reference point. For example, 「走ってくる」 (to come running).\u000a2.  **Change up to now**: A change that started in the past and has continued or developed up to the present. For example, 「寒くなってきた」 (it has become cold / it''s getting cold).\u000a3.  **Action from past to present**: An action that started in the past and continues or has just finished in the present. For example, 「日本語を勉強してきた」 (I have been studying Japanese).\u000a\u000aThis grammar point emphasizes the direction of the action or change *towards* the current point in time or location. It contrasts with 「～ていく」, which implies movement *away* from the speaker or a change that progresses into the future.'),'N4',1,'Ways of Doing and Being','[{"ja":"雨が降ってきた。","romaji":"ame ga futte kita.","en":"It started raining (and has come to this point)."},{"ja":"友達が家まで歩いてきた。","romaji":"tomodachi ga ie made aruite kita.","en":"My friend walked to my house (and arrived)."},{"ja":"日本に住んでから、日本語が話せるようになってきた。","romaji":"nihon ni sunde kara, nihongo ga hanaseru you ni natte kita.","en":"Since living in Japan, I''ve become able to speak Japanese (gradually)."},{"ja":"お腹がすいてきた。","romaji":"onaka ga suite kita.","en":"I''m starting to get hungry."}]','["n4-teiku"]','["compound verb","direction","change"]',108);
INSERT INTO grammar_points VALUES(109,'n4-kata','方（かた）','kata','Way of doing; how to do; method.','Verb ます-stem + 方（かた）',unistr('「～方 (かた)」 is a suffix attached to the ます-stem of a verb to express "the way of doing something," "how to do something," or "a method." It transforms a verb into a noun, allowing you to talk about the technique or manner of an action.\u000a\u000aFor example, from 「書きます (かきます)」 (to write), you get 「書き方 (かきかた)」 (how to write/way of writing). From 「食べます (たべます)」 (to eat), you get 「食べ方 (たべかた)」 (how to eat/way of eating).\u000a\u000aThis pattern is very useful for asking for instructions, explaining procedures, or describing someone''s style or method. It is a common and essential N4 grammar point for expressing practical knowledge.'),'N4',1,'Ways of Doing and Being','[{"ja":"この漢字の書き方を教えてください。","romaji":"kono kanji no kakikata o oshiete kudasai.","en":"Please teach me how to write this kanji."},{"ja":"この機械の使い方が分かりません。","romaji":"kono kikai no tsukaikata ga wakarimasen.","en":"I don''t know how to use this machine."},{"ja":"彼の話し方はとても丁寧です。","romaji":"kare no hanashikata wa totemo teinei desu.","en":"His way of speaking is very polite."},{"ja":"料理の作り方を習いたいです。","romaji":"ryouri no tsukurikata o naritai desu.","en":"I want to learn how to cook."}]','[]','["suffix","noun formation"]',109);
INSERT INTO grammar_points VALUES(110,'n4-dake-de','だけで','dake de','Just by; only by; with only.',unistr('Verb (Casual) + だけで\u000aNoun + だけで\u000aい-Adjective + だけで\u000aな-Adjective + な + だけで'),unistr('「～だけで」 combines 「だけ」 (only/just) with the particle 「で」 (by means of/at/in). It means "just by (doing/being something)," "only with (something)," or "merely by." It emphasizes that a minimal action or condition is sufficient to cause a certain result or feeling.\u000a\u000aThis pattern can attach to various word types. For verbs, use the casual form (dictionary form, た-form, ない-form). For nouns and い-adjectives, 「だけ」 attaches directly. For な-adjectives, 「な」 is inserted before 「だけで」.\u000a\u000aIt often highlights a surprising or significant outcome from a seemingly small cause. It can express both positive and negative feelings, such as happiness from a simple act or frustration from a mere thought.'),'N4',1,'Ways of Doing and Being','[{"ja":"あなたに会うだけで元気になる。","romaji":"anata ni au dake de genki ni naru.","en":"I feel energized just by meeting you."},{"ja":"その写真を見るだけで、昔を思い出す。","romaji":"sono shashin o miru dake de, mukashi o omoidasu.","en":"Just by looking at that photo, I remember the old days."},{"ja":"宿題のことを考えるだけでやる気がなくなります。","romaji":"shukudai no koto o kangaeru dake de yaruki ga naku narimasu.","en":"Just by thinking about homework, I lose motivation."},{"ja":"彼女は優しいだけで、とても人気がある。","romaji":"kanojo wa yasashii dake de, totemo ninki ga aru.","en":"She is very popular just because she is kind."}]','["n5-dake"]','["particle","emphasis","condition"]',110);
INSERT INTO grammar_points VALUES(111,'n4-daga','だが','daga','But; however; nevertheless','Sentence 1 (Casual/Plain form) + だが + Sentence 2',unistr('だが is a conjunction used to connect two contrasting clauses or sentences. It expresses a sense of ''but,'' ''however,'' or ''nevertheless.'' It is often used to introduce a statement that contradicts or presents an opposing view to the preceding statement.\u000a\u000aWhile similar to しかし (shikashi) and でも (demo), だが tends to be slightly more formal or literary, and can sometimes carry a stronger sense of contrast or objection. It is commonly found in written Japanese or in more formal spoken contexts.'),'N4',1,'Ways of Doing and Being','[{"ja":"行きたかった。だが、時間がなかった。","romaji":"Ikitakatta. Daga, jikan ga nakatta.","en":"I wanted to go. However, I didn''t have time."},{"ja":"彼は頭がいい。だが、少しわがままだ。","romaji":"Kare wa atama ga ii. Daga, sukoshi wagamama da.","en":"He is smart. But, he is a little selfish."},{"ja":"雨が降っていた。だが、傘を持たずに出かけた。","romaji":"Ame ga futte ita. Daga, kasa wo motazu ni dekaketa.","en":"It was raining. Nevertheless, I went out without an umbrella."},{"ja":"この本は難しい。だが、とても面白い。","romaji":"Kono hon wa muzukashii. Daga, totemo omoshiroi.","en":"This book is difficult. But it''s very interesting."}]','["n5-demo","n4-shikashi"]','["conjunction"]',111);
INSERT INTO grammar_points VALUES(112,'n4-nakute','なくて (Sequence)','nakute (sequence)','Not ~ and; not being ~ and',unistr('い-adjective (stem) + くなくて\u000aな-adjective (stem) + じゃなくて\u000aNoun + じゃなくて\u000aVerb (ない形) + なくて'),unistr('The `なくて` form is used to connect two clauses where the first clause describes a negative state or action. In this ''sequence'' usage, it simply lists negative conditions or describes a situation where the absence of something leads to another state or action.\u000a\u000aIt functions similarly to the `て-form` for connecting clauses, but specifically for negative forms. It can indicate a simple continuation of events or conditions, or a contrast, rather than a strong cause-and-effect relationship (which is often covered by `なくて` for reasons/causes).'),'N4',1,'Ways of Doing and Being','[{"ja":"この部屋は広くなくて、少し狭いです。","romaji":"Kono heya wa hirokunakute, sukoshi semai desu.","en":"This room is not spacious, and it''s a little cramped."},{"ja":"彼は歌が上手じゃなくて、踊りも苦手です。","romaji":"Kare wa uta ga jouzu janakute, odori mo nigate desu.","en":"He is not good at singing, and he''s also bad at dancing."},{"ja":"今日は雨が降らなくて、洗濯物が乾いた。","romaji":"Kyou wa ame ga furanakute, sentakumono ga kawaita.","en":"It didn''t rain today, and the laundry dried."},{"ja":"私はコーヒーが好きじゃなくて、いつも紅茶を飲みます。","romaji":"Watashi wa koohii ga suki janakute, itsumo koucha wo nomimasu.","en":"I don''t like coffee, and I always drink tea."}]','["n4-nakute-113","n5-te"]','["conjunction","adjective","verb"]',112);
INSERT INTO grammar_points VALUES(113,'n4-nakute-113','なくて (Reasons and Causes)','nakute (reasons and causes)','Because not ~; not ~ so ~',unistr('い-adjective (stem) + くなくて\u000aな-adjective (stem) + じゃなくて\u000aNoun + じゃなくて\u000aVerb (ない形) + なくて'),unistr('The `なくて` form is used to connect two clauses, where the first clause expresses a negative reason or cause for the situation described in the second clause. It indicates that ''because something is not the case'' or ''because something was not done,'' a particular outcome or state occurred.\u000a\u000aThis usage is very common for explaining why an action couldn''t be performed, why a certain state exists, or why a negative consequence happened. It''s a versatile way to express negative causality in Japanese.'),'N4',1,'Ways of Doing and Being','[{"ja":"天気が良くなくて、出かけなかった。","romaji":"Tenki ga yokunakute, dekakenakatta.","en":"The weather was not good, so I didn''t go out."},{"ja":"時間がなくて、映画を見られなかった。","romaji":"Jikan ga nakute, eiga wo mirarenakatta.","en":"Because I didn''t have time, I couldn''t watch the movie."},{"ja":"体が丈夫じゃなくて、よく病気になります。","romaji":"Karada ga joubu janakute, yoku byouki ni narimasu.","en":"Because my body isn''t strong, I often get sick."},{"ja":"この本は面白くなくて、最後まで読めなかった。","romaji":"Kono hon wa omoshirokunakute, saigo made yomenakatta.","en":"Because this book wasn''t interesting, I couldn''t read it to the end."}]','["n4-nakute","n5-kara"]','["conjunction","adjective","verb"]',113);
INSERT INTO grammar_points VALUES(114,'n4-naide','ないで','naide','Without doing ~; not doing ~ and ~','Verb (ない-form) + で',unistr('The `ないで` form has two primary uses. First, it indicates that an action is performed *without* doing another action. This means the first action (in `ないで` form) is omitted while the second action takes place.\u000a\u000aSecond, it can mean ''not doing something, and instead doing something else'' or ''not doing something, and as a result, something else happens.'' It connects two clauses, with the first clause describing a negative action or state, and the second describing a subsequent action or consequence. It''s important to distinguish `ないで` from `なくて`; `ないで` focuses on the *omission* of an action, while `なくて` often implies a *reason* or *cause* for a negative outcome.'),'N4',1,'Ways of Doing and Being','[{"ja":"朝ごはんを食べないで学校に行った。","romaji":"Asagohan wo tabenaide gakkou ni itta.","en":"I went to school without eating breakfast."},{"ja":"傘を持たないで出かけた。","romaji":"Kasa wo motanaide dekaketa.","en":"I went out without bringing an umbrella."},{"ja":"電気を消さないで寝てしまった。","romaji":"Denki wo kesanaide nete shimatta.","en":"I fell asleep without turning off the light."},{"ja":"今日はどこへも行かないで、家でゆっくりする。","romaji":"Kyou wa doko e mo ikanaide, ie de yukkuri suru.","en":"Today, I won''t go anywhere and will relax at home."}]','["n4-nakute","n4-nakute-113"]','["verb","conjunction"]',114);
INSERT INTO grammar_points VALUES(115,'n4-reru-rareru','れる・られる (Passive)','reru rareru (passive)','To be ~; to be done ~; passive voice',unistr('Group 1 Verbs: Verb (ない-form stem) + れる\u000aGroup 2 Verbs: Verb (stem) + られる\u000aGroup 3 Verbs: する → される, 来る → 来られる'),unistr('The passive voice in Japanese is formed using `れる` or `られる` depending on the verb group. It indicates that the subject of the sentence is receiving an action, rather than performing it. The agent performing the action is often marked with the particle `に`.\u000a\u000aThis grammar point is used in several situations: to describe an action done *to* the subject, often implying an unwanted or unexpected event (the ''suffering passive''); to state a fact or general truth about something; or when the agent of the action is unknown or unimportant. It''s a fundamental structure for expressing actions from the perspective of the recipient.'),'N4',1,'Ways of Doing and Being','[{"ja":"電車で足を踏まれた。","romaji":"Densha de ashi wo fumareta.","en":"My foot was stepped on in the train."},{"ja":"先生に褒められた。","romaji":"Sensei ni homerareta.","en":"I was praised by the teacher."},{"ja":"この本は多くの人に読まれています。","romaji":"Kono hon wa ooku no hito ni yomarete imasu.","en":"This book is read by many people."},{"ja":"私のケーキが弟に食べられた。","romaji":"Watashi no keeki ga otouto ni taberareta.","en":"My cake was eaten by my younger brother."}]','[]','["verb","passive voice"]',115);
INSERT INTO grammar_points VALUES(116,'n4-他動詞自動詞','他動詞（たどうし）・自動詞（じどうし）','tadoushi jidoushi','Transitive and Intransitive Verbs','This is a grammatical concept, not a specific structure.',unistr('In Japanese, verbs are categorized into two main types: **他動詞 (tadoushi)**, which are transitive verbs, and **自動詞 (jidoushi)**, which are intransitive verbs. Understanding this distinction is crucial for correct particle usage and natural expression.\u000a\u000a**他動詞 (Transitive Verbs)** require a direct object, which is typically marked by the particle **を (o)**. The action of a transitive verb is performed *by* someone *on* something. For example, 「ドアを開ける」(doa o akeru - to open the door) uses the transitive verb 開ける (akeru) because someone is performing the action of opening on the door.\u000a\u000a**自動詞 (Intransitive Verbs)** do not take a direct object. The action or state described by an intransitive verb occurs *on its own* or *to the subject*. The subject of an intransitive verb is typically marked by the particle **が (ga)**. For example, 「ドアが開く」(doa ga aku - the door opens) uses the intransitive verb 開く (aku) because the door itself is undergoing the action of opening. Many verbs have both a transitive and an intransitive counterpart, often with similar meanings but different particle usage and nuance.'),'N4',1,'Ways of Doing and Being','[{"ja":"窓が開いた。（自動詞）","romaji":"Mado ga aita.","en":"The window opened. (intransitive)"},{"ja":"私が窓を開けた。（他動詞）","romaji":"Watashi ga mado o aketa.","en":"I opened the window. (transitive)"},{"ja":"電気が消えた。（自動詞）","romaji":"Denki ga kieta.","en":"The light went out. (intransitive)"},{"ja":"私が電気を消した。（他動詞）","romaji":"Watashi ga denki o keshita.","en":"I turned off the light. (transitive)"}]','[]','["verb type","grammar concept"]',116);
INSERT INTO grammar_points VALUES(117,'n4-直す','直（なお）す','naosu','To fix; to repair; to correct; to do over',unistr('Verb (ます-stem) + 直す\u000aVerb (dictionary form) + 直す (as a standalone verb)'),unistr('The verb **直す (naosu)** has two primary uses. Firstly, it can be used as a standalone verb meaning "to fix," "to repair," or "to correct" something. In this usage, it is a transitive verb, taking an object marked by the particle **を (o)**.\u000a\u000aSecondly, and more commonly at the N4 level, **直す (naosu)** can be attached to the ます-stem of another verb to form a compound verb. When used as a suffix, **〜直す (naosu)** means "to do (something) over again" or "to redo." It implies that an action was done once, but needs to be repeated or corrected from the beginning. This usage emphasizes the repetition or correction of an action.'),'N4',1,'Ways of Doing and Being','[{"ja":"この時計を直してください。","romaji":"Kono tokei o naoshite kudasai.","en":"Please fix this watch."},{"ja":"間違ったので、もう一度書き直します。","romaji":"Machigatta node, mou ichido kakinaoshimasu.","en":"I made a mistake, so I will rewrite it again."},{"ja":"このレポートを読み直す必要があります。","romaji":"Kono repooto o yominaosu hitsuyou ga arimasu.","en":"I need to reread this report."},{"ja":"壊れた椅子を直すのは難しいです。","romaji":"Kowareta isu o naosu no wa muzukashii desu.","en":"It''s difficult to repair a broken chair."}]','[]','["verb","suffix"]',117);
INSERT INTO grammar_points VALUES(118,'n4-と言う事','と言（い）う事（こと）','to iu koto','The fact that; meaning that; to say that',unistr('Verb (Casual) + ということ\u000aい-Adjective + ということ\u000aな-Adjective + だ + ということ\u000aNoun + だ + ということ'),unistr('**〜ということ (to iu koto)** is a versatile phrase used to nominalize a preceding clause, turning it into a noun phrase. It often functions to explain, define, or refer to a concept, statement, or fact. It can be translated as "the fact that...", "meaning that...", or "it means that...".\u000a\u000aThis pattern is frequently used when you are explaining the meaning of something, summarizing a statement, or referring to a general idea. It allows you to talk about actions, states, or entire sentences as if they were single nouns. The casual form of verbs and adjectives is used before **ということ**, and for な-adjectives and nouns, **だ** is added before **ということ**.'),'N4',1,'Ways of Doing and Being','[{"ja":"「ありがとう」というのは「感謝」という意味です。","romaji":"“Arigatou” to iu no wa “kansha” to iu imi desu.","en":"“Arigatou” means “gratitude.”"},{"ja":"彼が来ないということは、会議は中止だということだ。","romaji":"Kare ga konai to iu koto wa, kaigi wa chuushi da to iu koto da.","en":"The fact that he''s not coming means the meeting is canceled."},{"ja":"健康であるということは、とても幸せなことです。","romaji":"Kenkou de aru to iu koto wa, totemo shiawase na koto desu.","en":"Being healthy is a very happy thing."},{"ja":"日本語を勉強するということは、毎日努力することです。","romaji":"Nihongo o benkyou suru to iu koto wa, mainichi doryoku suru koto desu.","en":"Studying Japanese means making an effort every day."}]','["n5-koto"]','["nominalizer","phrase"]',118);
INSERT INTO grammar_points VALUES(119,'n4-時','時（とき）','toki','When; at the time of',unistr('Verb (Casual) + 時\u000aい-Adjective + 時\u000aな-Adjective + な + 時\u000aNoun + の + 時'),unistr('**時 (toki)** is a noun meaning "time" or "moment." When used as a grammatical connector, it links two clauses, indicating the time or situation in which the action or state of the second clause occurs. It can be translated as "when," "at the time of," or "during."\u000a\u000aThe conjugation before **時** depends on the part of speech. For verbs, use the casual form (present or past). For い-adjectives, use the plain form. For な-adjectives, add **な** before **時**. For nouns, add **の** before **時**. This pattern is essential for expressing temporal relationships between events.'),'N4',2,'Linking and Temporal','[{"ja":"暇な時、本を読みます。","romaji":"Hima na toki, hon o yomimasu.","en":"When I have free time, I read books."},{"ja":"日本に行った時、お寺を見ました。","romaji":"Nihon ni itta toki, otera o mimashita.","en":"When I went to Japan, I saw temples."},{"ja":"寒い時、温かいコーヒーを飲みます。","romaji":"Samui toki, atatakai koohii o nomimasu.","en":"When it''s cold, I drink hot coffee."},{"ja":"子供の時、よく公園で遊びました。","romaji":"Kodomo no toki, yoku kouen de asobimashita.","en":"When I was a child, I often played in the park."}]','["n4-たら","n4-と","n4-ば"]','["conjunction","temporal"]',119);
INSERT INTO grammar_points VALUES(120,'n4-まず','まず','mazu','First; to begin with; before anything else','まず + Sentence',unistr('**まず (mazu)** is an adverb that means "first," "to begin with," or "before anything else." It is used to indicate the initial step in a sequence of actions or to highlight the most important or immediate thing that needs to be done.\u000a\u000aThis adverb is commonly used when giving instructions, explaining a process, or prioritizing tasks. It sets the stage for subsequent actions or information. While often translated simply as "first," it carries a nuance of initiating something or addressing the primary concern before moving on.'),'N4',2,'Linking and Temporal','[{"ja":"まず、手を洗ってください。","romaji":"Mazu, te o aratte kudasai.","en":"First, please wash your hands."},{"ja":"料理をする前に、まず材料を準備します。","romaji":"Ryouri o suru mae ni, mazu zairyou o junbi shimasu.","en":"Before cooking, first I prepare the ingredients."},{"ja":"新しい仕事では、まず会社のルールを覚えることが大切です。","romaji":"Atarashii shigoto de wa, mazu kaisha no ruuru o oboeru koto ga taisetsu desu.","en":"In a new job, it''s important to first learn the company rules."},{"ja":"まず、今日の予定を確認しましょう。","romaji":"Mazu, kyou no yotei o kakunin shimashou.","en":"First, let''s confirm today''s schedule."}]','["n4-次に","n4-それから"]','["adverb","sequence"]',120);
INSERT INTO grammar_points VALUES(121,'n4-まで','まで','made','even; to the extent of; as far as','Noun + まで',unistr('The particle `まで` can be used to emphasize an extreme or unexpected extent, often translating to "even" or "as far as." It highlights that something applies to a surprising degree or includes an unexpected item.\u000a\u000aThis usage is distinct from the N5 `まで` which means "until" and indicates a duration or endpoint in time or space. When used with nouns, it often implies that the noun represents an extreme case or an unexpected inclusion.\u000a\u000aFor example, saying 「子供まで知っている」 (kodomo made shitte iru) implies that *even* children know it, suggesting it''s common knowledge, which is a surprising extent.'),'N4',2,'Linking and Temporal','[{"ja":"子供まで知っている。","romaji":"Kodomo made shitte iru.","en":"Even children know it."},{"ja":"彼は忙しくて、食事をする時間までなかった。","romaji":"Kare wa isogashikute, shokuji o suru jikan made nakatta.","en":"He was so busy, he didn''t even have time to eat."},{"ja":"先生まで間違えた。","romaji":"Sensei made machigaeta.","en":"Even the teacher made a mistake."},{"ja":"疲れて、立つことまでできなかった。","romaji":"Tsukarete, tatsu koto made dekinakatta.","en":"I was so tired, I couldn''t even stand up."}]','["n5-made"]','["particle","emphasis"]',121);
INSERT INTO grammar_points VALUES(122,'n4-までに','までに','made ni','by; by the time; indicates a deadline',unistr('Noun + までに\u000aVerb (Casual/Dictionary form) + までに'),unistr('The particle combination `までに` specifies a deadline or a time limit by which an action must be completed. It indicates that an action needs to be finished *before* or *at* a certain point in time.\u000a\u000aThis is different from `まで` (N5), which indicates a continuous action *until* a certain point. With `までに`, the action itself is completed at some point before the deadline, not necessarily continuing up to it.\u000a\u000aFor instance, 「8時までに来てください」 (hachi-ji made ni kite kudasai) means you should arrive *by* 8 o''clock, implying you could arrive at 7:30 or 7:59, but not after 8:00.'),'N4',2,'Linking and Temporal','[{"ja":"8時までに来てください。","romaji":"Hachi-ji made ni kite kudasai.","en":"Please come by 8 o''clock."},{"ja":"この本、来週までに返してくださいね。","romaji":"Kono hon, raishuu made ni kaeshite kudasai ne.","en":"Please return this book by next week."},{"ja":"レポートは金曜日までに出してください。","romaji":"Repooto wa kinyoubi made ni dashite kudasai.","en":"Please submit the report by Friday."},{"ja":"いつまでに必要ですか。","romaji":"Itsu made ni hitsuyou desu ka?","en":"When do you need this by?"}]','["n5-made"]','["particle","time expression"]',122);
INSERT INTO grammar_points VALUES(123,'n4-また','また','mata','again; also; in addition; furthermore',unistr('また + Verb/Adjective/Noun phrase\u000aSentence A. また、Sentence B.'),unistr('`また` is a versatile word with several meanings, primarily functioning as an adverb or a conjunction. Its most common meaning is "again," indicating a repetition of an action or event.\u000a\u000aIt can also mean "also" or "in addition," used to add more information or connect two related statements. In this sense, it acts similarly to `そして` (soshite) or `それに` (sore ni), but often with a slightly more casual or conversational tone.\u000a\u000aBe careful not to confuse `また` with `または` (matawa), which means "or." While they share similar sounds, their meanings and usage are distinct.'),'N4',2,'Linking and Temporal','[{"ja":"また明日会いましょう。","romaji":"Mata ashita aimashou.","en":"Let''s meet again tomorrow."},{"ja":"彼は英語が話せる。また、フランス語も話せる。","romaji":"Kare wa eigo ga hanaseru. Mata, furansugo mo hanaseru.","en":"He can speak English. Also, he can speak French."},{"ja":"また来てください。","romaji":"Mata kite kudasai.","en":"Please come again."},{"ja":"今日は雨だ。また、風も強い。","romaji":"Kyou wa ame da. Mata, kaze mo tsuyoi.","en":"It''s raining today. Also, the wind is strong."}]','[]','["adverb","conjunction"]',123);
INSERT INTO grammar_points VALUES(124,'n4-始める','始（はじ）める','hajimeru','to start; to begin to do ~','Verb (ます-stem) + 始める',unistr('`始める` (hajimeru) is a compound verb construction used to indicate the beginning of an action. By attaching `始める` to the ます-stem of another verb, you create a new verb that means "to start doing [that verb''s action]."\u000a\u000aThis grammar point describes the initiation of an action or a state. It emphasizes the moment when an activity commences. For example, `食べ始める` (tabe hajimeru) means "to start eating," and `降り始める` (furi hajimeru) means "to start raining."\u000a\u000aLike regular verbs, `始める` can be conjugated into various tenses and forms (e.g., 始めます, 始めた, 始めない) to fit the context of the sentence.'),'N4',2,'Linking and Temporal','[{"ja":"食べ始める。","romaji":"Tabe hajimeru.","en":"To begin eating."},{"ja":"雨が降り始めた。","romaji":"Ame ga furi hajimeta.","en":"It started to rain."},{"ja":"いつそれをやり始めるの？","romaji":"Itsu sore o yari hajimeru no?","en":"When will you start doing that?"},{"ja":"今朝、歯が痛くなり始めた。","romaji":"Kesa, ha ga itaku nari hajimeta.","en":"My tooth started hurting this morning."}]','["n4-owaru"]','["compound verb","verb suffix"]',124);
INSERT INTO grammar_points VALUES(125,'n4-終わる','終（お）わる','owaru','to finish; to end doing ~','Verb (ます-stem) + 終わる',unistr('`終わる` (owaru) is a compound verb construction that signifies the completion or ending of an action. By attaching `終わる` to the ます-stem of another verb, you create a new verb meaning "to finish doing [that verb''s action]."\u000a\u000aThis grammar point focuses on the conclusion of an activity. For example, `食べ終わる` (tabe owaru) means "to finish eating," and `話し終わる` (hanashi owaru) means "to finish speaking."\u000a\u000aSimilar to `始める`, `終わる` can be conjugated into various tenses and forms (e.g., 終わります, 終わった, 終わらない) to express when the action was completed or will be completed.'),'N4',2,'Linking and Temporal','[{"ja":"みんなが朝食を食べ終わるまで待ちましょう。","romaji":"Minna ga choushoku o tabe owaru made machimashou.","en":"Let''s wait until everyone has finished eating breakfast."},{"ja":"そのゲームをやり終わるまでに5時間くらいかかる。","romaji":"Sono geemu o yari owaru made ni go-jikan kurai kakaru.","en":"It takes about 5 hours to finish that game."},{"ja":"彼が話し終わるとみんな黙っていた。","romaji":"Kare ga hanashi owaru to minna damatteita.","en":"There was silence when he finished speaking."},{"ja":"仕事をし終わったらすぐ行く。","romaji":"Shigoto o shi owattara sugu iku.","en":"I''ll go/come as soon as I finish work."}]','["n4-hajimeru"]','["compound verb","verb suffix"]',125);
INSERT INTO grammar_points VALUES(126,'n4-頃','頃（ころ）','koro','around; about (time/age); when',unistr('時間 + 頃（ごろ）\u000a名詞 + の + 頃（ころ）\u000a動詞 (辞書形/た形) + 頃（ころ）'),unistr('「頃（ころ）」 is used to express an approximate time, age, or period. When used with specific time expressions (like hours or days), it is usually pronounced 「ごろ」. For example, 「8時ごろ」 (hachiji goro - around 8 o''clock).\u000a\u000aWhen used with nouns referring to a period or age, it is typically pronounced 「ころ」. For instance, 「子供のころ」 (kodomo no koro - when I was a child) or 「この頃」 (kono koro - these days). It can also follow a verb in its dictionary form or past tense (た形) to mean "when" that action or state occurred.\u000a\u000aThis grammar point indicates a general timeframe rather than a precise moment. It''s useful for describing events that happened or will happen approximately at a certain point.'),'N4',2,'Linking and Temporal','[{"ja":"夜の8時ごろ、うちに来てもらえますか？","romaji":"yoru no hachiji goro, uchi ni kite moraemasu ka?","en":"Could you come to my place around 8 p.m.?"},{"ja":"私は若いころ、よく旅行しました。","romaji":"watashi wa wakai koro, yoku ryokou shimashita.","en":"When I was young, I traveled a lot."},{"ja":"この頃、仕事がとても忙しいです。","romaji":"kono koro, shigoto ga totemo isogashii desu.","en":"These days, my work is very busy."},{"ja":"日本へ来た頃は、日本語が全然話せませんでした。","romaji":"nihon e kita koro wa, nihongo ga zenzen hanasemasen deshita.","en":"When I first came to Japan, I couldn''t speak Japanese at all."}]','["n5-ni-time"]','["noun","temporal"]',126);
INSERT INTO grammar_points VALUES(127,'n4-後で','後（あと）で','ato de','after; later',unistr('動詞 (た形) + 後（あと）で\u000a名詞 + の + 後（あと）で'),unistr('「後で（あとで）」 is used to indicate that an action or event takes place after another action or event has been completed. It clearly establishes a sequence of events.\u000a\u000aWhen connecting to a verb, the verb must be in its past tense (た形). For example, 「食べた後で」 (tabeta ato de - after eating). When connecting to a noun, the particle 「の」 is used, such as 「仕事の後で」 (shigoto no ato de - after work).\u000a\u000aThis pattern is similar to 「～てから」 (te kara), but 「後で」 often implies a slightly longer interval or a more distinct separation between the two actions. It''s a common way to express sequential actions in daily conversation.'),'N4',2,'Linking and Temporal','[{"ja":"図書館で宿題をした後で、家に帰ります。","romaji":"toshokan de shukudai o shita ato de, ie ni kaerimasu.","en":"After I finish my homework at the library, I will go home."},{"ja":"晩ご飯の後で、アイスクリームを食べました。","romaji":"bangohan no ato de, aisukuriimu o tabemashita.","en":"After dinner, I ate ice cream."},{"ja":"授業が終わった後で、部活動に行きます。","romaji":"jugyou ga owatta ato de, bukatsudou ni ikimasu.","en":"After classes finish, I will go to my club activities."},{"ja":"お酒を飲んだ後で、運転してはいけません。","romaji":"osake o nonda ato de, unten shite wa ikemasen.","en":"You must not drive after drinking alcohol."}]','["n5-te-kara"]','["temporal","conjunction"]',127);
INSERT INTO grammar_points VALUES(128,'n4-ていた','～ていた','te ita','was doing; had done; was in a state of','動詞 (て形) + いた',unistr('「～ていた」 is the past tense form of 「～ている」. It expresses an action or state that was ongoing or had occurred in the past. It has several key uses.\u000a\u000aFirstly, it indicates an action that was in progress at a specific point in the past, similar to the English past continuous tense ("was doing"). For example, 「昨日の3時にテレビを見ていた」 (Kinou no sanji ni terebi o mite ita - I was watching TV at 3 o''clock yesterday).\u000a\u000aSecondly, it can describe a state that resulted from a past action and continued to exist in the past, or a completed action whose result was still evident. For instance, 「窓が割れていた」 (mado ga warete ita - The window was broken). Lastly, it can refer to habitual or repeated actions that occurred regularly in the past, like 「子供のころ、毎日公園で遊んでいた」 (kodomo no koro, mainichi kouen de asonde ita - When I was a child, I used to play in the park every day).'),'N4',2,'Linking and Temporal','[{"ja":"昨日の夜、私は本を読んでいました。","romaji":"kinou no yoru, watashi wa hon o yonde imashita.","en":"Last night, I was reading a book."},{"ja":"彼が来た時、ドアは開いていました。","romaji":"kare ga kita toki, doa wa aite imashita.","en":"When he arrived, the door was open."},{"ja":"昔、この町には大きな川が流れていました。","romaji":"mukashi, kono machi ni wa ookina kawa ga nagarete imashita.","en":"A long time ago, a big river flowed through this town."},{"ja":"彼女は10年間、この会社で働いていました。","romaji":"kanojo wa juunenkan, kono kaisha de hataraite imashita.","en":"She had been working at this company for 10 years."}]','["n5-te-iru"]','["verb conjugation","aspect"]',128);
INSERT INTO grammar_points VALUES(129,'n4-に','に (Frequency)','ni (frequency)','per; every (frequency)','期間 + に + 回数',unistr('The particle 「に」 is used to express the frequency of an action or event within a specific period of time. It indicates "per" or "every" in this context.\u000a\u000aTo form this structure, you state the period (e.g., 一日 - ichinichi, a day; 一週間 - isshuukan, a week) followed by 「に」, and then the number of times the action occurs (e.g., 一回 - ikkai, once; 三回 - sankai, three times). For example, 「一日に三回」 (ichinichi ni sankai) means "three times a day."\u000a\u000aThis grammar point is essential for describing routines, habits, or how often something happens. It helps quantify the regularity of actions.'),'N4',2,'Linking and Temporal','[{"ja":"私は一週間に三回、ジムに行きます。","romaji":"watashi wa isshuukan ni sankai, jimu ni ikimasu.","en":"I go to the gym three times a week."},{"ja":"この薬は一日に二回飲んでください。","romaji":"kono kusuri wa ichinichi ni nikai nonde kudasai.","en":"Please take this medicine twice a day."},{"ja":"このバスは10分に一本しか来ません。","romaji":"kono basu wa juppun ni ippon shika kimasen.","en":"This bus only comes once every 10 minutes."},{"ja":"彼は一日に二時間、日本語を勉強しています。","romaji":"kare wa ichinichi ni niji kan, nihongo o benkyou shite imasu.","en":"He studies Japanese for two hours a day."}]','["n5-ni-time"]','["particle","frequency"]',129);
INSERT INTO grammar_points VALUES(130,'n4-到頭','到頭（とうとう）','toutou','finally; at last; in the end','到頭（とうとう） + 動詞',unistr('「到頭（とうとう）」 is an adverb that means "finally," "at last," or "in the end." It is used to describe an event or situation that happens after a long period of waiting, effort, or a series of developments.\u000a\u000aIt often carries a nuance of something that was expected or inevitable, and can express a sense of relief, satisfaction, or sometimes resignation. While it can be used for both positive and negative outcomes, it frequently implies a culmination after a process.\u000a\u000aOther similar adverbs include 「やっと」 (yatto) which emphasizes relief after difficulty, and 「ついに」 (tsuini) which often implies a long-awaited or decisive outcome. 「到頭」 is generally interchangeable with 「ついに」 in many contexts, but 「到頭」 can sometimes carry a slightly more dramatic or conclusive feel.'),'N4',2,'Linking and Temporal','[{"ja":"到頭、私の夢が叶いました。","romaji":"toutou, watashi no yume ga kanaimashita.","en":"Finally, my dream came true."},{"ja":"長い会議が到頭終わりました。","romaji":"nagai kaigi ga toutou owarimashita.","en":"The long meeting finally ended."},{"ja":"何回も失敗したが、到頭成功した。","romaji":"nankai mo shippai shita ga, toutou seikou shita.","en":"He failed many times, but finally succeeded."},{"ja":"古い車が到頭完全に壊れてしまった。","romaji":"furui kuruma ga toutou kanzen ni kowarete shimatta.","en":"The old car finally broke down completely."}]','["n4-yatto","n4-tsuini"]','["adverb"]',130);
INSERT INTO grammar_points VALUES(131,'n4-yori','より','yori','than; more than; rather than','Noun + より',unistr('より is a particle used to indicate a point of comparison, meaning "than" or "more than". It is placed after the noun that serves as the standard for comparison. The item being compared is usually introduced first, followed by the standard of comparison with より, and then an adjective or verb describing the difference.\u000aThis grammar point is fundamental for making comparisons in Japanese, such as comparing sizes, speeds, prices, or abilities. It can also be used to express "rather than" when choosing between two options, though its primary use is for direct comparison.'),'N4',2,'Linking and Temporal','[{"ja":"この本はあの本より面白いです。","romaji":"kono hon wa ano hon yori omoshiroi desu.","en":"This book is more interesting than that book."},{"ja":"私は兄より背が高いです。","romaji":"watashi wa ani yori se ga takai desu.","en":"I am taller than my older brother."},{"ja":"日本の夏はタイの夏より涼しいですか。","romaji":"nihon no natsu wa tai no natsu yori suzushii desu ka.","en":"Is summer in Japan cooler than summer in Thailand?"},{"ja":"彼女は私より日本語が上手です。","romaji":"kanojo wa watashi yori nihongo ga jouzu desu.","en":"She is better at Japanese than I am."}]','["n5-no-hou-ga"]','["particle","comparison"]',131);
INSERT INTO grammar_points VALUES(132,'n4-goto-ni','毎（ごと）に','goto ni','every; each (interval/occurrence)','Noun + ごとに',unistr('「ごとに」 is used to express that something happens "every" or "each" time a certain interval or condition is met. It emphasizes the regularity or repetition of an action or event. It is commonly used with time expressions (e.g., 10分ごと, 1時間ごと) or with nouns that represent units or occurrences.\u000aWhen used with time, it specifies that an action occurs at regular intervals. For example, 「10分ごとに」 means "every 10 minutes". It can also be used with other nouns like 「人ごとに」 (for each person) or 「ページごとに」 (on every page). The kanji 毎 can also be read まい as in 毎日 (mainichi) or 毎週 (maishuu), but when combined with ごと, it specifically means "each/every" in this pattern.'),'N4',2,'Linking and Temporal','[{"ja":"1時間ごとに休憩を取ります。","romaji":"ichijikan goto ni kyuukei o torimasu.","en":"I take a break every hour."},{"ja":"この薬は食後に3時間ごとに飲んでください。","romaji":"kono kusuri wa shokugo ni sanjikan goto ni nonde kudasai.","en":"Please take this medicine every three hours after meals."},{"ja":"このバスは駅と空港の間を30分ごとに走っています。","romaji":"kono basu wa eki to kuukou no aida o sanjuppun goto ni hashitte imasu.","en":"This bus runs between the station and the airport every 30 minutes."},{"ja":"彼は会議で発言する人ごとにメモを取った。","romaji":"kare wa kaigi de hatsugen suru hito goto ni memo o totta.","en":"He took notes for each person who spoke at the meeting."}]','["n5-mai"]','["adverbial","frequency"]',132);
INSERT INTO grammar_points VALUES(133,'n4-narubeku','なるべく','narubeku','as much as possible; if possible','なるべく + Verb / Adjective',unistr('「なるべく」 is an adverb that means "as much as possible" or "if possible." It expresses a request or a desire for something to be done to the greatest extent feasible or practical. It often precedes a verb or an adjective, indicating that the action or state should be maximized.\u000aThis expression is commonly used in polite requests or instructions, encouraging the listener to make an effort to achieve a certain condition. For example, 「なるべく早く」 means "as early as possible," and 「なるべく多く」 means "as much as possible."'),'N4',2,'Linking and Temporal','[{"ja":"なるべく早く宿題を終わらせてください。","romaji":"narubeku hayaku shukudai o owarasete kudasai.","en":"Please finish your homework as soon as possible."},{"ja":"なるべく静かにしてください。","romaji":"narubeku shizuka ni shite kudasai.","en":"Please be as quiet as possible."},{"ja":"質問があれば、なるべく具体的に教えてください。","romaji":"shitsumon ga areba, narubeku gutaiteki ni oshiete kudasai.","en":"If you have questions, please tell me as specifically as possible."},{"ja":"なるべく毎日運動するようにしています。","romaji":"narubeku mainichi undou suru you ni shite imasu.","en":"I try to exercise every day as much as possible."}]','[]','["adverb"]',133);
INSERT INTO grammar_points VALUES(134,'n4-ru-tokoro-da','～る所（ところ）だ','ru tokoro da','about to; on the verge of (doing something)','Verb (dictionary form) + ところだ',unistr('「～る所（ところ）だ」 is a grammar pattern used to indicate that an action is about to happen very soon, or that one is on the verge of doing something. The verb must be in its dictionary (plain) form. It conveys a sense of immediacy, often translated as "about to" or "just about to."\u000aThis pattern is one of three common uses of 「ところ」 to describe the timing of an action. It specifically refers to the moment right before an action begins. It is often accompanied by adverbs like 「今から」 (from now on) or 「これから」 (from now on, soon).'),'N4',2,'Linking and Temporal','[{"ja":"今から家を出るところです。","romaji":"ima kara ie o deru tokoro desu.","en":"I''m about to leave the house now."},{"ja":"ちょうどご飯を食べるところでした。","romaji":"choudo gohan o taberu tokoro deshita.","en":"I was just about to eat."},{"ja":"映画が始まるところなので、急ぎましょう。","romaji":"eiga ga hajimaru tokoro nano de, isogimashou.","en":"The movie is about to start, so let''s hurry."},{"ja":"彼は今、新しいプロジェクトを始めるところです。","romaji":"kare wa ima, atarashii purojekuto o hajimeru tokoro desu.","en":"He is about to start a new project now."}]','["n4-te-iru-tokoro-da","n4-ta-tokoro-da"]','["temporal expression","noun"]',134);
INSERT INTO grammar_points VALUES(135,'n4-noni','のに','noni','although; despite; even though',unistr('Verb (casual form) + のに\u000aい-Adjective + のに\u000aな-Adjective + なのに\u000aNoun + なのに'),unistr('「のに」 is a conjunction used to connect two clauses, expressing a sense of contrast, surprise, dissatisfaction, or unexpectedness. It means "although," "despite," or "even though." The second clause presents a situation or outcome that is contrary to what would logically be expected from the first clause.\u000aIt implies that the speaker feels something is regrettable or unexpected. For example, if it''s sunny, you''d expect to go out, but if you say 「晴れているのに、出かけられない」, it expresses regret that you can''t go out despite the good weather.\u000aBe careful not to confuse this with the N3/N2 usage of 「のに」 which indicates purpose or suitability (e.g., 「これは書くのに便利だ」 - This is convenient for writing). For N4, focus solely on its meaning of "although/despite."'),'N4',2,'Linking and Temporal','[{"ja":"勉強したのに、試験に落ちてしまった。","romaji":"benkyou shita noni, shiken ni ochite shimatta.","en":"Even though I studied, I failed the exam."},{"ja":"彼は日本人なのに、お箸が使えません。","romaji":"kare wa nihonjin nano ni, ohashi ga tsukaemasen.","en":"Even though he is Japanese, he cannot use chopsticks."},{"ja":"約束したのに、彼女は来ませんでした。","romaji":"yakusoku shita noni, kanojo wa kimasen deshita.","en":"Even though she promised, she didn''t come."},{"ja":"日曜日なのに、会社に行かなければなりません。","romaji":"nichiyoubi nano ni, kaisha ni ikanakereba narimasen.","en":"Even though it''s Sunday, I have to go to work."}]','["n4-ga","n4-keredo"]','["conjunction"]',135);
INSERT INTO grammar_points VALUES(136,'n4-to-omou','と思（おも）う','to omou','to think; I think; believe',unistr('Verb (casual) + と思う\u000aい-adjective (casual) + と思う\u000aな-adjective (casual, drop な + だ) + と思う\u000aNoun + だ + と思う'),unistr('「と思う」 (to omou) is a common expression used to state one''s opinion or belief. It directly follows a casual form of a verb, い-adjective, な-adjective, or noun.\u000a\u000aWhen attaching to a な-adjective or noun, you must add 「だ」 before 「と思う」. For example, 「きれいだ」 (beautiful) becomes 「きれいだと思う」, and 「学生だ」 (student) becomes 「学生だと思う」.\u000a\u000aThis pattern can be used to express your own thoughts or to inquire about someone else''s thoughts by adding 「か」 at the end (e.g., 「と思いますか」). The polite form is 「と思います」.'),'N4',3,'Seems Like, Could Be','[{"ja":"きれいだと思わない？","romaji":"kirei da to omowanai?","en":"Don''t you think it''s beautiful?"},{"ja":"それはかなりむずかしいと思います。","romaji":"sore wa kanari muzukashii to omoimasu.","en":"I think that is quite difficult."},{"ja":"今日は午後から雨が降ると思います。","romaji":"kyou wa gogo kara ame ga furu to omoimasu.","en":"I think it will rain from the afternoon today."},{"ja":"この問題、テストに出ると思いますか。","romaji":"kono mondai, tesuto ni deru to omoimasu ka.","en":"Do you think this problem will be on the test?"}]','[]','["verb","expression"]',136);
INSERT INTO grammar_points VALUES(137,'n4-nado','等（など）','nado','such as; and so on; etc.',unistr('Noun + など\u000aVerb (casual) + など'),unistr('「など」 (nado) is used to list a few examples and imply that there are other similar items or actions not explicitly mentioned. It translates to "such as," "and so on," or "etc."\u000a\u000aIt typically follows a noun or a casual form of a verb. When listing multiple items, it often appears after 「や」 (ya) to connect the items, like 「AやBなど」 (A, B, and so on).\u000a\u000aWhile 「など」 suggests other items exist, it doesn''t necessarily mean there are many more; it simply indicates that the list is not exhaustive.'),'N4',3,'Seems Like, Could Be','[{"ja":"りんごやバナナなどを買いました。","romaji":"ringo ya banana nado o kaimashita.","en":"I bought apples, bananas, etc."},{"ja":"週末は映画を見たり、本を読んだりなどします。","romaji":"shuumatsu wa eiga o mitari, hon o yondari nado shimasu.","en":"On weekends, I watch movies, read books, and so on."},{"ja":"東京にはスカイツリーや東京タワーなど、高い建物がたくさんあります。","romaji":"toukyou ni wa sukaitsurii ya toukyou tawaa nado, takai tatemono ga takusan arimasu.","en":"In Tokyo, there are many tall buildings such as Sky Tree and Tokyo Tower."},{"ja":"彼は日本語だけでなく、英語なども話せます。","romaji":"kare wa nihongo dake de naku, eigo nado mo hanasemasu.","en":"He can speak not only Japanese but also English, etc."}]','[]','["particle","listing"]',137);
INSERT INTO grammar_points VALUES(138,'n4-mitai','みたい','mitai','looks like; seems like; similar to',unistr('Noun + みたいだ / みたいに / みたいな + Noun\u000aVerb (casual) + みたいだ / みたいに / みたいな + Noun\u000aい-adjective (casual) + みたいだ / みたいに / みたいな + Noun\u000aな-adjective (casual, drop な) + みたいだ / みたいに / みたいな + Noun'),unistr('「みたい」 (mitai) is an informal expression used to indicate similarity, resemblance, or conjecture based on observation. It has two main uses:\u000a\u000a1.  **Similarity/Resemblance**: To say something is "like" or "similar to" something else. In this usage, it functions similarly to 「のようだ」 but is more casual. For example, 「夢みたいだ」 (It''s like a dream).\u000a\u000a2.  **Conjecture/Appearance**: To express that something "looks like" or "seems like" a certain state or action, based on what you see or feel. For example, 「雨が降るみたいだ」 (It looks like it will rain). It can attach to verbs (casual form), い-adjectives (casual form), な-adjectives (dropping な), and nouns.\u000a\u000a「みたい」 can appear in various forms: 「みたいだ」 (sentence end), 「みたいに」 (adverbial, modifying a verb or adjective), and 「みたいな + Noun」 (adjectival, modifying a noun). It is generally more casual than 「ようです」 (you desu).'),'N4',3,'Seems Like, Could Be','[{"ja":"夢みたいだ。","romaji":"yume mitai da.","en":"It''s like a dream."},{"ja":"外は、夏みたいだよ。","romaji":"soto wa, natsu mitai da yo.","en":"It''s like summer outside."},{"ja":"何となく雨みたいだ。","romaji":"nantonaku ame mitai da.","en":"It somehow looks like it''s going to rain."},{"ja":"彼は少し疲れてるみたいだ。","romaji":"kare wa sukoshi tsukareteru mitai da.","en":"He looks a little tired."}]','["n4-you-da"]','["auxiliary","conjecture","similarity"]',138);
INSERT INTO grammar_points VALUES(139,'n4-koto-ga-aru','ことがある','koto ga aru','there are times when; sometimes',unistr('Verb (casual non-past) + ことがある\u000aVerb (casual past) + ことがある'),unistr('「ことがある」 (koto ga aru) is used to express that something happens occasionally, from time to time, or that there are instances when a certain event occurs. It indicates a recurring, though not necessarily frequent, event or state.\u000a\u000aIt attaches to the casual form of a verb, most commonly the non-past form (e.g., 「行くことがある」 - there are times when I go) or the past form (e.g., 「行ったことがある」 - there are times when I went, though this can also imply experience).\u000a\u000aThis grammar point is distinct from 「〜たことがある」 (ta koto ga aru), which specifically refers to having the experience of doing something in the past. While both use 「ことがある」, the nuance differs based on context and the verb tense preceding it. For general occasional occurrences, the non-past verb form is often used.'),'N4',3,'Seems Like, Could Be','[{"ja":"たまに彼女と一緒にテニスをしに行くことがある。","romaji":"tamani kanojo to isshoni tenisu o shini iku koto ga aru.","en":"Sometimes I go to play tennis with my girlfriend."},{"ja":"たまに自転車で通勤することがある。","romaji":"tamani jitensha de tsuukin suru koto ga aru.","en":"Sometimes I commute to work by bicycle."},{"ja":"私は会議中でも、寝てしまうことがある。","romaji":"watashi wa kaigichuu demo, nete shimau koto ga aru.","en":"Sometimes I fall asleep even during meetings."},{"ja":"時々仕事をやめたいと思うことがある。","romaji":"tokidoki shigoto o yametai to omou koto ga aru.","en":"There are times when I feel like quitting my job."}]','["n5-ta-koto-ga-aru"]','["expression","frequency"]',139);
INSERT INTO grammar_points VALUES(140,'n4-sou','そう','sou','looks like; seems like; appears to be',unistr('Verb (stem) + そうだ\u000aい-adjective (drop い) + そうだ\u000aな-adjective (drop な) + そうだ'),unistr('「そう」 (sou) is used to express an appearance or conjecture based on direct observation or sensory information. It means "looks like," "seems like," or "appears to be."\u000a\u000aIt attaches to the stem form of verbs (e.g., 「降る」 → 「降りそうだ」), the stem of い-adjectives (dropping the final い, e.g., 「おいしい」 → 「おいしそうだ」), and the stem of な-adjectives (dropping the final な, e.g., 「元気」 → 「元気そうだ」). There are a few irregular forms, such as 「ない」 becoming 「なさそうだ」 and 「いい」 becoming 「よさそうだ」.\u000a\u000aThis 「そう」 is different from 「〜だそうです」, which is used to report hearsay or information heard from someone else. This form of 「そう」 is about what you perceive directly.'),'N4',3,'Seems Like, Could Be','[{"ja":"いまにも、雨が降りそうだ。","romaji":"imanimo, ame ga furisou da.","en":"It looks like it''s going to start raining any moment."},{"ja":"その人は倒れそうです。","romaji":"sono hito wa taoresou desu.","en":"That person looks like they''re about to fall over."},{"ja":"そろそろ雨がやみそうなので、もう少し待ちましょう。","romaji":"sorosoro ame ga yamisou nano de, mou sukoshi machimashou.","en":"It seems like the rain is going to stop soon, so let''s wait a little bit more."},{"ja":"どうしたの？眠そうだね。","romaji":"doushita no? nemusou da ne.","en":"What''s wrong? You look pretty sleepy."}]','["n4-mitai","n4-you-da"]','["auxiliary","conjecture","appearance"]',140);
INSERT INTO grammar_points VALUES(141,'n4-sa','さ','sa','Nominalizer for adjectives; -ness',unistr('い-adjective (stem) + さ\u000aな-adjective (stem) + さ'),unistr('The suffix `さ` is attached to the stem of adjectives to transform them into nouns. This nominalization expresses the degree or extent of a quality, often referring to an objective measurement or characteristic.\u000a\u000aFor example, `高い` (takai - high) becomes `高さ` (takasa - height), and `重い` (omoi - heavy) becomes `重さ` (omosa - weight). It is commonly used when discussing dimensions, weight, temperature, or other measurable attributes.\u000a\u000aWhile `さ` and `み` (another nominalizing suffix) both create nouns from adjectives, `さ` is generally used for objective qualities that can be measured or quantified, whereas `み` often refers to subjective feelings or inherent qualities (e.g., `悲しみ` - kanashimi - sadness).'),'N4',3,'Seems Like, Could Be','[{"ja":"富士山の高さは3776メートルです。","romaji":"fujisan no takasa wa sanzen nanahyakunanajuuroku meetoru desu.","en":"Mount Fuji''s height is 3776 meters."},{"ja":"この部屋の広さはどれくらいですか？","romaji":"kono heya no hirosa wa dore kurai desu ka?","en":"What is the size (spaciousness) of this room?"},{"ja":"ワサビの辛さが好きなので、たくさん入れます。","romaji":"wasabi no karasa ga suki nano de, takusan iremasu.","en":"I like the spiciness of wasabi, so I add a lot."},{"ja":"この問題の難しさがよく分かりません。","romaji":"kono mondai no muzukashisa ga yoku wakarimasen.","en":"I don''t really understand the difficulty of this problem."}]','[]','["nominalizer","suffix"]',141);
INSERT INTO grammar_points VALUES(142,'n4-toka','とか','toka','And; or; such as; things like...',unistr('Noun + とか\u000aVerb (Casual) + とか\u000aい-adjective (Casual) + とか\u000aな-adjective (Casual) + とか'),unistr('`とか` is a particle used to list a few examples, implying that there are other similar items, actions, or qualities that are not explicitly mentioned. It suggests an incomplete list, often used when you don''t need to be exhaustive or want to be vague.\u000a\u000aIt can be attached to nouns, verbs, and adjectives in their casual forms. When listing multiple items, `とか` can be repeated after each item, or it can be used once at the end of a list. It conveys a sense of '),'N4',3,'Seems Like, Could Be','[{"ja":"週末は映画を見に行くとか、友達とご飯を食べるとかしたいです。","romaji":"shuumatsu wa eiga o mi ni iku toka, tomodachi to gohan o taberu toka shitai desu.","en":"On the weekend, I want to do things like go see a movie or eat with friends."},{"ja":"趣味とかありますか？例えば、スポーツとか読書とか。","romaji":"shumi toka arimasu ka? tatoeba, supootsu toka dokusho toka.","en":"Do you have any hobbies or anything? For example, sports or reading?"},{"ja":"このカフェはコーヒーとかケーキとかが美味しいです。","romaji":"kono kafe wa koohii toka keeki toka ga oishii desu.","en":"This cafe has delicious coffee, cake, and so on."},{"ja":"疲れたとか、眠いとか言わないで、頑張りましょう。","romaji":"tsukareta toka, nemui toka iwanaide, ganbarimashou.","en":"Don''t say things like ''I''m tired'' or ''I''m sleepy''; let''s do our best."}]','["n5-ya","n4-tari"]','["particle","listing"]',142);
INSERT INTO grammar_points VALUES(143,'n4-souiu','そういう','souiu','That kind of; such a; like that','そういう + Noun',unistr('`そういう` is a demonstrative adjective (連体詞 - rentaishi) that means "that kind of," "such a," or "like that." It is used to refer to something that has been previously mentioned or is understood from the context.\u000a\u000aIt always directly modifies a noun, describing the type or nature of that noun. `そういう` is a more casual form compared to `そのような` (sono you na), which carries a slightly more formal nuance.\u000a\u000aThis expression is very common in daily conversation to refer back to a concept, idea, or situation without having to repeat it explicitly.'),'N4',3,'Seems Like, Could Be','[{"ja":"そういうことですか。やっと分かりました。","romaji":"sou iu koto desu ka. yatto wakarimashita.","en":"Is that what you mean? I finally understand."},{"ja":"私はそういう人が好きじゃないです。","romaji":"watashi wa sou iu hito ga suki janai desu.","en":"I don''t like that kind of person."},{"ja":"そういう話は聞きたくないです。","romaji":"sou iu hanashi wa kikitakunai desu.","en":"I don''t want to hear that kind of story."},{"ja":"そういう考え方は面白いですね。","romaji":"sou iu kangaekata wa omoshiroi desu ne.","en":"That way of thinking is interesting, isn''t it?"}]','["n5-kore-sore-are-dore","n5-kono-sono-ano-dono"]','["demonstrative","adjective"]',143);
INSERT INTO grammar_points VALUES(144,'n4-uyou','う・よう (Volitional)','u you (volitional)','Let''s; I shall; (suggesting an action)',unistr('Group 1 Verbs: Change final う-sound to お-sound + う (e.g., 飲む → 飲もう)\u000aGroup 2 Verbs: Drop る + よう (e.g., 食べる → 食べよう)\u000aIrregular Verbs: する → しよう, 来る (くる) → 来よう (こよう)'),unistr('The volitional form (`う` or `よう`) expresses the speaker''s intention or a suggestion to do something together. It is the casual equivalent of the `〜ましょう` form.\u000a\u000aWhen used alone, it can indicate a strong personal resolve or intention, similar to "I shall..." or "I will...". For example, `頑張ろう` (ganbarou) means "I''ll do my best" or "Let''s do our best."\u000a\u000aWhen used in a question with `か` (e.g., `行こうか?`), it becomes an invitation or a casual suggestion, asking for agreement or input from the listener. This form is widely used in casual conversations among friends and family.'),'N4',3,'Seems Like, Could Be','[{"ja":"今日は疲れたから、早く帰ろう。","romaji":"kyou wa tsukareta kara, hayaku kaerou.","en":"I''m tired today, so let''s go home early."},{"ja":"明日、一緒に映画を見に行こうか？","romaji":"ashita, issho ni eiga o mi ni ikou ka?","en":"Shall we go see a movie together tomorrow?"},{"ja":"もっと日本語を勉強しようと思います。","romaji":"motto nihongo o benkyou shiyou to omoimasu.","en":"I intend to study more Japanese."},{"ja":"お腹が空いたね。何か食べようか。","romaji":"onaka ga suita ne. nani ka tabeyou ka.","en":"I''m hungry, aren''t I? Shall we eat something?"}]','["n5-mashou"]','["verb conjugation","volitional"]',144);
INSERT INTO grammar_points VALUES(145,'n4-youda','様（よう）だ','you da','It seems; it appears; it looks like',unistr('Noun + の + ようだ\u000aい-adjective + ようだ\u000aな-adjective (stem) + な + ようだ\u000aVerb (Casual) + ようだ'),unistr('`〜ようだ` is a grammar pattern used to express a conjecture or inference based on observation. It indicates that something appears to be a certain way, or is similar to something else, based on what the speaker sees, hears, or feels.\u000a\u000aIt implies a higher degree of certainty or a more direct observation than `〜らしい` (which is based on hearsay or general impression) and is distinct from `〜そうだ` (which can indicate direct sensory appearance or reported information). `〜ようだ` often suggests a resemblance or a strong likelihood.\u000a\u000aThis pattern can be used with nouns, verbs, and adjectives. The polite form is `〜ようです`. It is a versatile expression for making educated guesses or describing things that resemble something else.'),'N4',3,'Seems Like, Could Be','[{"ja":"彼はとても忙しいようだ。","romaji":"kare wa totemo isogashii you da.","en":"It seems like he is very busy."},{"ja":"この料理は辛いようだね。","romaji":"kono ryouri wa karai you da ne.","en":"This dish seems spicy, doesn''t it?"},{"ja":"空が暗いから、雨が降るようです。","romaji":"sora ga kurai kara, ame ga furu you desu.","en":"The sky is dark, so it looks like it''s going to rain."},{"ja":"彼女はまるでモデルのようだ。","romaji":"kanojo wa marude moderu no you da.","en":"She looks just like a model."}]','["n4-rashii","n4-souda-appearance","n4-souda-hearsay"]','["conjecture","expression"]',145);
INSERT INTO grammar_points VALUES(146,'n4-zenzen','全然（ぜんぜん）','zenzen','(Not) at all; completely (informal positive)',unistr('全然 + Negative Verb/Adjective\u000a全然 + Positive Verb/Adjective (informal, emphatic)'),unistr('「全然」 is an adverb primarily used to emphasize a negative statement, meaning "not at all" or "not in the slightest." It always precedes the negative form of a verb or adjective, strengthening the negation.\u000a\u000aIn modern, informal Japanese, 「全然」 can also be used with positive verbs or adjectives to mean "completely" or "totally." This usage is common in casual conversation but might be considered incorrect in formal writing or by some older speakers. When used with a positive, it strengthens the affirmation, often expressing surprise or a strong feeling.'),'N4',3,'Seems Like, Could Be','[{"ja":"私は日本語が全然話せない。","romaji":"watashi wa nihongo ga zenzen hanasenai.","en":"I can''t speak Japanese at all."},{"ja":"この映画は全然面白くない。","romaji":"kono eiga wa zenzen omoshirokunai.","en":"This movie is not interesting at all."},{"ja":"彼は全然大丈夫だよ。","romaji":"kare wa zenzen daijoubu da yo.","en":"He''s totally fine/completely okay. (informal positive usage)"},{"ja":"宿題が全然終わらない。","romaji":"shukudai ga zenzen owaranai.","en":"I can''t finish my homework at all."}]','["n4-amari-nai"]','["adverb"]',146);
INSERT INTO grammar_points VALUES(147,'n4-kana','かな','kana','I wonder; I suppose; should I? (self-questioning)',unistr('Verb (Casual) + かな\u000aい-Adjective + かな\u000aな-Adjective (stem) + かな\u000aNoun + かな'),unistr('「かな」 is a sentence-ending particle used to express a personal wonder, doubt, or a question directed to oneself. It''s a softer, more casual version of 「でしょうか」 or 「だろうか」.\u000a\u000aIt can be used to ponder a situation, question one''s own actions, or express uncertainty about something. It often implies a slight hesitation or a search for an answer. While 「かな」 is generally used by men, women also use it in casual speech, especially when talking to themselves or expressing a soft inquiry.'),'N4',3,'Seems Like, Could Be','[{"ja":"明日、雨が降るかな。","romaji":"ashita, ame ga furu kana.","en":"I wonder if it will rain tomorrow."},{"ja":"彼はもう帰ったかな。","romaji":"kare wa mou kaetta kana.","en":"I wonder if he''s already gone home."},{"ja":"このケーキ、美味しいかな。","romaji":"kono keeki, oishii kana.","en":"I wonder if this cake is delicious."},{"ja":"私も一緒に行こうかな。","romaji":"watashi mo issho ni ikou kana.","en":"I wonder if I should go too."}]','["n5-ka","n4-darou"]','["particle","sentence-ending particle"]',147);
INSERT INTO grammar_points VALUES(148,'n4-amari-nai','余（あま）り～ない','amari-nai','Not very; not much; hardly',unistr('あまり + Verb (Negative)\u000aあまり + い-Adjective (Negative)\u000aあまり + な-Adjective (Negative)\u000aあまり + Noun + じゃない'),unistr('「あまり～ない」 is an adverbial phrase used to express a partial negation, meaning "not very," "not much," or "hardly." It always precedes a negative form of a verb, adjective, or noun phrase.\u000a\u000aThis phrase indicates that something is not happening to a great extent or is not true in a strong sense. It''s softer than a complete negation like 「全然～ない」 (not at all). It''s a very common expression in daily conversation to soften statements or express mild disagreement or lack of enthusiasm.'),'N4',3,'Seems Like, Could Be','[{"ja":"私はあまりテレビを見ない。","romaji":"watashi wa amari terebi o minai.","en":"I don''t watch TV very much."},{"ja":"この本はあまり面白くない。","romaji":"kono hon wa amari omoshirokunai.","en":"This book is not very interesting."},{"ja":"彼はあまり日本語が上手じゃない。","romaji":"kare wa amari nihongo ga jouzu janai.","en":"He''s not very good at Japanese."},{"ja":"今日はあまり寒くないですね。","romaji":"kyou wa amari samukunai desu ne.","en":"It''s not very cold today, is it?"}]','["n4-zenzen"]','["adverb"]',148);
INSERT INTO grammar_points VALUES(149,'n4-ba','ば','ba','If; when (conditional form)',unistr('Verb (ば-form) + (clause)\u000aい-Adjective (remove い, add ければ) + (clause)\u000aな-Adjective (remove な, add ならば / であれば) + (clause)\u000aNoun + ならば / であれば + (clause)'),unistr('The 「ば」 conditional form (also known as the "provisional form") is used to express a general condition or a natural consequence. It implies that if the first clause happens, the second clause will naturally follow.\u000a\u000aIt is often used for general truths, habitual actions, or when the speaker expects a certain outcome. The result clause (the second part) typically describes a natural consequence, a suggestion, or a statement of fact.\u000a\u000aUnlike 「と」 (which implies an immediate, certain result) or 「たら」 (which focuses on the completion of the first action), 「ば」 often suggests a more general or hypothetical condition. It cannot be used with volitional expressions (e.g., "let''s," "I want to") in the main clause if the subject is the same.'),'N4',3,'Seems Like, Could Be','[{"ja":"早く起きれば、間に合うでしょう。","romaji":"hayaku okireba, ma ni au deshou.","en":"If you wake up early, you''ll probably make it in time."},{"ja":"練習すればするほど、上手になります。","romaji":"renshuu sureba suru hodo, jouzu ni narimasu.","en":"The more you practice, the better you become."},{"ja":"安ければ買います。","romaji":"yasukereba kaimasu.","en":"If it''s cheap, I''ll buy it."},{"ja":"静かなら、勉強しやすいです。","romaji":"shizuka nara, benkyou shi yasui desu.","en":"If it''s quiet, it''s easy to study."}]','["n5-to","n4-tara","n4-nara"]','["conditional","conjunction"]',149);
INSERT INTO grammar_points VALUES(150,'n4-nara','なら','nara','If (it is the case that); as for (conditional)',unistr('Verb (Casual) + なら\u000aい-Adjective + なら\u000aな-Adjective (stem) + なら\u000aNoun + なら'),unistr('「なら」 is a conditional particle used when the condition is based on information or a situation presented by someone else, or when you are stating a condition about a specific topic. It often means "if that''s the case" or "if it''s about X."\u000a\u000aIt implies that the speaker is responding to a previous statement or topic. The action or statement in the main clause is often a suggestion, advice, or a decision based on the condition.\u000a\u000a「なら」 can also be used to introduce a topic, similar to 「は」 (as for), but with a conditional nuance. It''s distinct from 「ば」, 「と」, and 「たら」 because it often refers to a hypothetical situation or a condition that is already known or assumed.'),'N4',3,'Seems Like, Could Be','[{"ja":"ラーメンを食べるなら、あそこの店がいいよ。","romaji":"raamen o taberu nara, asoko no mise ga ii yo.","en":"If you''re going to eat ramen, that shop over there is good."},{"ja":"日本に行くなら、京都がおすすめです。","romaji":"nihon ni iku nara, kyouto ga osusume desu.","en":"If you''re going to Japan, Kyoto is recommended."},{"ja":"忙しいなら、手伝いましょうか。","romaji":"isogashii nara, tetsudaimashou ka.","en":"If you''re busy, shall I help you?"},{"ja":"泳ぐなら、このプールがいいですよ。","romaji":"oyogu nara, kono puuru ga ii desu yo.","en":"If you''re going to swim, this pool is good."}]','["n4-ba","n4-tara","n5-to"]','["conditional","conjunction"]',150);
INSERT INTO grammar_points VALUES(151,'n4-garu','がる','garu','to show signs of; to appear to feel/want (third person)',unistr('い-adjective (stem) + がる\u000aな-adjective (stem) + がる\u000aVerb (ます-stem) + たがる (see N4 たがる)\u000aNoun + がる (e.g., 嫌がる)'),unistr('The grammar point `～がる` is used to describe the observable signs or outward appearance of someone else''s feelings, emotions, or desires. It is crucial to remember that `～がる` is *only* used for third-person subjects (he, she, they, etc.) and not for the speaker''s own feelings. When you use `～がる`, you are essentially saying that someone *appears* to feel or want something based on their actions or expressions.\u000a\u000aThis form attaches to the stem of い-adjectives (e.g., 怖い (kowai) -> 怖がる (kowagaru - to appear scared)) and some な-adjectives (e.g., 嫌い (kirai) -> 嫌がる (iyagaru - to show dislike)). It conjugates like a Group 1 verb (五段動詞), meaning it can be used in various tenses and forms, such as `怖がります` (polite), `怖がらない` (negative), `怖がっている` (currently showing signs), and `怖がった` (past tense).\u000a\u000aIt''s important to distinguish `～がる` from directly stating one''s own feelings. For example, if *you* are scared, you say `怖いです` (kowai desu). If *someone else* appears scared, you say `彼は怖がっています` (kare wa kowagatteimasu). This grammar point allows you to infer and describe the internal states of others based on external cues.'),'N4',3,'Seems Like, Could Be','[{"ja":"子供は暗い場所を怖がる。","romaji":"kodomo wa kurai basho o kowagaru.","en":"Children are afraid of dark places."},{"ja":"彼女は新しいドレスを欲しがっている。","romaji":"kanojo wa atarashii doresu o hoshigatteiru.","en":"She is showing signs of wanting a new dress."},{"ja":"彼は負けて悔しがっていた。","romaji":"kare wa makete kuyashigatteita.","en":"He was showing signs of regret after losing."},{"ja":"弟は注射を嫌がる。","romaji":"otouto wa chuusha o iyagaru.","en":"My younger brother dislikes injections."}]','["n4-tagaru"]','["verb suffix","expression of feeling"]',151);
INSERT INTO grammar_points VALUES(152,'n4-ga-suru','がする','ga suru','to smell/hear/taste/feel (a sensation)','Noun (smell/sound/taste/sensation) + がする',unistr('The grammar pattern `～がする` is used to express that one perceives a smell, sound, taste, or a physical sensation. It indicates that the perception is often involuntary or comes from an unspecified source, rather than actively trying to perceive something. The `する` here acts as an intransitive verb, meaning "to be perceived" or "to occur."\u000a\u000aThis pattern is commonly used with nouns related to the five senses and bodily sensations. For example, `匂い (nioi)` for smell, `音 (oto)` or `声 (koe)` for sound, `味 (aji)` for taste, and `寒気 (samuke)` or `吐き気 (hakike)` for physical feelings. It allows you to describe what you are experiencing through your senses.\u000a\u000aFor instance, if you say `変な匂いがする` (hen na nioi ga suru), it means "I smell a strange odor" or "There''s a strange smell." It''s a natural way to describe sensory input without implying an active search for it. This is a fundamental expression for describing sensory experiences in Japanese.'),'N4',3,'Seems Like, Could Be','[{"ja":"変な匂いがする。","romaji":"hen na nioi ga suru.","en":"I smell something strange."},{"ja":"どこかで犬の鳴き声がする。","romaji":"dokoka de inu no nakigoe ga suru.","en":"I hear a dog barking somewhere."},{"ja":"このスープは少し塩味がする。","romaji":"kono suupu wa sukoshi shioaji ga suru.","en":"This soup tastes a little salty."},{"ja":"急に寒気がした。","romaji":"kyuu ni samuke ga shita.","en":"I suddenly felt a chill."}]','[]','["expression","verb phrase"]',152);
INSERT INTO grammar_points VALUES(153,'n4-tagaru','たがる','tagaru','to want to do (third person)','Verb (ます-stem) + たがる',unistr('The grammar pattern `～たがる` is used to express that a *third person* (someone other than the speaker) wants to do something. It is formed by taking the `～たい` form of a verb (which expresses the speaker''s own desire) and replacing the final `い` with `がる`. For example, `食べたい` (tabetai - I want to eat) becomes `食べたがる` (tabetagaru - someone else wants to eat).\u000a\u000aSimilar to `～がる`, `～たがる` indicates that the speaker is observing the third person''s desire based on their actions, words, or general demeanor. It implies an inference rather than direct knowledge of their internal feelings. This form conjugates like a Group 1 verb (五段動詞), allowing for various tenses and negative forms, such as `行きたがっています` (is wanting to go) or `読みたがらない` (doesn''t want to read).\u000a\u000aIt is crucial to remember the distinction: use `～たい` for your own desires (e.g., `私は食べたいです` - I want to eat) and `～たがる` for someone else''s desires (e.g., `彼は食べたがっています` - He wants to eat). This grammar point is essential for accurately describing the desires of others in Japanese.'),'N4',3,'Seems Like, Could Be','[{"ja":"妹は新しいゲームをしたがっている。","romaji":"imouto wa atarashii geemu o shitagatteiru.","en":"My younger sister wants to play a new game."},{"ja":"彼は日本へ行きたがっているようだ。","romaji":"kare wa nihon e ikitagatteiru you da.","en":"He seems to want to go to Japan."},{"ja":"子供たちは早く公園で遊びたがった。","romaji":"kodomotachi wa hayaku kouen de asobitagatta.","en":"The children wanted to play in the park quickly."},{"ja":"彼女は一人で帰りたがらない。","romaji":"kanojo wa hitori de kaeritagaranai.","en":"She doesn''t want to go home alone."}]','["n4-garu","n5-tai"]','["verb suffix","expression of desire"]',153);
INSERT INTO grammar_points VALUES(154,'n4-kamoshirenai','かもしれない','kamoshirenai','might; perhaps; possibly',unistr('Verb (casual form) + かもしれない\u000aい-adjective (casual form) + かもしれない\u000aな-adjective (stem) + かもしれない (or な-adjective + だ + かもしれない)\u000aNoun + かもしれない (or Noun + だ + かもしれない)'),unistr('The grammar pattern `～かもしれない` is used to express possibility or conjecture, meaning "it might be that..." or "perhaps...". It indicates that the speaker is not entirely certain about something, but considers it to be a possibility. It conveys a lower degree of certainty than `～でしょう` (deshou).\u000a\u000aThis expression can attach to various parts of speech. For verbs and い-adjectives, use their casual forms directly before `かもしれない`. For な-adjectives and nouns, you can attach `かもしれない` directly to the stem (e.g., `元気かもしれない`, `学生かもしれない`), or include `だ` (e.g., `元気だかもしれない`, `学生だかもしれない`), though `だ` is often omitted in casual speech.\u000a\u000a`かもしれない` is a versatile phrase for expressing uncertainty. The more polite form is `～かもしれません` (kamo shiremasen). In very casual speech, especially among close friends, `～かも` (kamo) can be used on its own. It''s a fundamental expression for speculating about future events or current states.'),'N4',4,'Comparisons and Speculation','[{"ja":"明日は雨が降るかもしれない。","romaji":"ashita wa ame ga furu kamoshirenai.","en":"It might rain tomorrow."},{"ja":"彼はもう家に着いているかもしれない。","romaji":"kare wa mou ie ni tsuiteiru kamoshirenai.","en":"He might have already arrived home."},{"ja":"この問題は難しいかもしれない。","romaji":"kono mondai wa muzukashii kamoshirenai.","en":"This problem might be difficult."},{"ja":"彼女は学生じゃないかもしれない。","romaji":"kanojo wa gakusei janai kamoshirenai.","en":"She might not be a student."}]','["n5-deshou","n4-sou-da-looks-like"]','["expression of possibility","conjecture"]',154);
INSERT INTO grammar_points VALUES(155,'n4-mitai-ni','みたいに','mitai ni','like; similar to; as if',unistr('Noun + みたいに\u000aVerb (casual form) + みたいに\u000aい-adjective (casual form) + みたいに\u000aな-adjective (stem) + みたいに'),unistr('The grammar pattern `～みたいに` is the adverbial form of `～みたいだ` (mitai da), which means "like," "similar to," or "as if." When `～みたいに` is used, it functions as an adverb, modifying a verb or an adjective that follows it. It indicates that an action or state is performed or exists in a manner resembling something else.\u000a\u000aThis expression is commonly used in casual conversation and is a straightforward way to make comparisons. It can attach to nouns, verbs (casual form), い-adjectives (casual form), and な-adjectives (stem form). For example, `子供みたいに` (kodomo mitai ni) means "like a child," and `夢みたいに` (yume mitai ni) means "like a dream."\u000a\u000aWhile `～のように` (no you ni) carries a similar meaning, `～みたいに` is generally more informal and frequently used in spoken Japanese. It''s a versatile tool for adding descriptive comparisons to your sentences, making your language more vivid and relatable.'),'N4',4,'Comparisons and Speculation','[{"ja":"彼は子供みたいに泣いた。","romaji":"kare wa kodomo mitai ni naita.","en":"He cried like a child."},{"ja":"彼女はモデルみたいにスタイルがいい。","romaji":"kanojo wa moderu mitai ni sutairu ga ii.","en":"She has a good figure like a model."},{"ja":"夢みたいに素敵な一日だった。","romaji":"yume mitai ni suteki na ichinichi datta.","en":"It was a wonderful day, like a dream."},{"ja":"あなたみたいに日本語が話せるようになりたい。","romaji":"anata mitai ni nihongo ga hanaseru you ni naritai.","en":"I want to be able to speak Japanese like you."}]','["n4-mitai-da","n4-no-you-ni"]','["comparison","adverbial phrase"]',155);
INSERT INTO grammar_points VALUES(156,'n4-sou-ni','そうに','sou ni','looks like; seems like (describing an action or state)',unistr('い-adjective (stem) + そうに\u000aな-adjective (stem) + そうに\u000aVerb (ます-stem) + そうに'),unistr('「そうに」 is used to describe how someone or something *appears* or *seems* when performing an action or in a certain state. It attaches to the stem of adjectives or the ます-stem of verbs.\u000a\u000aWhen used with い-adjectives, the final い is dropped (e.g., 楽しい -> 楽しそうに). For な-adjectives, the な is dropped (e.g., 暇な -> 暇そうに). For verbs, it attaches to the ます-stem (e.g., 走ります -> 走りそうに).\u000a\u000aThis form often precedes a verb that describes the observation, such as 見える (mieru - to appear, to be visible) or 話す (hanasu - to speak), indicating *how* the action is performed or *how* something appears. It functions adverbially, modifying the following verb.'),'N4',4,'Comparisons and Speculation','[{"ja":"楽しそうに歌っている。","romaji":"tanoshisou ni utatteiru.","en":"They are singing happily/as if having fun."},{"ja":"彼は忙しそうに電話で話している。","romaji":"kare wa isogashisou ni denwa de hanashiteiru.","en":"He is talking on the phone busily/as if busy."},{"ja":"子供たちは嬉しそうにプレゼントを開けた。","romaji":"kodomotachi wa ureshisou ni purezento o aketa.","en":"The children happily/joyfully opened the presents."},{"ja":"彼女は悲しそうに窓の外を見ていた。","romaji":"kanojo wa kanashisou ni mado no soto o miteita.","en":"She was sadly/as if sad looking out the window."}]','["n4-sou-da"]','["adverbial","appearance","adjective","verb"]',156);
INSERT INTO grammar_points VALUES(157,'n4-no-you-ni','の様（よう）に','no you ni','like; as if; in the manner of',unistr('Noun + のように\u000aVerb (casual form) + ように'),unistr('「～のように」 is used to make a comparison, indicating that something is "like" or "similar to" a noun, or that an action is performed "as if" or "in the manner of" something. It functions adverbially, modifying a verb or adjective that follows.\u000a\u000aWhen comparing to a noun, 「の」 is used before 「ように」 (e.g., 子供のように - like a child). When comparing to an action or state described by a verb, the verb is in its casual form (e.g., 走るように - as if running).\u000a\u000aThis pattern emphasizes similarity or resemblance in action or state. It''s distinct from 「～みたいに」 (mitai ni), which is more casual, and 「～そうだ」 (sou da), which expresses appearance based on direct observation.'),'N4',4,'Comparisons and Speculation','[{"ja":"彼は子供のように無邪気に笑った。","romaji":"kare wa kodomo no you ni mujaki ni waratta.","en":"He laughed innocently like a child."},{"ja":"まるで夢を見ているかのように感じた。","romaji":"marude yume o miteiru ka no you ni kanjita.","en":"I felt as if I were dreaming."},{"ja":"彼女は鳥のように自由に空を飛んだ。","romaji":"kanojo wa tori no you ni jiyuu ni sora o tonda.","en":"She flew freely in the sky like a bird."},{"ja":"彼はプロの選手のようにボールを蹴った。","romaji":"kare wa puro no senshu no you ni booru o ketta.","en":"He kicked the ball like a professional player."}]','["n4-mitai-ni","n4-you-da"]','["comparison","adverbial","noun","verb"]',157);
INSERT INTO grammar_points VALUES(158,'n4-ou-you-to-omou','う・よう + と思（おも）う','ou you to omou','I think I will; I intend to; I''m going to','Verb (volitional form) + と思う',unistr('This grammar pattern expresses the speaker''s intention or plan. The volitional form of a verb (e.g., 食べよう, 行こう) indicates a will or suggestion, and when combined with 「と思う」, it means "I think I will do X" or "I intend to do X."\u000a\u000aIt''s used for plans or decisions that are not yet set in stone, or for expressing a personal resolve. The nuance is softer than a definite plan expressed with 「～つもりだ」 (tsumori da).\u000a\u000aThe volitional form is formed by changing Group 1 verbs to their お-column sound + う (e.g., 飲む -> 飲もう), Group 2 verbs to their ます-stem + よう (e.g., 食べる -> 食べよう), and irregular verbs する -> しよう, 来る -> 来よう.'),'N4',4,'Comparisons and Speculation','[{"ja":"来年、日本に行こうと思う。","romaji":"rainen, nihon ni ikou to omou.","en":"I think I''ll go to Japan next year."},{"ja":"今日は早く家に帰ろうと思う。","romaji":"kyou wa hayaku ie ni kaerou to omou.","en":"I think I''ll go home early today."},{"ja":"新しい言語を勉強しようと思っています。","romaji":"atarashii gengo o benkyou shiyou to omotteimasu.","en":"I''m thinking of studying a new language."},{"ja":"週末は友達と映画を見ようと思う。","romaji":"shuumatsu wa tomodachi to eiga o miyou to omou.","en":"I think I''ll watch a movie with friends this weekend."}]','["n4-tsumori-da","n5-volitional"]','["intention","volition","verb","plan"]',158);
INSERT INTO grammar_points VALUES(159,'n4-ku-ni','く・に','ku ni','adverbial form of adjectives',unistr('い-adjective (stem) + く\u000aな-adjective (stem) + に'),unistr('This grammar point explains how adjectives are transformed into adverbs to modify verbs.\u000a\u000aFor い-adjectives, the final い is replaced with 「く」 (e.g., 早く - hayaku, from 早い - hayai). This 「く」 form directly modifies a verb, describing *how* an action is performed (e.g., 早く走る - run quickly).\u000a\u000aFor な-adjectives, the 「な」 is replaced with 「に」 (e.g., きれいに - kirei ni, from きれいな - kirei na). This 「に」 form also modifies a verb, describing *how* an action is performed or the state in which it is done (e.g., きれいに書く - write neatly).\u000a\u000aThese adverbial forms are essential for adding descriptive detail to actions in Japanese.'),'N4',4,'Comparisons and Speculation','[{"ja":"彼は速く走ることができる。","romaji":"kare wa hayaku hashiru koto ga dekiru.","en":"He can run fast."},{"ja":"この部屋をきれいに掃除してください。","romaji":"kono heya o kirei ni souji shite kudasai.","en":"Please clean this room neatly."},{"ja":"もっと静かに話してください。","romaji":"motto shizuka ni hanashite kudasai.","en":"Please speak more quietly."},{"ja":"彼女は上手に日本語を話します。","romaji":"kanojo wa jouzu ni nihongo o hanashimasu.","en":"She speaks Japanese skillfully."}]','["n5-i-adjective","n5-na-adjective"]','["adverb","adjective","modification"]',159);
INSERT INTO grammar_points VALUES(160,'n4-ni-suru-ku-suru','にする・くする','ni suru ku suru','to make something (adjective); to decide on',unistr('い-adjective (stem) + くする\u000aな-adjective (stem) + にする\u000aNoun + にする'),unistr('This grammar pattern is used to express changing something into a certain state or making a decision.\u000a\u000aWhen used with adjectives, 「～くする」 (for い-adjectives) and 「～にする」 (for な-adjectives) mean "to make something (more) [adjective]". For example, 「大きくする」 (ookiku suru) means "to make bigger," and 「きれいにする」 (kirei ni suru) means "to make clean."\u000a\u000aWhen used with nouns, 「～にする」 means "to decide on" or "to choose" something. For example, 「コーヒーにする」 (koohii ni suru) means "to decide on coffee" or "to choose coffee." This usage implies a choice or decision.'),'N4',4,'Comparisons and Speculation','[{"ja":"部屋をきれいにしてください。","romaji":"heya o kirei ni shite kudasai.","en":"Please make the room clean."},{"ja":"音を大きくする。","romaji":"oto o ookiku suru.","en":"To make the sound louder."},{"ja":"夕食はカレーライスにする。","romaji":"yuushoku wa karee raisu ni suru.","en":"I''ll decide on curry rice for dinner."},{"ja":"髪を短くした。","romaji":"kami o mijikaku shita.","en":"I made my hair short (I cut my hair short)."}]','["n5-suru"]','["causative","adjective","noun","decision"]',160);
INSERT INTO grammar_points VALUES(161,'n4-toii','といい','toii','I hope; I wish; It would be good if...',unistr('Verb (casual, non-past) + といい\u000aい-adjective (non-past) + といい\u000aな-adjective (stem) + だといい\u000aNoun + だといい'),unistr('「といい」is used to express a hope or wish for something to happen or for a certain state to exist. It can be used for oneself or for others.\u000a\u000aWhen used with 「ね」 (といいね), it often implies seeking agreement or sharing the wish with the listener. When used with 「な」 (といいな), it expresses a personal wish or desire.\u000a\u000aThis pattern can also convey a gentle suggestion or advice, implying that a certain action or situation would be beneficial.'),'N4',4,'Comparisons and Speculation','[{"ja":"明日晴れるといいね。","romaji":"Ashita hareru to ii ne.","en":"I hope it''ll be sunny tomorrow."},{"ja":"早く元気になるといいですね。","romaji":"Hayaku genki ni naru to ii desu ne.","en":"I hope you get well soon."},{"ja":"もっと日本語が上手になるといいな。","romaji":"Motto nihongo ga jouzu ni naru to ii na.","en":"I wish I could become better at Japanese."},{"ja":"この仕事、うまくいくといいんだけど。","romaji":"Kono shigoto, umaku iku to ii n da kedo.","en":"I hope this job goes well."}]','["n4-ba-ii","n5-hougaii"]','["expression","wish"]',161);
INSERT INTO grammar_points VALUES(162,'n4-you-ni-naru','様（よう）になる','you ni naru','To come to be able to; To reach the point where; To start to',unistr('Verb (potential form) + ようになる\u000aVerb (dictionary form) + ようになる'),unistr('「ようになる」expresses a change or development over time, indicating that one has reached a new state or acquired a new ability. It signifies a gradual process or a result of effort.\u000a\u000aIt is frequently used with potential verbs (e.g., 食べられるようになる, 話せるようになる) to show that one has gained the ability to do something that they couldn''t do before.\u000a\u000aIt can also be used with non-potential verbs to indicate a change in habit or a new routine, meaning "to come to do something" or "to start doing something regularly."'),'N4',4,'Comparisons and Speculation','[{"ja":"日本語が話せるようになった。","romaji":"Nihongo ga hanaseru you ni natta.","en":"I''ve come to be able to speak Japanese."},{"ja":"毎日運動するようになった。","romaji":"Mainichi undou suru you ni natta.","en":"I''ve started exercising every day."},{"ja":"一人で旅行できるようになりました。","romaji":"Hitori de ryokou dekiru you ni narimashita.","en":"I''ve become able to travel alone."},{"ja":"最近、早く起きられるようになった。","romaji":"Saikin, hayaku okirareru you ni natta.","en":"Recently, I''ve become able to wake up early."}]','["n4-you-ni-suru"]','["expression","change"]',162);
INSERT INTO grammar_points VALUES(163,'n4-mai-no-you-ni','毎（まい）～の様（よう）に','mai no you ni','Almost every ~; Nearly every ~','毎 + Noun + のように',unistr('「毎～のように」is used to express that something happens with very high frequency, almost every time, but not necessarily exactly every single time. It emphasizes the regularity and near-constant occurrence of an event.\u000a\u000aThe noun following 「毎」typically refers to a unit of time (e.g., 毎日, 毎週, 毎年). This pattern highlights that the action or state is so frequent that it''s comparable to happening every single instance of that time unit.\u000a\u000aIt conveys a sense of strong repetition or habit, often implying that the speaker is slightly surprised or emphasizing the high frequency.'),'N4',4,'Comparisons and Speculation','[{"ja":"毎日のように雨が降る。","romaji":"Mainichi no you ni ame ga furu.","en":"It rains almost every day."},{"ja":"彼は毎週末のように図書館に行く。","romaji":"Kare wa maishuumatsu no you ni toshokan ni iku.","en":"He goes to the library almost every weekend."},{"ja":"毎晩のように電話で話している。","romaji":"Maiban no you ni denwa de hanashite iru.","en":"They talk on the phone almost every night."},{"ja":"毎年のように家族で旅行に行きます。","romaji":"Maitoshi no you ni kazoku de ryokou ni ikimasu.","en":"We go on a trip with our family almost every year."}]','[]','["frequency","comparison"]',163);
INSERT INTO grammar_points VALUES(164,'n4-janai-ka','じゃないか','janai ka','Isn''t it?; Right?; Let''s ~ (emphatic suggestion)',unistr('Verb (casual) + じゃないか\u000aい-adjective (casual) + じゃないか\u000aな-adjective (stem) + じゃないか\u000aNoun + じゃないか'),unistr('「じゃないか」has two main uses. First, it''s used to seek confirmation, express agreement, or state a realization, often with a nuance of "I told you so" or "you should know this." It can convey a slight sense of scolding or exasperation depending on the context and intonation.\u000a\u000aSecond, when combined with the volitional form of a verb (e.g., 行こうじゃないか), it forms an emphatic suggestion or invitation, similar to "Let''s do X, shall we?" or "Why don''t we do X?" This usage is often more assertive or encouraging than a simple volitional form.\u000a\u000aIt''s a casual expression and should generally be avoided in formal situations. The nuance can change significantly with intonation.'),'N4',4,'Comparisons and Speculation','[{"ja":"行こうじゃないか。","romaji":"Ikou janai ka.","en":"Let''s go, shall we?"},{"ja":"ダメじゃないか。","romaji":"Dame janai ka.","en":"That''s no good, isn''t it? (You shouldn''t do that)."},{"ja":"だから言ったじゃないか！","romaji":"Dakara itta janai ka!","en":"I told you so! (Didn''t I?)"},{"ja":"このケーキ、美味しいじゃないか。","romaji":"Kono keeki, oishii janai ka.","en":"This cake is delicious, isn''t it? (Oh, it is delicious!)"}]','["n5-deshou","n4-darou"]','["particle","confirmation","suggestion"]',164);
INSERT INTO grammar_points VALUES(165,'n4-rashii-1','らしい ①','rashii 1','It seems; Apparently; I heard that',unistr('Verb (casual) + らしい\u000aい-adjective (casual) + らしい\u000a な-adjective (stem) + らしい\u000aNoun + らしい'),unistr('「らしい」is used to convey information that the speaker has heard or observed, suggesting that something is likely true or appears to be the case. It implies a higher degree of certainty or reliability than 「そうだ」(hearsay) because the speaker often has some evidence or a strong reason to believe it.\u000a\u000aIt can be based on indirect information, rumors, or general knowledge, but it''s presented as a reasonable inference. The speaker is not stating a fact but rather what seems to be the fact based on available information.\u000a\u000aUnlike 「ようだ」which often implies a direct observation or impression, 「らしい」is more about information gathered from external sources or a strong logical deduction.'),'N4',4,'Comparisons and Speculation','[{"ja":"彼は忙しいらしい。","romaji":"Kare wa isogashii rashii.","en":"It seems he''s busy. / Apparently he''s busy."},{"ja":"明日は雪が降るらしい。","romaji":"Ashita wa yuki ga furu rashii.","en":"Apparently, it will snow tomorrow."},{"ja":"このレストランは美味しいらしいよ。","romaji":"Kono resutoran wa oishii rashii yo.","en":"I heard this restaurant is delicious."},{"ja":"彼女は最近、彼氏ができたらしい。","romaji":"Kanojo wa saikin, kareshi ga dekita rashii.","en":"Apparently, she got a boyfriend recently."}]','["n4-souda-hearsay","n4-youda"]','["speculation","hearsay"]',165);
INSERT INTO grammar_points VALUES(166,'n4-teoku','～ておく','teoku','To do something in advance; to leave something as is; to prepare','Verb (て-form) + おく',unistr('The grammar pattern ～ておく (te oku) has two main uses. The primary use is to express that an action is performed in advance, often as preparation for a future event or situation. For example, if you are going on a trip, you might buy tickets in advance (切符を買っておく).\u000a\u000aThe second use is to indicate that an action is performed and the resulting state is maintained, or to simply leave something as it is. For instance, if you want to keep a window open, you might say 窓を開けておく (mado o akete oku).\u000a\u000aIn casual speech, ～ておく often contracts to ～とく (toku) for verbs ending in -te, and ～どく (doku) for verbs ending in -de. For example, 読んでおく (yonde oku) becomes 読んどく (yondoku), and 食べておく (tabete oku) becomes 食べとく (tabetoku).'),'N4',4,'Comparisons and Speculation','[{"ja":"お弁当を作っておいたよ。","romaji":"obentou o tsukutte oita yo.","en":"I made your bento (lunch box) in advance."},{"ja":"出かける前に何か食べておこう。","romaji":"dekakeru mae ni nanika tabete okou.","en":"Let''s eat something before we head out (as preparation)."},{"ja":"旅行の前に切符を買っておきます。","romaji":"ryokou no mae ni kippu o katte okimasu.","en":"I will buy the tickets before the trip (as preparation)."},{"ja":"お母さんには内緒にしておくね。","romaji":"okaasan ni wa naisho ni shite oku ne.","en":"I will keep it a secret from Mom, okay? (leaving it in that state)."}]','["n5-teiru","n5-tearu"]','["verb conjugation","preparation","state"]',166);
INSERT INTO grammar_points VALUES(167,'n4-ga-hoshii','が欲（ほ）しい','ga hoshii','To want (a noun); to desire (a thing)','Noun + が + 欲しい',unistr('が欲しい (ga hoshii) is used to express the speaker''s desire for a specific noun or thing. 欲しい is an i-adjective, so it conjugates like other i-adjectives (e.g., 欲しくない, 欲しかった).\u000a\u000aThis pattern is primarily used to express one''s own desires. When talking about someone else''s desires, it''s generally considered impolite or too direct to use 欲しい directly. Instead, you would use expressions like ～が欲しいですか (to ask), or ～がっている (to describe someone else''s apparent desire).\u000a\u000aIt''s important to distinguish this from ～たい (tai), which is used to express the desire to *do* something (e.g., 食べたい - I want to eat), whereas 欲しい expresses the desire for a *thing* (e.g., 水が欲しい - I want water).'),'N4',4,'Comparisons and Speculation','[{"ja":"新しいパソコンが欲しい。","romaji":"atarashii pasokon ga hoshii.","en":"I want a new computer."},{"ja":"今、一番欲しいものは何ですか。","romaji":"ima, ichiban hoshii mono wa nan desu ka.","en":"What is the thing you want most right now?"},{"ja":"彼女はもっと時間が欲しいと言いました。","romaji":"kanojo wa motto jikan ga hoshii to iimashita.","en":"She said she wants more time."},{"ja":"この本が欲しかったけど、売り切れていました。","romaji":"kono hon ga hoshikatta kedo, urikirete imashita.","en":"I wanted this book, but it was sold out."}]','["n5-tai","n4-te-hoshii"]','["adjective","desire"]',167);
INSERT INTO grammar_points VALUES(168,'n4-te-hoshii','～て欲（ほ）しい','te hoshii','To want someone to do something','Verb (て-form) + 欲しい',unistr('The pattern ～て欲しい (te hoshii) is used to express the speaker''s desire for *someone else* to perform an action. The person who is desired to perform the action is often indicated by the particle に, or is clear from context.\u000a\u000aSimilar to が欲しい, this expression directly states the speaker''s desire, so it can sound a bit strong or demanding depending on the context and intonation. It''s generally used among close friends or family, or when making a direct request.\u000a\u000aThis grammar point combines the て-form of a verb with 欲しい, which functions as an i-adjective. Therefore, it conjugates like an i-adjective (e.g., ～て欲しくない, ～て欲しかった).'),'N4',4,'Comparisons and Speculation','[{"ja":"早く来てほしい。","romaji":"hayaku kite hoshii.","en":"I want you to come soon."},{"ja":"彼にこの仕事を終わらせてほしい。","romaji":"kare ni kono shigoto o owarasete hoshii.","en":"I want him to finish this job."},{"ja":"もう少し静かにしてほしいです。","romaji":"mou sukoshi shizuka ni shite hoshii desu.","en":"I''d like you to be a little quieter."},{"ja":"みんなが幸せになってほしいと願っています。","romaji":"minna ga shiawase ni natte hoshii to negatte imasu.","en":"I wish for everyone to become happy."}]','["n4-ga-hoshii","n5-tai"]','["verb conjugation","desire","request"]',168);
INSERT INTO grammar_points VALUES(169,'n4-to-kiita','と聞（き）いた','to kiita','I heard that...','Casual form of sentence + と + 聞いた',unistr('The pattern ～と聞いた (to kiita) is used to report information that the speaker has heard from someone else or from a source. It indicates that the information is second-hand, not something the speaker directly observed or knows for a fact.\u000a\u000aThe clause preceding と must be in its casual (plain) form, regardless of whether it''s a verb, i-adjective, na-adjective, or noun. For na-adjectives and nouns, the だ (da) ending is typically included in the casual form (e.g., 暇だ, 学生だ).\u000a\u000aThis phrase is a common way to introduce reported speech or information. It can also be used with ことがあります (koto ga arimasu) to mean "I have heard that... (at some point in the past)".'),'N4',4,'Comparisons and Speculation','[{"ja":"彼がお父さんになったと聞いた。","romaji":"kare ga otousan ni natta to kiita.","en":"I heard that he became a father."},{"ja":"この映画が面白いと聞いたことがあります。","romaji":"kono eiga ga omoshiroi to kiita koto ga arimasu.","en":"I have heard that this movie is interesting."},{"ja":"彼が帰ってくると聞いた。","romaji":"kare ga kaette kuru to kiita.","en":"I heard that he will be coming back."},{"ja":"あなたの日本語がうまくなっていると聞いた。","romaji":"anata no nihongo ga umaku natteiru to kiita.","en":"I heard your Japanese is getting better."}]','["n4-sou-da-hearsay","n4-rashii"]','["reporting","quotation"]',169);
INSERT INTO grammar_points VALUES(170,'n4-kikoeru','聞（き）こえる','kikoeru','To be audible; to be heard; can hear (involuntarily)','Noun + が + 聞こえる',unistr('聞（き）こえる (kikoeru) is an intransitive verb meaning "to be audible" or "to be heard." It describes a sound that reaches one''s ears naturally or involuntarily, without conscious effort. The particle が (ga) is used to mark the sound that is heard.\u000a\u000aThis verb is often contrasted with 聞く (kiku), which is a transitive verb meaning "to listen" or "to hear intentionally." While 聞く implies an active effort to perceive sound, 聞こえる describes the passive experience of sound being present and audible.\u000a\u000aIt can also be compared to 聞ける (kikeru), which is the potential form of 聞く, meaning "can hear (if one tries)." 聞こえる, on the other hand, implies that the sound is simply available to be heard, regardless of effort.'),'N4',4,'Comparisons and Speculation','[{"ja":"音楽が聞こえる。","romaji":"ongaku ga kikoeru.","en":"I can hear music (music is audible)."},{"ja":"遠くから犬の鳴き声が聞こえました。","romaji":"tooku kara inu no nakigoe ga kikoemashita.","en":"I heard a dog barking from afar."},{"ja":"先生の声が小さくて、よく聞こえません。","romaji":"sensei no koe ga chiisakute, yoku kikoemasen.","en":"The teacher''s voice is quiet, so I can''t hear well."},{"ja":"隣の部屋から話し声が聞こえる。","romaji":"tonari no heya kara hanashigoe ga kikoeru.","en":"I can hear voices from the next room."}]','["n5-kiku","n5-mieru"]','["verb","potential","involuntary action"]',170);
INSERT INTO grammar_points VALUES(171,'n4-mieru','見（み）える','mieru','to be visible; to be seen; to appear; to seem',unistr('Noun + が + 見える\u000aNoun + に + 見える\u000aVerb (casual) + ように + 見える'),unistr('「見える」 has two primary uses in N4. The first is to express that something is naturally visible or can be seen without conscious effort. This is often considered the potential form of 「見る (miru)」, meaning "to see." It implies that something enters one''s field of vision naturally, such as a mountain in the distance or a boat on the sea. It is typically used with the particle 「が」.\u000a\u000aThe second use of 「見える」 is to describe how something or someone appears or seems to be, based on observation. This can be used with a noun followed by 「に」 to indicate what something looks like (e.g., 「先生に見える」 - "looks like a teacher"). It can also be used with a casual verb form followed by 「ように」 to express that something appears to be in a certain state or doing a certain action (e.g., 「疲れているように見える」 - "appears to be tired").\u000a\u000aIt''s important to distinguish 「見える」 from 「見られる (mirareru)」, which is the passive form of 「見る」 and means "to be seen (by someone)" or the potential form meaning "can see (with effort/ability)." 「見える」 refers to natural visibility, while 「見られる」 implies an action or ability.'),'N4',4,'Comparisons and Speculation','[{"ja":"遠くに山が見えます。","romaji":"Tooku ni yama ga miemasu.","en":"I can see mountains in the distance."},{"ja":"この部屋からは海が見える。","romaji":"Kono heya kara wa umi ga mieru.","en":"You can see the ocean from this room."},{"ja":"彼は日本人に見えますが、実はアメリカ人です。","romaji":"Kare wa nihonjin ni miemasu ga, jitsu wa amerikajin desu.","en":"He looks Japanese, but he''s actually American."},{"ja":"彼女はとても忙しいように見える。","romaji":"Kanojo wa totemo isogashii yō ni mieru.","en":"She appears to be very busy."}]','["n4-kikoeru"]','["verb","potential form","appearance"]',171);
INSERT INTO grammar_points VALUES(172,'n4-dasu','出（だ）す','dasu','to begin to; to start to; to take/put out; to send out',unistr('Verb (ます-stem) + 出す\u000aNoun + を + 出す'),unistr('「出す (dasu)」 has two main uses at the N4 level. The first is as a suffix attached to the ます-stem of a verb, forming a compound verb. In this usage, 「〜出す」 means "to suddenly begin" or "to start doing" an action. It often implies an abrupt, unexpected, or spontaneous commencement of an action.\u000a\u000aThe second use is as a standalone transitive verb. In this context, 「出す」 means "to take out," "to put out," "to send out," or "to submit." It describes the action of moving something from an inside, hidden, or contained state to an outside, visible, or released state. This can apply to physical objects, information, or even sounds.\u000a\u000aUnderstanding the context is key to differentiating between these two uses. When combined with another verb, it indicates the start of an action. When used independently with a direct object, it indicates the action of bringing something forth or sending it out.'),'N4',4,'Comparisons and Speculation','[{"ja":"雨が急に降り出した。","romaji":"Ame ga kyū ni furidashita.","en":"It suddenly started raining."},{"ja":"赤ちゃんが泣き出した。","romaji":"Akachan ga nakidashita.","en":"The baby started crying."},{"ja":"財布をカバンから出した。","romaji":"Saifu o kaban kara dashita.","en":"I took my wallet out of my bag."},{"ja":"手紙をポストに出した。","romaji":"Tegami o posuto ni dashita.","en":"I mailed the letter in the mailbox."}]','["n4-hajimeru"]','["compound verb","verb"]',172);
INSERT INTO grammar_points VALUES(173,'n4-dai','代（だい）','dai','age range; generation; decade','Number + 代（だい）',unistr('「代（だい）」 is a suffix used after a number to indicate a range or period. Its most common use at the N4 level is to refer to a person''s age range, such as their 20s, 30s, 40s, and so on. For example, 「20代 (nijuudai)」 means "in one''s twenties."\u000a\u000aIt can also be used to refer to decades, such as the 1980s or 2000s. For instance, 「1980年代 (senkyuuhyakuhachijuunendai)」 means "the 1980s." This usage helps categorize periods of time or groups of people by age.\u000a\u000aWhen referring to age, it''s a general range, not a specific age. For example, someone in their 20s could be 20, 25, or 29. It''s a convenient way to describe someone''s general age group.'),'N4',5,'Quantifiers and Limits','[{"ja":"彼女はまだ10代の学生です。","romaji":"Kanojo wa mada jūdai no gakusei desu.","en":"She is still a student in her teens."},{"ja":"私の父は50代ですが、とても元気です。","romaji":"Watashi no chichi wa gojūdai desu ga, totemo genki desu.","en":"My father is in his 50s, but he is very energetic."},{"ja":"この映画は1990年代に作られました。","romaji":"Kono eiga wa senkyūhyakukyūjūnendai ni tsukuraremashita.","en":"This movie was made in the 1990s."},{"ja":"彼は30代で会社を立ち上げました。","romaji":"Kare wa sanjūdai de kaisha o tachiagemashita.","en":"He started a company in his 30s."}]','[]','["suffix","counter"]',173);
INSERT INTO grammar_points VALUES(174,'n4-number-mo','Number + も','number mo','as many/much as; even (a large number); emphasizing quantity',unistr('Number + Counter + も\u000aNumber + も (when counter is implied)'),unistr('When 「も」 is placed after a number (often followed by a counter), it emphasizes that the quantity is surprisingly large or more than expected. It conveys a sense of "as many/much as" or "even as many/much as," expressing the speaker''s surprise, admiration, or sometimes exasperation regarding the quantity.\u000a\u000aThis usage highlights the magnitude of the number, making it stand out. For example, saying 「3時間も待った (sanjikan mo matta)」 implies that waiting for three hours was a long time, perhaps longer than anticipated or desired. It adds an emotional nuance to the quantity.\u000a\u000aIt''s commonly used with time, money, people, or objects to stress the large amount. This contrasts with 「しか〜ない (shika ~ nai)」, which emphasizes a surprisingly small quantity.'),'N4',5,'Quantifiers and Limits','[{"ja":"3時間も待った。","romaji":"Sanjikan mo matta.","en":"I waited for as long as 3 hours."},{"ja":"彼は本を100冊も持っている。","romaji":"Kare wa hon o hyakusatsu mo motte iru.","en":"He has as many as 100 books."},{"ja":"毎日、コーヒーを5杯も飲みます。","romaji":"Mainichi, kōhī o gohai mo nomimasu.","en":"I drink as many as 5 cups of coffee every day."},{"ja":"このケーキは1000円もする。","romaji":"Kono kēki wa sen''en mo suru.","en":"This cake costs as much as 1000 yen."}]','["n4-number-shika-nai"]','["particle","emphasis","quantity"]',174);
INSERT INTO grammar_points VALUES(175,'n4-hotondo','殆（ほとん）ど','hotondo','almost all; most; hardly any; scarcely',unistr('殆ど + Noun (の)\u000a殆ど + Verb / Adjective\u000a殆ど + ない (negative form)'),unistr('「殆ど (hotondo)」 is an adverbial noun that means "almost all" or "most" when referring to a large proportion or degree. It indicates that something is very close to 100% or nearly complete. When modifying a noun, it typically takes the form 「殆どのNoun」.\u000a\u000aIt can also function as an adverb, modifying verbs or adjectives to mean "almost" or "nearly." For example, 「殆ど終わった (hotondo owatta)」 means "it''s almost finished." In this sense, it expresses a high degree of completion or approximation.\u000a\u000aFurthermore, 「殆ど」 can be used with a negative verb form (e.g., 「殆ど〜ない」) to mean "hardly any," "scarcely," or "almost never." This usage emphasizes the rarity or near absence of something. For instance, 「殆ど話さない (hotondo hanasanai)」 means "hardly ever speaks."'),'N4',5,'Quantifiers and Limits','[{"ja":"殆どの学生が試験に合格した。","romaji":"Hotondo no gakusei ga shiken ni gōkaku shita.","en":"Almost all students passed the exam."},{"ja":"今日の仕事は殆ど終わりました。","romaji":"Kyō no shigoto wa hotondo owarimashita.","en":"Today''s work is almost finished."},{"ja":"彼は殆ど日本語を話さない。","romaji":"Kare wa hotondo nihongo o hanasanai.","en":"He hardly speaks any Japanese."},{"ja":"この町には外国人が殆どいません。","romaji":"Kono machi ni wa gaikokujin ga hotondo imasen.","en":"There are hardly any foreigners in this town."}]','[]','["adverb","quantity"]',175);
INSERT INTO grammar_points VALUES(176,'n4-sonna','そんな','sonna','Such a; that kind of; like that','そんな + Noun',unistr('「そんな」is a demonstrative adjective (連体詞 rentaishi) used to refer to something or someone that is "like that" or "such a" thing/person. It indicates that the speaker is referring to something previously mentioned, understood from context, or a general characteristic.\u000a\u000aIt often carries a nuance of surprise, disapproval, or strong feeling, but can also be used neutrally to simply describe something. It is part of the こ・そ・あ・ど series, similar to 「こんな」(this kind of) and 「あんな」(that kind of, far away).'),'N4',5,'Quantifiers and Limits','[{"ja":"そんなこと言わないで。","romaji":"Sonna koto iwanaide.","en":"Don''t say such a thing."},{"ja":"そんなに急がなくてもいいですよ。","romaji":"Sonna ni isoganakute mo ii desu yo.","en":"You don''t have to rush that much."},{"ja":"彼はそんな人じゃない。","romaji":"Kare wa sonna hito ja nai.","en":"He''s not that kind of person."},{"ja":"そんなに難しい問題じゃない。","romaji":"Sonna ni muzukashii mondai ja nai.","en":"It''s not such a difficult problem."}]','["n5-konna","n5-anna"]','["demonstrative","adjective"]',176);
INSERT INTO grammar_points VALUES(177,'n4-kaku','各（かく）','kaku','Each; every; respective','各 + Noun',unistr('「各（かく）」is a prefix or a word used before a noun to mean "each" or "every" individual item or group within a larger set. It emphasizes the individuality or distinctness of each member.\u000a\u000aIt is commonly used in formal contexts, official documents, or written language rather than casual conversation. It can be attached to various nouns, especially those referring to countries, schools, departments, or individuals.'),'N4',5,'Quantifiers and Limits','[{"ja":"各国の代表が集まった。","romaji":"Kakkoku no daihyou ga atsumatta.","en":"Representatives from each country gathered."},{"ja":"各自、自分の意見を述べてください。","romaji":"Kakuji, jibun no iken o nobete kudasai.","en":"Each person, please state your own opinion."},{"ja":"各クラスに新しい先生がいます。","romaji":"Kaku kurasu ni atarashii sensei ga imasu.","en":"There is a new teacher in each class."},{"ja":"各駅停車は時間がかかります。","romaji":"Kakuekiteisha wa jikan ga kakarimasu.","en":"Local trains (stopping at each station) take time."}]','[]','["prefix","quantifier"]',177);
INSERT INTO grammar_points VALUES(178,'n4-ijou-1','以上（いじょう） ①','ijou','More than; or more; above','Quantity + 以上',unistr('「以上（いじょう）」is used with numbers or quantities to indicate "more than or equal to" that specific amount. It sets a lower limit, meaning the value includes the stated number and everything greater than it.\u000a\u000aThis expression is frequently encountered in various contexts, such as age restrictions, minimum requirements, or statistical data. It is the opposite of 「以下（いか）」.'),'N4',5,'Quantifiers and Limits','[{"ja":"100人以上が参加した。","romaji":"Hyakunin ijou ga sanka shita.","en":"More than 100 people participated."},{"ja":"20歳以上の方しか入れません。","romaji":"Nijussai ijou no kata shika iremasen.","en":"Only people 20 years old or older can enter."},{"ja":"この仕事には3年以上の経験が必要です。","romaji":"Kono shigoto ni wa sannen ijou no keiken ga hitsuyou desu.","en":"This job requires more than 3 years of experience."},{"ja":"彼は毎日8時間以上勉強します。","romaji":"Kare wa mainichi hachijikan ijou benkyou shimasu.","en":"He studies more than 8 hours every day."}]','["n4-ika"]','["quantifier","expression"]',178);
INSERT INTO grammar_points VALUES(179,'n4-ika','以下（いか）','ika','Less than; or less; below','Quantity + 以下',unistr('「以下（いか）」is used with numbers or quantities to indicate "less than or equal to" that specific amount. It sets an upper limit, meaning the value includes the stated number and everything smaller than it.\u000a\u000aThis expression is commonly used for age limits, weight restrictions, or temperature ranges. It is the opposite of 「以上（いじょう）」.'),'N4',5,'Quantifiers and Limits','[{"ja":"10度以下になります。","romaji":"Juudo ika ni narimasu.","en":"It will drop below 10 degrees."},{"ja":"5歳以下のお子様は無料です。","romaji":"Gosai ika no okosama wa muryou desu.","en":"Children 5 years old or younger are free."},{"ja":"この荷物は10キロ以下でなければなりません。","romaji":"Kono nimotsu wa jukkiro ika de nakereba narimasen.","en":"This luggage must be 10 kilograms or less."},{"ja":"彼はいつも平均点以下です。","romaji":"Kare wa itsumo heikinten ika desu.","en":"He is always below the average score."}]','["n4-ijou-1"]','["quantifier","expression"]',179);
INSERT INTO grammar_points VALUES(180,'n4-igai','以外（いがい）','igai','Except for; other than; besides','Noun + 以外',unistr('「以外（いがい）」is used after a noun to mean "except for," "other than," or "besides" that specific noun. It indicates that everything else is included or applies, with the stated noun being the sole exclusion.\u000a\u000aThis grammar point is useful for specifying exceptions or highlighting what is different from a general rule or group. It can be used in various situations, from daily conversations to more formal statements.'),'N4',5,'Quantifiers and Limits','[{"ja":"日曜日以外は毎日働いています。","romaji":"Nichiyoubi igai wa mainichi hataraite imasu.","en":"I work every day except Sunday."},{"ja":"彼は日本語以外に英語も話せます。","romaji":"Kare wa Nihongo igai ni Eigo mo hanasemasu.","en":"Besides Japanese, he can also speak English."},{"ja":"この店は水曜日以外は開いています。","romaji":"Kono mise wa Suiyoubi igai wa aite imasu.","en":"This store is open every day except Wednesday."},{"ja":"私以外、誰もその秘密を知りません。","romaji":"Watashi igai, dare mo sono himitsu o shirimasen.","en":"No one knows that secret except me."}]','[]','["particle","expression"]',180);
INSERT INTO grammar_points VALUES(181,'n4-zutto-①','ずっと ①','zutto ①','Continuously; all the time; by far','ずっと + Verb/Adjective',unistr('「ずっと」 is an adverb with two primary uses. The first use indicates a continuous state or action over a long period, meaning "all the time," "continuously," or "for a long time." It emphasizes the uninterrupted nature of something.\u000a\u000aThe second common use of 「ずっと」 is for comparison, meaning "by far" or "much more." When used with comparative adjectives or phrases, it highlights a significant difference or superiority. For example, 「ずっと大きい」 means "much bigger" or "by far the biggest."'),'N4',5,'Quantifiers and Limits','[{"ja":"彼は昨日からずっとゲームをしている。","romaji":"Kare wa kinou kara zutto geemu o shite iru.","en":"He has been playing games continuously since yesterday."},{"ja":"この本はあの本よりずっと面白い。","romaji":"Kono hon wa ano hon yori zutto omoshiroi.","en":"This book is much more interesting than that book."},{"ja":"子供の時、ずっと犬が欲しかった。","romaji":"Kodomo no toki, zutto inu ga hoshikatta.","en":"When I was a child, I always wanted a dog."},{"ja":"富士山は他の山よりずっと高い。","romaji":"Fujisan wa hoka no yama yori zutto takai.","en":"Mt. Fuji is by far taller than other mountains."}]','[]','["adverb","duration","comparison"]',181);
INSERT INTO grammar_points VALUES(182,'n4-daitai','大体（だいたい）','daitai','Mostly; approximately; generally','大体 + Verb/Noun/Quantity',unistr('「大体（だいたい）」 is an adverb used to express approximation or generalization. It can mean "mostly," "approximately," "generally," or "for the most part." It implies that something is not exact or complete, but close enough or true in most cases.\u000a\u000aThis grammar point is useful when you want to convey a general idea without being precise, whether it''s about quantity, time, understanding, or the completion status of a task. It suggests a broad overview rather than specific details.'),'N4',5,'Quantifiers and Limits','[{"ja":"宿題はもう大体終わりました。","romaji":"Shukudai wa mou daitai owarimashita.","en":"My homework is mostly finished already."},{"ja":"会議には大体20人ぐらい参加しました。","romaji":"Kaigi ni wa daitai nijuunin gurai sanka shimashita.","en":"Approximately 20 people participated in the meeting."},{"ja":"彼の言っていることは大体理解できます。","romaji":"Kare no itteiru koto wa daitai rikai dekimasu.","en":"I can generally understand what he is saying."},{"ja":"この仕事は大体一週間でできます。","romaji":"Kono shigoto wa daitai isshuukan de dekimasu.","en":"This work can be done in about a week."}]','[]','["adverb","approximation"]',182);
INSERT INTO grammar_points VALUES(183,'n4-no-naka-de','の中（なか）で','naka de','In; inside; among; within','Noun + の中で',unistr('「〜の中で」 is a grammar pattern used to indicate a location, a group, or a scope. It literally means "inside of" when referring to a physical space, but it can also mean "among" a group of people or things, or "within" a certain category or timeframe.\u000a\u000aThe particle 「で」 following 「中（なか）」 specifies the location where an action takes place or the context within which something exists or occurs. It''s a versatile expression for defining boundaries, both concrete and abstract.'),'N4',5,'Quantifiers and Limits','[{"ja":"箱の中におもちゃがあります。","romaji":"Hako no naka ni omocha ga arimasu.","en":"There are toys inside the box."},{"ja":"クラスの中で、彼が一番背が高いです。","romaji":"Kurasu no naka de, kare ga ichiban se ga takai desu.","en":"Among the class, he is the tallest."},{"ja":"この一年の中で、色々なことがありました。","romaji":"Kono ichinen no naka de, iroiro na koto ga arimashita.","en":"Many things happened within this one year."},{"ja":"心の中で、いつもあなたを応援しています。","romaji":"Kokoro no naka de, itsumo anata o ouen shite imasu.","en":"In my heart, I''m always cheering for you."}]','[]','["noun","particle","location"]',183);
INSERT INTO grammar_points VALUES(184,'n4-you-ni-na','様（よう） + に・な','you ni na','Like; as if; in a way that; for the purpose of','Verb (casual) + ように\nNoun + のように\nい-Adjective + ように\n な-Adjective + なように\nVerb (casual) + ような + Noun\nNoun + のような + Noun\nい-Adjective + ような + Noun\n な-Adjective + なような + Noun',unistr('「〜ように」 and 「〜ような」 are versatile grammar patterns with several uses. 「〜ように」 functions adverbially, meaning "like," "as if," or "in a way that." It can also express a purpose or goal, translating to "so that" or "in order to." When expressing purpose, it often connects to verbs of effort or change, such as 「〜ようにする」 (to make an effort to) or 「〜ようになる」 (to become able to).\u000a\u000a「〜ような」 functions adjectivally, modifying a noun. It means "a noun like..." or "a noun that is similar to..." It''s used to describe the nature or characteristic of a noun by comparing it to something else. Both forms are crucial for expressing comparisons, similarities, and intentions in Japanese.'),'N4',5,'Quantifiers and Limits','[{"ja":"先生のように日本語が上手になりたい。","romaji":"Sensei no you ni nihongo ga jouzu ni naritai.","en":"I want to become good at Japanese like my teacher."},{"ja":"忘れないようにメモを取りました。","romaji":"Wasurenai you ni memo o torimashita.","en":"I took notes so that I wouldn''t forget."},{"ja":"彼女は鳥のような声で歌います。","romaji":"Kanojo wa tori no you na koe de utaimasu.","en":"She sings with a voice like a bird''s."},{"ja":"もっと日本語が話せるようになりたい。","romaji":"Motto nihongo ga hanaseru you ni naritai.","en":"I want to become able to speak Japanese more."}]','[]','["noun","adverb","comparison","purpose"]',184);
INSERT INTO grammar_points VALUES(185,'n4-amount-wa','(Amount) + は','amount wa','At least; as much as; as many as','Quantity/Amount + は',unistr('When the particle 「は」 is placed directly after a quantity or amount, it emphasizes that number, often implying it''s a minimum requirement or a surprisingly large quantity. It can convey the meaning of "at least" or "as much/many as."\u000a\u000aThis usage highlights the quantity as a topic of focus or a point of emphasis. It''s commonly used to express a lower limit that is considered necessary or to indicate that a certain amount is significant or unexpected.'),'N4',5,'Quantifiers and Limits','[{"ja":"このケーキは一人で二つは食べられる。","romaji":"Kono keeki wa hitori de futatsu wa taberareru.","en":"I can eat at least two of these cakes by myself."},{"ja":"毎日、三時間は日本語を勉強します。","romaji":"Mainichi, sanjikan wa nihongo o benkyou shimasu.","en":"I study Japanese for at least three hours every day."},{"ja":"このイベントには百人以上は来るでしょう。","romaji":"Kono ibento ni wa hyakunin ijou wa kuru deshou.","en":"At least over a hundred people will probably come to this event."},{"ja":"この本は一度は読んでおくべきだ。","romaji":"Kono hon wa ichido wa yonde oku beki da.","en":"You should read this book at least once."}]','[]','["particle","quantity","emphasis"]',185);
INSERT INTO grammar_points VALUES(186,'n4-nan-ka','何（なん） + (Counter) + か','nan ka','some; several; a few','何 + Counter + か',unistr('This pattern uses `何 (nan)` followed by a counter and `か` to indicate an unspecified, small quantity or number. It''s used when you don''t know the exact number, or you don''t want to specify it, but you want to convey that there is ''some'' or ''a few'' of something.\u000a\u000aIt''s similar to asking a question with `何 (nan)` + counter, but the addition of `か` turns it into an indefinite quantity. For example, `何人 (nannin)` means "how many people?", while `何人か (nannin ka)` means "some people" or "a few people".'),'N4',5,'Quantifiers and Limits','[{"ja":"何か月か日本にいました。","romaji":"Nankagetsu ka Nihon ni imashita.","en":"I was in Japan for several months."},{"ja":"何人か友達が来ます。","romaji":"Nannin ka tomodachi ga kimasu.","en":"A few friends are coming."},{"ja":"何回かその映画を見ました。","romaji":"Nankai ka sono eiga o mimashita.","en":"I watched that movie several times."},{"ja":"何時間か勉強しました。","romaji":"Nanjikan ka benkyō shimashita.","en":"I studied for a few hours."}]','["n4-shika-nai"]','["quantifier","counter"]',186);
INSERT INTO grammar_points VALUES(187,'n4-ma','真（ま）っ','ma','completely; truly; exactly','真（ま）っ + い形容詞 (stem) / Noun','`真（ま）っ` is a prefix used to emphasize the ','N4',5,'Quantifiers and Limits','[{"ja":"空が真っ青だ。","romaji":"Sora ga massao da.","en":"The sky is completely blue."},{"ja":"雪で道が真っ白になった。","romaji":"Yuki de michi ga masshiro ni natta.","en":"The road became completely white with snow."},{"ja":"部屋は真っ暗だった。","romaji":"Heya wa makkura datta.","en":"The room was pitch dark."},{"ja":"彼は真っ直ぐ家に帰った。","romaji":"Kare wa massugu ie ni kaetta.","en":"He went straight home."}]','[]','["prefix","adjective","adverb"]',187);
INSERT INTO grammar_points VALUES(188,'n4-shika-nai','(Number) + しか〜ない','shika nai','only; nothing but; no more than',unistr('Noun + しか + Verb (negative form)\u000aQuantity + しか + Verb (negative form)'),unistr('`しか` is a particle that always appears with a negative verb form at the end of the sentence. It expresses a sense of limitation, meaning "only" or "nothing but" the specified item or quantity.\u000a\u000aUnlike `だけ (dake)`, which simply states a quantity, `しか〜ない` implies that the amount is small or insufficient, or that the speaker wishes there were more. It often carries a nuance of regret or disappointment. For example, `500円だけあります (gohyaku en dake arimasu)` means "I have only 500 yen" (neutral statement), while `500円しかありません (gohyaku en shika arimasen)` means "I only have 500 yen" (implying it''s not enough or a small amount).'),'N4',5,'Quantifiers and Limits','[{"ja":"500円しかない。","romaji":"Gohyaku en shika nai.","en":"I only have 500 yen (and it''s not much)."},{"ja":"私は日本語しか話せません。","romaji":"Watashi wa Nihongo shika hanasemasen.","en":"I can only speak Japanese."},{"ja":"宿題はあと一つしか残っていない。","romaji":"Shukudai wa ato hitotsu shika nokotte inai.","en":"There''s only one homework assignment left."},{"ja":"今日はパンしか食べなかった。","romaji":"Kyō wa pan shika tabenakatta.","en":"I only ate bread today."}]','["n5-dake"]','["particle","negative expression","limitation"]',188);
INSERT INTO grammar_points VALUES(189,'n4-wa-no-hitotsu-da','は～の一（ひと）つだ','wa no hitotsu da','is one of the ~','Noun A + は + Noun B + の + 一つだ',unistr('This grammar pattern is used to state that a particular noun (Noun A) is one item or example among a larger group or category (Noun B). It highlights that Noun A is not unique but rather a member of a collection.\u000a\u000aWhen referring to people, `一人 (hitori)` is used instead of `一つ (hitotsu)`. For example, `彼はクラスで一番頭がいい学生の一人だ (Kare wa kurasu de ichiban atama ga ii gakusei no hitori da)` means "He is one of the smartest students in the class."'),'N4',5,'Quantifiers and Limits','[{"ja":"富士山は日本の美しい山の一つだ。","romaji":"Fujisan wa Nihon no utsukushii yama no hitotsu da.","en":"Mt. Fuji is one of Japan''s beautiful mountains."},{"ja":"読書は私の趣味の一つです。","romaji":"Dokushō wa watashi no shumi no hitotsu desu.","en":"Reading is one of my hobbies."},{"ja":"これは世界で最も古い都市の一つだ。","romaji":"Kore wa sekai de mottomo furui toshi no hitotsu da.","en":"This is one of the oldest cities in the world."},{"ja":"彼はクラスで一番頭がいい学生の一人だ。","romaji":"Kare wa kurasu de ichiban atama ga ii gakusei no hitori da.","en":"He is one of the smartest students in the class."}]','[]','["expression","noun phrase"]',189);
INSERT INTO grammar_points VALUES(190,'n4-nai-wa-nai','ない～はない','nai wa nai','it''s not that there isn''t; it''s possible',unistr('Verb (ない form) + ことは + ない\u000aい形容詞 (ない form) + ことは + ない\u000aな形容詞 (stem) + ではない + ことは + ない\u000aNoun + ではない + ことは + ない'),unistr('This is a double negative construction that softens a negative statement, implying that something *is* possible or *does* exist, even if it''s not ideal, common, or easy. It''s often used to express a reluctant or qualified affirmation.\u000a\u000aThe pattern literally means "it''s not that (something) is not..." which translates to "it is possible that..." or "it''s not impossible that...". It suggests a possibility or existence despite initial appearances or expectations. It can also be used to express a mild disagreement or a nuanced opinion.'),'N4',5,'Quantifiers and Limits','[{"ja":"行けないことはない。","romaji":"Ikenai koto wa nai.","en":"It''s not that I can''t go (it''s possible to go)."},{"ja":"食べられないことはないが、あまり好きじゃない。","romaji":"Taberarenai koto wa nai ga, amari suki janai.","en":"It''s not that I can''t eat it, but I don''t really like it."},{"ja":"難しくないことはないが、頑張ればできる。","romaji":"Muzukashikunai koto wa nai ga, ganbareba dekiru.","en":"It''s not that it''s not difficult, but if you try hard, you can do it."},{"ja":"彼の言うことが本当ではないことはない。","romaji":"Kare no iu koto ga hontō dewa nai koto wa nai.","en":"It''s not that what he says isn''t true (it might be true)."}]','[]','["double negative","expression","possibility"]',190);
INSERT INTO grammar_points VALUES(191,'n4-sukoshimo-nai','少（すこ）しも～ない','sukoshimo nai','Not even a little; not at all.',unistr('少（すこ）しも + Verb (ない-form)\u000a少（すこ）しも + I-adjective (く-form) + ない\u000a少（すこ）しも + Na-adjective (で-form) + はない\u000a少（すこ）しも + Noun + ではない'),unistr('The pattern `少（すこ）しも～ない` is used to emphasize a complete lack of something or a complete inability to do something. `少（すこ）しも` literally means "even a little bit," and when combined with a negative verb or adjective, it strongly conveys "not even a little bit" or "not at all."\u000a\u000aThis expression is often used to express strong denial, a complete absence, or to highlight that something is entirely different from what might be expected. It adds a strong sense of emphasis to the negative statement.'),'N4',5,'Quantifiers and Limits','[{"ja":"少しも分からない。","romaji":"sukoshimo wakaranai.","en":"I don''t understand at all."},{"ja":"彼は少しも日本語が話せない。","romaji":"kare wa sukoshimo nihongo ga hanasenai.","en":"He can''t speak Japanese at all."},{"ja":"この料理は少しも美味しくない。","romaji":"kono ryouri wa sukoshimo oishikunai.","en":"This dish is not delicious at all."},{"ja":"昨日は少しも眠れなかった。","romaji":"kinou wa sukoshimo nemurenakatta.","en":"I couldn''t sleep at all last night."}]','[]','["adverbial phrase","negation"]',191);
INSERT INTO grammar_points VALUES(192,'n4-sukunakunai','少（すく）なくない','sukunakunai','Not a few; quite a lot/many.',unistr('Verb (casual form) + ことは + 少（すく）なくない\u000aI-adjective (casual form) + ことは + 少（すく）なくない\u000aNa-adjective (casual form) + ことは + 少（すく）なくない\u000aNoun + は + 少（すく）なくない'),unistr('`少（すく）なくない` is the negative form of `少（すく）ない` (sukunai), which means "few" or "little." Therefore, `少（すく）なくない` literally translates to "not few" or "not little."\u000a\u000aThis expression is used to indicate that the quantity or number of something is actually quite large or significant, despite the literal negative phrasing. It''s a way of saying "many" or "a lot" with a slight nuance of understatement or emphasis. It is commonly used to express that something happens frequently or that there are many instances of a particular thing.'),'N4',5,'Quantifiers and Limits','[{"ja":"日本語を勉強する人は少なくない。","romaji":"nihongo o benkyou suru hito wa sukunakunai.","en":"There are quite a few people studying Japanese."},{"ja":"この町には外国人が少なくない。","romaji":"kono machi ni wa gaikokujin ga sukunakunai.","en":"There are quite a few foreigners in this town."},{"ja":"間違いをすることは少なくない。","romaji":"machigai o suru koto wa sukunakunai.","en":"It''s not uncommon to make mistakes. (People make mistakes quite often.)"},{"ja":"彼の意見に賛成する人は少なくないだろう。","romaji":"kare no iken ni sansei suru hito wa sukunakunai darou.","en":"There are probably quite a few people who agree with his opinion."}]','[]','["adjective","negation"]',192);
INSERT INTO grammar_points VALUES(193,'n4-baai-wa','場合（ばあい）は','baai wa','In the case of; in the event that.',unistr('Verb (casual form) + 場合（ばあい）は\u000aI-adjective (casual form) + 場合（ばあい）は\u000aNa-adjective (casual form) + な + 場合（ばあい）は\u000aNoun + の + 場合（ばあい）は'),unistr('`場合（ばあい）は` is used to specify a condition or a situation, similar to "if" or "in case of" in English. It sets up a scenario and then describes what should happen or what is true under that specific circumstance.\u000a\u000aThe verb, i-adjective, or na-adjective preceding `場合` must be in its casual (plain) form. For na-adjectives, `な` is added before `場合`. For nouns, `の` is added. This pattern is very common in instructions, warnings, and formal explanations where specific conditions lead to specific actions or outcomes.'),'N4',6,'Causative and Completion','[{"ja":"パスワードを忘れた場合は、こちらからご連絡ください。","romaji":"pasuwaado o wasureta baai wa, kochira kara gorenraku kudasai.","en":"If you forget your password, please contact us here."},{"ja":"火事の場合は、119をかけます。","romaji":"kaji no baai wa, hyakujuukyuu o kakemasu.","en":"In the event of a fire, call 119."},{"ja":"地震が起きた場合は、テーブルの下に潜ってください。","romaji":"jishin ga okita baai wa, teeburu no shita ni mogutte kudasai.","en":"In the case of an earthquake, please get under a table."},{"ja":"雨が降る場合は、試合は中止になります。","romaji":"ame ga furu baai wa, shiai wa chuushi ni narimasu.","en":"If it rains, the game will be canceled."}]','[]','["conditional","noun"]',193);
INSERT INTO grammar_points VALUES(194,'n4-te-yaru','～てやる','te yaru','To do a favor for someone (inferior/animal/plant); to do for.','Verb (て-form) + やる',unistr('The `～てやる` pattern is used when the speaker performs an action for someone else, implying that the recipient is of lower status, an animal, or a plant. It conveys a sense of doing a favor or providing a service.\u000a\u000aIt''s important to note that using `～てやる` for someone of equal or higher status can sound rude or condescending. For people of equal status, `～てあげる` is generally used, and for superiors, `～てさしあげる` or other honorifics are appropriate. While it literally means "to do for," the nuance is often "I''ll do it for you" or "I''ll give you the favor of doing X." It''s a casual expression, but its usage depends heavily on the social context and relationship between the speaker and the recipient.'),'N4',6,'Causative and Completion','[{"ja":"弟に宿題を手伝ってやる。","romaji":"otouto ni shukudai o tetsudatte yaru.","en":"I''ll help my younger brother with his homework."},{"ja":"犬に餌をやってやる。","romaji":"inu ni esa o yatte yaru.","en":"I''ll feed the dog."},{"ja":"庭の木に水をやってやる。","romaji":"niwa no ki ni mizu o yatte yaru.","en":"I''ll water the trees in the garden."},{"ja":"いいよ、僕がやってやるよ。","romaji":"ii yo, boku ga yatte yaru yo.","en":"It''s fine, I''ll do it for you. (casual, to a friend or junior)"}]','["n5-te-ageru","n4-te-kureru","n4-te-morau"]','["verb","giving/receiving verbs"]',194);
INSERT INTO grammar_points VALUES(195,'n4-te-yokatta','～てよかった','te yokatta','I''m glad that ~; It''s good that ~.',unistr('Verb (て-form) + よかった\u000aI-adjective (く-form) + て + よかった\u000aNa-adjective (で-form) + で + よかった\u000aNoun (で-form) + で + よかった'),unistr('The `～てよかった` pattern expresses relief, satisfaction, or happiness about a past event or situation. It literally means "it was good that..." or "I''m glad that...".\u000a\u000aThe verb preceding `よかった` must be in its `て-form`. For i-adjectives, the `い` is replaced with `くて`. For na-adjectives and nouns, `で` is used. This pattern can be used to express personal feelings or to comment on a situation that turned out well.'),'N4',6,'Causative and Completion','[{"ja":"行ってよかった！","romaji":"itte yokatta!","en":"I''m glad I went!"},{"ja":"これを買ってよかった。","romaji":"kore o katte yokatta.","en":"I''m glad I bought this."},{"ja":"あなたと出会えてよかった。","romaji":"anata to deaete yokatta.","en":"I''m glad I was able to meet you."},{"ja":"間に合ってよかったですね。","romaji":"maniaete yokatta desu ne.","en":"I''m glad you made it in time, aren''t you?"}]','[]','["expression","emotion"]',195);
INSERT INTO grammar_points VALUES(196,'n4-せるさせる','せる・させる (Causative)','seru saseru (causative)','To make/let/have (someone do something)',unistr('Group 1 Verb (う-ending) + せる\u000aGroup 2 Verb (る-ending) + させる\u000aGroup 3 Verb (する) + させる\u000aGroup 3 Verb (来る) + 来させる (こさせる)'),unistr('The causative form `せる・させる` is used to express that someone makes or lets another person do something. There are two main nuances: \u000a\u000a1.  **Making/Forcing (強制 - kyōsei)**: This implies that the subject forces or makes someone do an action. The particle `に` is used to mark the person who is made to do the action (e.g., 先生は学生に本を読ませた - The teacher made the students read books).\u000a\u000a2.  **Letting/Permitting (許可 - kyoka)**: This implies that the subject allows or permits someone to do an action. Again, the particle `に` marks the person who is allowed to do the action (e.g., 母親は子供にテレビを見させた - The mother let her child watch TV). The context usually clarifies which nuance is intended.'),'N4',6,'Causative and Completion','[{"ja":"先生は学生に作文を書かせた。","romaji":"Sensei wa gakusei ni sakubun o kakaseta.","en":"The teacher made the students write essays."},{"ja":"母は私に部屋を掃除させた。","romaji":"Haha wa watashi ni heya o sōji saseta.","en":"My mother made me clean my room."},{"ja":"私は子供に好きなだけ遊ばせた。","romaji":"Watashi wa kodomo ni suki na dake asobaseta.","en":"I let my children play as much as they wanted."},{"ja":"上司は私に残業させた。","romaji":"Jōshi wa watashi ni zangyō saseta.","en":"My boss made me work overtime."}]','[]','["verb conjugation","causative"]',196);
INSERT INTO grammar_points VALUES(197,'n4-と言ってもいい','と言（い）ってもいい','to itte mo ii','You could say; one might say; it''s fair to say',unistr('Verb (Casual) + と言ってもいい\u000aい-Adjective + と言ってもいい\u000aな-Adjective + だ + と言ってもいい\u000aNoun + だ + と言ってもいい'),unistr('`と言ってもいい` is a phrase used to express a strong opinion or conclusion, often with the nuance that it wouldn''t be an exaggeration to say something, or that it''s almost certainly true. It''s like saying "it''s safe to say" or "you could even call it..."\u000a\u000aThis expression can be used to emphasize a point or to present a conclusion that the speaker feels confident about. It often appears with `でしょう` or `だろう` at the end to soften the statement slightly or add a touch of speculation, making it sound more like a suggestion than a definitive declaration.'),'N4',6,'Causative and Completion','[{"ja":"それはよい買い物だったと言ってもいいでしょう。","romaji":"Sore wa yoi kaimono datta to itte mo ii deshō.","en":"I''d say it was a good buy."},{"ja":"彼はやさしいが，だまされやすいと言ってもいい。","romaji":"Kare wa yasashii ga, damasareyasui to itte mo ii.","en":"He''s a kind person, but you could say he''s easily deceived."},{"ja":"それはいい考えだ。いや，すばらしいと言ってもいいだろう。","romaji":"Sore wa ii kangae da. Iya, subarashii to itte mo ii darō.","en":"That''s a good idea. No, I''d even say it''s brilliant."},{"ja":"彼女はもうプロの歌手と言ってもいいレベルだ。","romaji":"Kanojo wa mō puro no kashu to itte mo ii reberu da.","en":"Her level is such that you could say she''s already a professional singer."}]','["n4-temodemo"]','["expression","phrase"]',197);
INSERT INTO grammar_points VALUES(198,'n4-てもでも','～ても・でも','temo demo','Even if; even though; no matter (what/who/when)',unistr('Verb (て-form) + も\u000aい-Adjective (く-form) + ても\u000aな-Adjective (で-form) + も\u000aNoun + でも'),unistr('`～ても・でも` is used to express a concession, meaning "even if" or "even though." It indicates that despite a certain condition or situation (the first clause), the action or state in the second clause still occurs or is true. It can be used for both hypothetical conditions and factual concessions.\u000a\u000aThis pattern can also be combined with interrogative words (e.g., どこ, だれ, いつ, 何) to mean "no matter where/who/when/what." For example, `どこへ行っても` means "no matter where I go" or "wherever I go." The choice between `ても` and `でも` depends on the part of speech preceding it, following the rules for forming the て-form (for verbs and い-adjectives) or で-form (for な-adjectives and nouns).'),'N4',6,'Causative and Completion','[{"ja":"雨が降っても行きます。","romaji":"Ame ga futte mo ikimasu.","en":"I''ll go even if it rains."},{"ja":"どんなに忙しくても、毎日日本語を勉強します。","romaji":"Donna ni isogashikute mo, mainichi nihongo o benkyō shimasu.","en":"No matter how busy I am, I study Japanese every day."},{"ja":"この料理は辛くても美味しいです。","romaji":"Kono ryōri wa karakute mo oishii desu.","en":"Even if this dish is spicy, it''s delicious."},{"ja":"子供でも、このゲームは難しいです。","romaji":"Kodomo demo, kono gēmu wa muzukashii desu.","en":"Even for a child, this game is difficult."}]','["n4-noni"]','["conjunction","particle"]',198);
INSERT INTO grammar_points VALUES(199,'n4-てしまう','～てしまう','te shimau','To finish completely; to do by accident/regretfully','Verb (て-form) + しまう',unistr('`～てしまう` is an auxiliary verb that attaches to the て-form of a verb, conveying two main nuances:\u000a\u000a1.  **Completion**: It indicates that an action has been completed thoroughly or entirely. For example, `読んでしまう` means to finish reading completely, and `食べてしまう` means to eat something all up. This usage often implies a sense of finality.\u000a\u000a2.  **Regret, Accident, or Trouble**: It can express that an action happened unintentionally, or with a sense of regret, embarrassment, or trouble. For instance, `忘れてしまった` means "I forgot it (unfortunately/by accident)," and `なくしてしまった` means "I lost it (regretfully)." In casual speech, `～てしまう` often contracts to `～ちゃう` (e.g., `食べちゃう`) and `～でしまう` contracts to `～じゃう` (e.g., `飲んじゃう`).'),'N4',6,'Causative and Completion','[{"ja":"宿題を忘れてしまった。","romaji":"Shukudai o wasurete shimatta.","en":"I accidentally forgot my homework."},{"ja":"ケーキを全部食べてしまった。","romaji":"Kēki o zenbu tabete shimatta.","en":"I ate all the cake."},{"ja":"財布をなくしてしまって、困っている。","romaji":"Saifu o nakushite shimatte, komatte iru.","en":"I lost my wallet and I''m in trouble."},{"ja":"この本はもう読んでしまった。","romaji":"Kono hon wa mō yonde shimatta.","en":"I have already finished reading this book."}]','["n4-teoku"]','["auxiliary verb","completion","regret"]',199);
INSERT INTO grammar_points VALUES(200,'n4-て-200','～て (Reasons and Causes)','te (reasons and causes)','Because of; due to; and (as a result)',unistr('Verb (て-form) + (Sentence)\u000aい-Adjective (く-form) + て + (Sentence)\u000aい-Adjective (～くて) + (Sentence)\u000aな-Adjective (で-form) + (Sentence)\u000aNoun + で + (Sentence)'),unistr('The `～て` form can be used to connect two clauses where the first clause indicates the reason or cause for the second clause. This usage is common when expressing natural phenomena, feelings, or situations that are not directly controlled by the speaker''s will.\u000a\u000aUnlike `～から` or `～ので`, the `～て` form for reasons and causes cannot be used with volitional, imperative, or strong requests in the second clause. It often describes a cause-and-effect relationship where the result is a natural consequence or an emotional reaction. It can also simply connect a sequence of events, but when expressing cause, it implies a more direct and often less subjective link than `から`.'),'N4',6,'Causative and Completion','[{"ja":"風邪を引いて会社を休みました。","romaji":"Kaze o hiite kaisha o yasumimashita.","en":"I caught a cold, so I took a day off work."},{"ja":"頭が痛くて、学校に行けません。","romaji":"Atama ga itakute, gakkō ni ikemasen.","en":"Because my head hurts, I can''t go to school."},{"ja":"道が混んでいて、遅刻しました。","romaji":"Michi ga konde ite, chikoku shimashita.","en":"Because the road was crowded, I was late."},{"ja":"嬉しくて、涙が出ました。","romaji":"Ureshikute, namida ga demashita.","en":"I was so happy that tears came out."}]','["n5-kara","n4-node"]','["conjunction","particle"]',200);
INSERT INTO grammar_points VALUES(201,'n4-させられる','させられる (Causative-Passive)','saserareru (causative-passive)','To be made/forced to do; to be allowed to do',unistr('Group 1 Verb (ない form) + される\u000aGroup 2 Verb (ない form) + させられる\u000aGroup 3 Verb (する -> させられる, 来る -> 来させられる)'),unistr('The causative-passive form combines the causative (making someone do something) and the passive (being acted upon) voices. It expresses that the speaker or subject is *made* or *forced* to do an action by someone else, often implying a feeling of burden, inconvenience, or suffering. It can also, less commonly, express being *allowed* to do something, but the primary N4 usage focuses on being compelled.\u000a\u000aTo form the causative-passive, first change the verb to its causative form (e.g., 書く -> 書かせる, 食べる -> 食べさせる). Then, change the causative verb into its passive form (e.g., 書かせる -> 書かされる, 食べさせる -> 食べさせられる). Note the irregular forms for Group 3 verbs: する becomes させられる, and 来る becomes 来させられる.\u000a\u000aThis grammar point is crucial for expressing situations where one''s actions are not entirely voluntary. The agent who forces the action is marked with 「に」, similar to the passive voice.'),'N4',6,'Causative and Completion','[{"ja":"仕事を辞めさせられた。","romaji":"shigoto o yamesaserareta.","en":"I was forced to quit my job."},{"ja":"息子は先生に宿題をさせられた。","romaji":"musuko wa sensei ni shukudai o saserareta.","en":"My son was made to do his homework by the teacher."},{"ja":"彼女に2時間も待たせられた。","romaji":"kanojo ni ni-jikan mo mataserareta.","en":"She made me wait for over two hours (I was forced to wait)."},{"ja":"その映画は私に人生について考えさせられる。","romaji":"sono eiga wa watashi ni jinsei ni tsuite kangaesaserareru.","en":"That movie makes me think about life."}]','["n4-させる","n5-れる"]','["verb conjugation","passive voice","causative"]',201);
INSERT INTO grammar_points VALUES(202,'n4-て-202','～て (Means and Manner)','te (means and manner)','By means of; using; with; by (doing)','Verb (て-form)',unistr('The て-form of a verb can be used to connect two clauses, where the first clause describes the means, method, or manner by which the action in the second clause is performed. It answers the question "How?" or "By what means?".\u000a\u000aThis usage of the て-form is distinct from simply listing sequential actions. Here, the action in the first clause is instrumental to the action in the second clause. For example, 「バスに乗って学校に行く」 means going to school *by means of* riding a bus.\u000a\u000aWhile similar meanings can sometimes be expressed with the particle 「で」 (e.g., 「バスで学校に行く」), the て-form allows for more complex actions or states to describe the means. It''s a versatile way to show how one action facilitates another.'),'N4',6,'Causative and Completion','[{"ja":"バスに乗って学校に行きます。","romaji":"basu ni notte gakkou ni ikimasu.","en":"I go to school by bus."},{"ja":"箸を使ってご飯を食べます。","romaji":"hashi o tsukatte gohan o tabemasu.","en":"I eat rice using chopsticks."},{"ja":"歩いて駅まで行きました。","romaji":"aruite eki made ikimashita.","en":"I walked to the station."},{"ja":"走って間に合った。","romaji":"hashitte maniaatta.","en":"I made it on time by running."}]','["n5-て"]','["verb conjugation","conjunction"]',202);
INSERT INTO grammar_points VALUES(203,'n4-てある','～てある','te aru','Something has been done (and the result remains); a state resulting from an intentional action','Transitive Verb (て-form) + ある',unistr('The grammar pattern 「～てある」 describes a state that exists as a result of a deliberate, intentional action performed by someone. It emphasizes that an action has been completed, and its resulting state is still present, often implying preparation or a specific purpose.\u000a\u000aThis pattern is typically used with transitive verbs (verbs that take a direct object). The subject of the sentence with 「～てある」 is usually the object of the original transitive verb. For example, if someone hung a picture (絵をかける), then the picture *has been hung* (絵がかけてある).\u000a\u000aIt''s important to distinguish 「～てある」 from 「～ている」 and 「～ておく」. While 「～ている」 can describe an ongoing action or a natural state, 「～てある」 specifically refers to a state resulting from a purposeful human action. 「～ておく」 means to do something in advance for a future purpose, whereas 「～てある」 describes the *resultant state* of such an action.'),'N4',6,'Causative and Completion','[{"ja":"壁に絵がかけてある。","romaji":"kabe ni e ga kakete aru.","en":"A picture has been hung on the wall."},{"ja":"窓が開けてある。","romaji":"mado ga akete aru.","en":"The window has been opened (by someone)."},{"ja":"テーブルの上に本が置いてある。","romaji":"teeburu no ue ni hon ga oite aru.","en":"A book has been placed on the table."},{"ja":"夕食が作ってある。","romaji":"yuushoku ga tsukutte aru.","en":"Dinner has been prepared."}]','["n4-ておく","n5-ている"]','["verb conjugation","state","transitive verb"]',203);
INSERT INTO grammar_points VALUES(204,'n4-様にて欲しい','様（よう）に～て欲（ほ）しい','you ni te hoshii','Want (someone) to make it so that; want (someone) to try to',unistr('Verb (辞書形/ない形) + ように + してほしい\u000aVerb (可能形) + ように + してほしい'),unistr('The pattern 「～ようにしてほしい」 expresses a desire for someone else to *make an effort* or *take action* to achieve a certain state or outcome. It''s a request or wish for someone to *try* to bring about a particular situation or to *ensure* that something happens.\u000a\u000aThis structure is formed by combining 「～ように」 (indicating a goal or manner) with 「～てほしい」 (expressing a desire for someone to do something). The 「て」 in the title refers to the て-form of the verb 「する」, resulting in 「してほしい」. So, it literally means "I want you to do it in such a way that..." or "I want you to make it so that...".\u000a\u000aIt''s stronger than a simple 「～てほしい」 because it implies a more active role or responsibility on the part of the person being addressed to facilitate the desired outcome. It can be used to ask someone to improve, to ensure something, or to enable a certain condition.'),'N4',6,'Causative and Completion','[{"ja":"もっと日本語が上手になるようにしてほしい。","romaji":"motto nihongo ga jouzu ni naru you ni shite hoshii.","en":"I want you to make an effort to improve your Japanese."},{"ja":"みんなが幸せになるようにしてほしい。","romaji":"minna ga shiawase ni naru you ni shite hoshii.","en":"I want everyone to try to be happy."},{"ja":"この問題が解決できるようにしてほしい。","romaji":"kono mondai ga kaiketsu dekiru you ni shite hoshii.","en":"I want you to make it so that this problem can be solved."},{"ja":"彼がもっと早く来るようにしてほしい。","romaji":"kare ga motto hayaku kuru you ni shite hoshii.","en":"I want you to make him come earlier."}]','["n5-てほしい","n4-ように"]','["desire","request"]',204);
INSERT INTO grammar_points VALUES(205,'n4-ている間に','～ている間（あいだ）に','te iru aida ni','While; during the time that (something else happens)',unistr('Verb (て-form) + いる + 間に\u000aNoun + の + 間に\u000aい-Adjective + 間に\u000aな-Adjective + な + 間に'),unistr('The pattern 「～ている間に」 indicates that a new action or event occurs *at some point within* the duration of an ongoing action or state. The first clause describes a continuous action or state, and the second clause describes a distinct event that takes place during that period.\u000a\u000aThis grammar point emphasizes that the second event is a single occurrence or a short-term action that happens *during* the longer, continuous activity of the first clause. The particle 「に」 is crucial here, as it specifies that the event happens *at a point* within the duration.\u000a\u000aIt''s important to differentiate this from 「～間（あいだ）」 (without 「に」), which implies that the second action or state continues *throughout the entire duration* of the first. With 「～ている間に」, the second event is typically shorter or more sudden, interrupting or simply occurring within the timeframe of the first.'),'N4',6,'Causative and Completion','[{"ja":"寝ている間に雪が降った。","romaji":"nete iru aida ni yuki ga futta.","en":"It snowed while I was sleeping."},{"ja":"母が買い物に行っている間に、宿題を終わらせた。","romaji":"haha ga kaimono ni itte iru aida ni, shukudai o owaraseta.","en":"While my mother was out shopping, I finished my homework."},{"ja":"先生が話している間に、メモを取った。","romaji":"sensei ga hanashite iru aida ni, memo o totta.","en":"I took notes while the teacher was speaking."},{"ja":"彼がいない間に、部屋を掃除した。","romaji":"kare ga inai aida ni, heya o souji shita.","en":"While he was away, I cleaned the room."}]','["n4-間"]','["time expression","conjunction"]',205);
INSERT INTO grammar_points VALUES(206,'n4-nakutemoii','なくてもいい','nakutemoii','Don''t have to; it''s okay not to','Verb (ない形) + なくてもいい',unistr('The grammar pattern 「なくてもいい」 is used to express that an action is not necessary or that it is acceptable not to do something. It literally means "even if you don''t do X, it''s good/okay."\u000a\u000aTo form this, take a verb''s negative (ない) form, remove the final 「い」, and add 「くてもいい」. For example, 「行く (iku)」 becomes 「行かない (ikanai)」, then 「行かなくてもいい (ikanakutemo ii)」. This pattern is commonly used in daily conversation to give permission not to do something or to state that something is not required.\u000a\u000aIt''s important to distinguish this from 「～てはいけない」 (must not do) or 「～なければならない」 (must do). While those express obligation or prohibition, 「なくてもいい」 expresses the *lack* of obligation. It offers a choice or states that an action is optional.'),'N4',6,'Causative and Completion','[{"ja":"明日は来なくてもいいです。","romaji":"ashita wa konakutemo ii desu.","en":"You don''t have to come tomorrow."},{"ja":"全部食べなくてもいいですよ。","romaji":"zenbu tabenakutemo ii desu yo.","en":"You don''t have to eat everything."},{"ja":"急がなくてもいいから、ゆっくり来てね。","romaji":"isoganakutemo ii kara, yukkuri kite ne.","en":"You don''t have to rush, so please come slowly."},{"ja":"この宿題は出さなくてもいいです。","romaji":"kono shukudai wa dasanakutemo ii desu.","en":"You don''t have to submit this homework."}]','[]','["verb form","necessity","permission"]',206);
INSERT INTO grammar_points VALUES(207,'n4-temiru','～てみる','temiru','to try doing ~; to try out ~','Verb (て形) + みる',unistr('The grammar pattern 「～てみる」 is used to express the idea of "trying to do something" or "doing something to see what happens." It implies an experimental or exploratory action, often with the nuance of giving something a shot or experiencing it.\u000a\u000aThis pattern is formed by taking the て-form of a verb and attaching 「みる」. For example, 「食べる (taberu)」 becomes 「食べてみる (tabete miru)」 (to try eating). The verb 「みる」 here is an auxiliary verb, not the literal verb "to see."\u000a\u000aIt can be used when you want to try a new experience, test a method, or simply give an action a go. It conveys a sense of curiosity or a willingness to attempt something, even if the outcome is uncertain.'),'N4',6,'Causative and Completion','[{"ja":"やってみる！","romaji":"yatte miru!","en":"I''ll give it a shot! / Here goes nothing!"},{"ja":"これを使ってみる。","romaji":"kore o tsukatte miru.","en":"I''ll try using this."},{"ja":"やってみないと分からない。","romaji":"yatte minai to wakaranai.","en":"You''ll never know until you try."},{"ja":"いつか海外に行ってみたいな。","romaji":"itsuka kaigai ni itte mitai na.","en":"One day I''d like to try going abroad."}]','[]','["verb form","auxiliary verb","attempt"]',207);
INSERT INTO grammar_points VALUES(208,'n4-tesumimasen','～てすみません','tesumimasen','I''m sorry for ~ing; Excuse me for ~ing','Verb (て形) + すみません',unistr('The grammar pattern 「～てすみません」 is used to apologize for an action that has been done. It directly translates to "I''m sorry for doing X" or "Excuse me for doing X."\u000a\u000aTo form this, take the て-form of a verb and attach 「すみません」. For example, 「遅れる (okureru)」 (to be late) becomes 「遅れてすみません (okurete sumimasen)」 (I''m sorry for being late).\u000a\u000aThis expression is a polite way to acknowledge a mistake or inconvenience caused by one''s actions. It is commonly used in various situations, from minor apologies to more significant ones, and can be made more formal by using 「～て申し訳ありません (te mōshiwake arimasen)」.'),'N4',6,'Causative and Completion','[{"ja":"遅れてすみません。","romaji":"okurete sumimasen.","en":"I''m sorry for being late."},{"ja":"待たせてすみません。","romaji":"matasete sumimasen.","en":"I''m sorry for making you wait."},{"ja":"ご迷惑をおかけしてすみません。","romaji":"gomeiwaku o okakeshite sumimasen.","en":"I''m sorry for causing you trouble."},{"ja":"連絡が遅くなってすみません。","romaji":"renraku ga osoku natte sumimasen.","en":"I''m sorry for the late contact."}]','[]','["verb form","apology"]',208);
INSERT INTO grammar_points VALUES(209,'n4-teageru','～てあげる','teageru','to do something for someone (from speaker''s perspective)','Verb (て形) + あげる',unistr('The grammar pattern 「～てあげる」 is one of the giving and receiving verbs, indicating that the speaker (or the subject of the sentence) performs an action for the benefit of someone else. It literally means "to do X and give it (as a favor)."\u000a\u000aTo form this, take the て-form of a verb and attach 「あげる」. For example, 「教える (oshieru)」 (to teach) becomes 「教えてあげる (oshiete ageru)」 (to teach someone).\u000a\u000aThis pattern is used when the action is directed *away* from the speaker or the speaker''s inner circle. It implies that the recipient benefits from the action. While it can sometimes sound like the speaker is doing a favor, it''s generally used neutrally to describe an action done for another person. However, using it when talking to superiors or strangers might sound presumptuous, so politeness levels should be considered.'),'N4',7,'Giving and Receiving','[{"ja":"母にセーターを買ってあげた。","romaji":"haha ni seetaa o katte ageta.","en":"I bought my mother a sweater."},{"ja":"いいよ，僕がやってあげるよ。","romaji":"iiyo, boku ga yatte ageru yo.","en":"No problem, I''ll do it for you."},{"ja":"車に君を乗せてあげる。","romaji":"kuruma ni kimi o nosete ageru.","en":"I''ll give you a ride (by car)."},{"ja":"君に見せてあげたかったよ。","romaji":"kimi ni misete agetakatta yo.","en":"I wanted to show it to you."}]','["n4-tekureru","n4-temorau"]','["verb form","giving/receiving verbs","favor"]',209);
INSERT INTO grammar_points VALUES(210,'n4-tekureru','～てくれる','tekureru','someone does something for me/us (from receiver''s perspective)','Verb (て形) + くれる',unistr('The grammar pattern 「～てくれる」 is another giving and receiving verb, indicating that someone performs an action for the benefit of the speaker or someone in the speaker''s inner circle. It literally means "to do X and give it (to me/us)."\u000a\u000aTo form this, take the て-form of a verb and attach 「くれる」. For example, 「手伝う (tetsudau)」 (to help) becomes 「手伝ってくれる (tetsudatte kureru)」 (someone helps me/us).\u000a\u000aThis pattern is used when the action is directed *towards* the speaker or someone close to them. It expresses gratitude or acknowledges that an action was done for one''s benefit. Unlike 「～てあげる」, which focuses on the giver''s action, 「～てくれる」 focuses on the recipient''s benefit. It is a very common and natural way to express that someone did something helpful for you.'),'N4',7,'Giving and Receiving','[{"ja":"手伝ってくれる？","romaji":"tetsudatte kureru?","en":"Will you help me?"},{"ja":"彼ならやってくれる。","romaji":"kare nara yatte kureru.","en":"We can count on him to help us."},{"ja":"母は僕に毎日弁当を作ってくれる。","romaji":"haha wa boku ni mainichi bentō o tsukutte kureru.","en":"My mom makes my bento lunch for me every day."},{"ja":"手を貸してくれますか？","romaji":"te o kashite kuremasu ka?","en":"Will you please help me out?"}]','["n4-teageru","n4-temorau"]','["verb form","giving/receiving verbs","favor"]',210);
INSERT INTO grammar_points VALUES(211,'n4-てもらう','～てもらう','temorau','To get someone to do something for you; to have a favor done.','Verb て-form + もらう',unistr('This pattern expresses that the speaker (or someone in the speaker''s in-group) receives a favor from someone else. The person performing the action is marked with the particle 「に」. It implies gratitude or that the action was beneficial to the receiver.\u000a\u000aIt''s a common way to ask for or describe receiving help. The nuance is that the action was done *for* the speaker, and the speaker is the beneficiary. This contrasts with 「～てあげる」 (speaker does for others) and 「～てくれる」 (others do for speaker, with focus on the giver''s kindness).'),'N4',7,'Giving and Receiving','[{"ja":"先生に日本語を教えてもらいました。","romaji":"sensei ni nihongo o oshiete moraimashita.","en":"I had my teacher teach me Japanese."},{"ja":"友達に荷物を持ってもらいました。","romaji":"tomodachi ni nimotsu o motte moraimashita.","en":"I had my friend carry my luggage."},{"ja":"医者に見てもらう必要があります。","romaji":"isha ni mite morau hitsuyou ga arimasu.","en":"I need to have a doctor look at it."},{"ja":"彼女に手伝ってもらって、宿題が終わりました。","romaji":"kanojo ni tetsudatte moratte, shukudai ga owarimashita.","en":"I had her help me, and I finished my homework."}]','["n4-てあげる","n4-てくれる"]','["giving/receiving verb","favor"]',211);
INSERT INTO grammar_points VALUES(212,'n4-なさい','なさい','nasai','Do (a soft but firm command, often from superior to inferior).','Verb ます-stem + なさい',unistr('「なさい」 is a command form that is softer than the plain imperative form (e.g., 「食べろ」), but still carries a sense of instruction or order. It is typically used by a superior to an inferior, such as a parent to a child, a teacher to a student, or a boss to an employee.\u000a\u000aIt implies a gentle but firm expectation for the action to be performed. While it''s a command, it''s less direct and harsh than the plain imperative, making it suitable for guidance or advice given from a position of authority.'),'N4',7,'Giving and Receiving','[{"ja":"早く宿題をしなさい。","romaji":"hayaku shukudai o shinasai.","en":"Do your homework quickly."},{"ja":"ちゃんと野菜を食べなさい。","romaji":"chanto yasai o tabenasai.","en":"Eat your vegetables properly."},{"ja":"静かにしなさい！","romaji":"shizuka ni shinasai!","en":"Be quiet!"},{"ja":"先生の話をよく聞きなさい。","romaji":"sensei no hanashi o yoku kikanasai.","en":"Listen carefully to the teacher''s talk."}]','["n5-てください","n4-な"]','["command","imperative"]',212);
INSERT INTO grammar_points VALUES(213,'n4-て-213','～て (Non-Sequence)','te (non-sequence)','And; but; because; state/reason (connecting clauses without strict sequence).',unistr('Verb て-form + Clause 2\u000aい-Adjective (-い) + くて + Clause 2\u000aな-Adjective (-な) + で + Clause 2\u000aNoun + で + Clause 2'),unistr('The て-form can connect clauses in various ways beyond just indicating a sequence of actions. It can show a reason or cause, a contrasting relationship, or simply list parallel states or characteristics. When used for reason, it implies that the first clause is the cause or reason for the second clause.\u000a\u000aWhen connecting adjectives or nouns, it functions like "and" or "but," describing multiple characteristics or states of a single subject. For example, 「背が高くて、かっこいい」 (tall and cool). It''s important to understand the context to grasp the exact relationship between the clauses, as the て-form is highly versatile.'),'N4',7,'Giving and Receiving','[{"ja":"兄は背が高くて、弟は背が低い。","romaji":"ani wa se ga takakute, otouto wa se ga hikui.","en":"My older brother is tall, but my younger brother is short."},{"ja":"寒くて、外に出たくない。","romaji":"samukute, soto ni detakunai.","en":"It''s cold, so I don''t want to go outside."},{"ja":"彼は親切で、いつも助けてくれる。","romaji":"kare wa shinsetsu de, itsumo tasukete kureru.","en":"He is kind and always helps me."},{"ja":"この本は面白くて、読みやすいです。","romaji":"kono hon wa omoshirokute, yomiyasui desu.","en":"This book is interesting and easy to read."}]','["n5-て","n4-から"]','["conjunction","clause connector","reason"]',213);
INSERT INTO grammar_points VALUES(214,'n4-ないで-214','ないで (Casual Request)','naide (casual request)','Please don''t do (something); without doing (something).','Verb ない-form (-い) + で',unistr('「ないで」 has two main uses. The first is to make a casual negative request, meaning "please don''t do X." It''s a softer way to tell someone not to do something compared to the plain negative imperative 「～な」. It''s often used among friends or family, or when the speaker wants to sound less formal than 「～ないでください」.\u000a\u000aThe second use is to indicate that an action is performed *without* doing another action, or that a state exists *without* a certain action occurring. In this case, it functions similarly to 「～ずに」, but 「ないで」 is more common in casual speech.'),'N4',7,'Giving and Receiving','[{"ja":"心配しないでください。","romaji":"shinpai shinaide kudasai.","en":"Please don''t worry."},{"ja":"ここで写真を撮らないでください。","romaji":"koko de shashin o toranaide kudasai.","en":"Please don''t take pictures here."},{"ja":"傘を持たないで出かけました。","romaji":"kasa o motanaide dekakemashita.","en":"I went out without taking an umbrella."},{"ja":"勉強しないで試験を受けた。","romaji":"benkyou shinaide shiken o uketa.","en":"I took the exam without studying."}]','["n5-ないでください","n4-ずに"]','["negative request","conjunction"]',214);
INSERT INTO grammar_points VALUES(215,'n4-てくれてありがとう','～てくれてありがとう','tekurete arigatou','Thank you for doing (something) for me/us.','Verb て-form + くれてありがとう',unistr('This expression is used to thank someone for doing a favor or performing an action that benefits the speaker or the speaker''s in-group. The 「てくれる」 part indicates that the action was performed *for* the speaker, and 「ありがとう」 expresses gratitude.\u000a\u000aIt''s a very common and polite way to express thanks for specific actions. The person who performed the action is often implied or can be explicitly stated with 「が」 or 「は」 (though 「が」 is more common when specifying the doer of the favor). This structure emphasizes the kindness of the person who performed the action.'),'N4',7,'Giving and Receiving','[{"ja":"手伝ってくれてありがとう。","romaji":"tetsudatte kurete arigatou.","en":"Thank you for helping me."},{"ja":"荷物を持ってきてくれてありがとう。","romaji":"nimotsu o motte kite kurete arigatou.","en":"Thank you for bringing my luggage."},{"ja":"私の誕生日を覚えていてくれてありがとう。","romaji":"watashi no tanjoubi o oboete ite kurete arigatou.","en":"Thank you for remembering my birthday."},{"ja":"困っている時に助けてくれてありがとう。","romaji":"komatte iru toki ni tasukete kurete arigatou.","en":"Thank you for helping me when I was in trouble."}]','["n4-てあげる","n4-てくれる","n4-てもらう"]','["giving/receiving verb","gratitude","expression"]',215);
INSERT INTO grammar_points VALUES(216,'n4-て-くれない','～て + くれない','て + kurenai','Won''t you do ~ for me? (casual request)','Verb て-form + くれない',unistr('「～てくれない」 is a casual way to ask someone to do something for you. It''s a direct request, often used among friends or family, and can sometimes imply a slight expectation or impatience, similar to "Won''t you do X for me?" or "Can''t you do X for me?".\u000a\u000aIt is the casual form of 「～てくれませんか」. While 「～てくれませんか」 is polite, 「～てくれない」 drops the politeness marker 「～ませんか」 to become more informal. It''s important to use this form appropriately with people you have a close relationship with.\u000a\u000aWhen making a request, the particle 「を」 is often omitted before the object, especially in casual speech, but it can be included.'),'N4',7,'Giving and Receiving','[{"ja":"ちょっと待ってくれない？","romaji":"Chotto matte kurenai?","en":"Will you wait a moment for me?"},{"ja":"この荷物、持ってくれない？","romaji":"Kono nimotsu, motte kurenai?","en":"Can you hold this luggage for me?"},{"ja":"明日、手伝ってくれない？","romaji":"Ashita, tetsudatte kurenai?","en":"Won''t you help me tomorrow?"},{"ja":"その本、貸してくれない？","romaji":"Sono hon, kashite kurenai?","en":"Could you lend me that book?"}]','["n4-て-ください","n4-て-くれませんか"]','["request","casual"]',216);
INSERT INTO grammar_points VALUES(217,'n4-のだろうか','のだろうか','no darou ka','I wonder if ~; I wonder whether ~',unistr('Verb (Casual) + のだろうか\u000aい-adj + のだろうか\u000aな-adj + なのだろうか\u000aNoun + なのだろうか'),unistr('「のだろうか」 is used to express the speaker''s doubt, speculation, or a rhetorical question. It conveys a sense of wondering or questioning about a situation or fact. It''s a more formal or thoughtful way of saying 「～かな」 or 「～だろうか」.\u000a\u000aThis pattern is formed by attaching 「のだろうか」 to the casual form of verbs and adjectives, and to nouns or な-adjectives followed by 「な」. The 「の」 acts as an explanatory or nominalizing particle, adding a nuance of seeking an explanation or confirmation.\u000a\u000aIt is often used when the speaker is pondering something to themselves or asking a question that doesn''t necessarily expect a direct answer, but rather invites consideration or discussion.'),'N4',7,'Giving and Receiving','[{"ja":"彼は本当に来るのだろうか。","romaji":"Kare wa hontou ni kuru no darou ka.","en":"I wonder if he will really come."},{"ja":"このやり方で合っているのだろうか。","romaji":"Kono yarikata de atteiru no darou ka.","en":"I wonder if this method is correct."},{"ja":"明日は晴れるのだろうか。","romaji":"Ashita wa hareru no darou ka.","en":"I wonder if it will be sunny tomorrow."},{"ja":"これは夢なのだろうか。","romaji":"Kore wa yume na no darou ka.","en":"I wonder if this is a dream."}]','["n4-だろう","n4-のか"]','["speculation","question"]',217);
INSERT INTO grammar_points VALUES(218,'n4-おになる','お～になる','o ni naru','Honorific expression for verbs (respectful)',unistr('お + Verb (ます-stem) + になる\u000aご + Noun (Suru-verb) + になる'),unistr('「お～になる」 is a general honorific expression used to show respect to the person performing the action. It is one of the main ways to form sonkeigo (尊敬語), or respectful language, in Japanese.\u000a\u000aTo use this form, take the ます-stem of a verb (e.g., 読みます → 読み) and attach 「お～になる」 (e.g., お読みになる). For certain verbs that are originally nouns followed by 「する」 (suru-verbs), you use 「ご」 instead of 「お」 (e.g., 連絡する → ご連絡になる).\u000a\u000aThis pattern is used when talking about the actions of a superior or someone you wish to show respect to, such as a teacher, boss, or elderly person. It elevates the action, thereby showing deference to the subject.'),'N4',7,'Giving and Receiving','[{"ja":"先生はもうお帰りになりましたか。","romaji":"Sensei wa mou okaeri ni narimashita ka.","en":"Has the teacher already returned?"},{"ja":"社長は何時ごろお出かけになりますか。","romaji":"Shachou wa nanji goro odekake ni narimasu ka.","en":"Around what time will the president leave?"},{"ja":"お客様、こちらにお座りになりますか。","romaji":"Okyaku-sama, kochira ni osuwari ni narimasu ka.","en":"Customer, would you like to sit here?"},{"ja":"部長は資料をごらんになりました。","romaji":"Buchou wa shiryō o goran ni narimashita.","en":"The department manager looked at the documents."}]','["n4-なさる","n4-いらっしゃる","n4-おっしゃる","n4-召し上がる","n4-くださる","n4-ごらんになる"]','["honorific","keigo"]',218);
INSERT INTO grammar_points VALUES(219,'n4-なさる','なさる','nasaru','To do (honorific equivalent of する)','なさる (honorific form of する)',unistr('「なさる」 is the honorific verb for 「する」 (to do). It is used to show respect to the person performing the action of ''doing''. This is a specific type of sonkeigo (尊敬語), or respectful language, where a completely different verb is used instead of a regular verb with an honorific prefix.\u000a\u000aWhen using 「なさる」, it conjugates like a Godan verb (Group 1 verb). For example, its ます-form is 「なさいます」, its て-form is 「なさって」, and its past tense is 「なさった」.\u000a\u000aIt is commonly used in formal situations or when speaking to or about someone of higher status, such as a boss, teacher, or elder. Using 「なさる」 demonstrates a high level of respect towards the subject of the action.'),'N4',7,'Giving and Receiving','[{"ja":"先生は何をなさいますか。","romaji":"Sensei wa nani o nasaimasu ka.","en":"What will the teacher do?"},{"ja":"社長はもうお帰りになりましたか、それともまだお仕事をなさっていますか。","romaji":"Shachou wa mou okaeri ni narimashita ka, soretomo mada oshigoto o nasatteimasu ka.","en":"Has the president already gone home, or is he still working?"},{"ja":"お客様、何かご不明な点はございませんか。いかがなさいましたか。","romaji":"Okyaku-sama, nanika gofumei na ten wa gozaimasen ka. Ikaga nasaimashita ka.","en":"Customer, do you have any questions? What seems to be the matter?"},{"ja":"今年の夏休みはどうなさるつもりですか。","romaji":"Kotoshi no natsuyasumi wa dou nasaru tsumori desu ka.","en":"What are you planning to do this summer holiday?"}]','["n5-する","n4-おになる"]','["honorific","keigo","verb"]',219);
INSERT INTO grammar_points VALUES(220,'n4-おください','お～ください','o kudasai','Please do ~ (honorific request)',unistr('お + Verb (ます-stem) + ください\u000aご + Noun (Suru-verb) + ください'),unistr('「お～ください」 is an honorific way to make a request or give a command, asking someone to do something respectfully. It is a polite and formal equivalent of 「～てください」.\u000a\u000aTo form this, take the ます-stem of a verb (e.g., 待ちます → 待ち) and attach 「お～ください」 (e.g., お待ちください). For certain verbs that are originally nouns followed by 「する」 (suru-verbs), you use 「ご」 instead of 「お」 (e.g., 連絡する → ご連絡ください).\u000a\u000aThis expression is commonly used in customer service, business settings, or when addressing someone of higher status to politely instruct or request an action. It conveys respect while still clearly stating what needs to be done.'),'N4',7,'Giving and Receiving','[{"ja":"こちらでお待ちください。","romaji":"Kochira de omachi kudasai.","en":"Please wait here."},{"ja":"この書類にご記入ください。","romaji":"Kono shorui ni gokinyuu kudasai.","en":"Please fill out this document."},{"ja":"どうぞ、お入りください。","romaji":"Douzo, ohairi kudasai.","en":"Please come in."},{"ja":"ご不明な点がございましたら、ご質問ください。","romaji":"Gofumei na ten ga gozaimashitara, goshitsumon kudasai.","en":"If you have any unclear points, please ask questions."}]','["n5-て-ください","n4-おになる"]','["honorific","keigo","request","command"]',220);
INSERT INTO grammar_points VALUES(221,'n4-irassharu','いらっしゃる','irassharu','To be; to come; to go (honorific)','いらっしゃる (Plain form)',unistr('いらっしゃる is the honorific form (尊敬語 - sonkeigo) of three common verbs: いる (to be), 来る (kuru - to come), and 行く (iku - to go). It is used to show respect to a person of higher status (e.g., a teacher, boss, or customer) when talking about their actions or state of being.\u000a\u000aWhen using いらっしゃる, you are elevating the action of the person you are speaking about, thereby showing deference. The polite masu form is いらっしゃいます. It is crucial to use honorifics correctly to maintain proper social etiquette in Japanese.'),'N4',7,'Giving and Receiving','[{"ja":"先生はもう学校にいらっしゃいましたか。","romaji":"sensei wa mou gakkou ni irasshaimashita ka.","en":"Has the teacher already come to school?"},{"ja":"社長は今、会議室にいらっしゃいます。","romaji":"shachou wa ima, kaigishitsu ni irasshaimasu.","en":"The company president is in the meeting room now."},{"ja":"お客様はどちらにいらっしゃいますか。","romaji":"okyaku-sama wa dochira ni irasshaimasu ka.","en":"Where is the customer going?"},{"ja":"明日、部長の家にお祝いにいらっしゃいませんか。","romaji":"ashita, buchou no ie ni oiwai ni irasshaimasen ka.","en":"Would you like to come to the manager''s house tomorrow to celebrate?"}]','["n4-kudasaru","n4-osuru"]','["honorific","verb"]',221);
INSERT INTO grammar_points VALUES(222,'n4-gozaimasu','御座（ござ）います','gozaimasu','To be; to exist (polite/humble)','御座います (Masu form)',unistr('御座います (gozaimasu) is the humble/polite form of the verb ある (aru - to be, to exist for inanimate objects). It is used to express the existence of something in a very polite and formal manner, often in business settings, customer service, or public announcements.\u000a\u000aWhile technically a humble form, it functions more broadly as a highly polite equivalent of あります. It conveys a sense of formality and respect towards the listener or the situation. It is typically used for inanimate objects or abstract concepts, similar to ある.'),'N4',7,'Giving and Receiving','[{"ja":"こちらにパンフレットがございます。","romaji":"kochira ni panfuretto ga gozaimasu.","en":"Here are the pamphlets."},{"ja":"お手洗いはあちらにございます。","romaji":"otearai wa achira ni gozaimasu.","en":"The restroom is over there."},{"ja":"申し訳ございませんが、ただ今、満席でございます。","romaji":"moushiwake gozaimasen ga, tadaima, manseki de gozaimasu.","en":"I am very sorry, but we are currently full."},{"ja":"何かご不明な点がございましたら、お尋ねください。","romaji":"nanika gofumei na ten ga gozaimashitara, otazune kudasai.","en":"If you have any unclear points, please ask."}]','["n4-degozaimasu","n5-aru"]','["humble","polite","verb"]',222);
INSERT INTO grammar_points VALUES(223,'n4-degozaimasu','で御座（ござ）います','degozaimasu','To be (very polite copula)',unistr('Noun + でございます\u000aな-adjective stem + でございます'),unistr('でございます (de gozaimasu) is the humble/polite form of the copula です (desu). It is used to state facts, identify oneself, or describe something in an extremely polite and formal way. This expression is commonly heard in business, customer service, and formal presentations.\u000a\u000aBy using でございます, the speaker shows utmost respect to the listener. It is often used when introducing oneself, confirming information, or making announcements in a professional context. It elevates the formality of the statement significantly compared to simply using です.'),'N4',7,'Giving and Receiving','[{"ja":"私が担当の山田でございます。","romaji":"watashi ga tantou no yamada de gozaimasu.","en":"I am Yamada, who is in charge."},{"ja":"こちらが本日のメニューでございます。","romaji":"kochira ga honjitsu no menyuu de gozaimasu.","en":"This is today''s menu."},{"ja":"恐れ入りますが、こちらは禁煙席でございます。","romaji":"osoreirimasu ga, kochira wa kinen-seki de gozaimasu.","en":"Excuse me, but this is a non-smoking seat."},{"ja":"お支払いは現金でよろしいでございますか。","romaji":"oshiharai wa genkin de yoroshii de gozaimasu ka.","en":"Is payment by cash acceptable?"}]','["n4-gozaimasu","n5-desu"]','["humble","polite","copula"]',223);
INSERT INTO grammar_points VALUES(224,'n4-osuru','お〜する','osuru','To humbly do (verb)',unistr('お + Verb (ます-stem) + する (for Group 1 & 2 verbs)\u000aご + Noun + する (for する verbs)'),unistr('The pattern お〜する (o~ suru) or ご〜する (go~ suru) is a common way to form humble expressions (謙譲語 - kenjougo) for verbs. It is used when the speaker performs an action for or towards someone of higher status, or when the action itself is directed towards a superior. This construction shows respect to the recipient of the action.\u000a\u000aFor Group 1 and Group 2 verbs, you attach お to the ます-stem of the verb (e.g., 持つ -> お持ちする). For する verbs (verbs formed by Noun + する), you attach ご to the noun part (e.g., 案内する -> ご案内する). This pattern emphasizes the speaker''s humility and respect.'),'N4',7,'Giving and Receiving','[{"ja":"お荷物をお持ちしましょうか。","romaji":"onimotsu wo omochi shimashou ka.","en":"Shall I carry your luggage for you?"},{"ja":"先生に質問をお聞きしました。","romaji":"sensei ni shitsumon wo okiki shimashita.","en":"I humbly asked the teacher a question."},{"ja":"お客様をご案内します。","romaji":"okyaku-sama wo goannai shimasu.","en":"I will guide the customer."},{"ja":"明日、またお電話いたします。","romaji":"ashita, mata odenwa itashimasu.","en":"I will call you again tomorrow."}]','["n4-itasu","n4-moushiageru"]','["humble","verb"]',224);
INSERT INTO grammar_points VALUES(225,'n4-itasu','致（いた）す','itasu','To do (humble)','致す (Plain form)',unistr('致す (itasu) is the humble form (謙譲語 - kenjougo) of the verb する (suru - to do). It is used when the speaker performs an action, and by using 致す, they humbly lower themselves to show respect to the listener or the person affected by the action.\u000a\u000aThis verb is frequently used in formal and business contexts. It can be used independently or as part of a compound verb, often replacing する in Noun + する verbs (e.g., 連絡する becomes ご連絡いたします). It conveys a strong sense of humility and professionalism.'),'N4',7,'Giving and Receiving','[{"ja":"後ほど、改めてご連絡いたします。","romaji":"nochihodo, aratamete gorenraku itashimasu.","en":"I will contact you again later."},{"ja":"私がご案内いたします。","romaji":"watashi ga goannai itashimasu.","en":"I will guide you."},{"ja":"全力で努力いたします。","romaji":"zenryoku de doryoku itashimasu.","en":"I will make every effort."},{"ja":"ご不明な点がございましたら、私がご説明いたします。","romaji":"gofumei na ten ga gozaimashitara, watashi ga gosetsumei itashimasu.","en":"If you have any unclear points, I will explain."}]','["n4-osuru","n5-suru"]','["humble","verb"]',225);
INSERT INTO grammar_points VALUES(226,'n4-teitadakemasenka','～ていただけませんか','te itadakemasen ka','Could you please...?; Would you mind...?','Verb て-form + いただけませんか',unistr('「～ていただけませんか」 is a very polite and humble way to ask someone to do something for you. It literally means "Won''t you be able to give me the favor of doing...?" and is a more formal and respectful request than 「～てください」 or 「～てくれませんか」.\u000a\u000aThis expression is commonly used when asking a favor from someone you don''t know well, someone of higher status, or in a formal situation. It shows consideration for the listener and acknowledges that you are asking for their time or effort.\u000a\u000aWhile it''s a question, it functions as a polite request. The listener is expected to respond by either agreeing to the request or politely declining.'),'N4',7,'Giving and Receiving','[{"ja":"写真を取っていただけませんか。","romaji":"shashin o totte itadakemasen ka.","en":"Could you please take a picture?"},{"ja":"この漢字の読み方を教えていただけませんか。","romaji":"kono kanji no yomikata o oshiete itadakemasen ka.","en":"Could you please tell me how to read this kanji?"},{"ja":"もう少しゆっくり話していただけませんか。","romaji":"mou sukoshi yukkuri hanashite itadakemasen ka.","en":"Could you please speak a little more slowly?"},{"ja":"荷物を持っていただけませんか。","romaji":"nimotsu o motte itadakemasen ka.","en":"Could you please hold my luggage?"}]','["n5-tekudasai","n4-tekuremasenka"]','["request","polite expression"]',226);
INSERT INTO grammar_points VALUES(227,'n4-tara','たら','tara','If; when; after',unistr('Verb た-form + ら\u000aい-Adjective (かった) + ら\u000aな-Adjective (だった) + ら\u000aNoun (だった) + ら'),unistr('The `～たら` conditional form is used to express a condition, meaning "if" or "when." It indicates that the action or state in the second clause will occur or be true *after* the condition in the first clause is met or completed.\u000a\u000aUnlike some other conditional forms, `～たら` can be used with a wide range of sentence types in the second clause, including requests, commands, suggestions, and expressions of the speaker''s will or intention. This makes it a very versatile conditional.\u000a\u000aIt can also be used to express a discovery or an unexpected outcome that occurs after a certain action. For example, 「窓を開けたら、涼しい風が入ってきた。」 (When I opened the window, a cool breeze came in.)'),'N4',8,'Conditionals and Necessity','[{"ja":"雨が降ったら、家で映画を見ます。","romaji":"ame ga futtara, ie de eiga o mimasu.","en":"If it rains, I''ll watch a movie at home."},{"ja":"日本に着いたら、連絡してください。","romaji":"nihon ni tsuitara, renraku shite kudasai.","en":"When you arrive in Japan, please contact me."},{"ja":"この本を読んだら、感想を教えてください。","romaji":"kono hon o yondara, kansou o oshiete kudasai.","en":"After you read this book, please tell me your thoughts."},{"ja":"もし時間があったら、一緒にコーヒーを飲みませんか。","romaji":"moshi jikan ga attara, issho ni koohii o nomimasen ka.","en":"If you have time, would you like to drink coffee together?"}]','["n5-to","n4-ba","n4-nara"]','["conditional","conjunction"]',227);
INSERT INTO grammar_points VALUES(228,'n4-hoka-ni','他（ほか）に','hoka ni','Besides; in addition; anything else; any other',unistr('Noun + の + 他に\u000aVerb (Casual) + 他に\u000a他に + Noun\u000a他に (alone)'),unistr('「他に」 is used to refer to something additional or different from what has already been mentioned or is currently being discussed. It can mean "besides," "in addition to," "anything else," or "any other."\u000a\u000aWhen used with a noun, it typically takes the form 「Noun + の + 他に」 to mean "besides Noun" or "in addition to Noun." When used with a verb, the verb is in its casual form. It can also stand alone, especially in questions like 「他に何か？」 (Anything else?).\u000a\u000aThis expression is very common in daily conversation, particularly when offering choices or asking if there are further items or points to consider.'),'N4',8,'Conditionals and Necessity','[{"ja":"他に何か質問はありますか。","romaji":"hoka ni nani ka shitsumon wa arimasu ka.","en":"Do you have any other questions?"},{"ja":"この他に、パンも買いました。","romaji":"kono hoka ni, pan mo kaimashita.","en":"Besides this, I also bought bread."},{"ja":"彼は英語の他に、フランス語も話せます。","romaji":"kare wa eigo no hoka ni, furansugo mo hanasemasu.","en":"Besides English, he can also speak French."},{"ja":"今日は仕事の他に、買い物もしました。","romaji":"kyou wa shigoto no hoka ni, kaimono mo shimashita.","en":"Today, in addition to work, I also went shopping."}]','[]','["adverb","particle"]',228);
INSERT INTO grammar_points VALUES(229,'n4-ga-hitsuyou','が必要（ひつよう）','ga hitsuyou','Need; necessary',unistr('Noun + が + 必要だ/です\u000aVerb (Casual) + ことが + 必要だ/です'),unistr('「必要だ/です」 means "necessary" or "needed." It is used to state that something is required or indispensable. The particle 「が」 marks the noun or nominalized verb that is necessary.\u000a\u000aWhen expressing that an action is necessary, the verb must first be converted into a noun phrase using 「こと」. For example, 「勉強することが必要です」 (It is necessary to study).\u000a\u000aThis grammar point is fundamental for expressing requirements, obligations, or what is essential in various situations, from daily life to more formal contexts.'),'N4',8,'Conditionals and Necessity','[{"ja":"パスポートが必要です。","romaji":"pasupooto ga hitsuyou desu.","en":"A passport is necessary."},{"ja":"この仕事には経験が必要です。","romaji":"kono shigoto ni wa keiken ga hitsuyou desu.","en":"Experience is necessary for this job."},{"ja":"健康のためには、毎日運動することが必要です。","romaji":"kenkou no tame ni wa, mainichi undou suru koto ga hitsuyou desu.","en":"For health, it is necessary to exercise every day."},{"ja":"もっと勉強することが必要だと感じています。","romaji":"motto benkyou suru koto ga hitsuyou da to kanjite imasu.","en":"I feel that it is necessary to study more."}]','[]','["expression","adjective"]',229);
INSERT INTO grammar_points VALUES(230,'n4-sonna-ni','そんなに','sonna ni','So much; that much; like that',unistr('そんなに + Verb\u000aそんなに + い-Adjective\u000aそんなに + な-Adjective'),unistr('「そんなに」 is an adverb that indicates degree or extent, meaning "that much," "so much," or "to that extent." It often refers to something that has been mentioned or is understood from the context.\u000a\u000aIt is very frequently used with negative expressions to soften or deny the degree of something, such as 「そんなに好きじゃない」 (I don''t like it that much) or 「そんなに難しくない」 (It''s not that difficult).\u000a\u000aWhile more common in negative sentences, it can also be used in affirmative sentences to emphasize a high degree, though this usage is less frequent in N4. It''s part of a set of demonstrative adverbs: 「こんなに」 (this much), 「そんなに」 (that much), 「あんなに」 (that much over there).'),'N4',8,'Conditionals and Necessity','[{"ja":"この本はそんなに面白くなかったです。","romaji":"kono hon wa sonna ni omoshirokunakatta desu.","en":"This book wasn''t that interesting."},{"ja":"そんなに心配しないでください。大丈夫ですよ。","romaji":"sonna ni shinpai shinaide kudasai. daijoubu desu yo.","en":"Please don''t worry so much. It''s okay."},{"ja":"彼はそんなに日本語が上手ではありません。","romaji":"kare wa sonna ni nihongo ga jouzu dewa arimasen.","en":"He is not that good at Japanese."},{"ja":"そんなに急がなくてもいいですよ。","romaji":"sonna ni isoganakute mo ii desu yo.","en":"You don''t have to hurry that much."}]','["n5-konna-ni"]','["adverb"]',230);
INSERT INTO grammar_points VALUES(231,'n4-hitsuyou-ga-aru','必要（ひつよう）がある','hitsuyou ga aru','need to; it is necessary to',unistr('Verb (辞書形) + 必要がある\u000aNoun + の + 必要がある'),unistr('「必要がある」 (hitsuyou ga aru) expresses that something is necessary or that one needs to do something. It literally means "there is a necessity." The verb preceding 「必要がある」 must be in its dictionary form.\u000a\u000aTo express the negative, "there is no need to," you use 「必要がない」 (hitsuyou ga nai). For a more polite expression, you can use 「必要があります」 (hitsuyou ga arimasu) and 「必要がありません」 (hitsuyou ga arimasen).\u000a\u000aThis grammar point is commonly used in both formal and informal contexts to state requirements or obligations.'),'N4',8,'Conditionals and Necessity','[{"ja":"私はもっと勉強する必要がある。","romaji":"watashi wa motto benkyou suru hitsuyou ga aru.","en":"I need to study more."},{"ja":"今日は会社に行く必要がない。","romaji":"kyou wa kaisha ni iku hitsuyou ga nai.","en":"There''s no need to go to the office today."},{"ja":"この書類にサインする必要はありません。","romaji":"kono shorui ni sain suru hitsuyou wa arimasen.","en":"You don''t need to sign this document."},{"ja":"子供には十分な睡眠の必要がある。","romaji":"kodomo ni wa juubun na suimin no hitsuyou ga aru.","en":"Children need enough sleep."}]','[]','["necessity"]',231);
INSERT INTO grammar_points VALUES(232,'n4-tatoeba','例（たと）えば','tatoeba','for example; for instance','例（たと）えば + [sentence/phrase]',unistr('「例えば」 (tatoeba) is an adverb used to introduce an example or a series of examples. It helps to clarify or illustrate a preceding statement by providing specific instances.\u000a\u000aIt can be placed at the beginning of a sentence or within a sentence, often followed by a comma in written Japanese. It is a very common and useful expression for giving specific details.'),'N4',8,'Conditionals and Necessity','[{"ja":"日本料理、例えば寿司や天ぷらが好きです。","romaji":"nihon ryouri, tatoeba sushi ya tenpura ga suki desu.","en":"I like Japanese food, for example, sushi and tempura."},{"ja":"趣味はたくさんあります。例えば、読書や映画鑑賞です。","romaji":"shumi wa takusan arimasu. tatoeba, dokusho ya eiga kanshou desu.","en":"I have many hobbies. For example, reading and watching movies."},{"ja":"彼は色々なスポーツができます。例えば、サッカーやバスケットボールです。","romaji":"kare wa iroiro na supootsu ga dekimasu. tatoeba, sakkaa ya basukettobooru desu.","en":"He can play various sports. For example, soccer and basketball."},{"ja":"例えば、この問題はどうやって解きますか？","romaji":"tatoeba, kono mondai wa dou yatte tokimasu ka?","en":"For example, how do you solve this problem?"}]','[]','["adverb","example"]',232);
INSERT INTO grammar_points VALUES(233,'n4-reru-rareru-potential','れる・られる (Potential)','reru rareru (potential)','can; be able to (potential form)',unistr('Group 1 Verbs: Verb (ます形) + えます / Verb (辞書形) + える\u000aGroup 2 Verbs: Verb (ます形) + られます / Verb (辞書形) + られる\u000aGroup 3 Verbs: します -> できます, 来ます -> 来られます (or 来れます)'),unistr('The potential form of a verb expresses ability or possibility, meaning "can do" or "be able to do" something. The conjugation rules vary depending on the verb group.\u000a\u000aFor Group 1 verbs (五段動詞), change the final 「う」 sound to an 「え」 sound and add 「る」 (e.g., 読む (yomu) -> 読める (yomeru)). For Group 2 verbs (一段動詞), remove 「る」 and add 「られる」 (e.g., 食べる (taberu) -> 食べられる (taberareru)). Irregular verbs like 「する」 become 「できる」 and 「来る」 becomes 「来られる」 (or the more casual 「来れる」).\u000a\u000aWhen using the potential form, the object particle 「を」 often changes to 「が」, emphasizing the ability to perform an action on something (e.g., 寿司を食べます -> 寿司が食べられます). This form is fundamental for expressing capabilities in Japanese.'),'N4',8,'Conditionals and Necessity','[{"ja":"私は日本語が話せます。","romaji":"watashi wa nihongo ga hanasemasu.","en":"I can speak Japanese."},{"ja":"この漢字は読めますか？","romaji":"kono kanji wa yomemasu ka?","en":"Can you read this kanji?"},{"ja":"辛いものは食べられません。","romaji":"karai mono wa taberaremasen.","en":"I cannot eat spicy food."},{"ja":"明日、来られますか？","romaji":"ashita, koraremasu ka?","en":"Can you come tomorrow?"}]','["n5-koto-ga-dekiru"]','["verb conjugation","potential form","ability"]',233);
INSERT INTO grammar_points VALUES(234,'n4-ndakedo','んだけど','ndakedo','but; and; however; (used to introduce a topic or request)',unistr('Verb (Casual) + んだけど\u000aい-Adjective + んだけど\u000aな-Adjective (な) + んだけど\u000aNoun (な) + んだけど'),unistr('「んだけど」 (ndakedo) is an informal and conversational expression that serves multiple functions, similar to 「のですが」 or 「ですが」. The 「ん」 (or 「の」) adds an explanatory or softening nuance to the statement.\u000a\u000aIt is commonly used to provide background information before making a request, suggestion, or asking a question. For example, you might say "I''m free tomorrow, but..." before inviting someone out. It can also express a mild contradiction or hesitation, similar to "but" or "however."\u000a\u000aFurthermore, 「んだけど」 can be used to introduce a topic or seek advice, creating a more gentle and less direct tone. It''s a versatile phrase that makes conversations sound more natural and less abrupt.'),'N4',8,'Conditionals and Necessity','[{"ja":"明日暇なんだけど、映画に行かない？","romaji":"ashita hima nandakedo, eiga ni ikanai?","en":"I''m free tomorrow, so wanna go to a movie?"},{"ja":"ちょっと聞きたいことがあるんだけど。","romaji":"chotto kikitai koto ga aru ndakedo.","en":"There''s something I want to ask you..."},{"ja":"この本、読んだんだけど、すごく面白かったよ。","romaji":"kono hon, yonda ndakedo, sugoku omoshirokatta yo.","en":"I read this book, and it was really interesting!"},{"ja":"ラーメンを食べたいんだけど、どこかいいお店知らない？","romaji":"raamen o tabetai ndakedo, dokoka ii omise shiranai?","en":"I want to eat ramen, but do you know any good shops?"}]','["n4-nodesu"]','["conjunction","informal","explanatory"]',234);
INSERT INTO grammar_points VALUES(235,'n4-hazu-da','筈（はず）だ','hazu da','it should be; it is expected to be; I expect that',unistr('Verb (Casual) + 筈だ\u000aい-Adjective + 筈だ\u000aな-Adjective (な) + 筈だ\u000aNoun + の + 筈だ'),unistr('「筈だ」 (hazu da) expresses a strong expectation or belief based on logical reasoning, evidence, or prior information. It implies a high probability that something is true or will happen, often translated as "should be," "is supposed to be," or "I expect that."\u000a\u000aUnlike 「だろう」 (darou) or 「かもしれない」 (kamoshirenai) which express weaker possibilities or guesses, 「筈だ」 is used when the speaker has a solid basis for their expectation. For example, if you know a train schedule, you can say the train 「来るはずだ」 (kuru hazu da - should come).\u000a\u000aThe negative form is 「はずがない」 (hazu ga nai), meaning "it cannot be" or "it''s impossible that." This form is used to express strong disbelief or certainty that something is not true.'),'N4',8,'Conditionals and Necessity','[{"ja":"彼はもう来たはずだ。","romaji":"kare wa mou kita hazu da.","en":"He should have come already."},{"ja":"今日は日曜日だから、店は閉まっているはずだ。","romaji":"kyou wa nichiyoubi dakara, mise wa shimatte iru hazu da.","en":"It''s Sunday today, so the store should be closed."},{"ja":"この電車は9時に着くはずです。","romaji":"kono densha wa kuji ni tsuku hazu desu.","en":"This train is supposed to arrive at 9 o''clock."},{"ja":"彼は日本語が上手なはずだよ。日本に5年住んでいたから。","romaji":"kare wa nihongo ga jouzu na hazu da yo. nihon ni gonen sunde ita kara.","en":"He should be good at Japanese. Because he lived in Japan for 5 years."}]','["n5-darou","n4-kamoshirenai"]','["expectation","probability"]',235);
INSERT INTO grammar_points VALUES(236,'n4-kadouka','かどうか','kadouka','whether or not',unistr('Verb (Casual) + かどうか\u000aい-adjective + かどうか\u000aな-adjective (stem) + かどうか\u000aNoun + かどうか'),unistr('「かどうか」 is used to express uncertainty or to inquire about alternatives. It translates to "whether or not" or "if... or not" in English. This pattern is commonly used when you don''t know if something is true, or when you are asking someone to confirm something.\u000a\u000aIt typically follows the plain (casual) form of verbs and adjectives. For な-adjectives and nouns, the だ is often omitted before かどうか, especially in casual speech, but can be included for a more formal tone (e.g., 静かかどうか, 学生かどうか).'),'N4',8,'Conditionals and Necessity','[{"ja":"明日晴れるかどうか知らない。","romaji":"ashita hareru ka dou ka shiranai.","en":"I don''t know if the weather will be clear or not tomorrow."},{"ja":"それが正しいかどうかわからない。","romaji":"sore ga tadashii ka dou ka wakaranai.","en":"I''m not sure if that is correct or not."},{"ja":"行くかどうか後で電話で知らせます。","romaji":"iku ka douka atode denwa de shirasemasu.","en":"Whether or not I go, I''ll let you know later by phone."},{"ja":"おいしいかどうか食べないとわからない。","romaji":"oishii ka douka tabenai to wakaranai.","en":"We won''t know if it''s good or not until we eat it."}]','["n4-ka"]','["conjunction","question"]',236);
INSERT INTO grammar_points VALUES(237,'n4-to','と','to','if; when; whenever (natural consequence)',unistr('Verb (Dictionary form) + と\u000aい-adjective + と\u000aな-adjective (stem) + だ + と\u000aNoun + だ + と'),unistr('The particle 「と」 is used to express a conditional relationship where the result is a natural, certain, or habitual consequence of the condition. It often translates to "if," "when," or "whenever."\u000a\u000aThis conditional form implies that if the first clause happens, the second clause *will definitely* happen. It''s frequently used for universal truths, natural phenomena, habitual actions, or instructions. Unlike other conditional forms like 「ば」 or 「たら」, 「と」 cannot be used with volitional expressions (e.g., commands, requests, suggestions) in the main clause.'),'N4',8,'Conditionals and Necessity','[{"ja":"春になると桜が咲く。","romaji":"haru ni naru to sakura ga saku.","en":"When spring comes, cherry blossoms bloom."},{"ja":"このボタンを押すと、ドアが開きます。","romaji":"kono botan wo osu to, doa ga akimasu.","en":"If you push this button, the door will open."},{"ja":"100を2で割ると50になる。","romaji":"hyaku wo ni de waru to gojuu ni naru.","en":"If you divide 100 by 2, it becomes 50."},{"ja":"毎日運動すると健康になる。","romaji":"mainichi undou suru to kenkou ni naru.","en":"If you exercise every day, you will become healthy."}]','["n4-ba","n4-tara","n4-nara"]','["conditional","particle"]',237);
INSERT INTO grammar_points VALUES(238,'n4-naito','ないと','naito','must; have to (colloquial)','Verb (ない-form) + と',unistr('「ないと」 is a colloquial contraction of 「～なければならない」 or 「～なくてはいけない」, both of which express necessity or obligation. It means "must do" or "have to do" something.\u000a\u000aThis form is very common in casual conversation and implies that if the action is not taken, there will be negative consequences or a problem. It''s a direct and informal way to state that something is required.'),'N4',8,'Conditionals and Necessity','[{"ja":"早く行かないと遅れるよ。","romaji":"hayaku ikanai to okureru yo.","en":"If you don''t go soon, you''ll be late."},{"ja":"宿題をしないと、先生に怒られる。","romaji":"shukudai wo shinai to, sensei ni okorareru.","en":"If I don''t do my homework, the teacher will get angry."},{"ja":"明日テストがあるから、勉強しないと。","romaji":"ashita tesuto ga aru kara, benkyou shinai to.","en":"There''s a test tomorrow, so I have to study."},{"ja":"電車に間に合わないと困る。","romaji":"densha ni maniawanai to komaru.","en":"It''ll be a problem if I don''t make it to the train."}]','["n4-nakerebanaranai","n4-nakutehaikenai"]','["colloquial","necessity"]',238);
INSERT INTO grammar_points VALUES(239,'n4-hazuganai','筈（はず）がない','hazuganai','there''s no way; cannot be; it''s impossible that',unistr('Verb (Casual) + はずがない\u000aい-adjective + はずがない\u000aな-adjective (stem) + な + はずがない\u000aNoun + の + はずがない'),unistr('「はずがない」 expresses a strong conviction that something is impossible or highly unlikely, based on common sense, known facts, or logical reasoning. It translates to "there''s no way," "it cannot be," or "it''s impossible that."\u000a\u000aThis pattern is used to strongly deny a possibility or an expectation. It''s a more emphatic denial than simply saying something is probably not true. The speaker is very confident in their assertion that something is not the case.'),'N4',8,'Conditionals and Necessity','[{"ja":"彼がそんなことをするはずがない。","romaji":"kare ga sonna koto wo suru hazu ga nai.","en":"There''s no way he would do such a thing."},{"ja":"今日は日曜日だから、学校があるはずがない。","romaji":"kyou wa nichiyoubi dakara, gakkou ga aru hazu ga nai.","en":"Today is Sunday, so there''s no way there''s school."},{"ja":"こんな簡単な問題が解けないはずがない。","romaji":"konna kantan na mondai ga tokenai hazu ga nai.","en":"There''s no way I can''t solve such an easy problem."},{"ja":"彼は日本にいるはずがない。昨日アメリカに行ったばかりだ。","romaji":"kare wa nihon ni iru hazu ga nai. kinou amerika ni itta bakari da.","en":"There''s no way he''s in Japan. He just went to America yesterday."}]','["n4-hazu"]','["modality","negation"]',239);
INSERT INTO grammar_points VALUES(240,'n4-shikanai','しか～ない','shikanai','only; nothing but; no choice but to',unistr('Noun + しか + Verb (Negative form)\u000aVerb (Dictionary form) + しか + ない'),unistr('The particle 「しか」 always pairs with a negative verb form to express "only" or "nothing but." It emphasizes a limitation or restriction, implying that there is no other option or quantity available.\u000a\u000aWhen used with a noun, it means "only [noun]" and implies that the amount or number is small or insufficient. When used with a verb in its dictionary form followed by 「ない」, it means "have no choice but to" or "can only do [verb]," indicating a lack of alternatives.'),'N4',8,'Conditionals and Necessity','[{"ja":"日本語しか話せない。","romaji":"nihongo shika hanasenai.","en":"I can only speak Japanese."},{"ja":"お金が100円しかない。","romaji":"okane ga hyakuen shika nai.","en":"I only have 100 yen."},{"ja":"宿題がたくさんあるから、勉強するしかない。","romaji":"shukudai ga takusan aru kara, benkyou suru shika nai.","en":"I have a lot of homework, so I have no choice but to study."},{"ja":"この店にはこれしか残っていない。","romaji":"kono mise ni wa kore shika nokotte inai.","en":"Only this is left in this store."}]','["n5-dake"]','["limitation","particle","necessity"]',240);
INSERT INTO grammar_points VALUES(241,'n4-dake-de-1','〜だけで','dake de','just by; only by; merely by',unistr('Verb (casual) + だけで\u000aNoun + だけで\u000aい-adj + だけで\u000a な-adj + だけで'),unistr('The grammar pattern `〜だけで` is used to express that something happens or is achieved *just by* or *only by* performing a certain action or being in a certain state. It emphasizes the minimal effort or condition required for a result.\u000aIt combines `だけ` (only/just) with the particle `で` (by means of/at). When used with verbs, the verb is in its casual (plain) form. For nouns, い-adjectives, and な-adjectives, `だけ` directly follows them, and then `で` is added.\u000aThis pattern often implies that the result is surprising or significant given the small action or condition.'),'N4',8,'Conditionals and Necessity','[{"ja":"あなたに会うだけで元気になる。","romaji":"anata ni au dake de genki ni naru.","en":"I get energetic just by meeting you."},{"ja":"この本を読むだけで日本語が上手になる。","romaji":"kono hon o yomu dake de nihongo ga jouzu ni naru.","en":"You''ll become good at Japanese just by reading this book."},{"ja":"彼は見るだけで何でも作れる。","romaji":"kare wa miru dake de nan demo tsukureru.","en":"He can make anything just by looking at it."},{"ja":"彼女の声を聞くだけで安心する。","romaji":"kanojo no koe o kiku dake de anshin suru.","en":"I feel relieved just by hearing her voice."}]','["n5-dake"]','["particle","expression"]',241);
INSERT INTO grammar_points VALUES(242,'n4-koto-ga-dekiru','ことが出来（でき）る','koto ga dekiru','can; be able to','Verb (dictionary form) + ことができる',unistr('The grammar pattern `〜ことができる` is used to express ability or possibility. It literally means "the thing of doing X is possible." This is a very common and versatile way to state what someone *can* or *is able to* do.\u000aTo form this, take a verb in its dictionary (plain non-past) form and attach `ことができる`. For example, `話す` (to speak) becomes `話すことができる` (can speak).\u000aWhile some verbs have a potential form (e.g., `話せる` for `話す`), `〜ことができる` can be used with any verb and is often preferred for clarity or when emphasizing the *possibility* rather than just the inherent ability.'),'N4',8,'Conditionals and Necessity','[{"ja":"5キロ走ることができる。","romaji":"go kiro hashiru koto ga dekiru.","en":"I can run 5 kilometers."},{"ja":"漢字を読むことができますか。","romaji":"kanji o yomu koto ga dekimasu ka.","en":"Can you read kanji?"},{"ja":"私は日本語を話すことができる。","romaji":"watashi wa nihongo o hanasu koto ga dekiru.","en":"I can speak Japanese."},{"ja":"ここで写真を撮ることはできません。","romaji":"koko de shashin o toru koto wa dekimasen.","en":"You cannot take pictures here."}]','["n5-dekiru"]','["verb","expression","ability"]',242);
INSERT INTO grammar_points VALUES(243,'n4-kai','かい','kai','(casual question marker, often for men)',unistr('Verb (casual) + かい\u000aNoun + かい\u000aい-adj + かい\u000a な-adj + かい'),unistr('The particle `かい` is a very casual question marker, primarily used by men or when speaking to children, close friends, or subordinates. It functions similarly to `か` but carries a more informal and sometimes slightly softer or more inquisitive tone.\u000aIt attaches directly to the plain form of verbs, nouns, い-adjectives, and な-adjectives. For nouns and な-adjectives, the `だ` is usually dropped before `かい`.\u000aWhile `かい` can be used for yes/no questions, it can also be used for questions that seek information, similar to `か`. However, its casual and masculine nuance is important to remember.'),'N4',8,'Conditionals and Necessity','[{"ja":"歩けるかい？","romaji":"arukeru kai?","en":"Can you walk?"},{"ja":"コーヒーいるかい？","romaji":"koohii iru kai?","en":"Do you want a coffee?"},{"ja":"一緒に来るかい？","romaji":"issho ni kuru kai?","en":"Do you want to come along?"},{"ja":"まだ終わってないのかい？","romaji":"mada owatte nai no kai?","en":"Aren''t you finished yet?"}]','["n5-ka"]','["particle","question marker","casual"]',243);
INSERT INTO grammar_points VALUES(244,'n4-moshi','もし','moshi','if; in case (emphasizes condition)','もし + Conditional form (〜ば, 〜たら, 〜なら, 〜と)',unistr('`もし` is an adverb that is used to emphasize a conditional statement. It always appears at the beginning of the conditional clause and is almost always followed by a conditional conjunction like `〜ば`, `〜たら`, `〜なら`, or `〜と`.\u000aThe primary role of `もし` is to highlight that the following statement is a *condition* or a *hypothesis*. It makes the "if" more prominent and can suggest that the condition is uncertain, hypothetical, or a possibility that needs to be considered.\u000aWhile conditional forms can be used without `もし`, adding `もし` makes the condition more explicit and can add a sense of "what if" or "in the event that."'),'N4',8,'Conditionals and Necessity','[{"ja":"もし時間があれば、来てください。","romaji":"moshi jikan ga areba, kite kudasai.","en":"If you have time, please come."},{"ja":"もし雨が降ったら、試合は中止になります。","romaji":"moshi ame ga futtara, shiai wa chuushi ni narimasu.","en":"If it rains, the game will be canceled."},{"ja":"もし彼が来ないなら、私が行きます。","romaji":"moshi kare ga konai nara, watashi ga ikimasu.","en":"If he doesn''t come, I will go."},{"ja":"もし宝くじが当たったら、世界旅行に行きたい。","romaji":"moshi takarakuji ga atattara, sekai ryokou ni ikitai.","en":"If I win the lottery, I want to go on a world trip."}]','["n5-ba","n5-tara","n5-nara","n5-to"]','["adverb","conditional"]',244);
INSERT INTO grammar_points VALUES(245,'n4-shi','し (Reasons)','shi','and; also; moreover (listing reasons/facts)',unistr('Verb (casual) + し\u000aNoun + だし\u000aい-adj + し\u000a な-adj + だし'),unistr('The particle `し` is used to list multiple reasons, facts, or conditions, often implying that there are other unstated reasons as well. It connects clauses, giving a sense of "and," "also," or "what''s more."\u000aIt attaches to the plain (casual) form of verbs and い-adjectives. For nouns and な-adjectives, `だ` is added before `し` (e.g., `学生だし`, `きれいだし`).\u000a`し` is particularly useful when you want to present several points to support an opinion or explain a situation, without necessarily implying a strong causal relationship between each point. It often leads to a conclusion or a statement of desire.'),'N4',9,'Ongoing and Continuous','[{"ja":"このコートは色がきれいだし、デザインも好きだし、買いたいです。","romaji":"kono kooto wa iro ga kirei da shi, dezain mo suki da shi, kaitai desu.","en":"This coat has a beautiful color, and I like the design too, so I want to buy it."},{"ja":"今日は週末だったし、天気も良かったので、公園は人が多かったです。","romaji":"kyou wa shuumatsu datta shi, tenki mo yokatta node, kouen wa hito ga ookatta desu.","en":"It was the weekend, and the weather was good, so the park was crowded."},{"ja":"彼は勉強ができるし、スポーツも上手だし、私の好きなタイプだ。","romaji":"kare wa benkyou ga dekiru shi, supootsu mo jouzu da shi, watashi no suki na taipu da.","en":"He''s good at studying, and he''s also good at sports, so he''s my type."},{"ja":"彼女は料理は上手いし、性格もいいし、理想の奥さんだ。","romaji":"kanojo wa ryouri wa umai shi, seikaku mo ii shi, risou no okusan da.","en":"She''s good at cooking, and her personality is good too, so she''s an ideal wife."}]','["n5-te","n5-kara"]','["conjunction","particle","reason"]',245);
INSERT INTO grammar_points VALUES(246,'n4-dedekiru','でできる','dedekiru','Made of; made from; consists of','Noun + でできる',unistr('「でできる」 (de dekiru) is used to express what a product or object is made *of* or *from*. It indicates the material or ingredient used in its creation. The particle 「で」 here signifies the material.\u000a\u000aWhen the material is still recognizable in the final product (e.g., a wooden table), 「でできる」 is typically used. If the material undergoes a significant chemical change and is no longer recognizable (e.g., cheese from milk), 「からできる」 is often preferred, though 「でできる」 can still be used in some contexts.\u000a\u000aThe form 「できている」 (dekite iru) is very common, indicating the state of being made of something.'),'N4',9,'Ongoing and Continuous','[{"ja":"この机は木でできている。","romaji":"Kono tsukue wa ki de dekite iru.","en":"This desk is made of wood."},{"ja":"このコップはガラスでできています。","romaji":"Kono koppu wa garasu de dekite imasu.","en":"This cup is made of glass."},{"ja":"日本の家は木でできているものが多いです。","romaji":"Nihon no ie wa ki de dekite iru mono ga ooi desu.","en":"Many Japanese houses are made of wood."},{"ja":"このケーキは卵と小麦粉でできています。","romaji":"Kono keeki wa tamago to komugiko de dekite imasu.","en":"This cake is made from eggs and flour."}]','[]','["verb","expression"]',246);
INSERT INTO grammar_points VALUES(247,'n4-nagara','ながら','nagara','While; during; doing two actions simultaneously','Verb (stem form) + ながら',unistr('「ながら」 (nagara) is used to express that two actions are happening at the same time, performed by the same subject. The action before 「ながら」 is usually the secondary or less important action, while the action after 「ながら」 is the main action.\u000a\u000aTo form this, take the stem form of the first verb (remove 「ます」 from the 「ます」 form) and attach 「ながら」. The second verb is conjugated normally.\u000a\u000aIt''s important that both actions are performed by the *same person or entity*. For example, you cannot say "I read a book while my friend watched TV" using 「ながら」.'),'N4',9,'Ongoing and Continuous','[{"ja":"話を聞きながらメモします。","romaji":"Hanashi o kikinagara memo shimasu.","en":"I take notes while listening to the story."},{"ja":"歩きながら話しましょう。","romaji":"Arukinagara hanashimashou.","en":"Let''s talk while walking."},{"ja":"テレビを見ながら晩ごはんを食べます。","romaji":"Terebi o minagara bangohan o tabemasu.","en":"I eat dinner while watching TV."},{"ja":"音楽を聞きながら料理します。","romaji":"Ongaku o kikinagara ryouri shimasu.","en":"I cook while listening to music."}]','[]','["conjunction","verb"]',247);
INSERT INTO grammar_points VALUES(248,'n4-ta-tokoro-da','～た所（ところ）だ','ta tokoro da','Just finished doing something; just did something','Verb (た-form) + ところだ',unistr('「～たところだ」 (ta tokoro da) indicates that an action has *just been completed*. It emphasizes that the action finished a very short time ago.\u000a\u000a「ところ」 literally means "place" or "point," but in this context, it refers to a "point in time." When combined with the past tense (た-form) of a verb, it signifies the immediate aftermath of an action.\u000a\u000aThis expression often appears with adverbs like 「今」 (ima, just now) to further emphasize the recency of the action.'),'N4',9,'Ongoing and Continuous','[{"ja":"今帰ったところです。","romaji":"Ima kaetta tokoro desu.","en":"I just got home."},{"ja":"たった今、昼ごはんを食べたところです。","romaji":"Tatta ima, hirugohan o tabeta tokoro desu.","en":"I just finished eating lunch right now."},{"ja":"彼は会議が終わったところだと言いました。","romaji":"Kare wa kaigi ga owatta tokoro da to iimashita.","en":"He said the meeting just ended."},{"ja":"宿題はもうやった？ うん、今終わったところだよ。","romaji":"Shukudai wa mou yatta? Un, ima owatta tokoro da yo.","en":"Have you done your homework yet? Yeah, I just finished it."}]','["n4-teiru-tokoro-da","n4-ru-tokoro-da"]','["expression","verb"]',248);
INSERT INTO grammar_points VALUES(249,'n4-teiru-tokoro-da','～ている所（ところ）だ','teiru tokoro da','In the process of doing something; currently doing something','Verb (て-form) + いる + ところだ',unistr('「～ているところだ」 (te iru tokoro da) indicates that an action is *currently in progress* or *in the middle of being done*. It emphasizes that the action is happening at this very moment.\u000a\u000aSimilar to 「～たところだ」, 「ところ」 here refers to a "point in time." When combined with the 「～ている」 form of a verb, it signifies the ongoing nature of an action.\u000a\u000aThis expression is often used with adverbs like 「今」 (ima, now) to highlight that the action is happening right at the present moment.'),'N4',9,'Ongoing and Continuous','[{"ja":"今ご飯を食べているところです。","romaji":"Ima gohan o tabete iru tokoro desu.","en":"I''m in the middle of eating right now."},{"ja":"彼は今、電話で話しているところです。","romaji":"Kare wa ima, denwa de hanashite iru tokoro desu.","en":"He is talking on the phone right now."},{"ja":"会議はまだ終わっていません。今、議論しているところです。","romaji":"Kaigi wa mada owatte imasen. Ima, giron shite iru tokoro desu.","en":"The meeting isn''t over yet. We are discussing it right now."},{"ja":"子供たちは公園で遊んでいるところです。","romaji":"Kodomotachi wa kouen de asonde iru tokoro desu.","en":"The children are playing in the park right now."}]','["n4-ta-tokoro-da","n4-ru-tokoro-da"]','["expression","verb"]',249);
INSERT INTO grammar_points VALUES(250,'n4-to-to-dochira-ga','と～と、どちらが','to to dochira ga','Between X and Y, which one is...?','Noun A + と + Noun B + と、どちらが + Adjective/Verb + ですか',unistr('「～と～と、どちらが～ですか」 (to ~ to, dochira ga ~ desu ka) is a common pattern used to ask for a comparison between two items or options. It directly translates to "Between X and Y, which one is...?"\u000a\u000aThe particle 「と」 (to) is used to list the items being compared. 「どちら」 (dochira) means "which one" (out of two options).\u000a\u000aThis structure is fundamental for making choices or expressing preferences between two distinct things.'),'N4',9,'Ongoing and Continuous','[{"ja":"犬と猫と、どちらが好きですか？","romaji":"Inu to neko to, dochira ga suki desu ka?","en":"Which do you like better, dogs or cats?"},{"ja":"夏と冬と、どちらが好きですか？","romaji":"Natsu to fuyu to, dochira ga suki desu ka?","en":"Which do you like better, summer or winter?"},{"ja":"日本語と英語と、どちらが難しいですか？","romaji":"Nihongo to eigo to, dochira ga muzukashii desu ka?","en":"Which is more difficult, Japanese or English?"},{"ja":"コーヒーと紅茶と、どちらを飲みますか？","romaji":"Koohii to koucha to, dochira o nomimasu ka?","en":"Which will you drink, coffee or tea?"}]','["n4-no-naka-de-ichiban"]','["particle","question","comparison"]',250);
INSERT INTO grammar_points VALUES(251,'n4-様にする','様（よう）にする','you ni suru','To try to; to make an effort to; to make sure to',unistr('Verb (Dictionary form) + ようにする\u000aVerb (Negative form) + ようにする'),unistr('「ようにする」 expresses the speaker''s conscious effort or intention to do something, or to make something a habit. It implies a continuous effort rather than a one-time action. It can also be used to describe making sure something happens or doesn''t happen.\u000a\u000aWhen used with a dictionary form verb, it means ''to try to do'' or ''to make an effort to do''. For example, 毎日運動するようにする (mainichi undou suru you ni suru) means ''I try to exercise every day''.\u000a\u000aWhen used with a negative form verb, it means ''to try not to do'' or ''to make sure not to do''. For instance, 遅刻しないようにする (chikoku shinai you ni suru) means ''I try not to be late''. This grammar point emphasizes the ongoing nature of the effort.'),'N4',9,'Ongoing and Continuous','[{"ja":"毎日野菜を食べるようにする。","romaji":"mainichi yasai o taberu you ni suru.","en":"I''ll try to eat vegetables every day."},{"ja":"遅刻しないようにしています。","romaji":"chikoku shinai you ni shite imasu.","en":"I make an effort not to be late."},{"ja":"日本語を毎日勉強するようにしています。","romaji":"nihongo o mainichi benkyou suru you ni shite imasu.","en":"I try to study Japanese every day."},{"ja":"夜は早く寝るようにしている。","romaji":"yoru wa hayaku neru you ni shite iru.","en":"I try to go to bed early at night."}]','["n4-様に言う"]','["expression","verb"]',251);
INSERT INTO grammar_points VALUES(252,'n4-なければいけない','なければいけない','nakereba ikenai','Must do; have to do; should do','Verb (ない form) + なければいけない',unistr('「なければいけない」 expresses an obligation or necessity, meaning "must do" or "have to do." It is formed by taking the negative (ない) form of a verb, dropping the い, and adding 「なければいけない」. For example, 「食べる」 (taberu) becomes 「食べない」 (tabenai), then 「食べなければいけない」 (tabenakereba ikenai).\u000a\u000aThis phrase is commonly used in daily conversation and can be slightly less formal than 「なければならない」, though both convey the same meaning of obligation. It implies that if the action is not performed, it will be problematic or undesirable. The final 「いけない」 can be changed to 「いけません」 for a more polite tone.\u000a\u000aIt is often shortened in casual speech to 「なきゃいけない」 or even just 「なきゃ」, especially among friends or family. For example, 「行かなきゃいけない」 (ikanakya ikenai) can become 「行かなきゃ」 (ikanakya).'),'N4',9,'Ongoing and Continuous','[{"ja":"早く寝なければいけない。","romaji":"hayaku nenakereba ikenai.","en":"I have to go to sleep early."},{"ja":"私も頑張らなければいけない。","romaji":"watashi mo ganbaranakereba ikenai.","en":"I have to do my best too."},{"ja":"私はすぐ答えなければいけない。","romaji":"watashi wa sugu kotaenakereba ikenai.","en":"I must answer right away."},{"ja":"明日はテストがあるから、勉強しなければいけません。","romaji":"ashita wa tesuto ga aru kara, benkyou shinakereba ikemasen.","en":"Tomorrow there''s a test, so I have to study."}]','["n4-なければならない","n4-なくてはいけない"]','["obligation","verb conjugation"]',252);
INSERT INTO grammar_points VALUES(253,'n4-なければならない','なければならない','nakereba naranai','Must do; have to do; should do','Verb (ない form) + なければならない',unistr('「なければならない」 expresses a strong obligation or necessity, meaning "must do" or "have to do." It is formed by taking the negative (ない) form of a verb, dropping the い, and adding 「なければならない」. For instance, 「読む」 (yomu) becomes 「読まない」 (yomanai), then 「読まなければならない」 (yomanakereba naranai).\u000a\u000aThis phrase is generally considered slightly more formal or emphatic than 「なければいけない」, though they are often interchangeable in meaning. It implies that if the action is not performed, it will be unacceptable or incorrect. The final 「ならない」 can be changed to 「なりません」 for a more polite tone.\u000a\u000aLike 「なければいけない」, this form can also be shortened in casual speech to 「なきゃならない」 or 「なきゃ」, but this is less common than with 「いけない」. It is frequently encountered in written Japanese, official statements, or when expressing a strong personal conviction.'),'N4',9,'Ongoing and Continuous','[{"ja":"薬を飲まなければなりません。","romaji":"kusuri o nomanakereba narimasen.","en":"I/you need to take my/your medicine."},{"ja":"宿題をしなければならない。","romaji":"shukudai o shinakereba naranai.","en":"I/you need to do my/your homework."},{"ja":"今すぐそこに行かなければなりませんか。","romaji":"ima sugu soko ni ikanakereba narimasen ka.","en":"Do I have to go there right now?"},{"ja":"母を手伝わなければならない。","romaji":"haha o tetsudawanakereba naranai.","en":"I have to help my mom."}]','["n4-なければいけない","n4-なくてはならない"]','["obligation","verb conjugation"]',253);
INSERT INTO grammar_points VALUES(254,'n4-続ける','続（つづ）ける','tsuzukeru','To continue to do; to keep doing','Verb (ます stem) + 続ける',unistr('「続ける」 (つづける) is a compound verb that means "to continue to do" or "to keep doing" an action. It is formed by attaching 「続ける」 to the ます-stem of another verb. For example, 「読む」 (yomu) becomes 「読みます」 (yomimasu), then 「読み続ける」 (yomitsuzukeru), meaning "to keep reading."\u000a\u000aThis grammar point emphasizes the ongoing nature of an action without interruption. It can refer to an action that has been happening for a period and is still ongoing, or an action that will continue into the future. It is a versatile expression used to describe persistence, duration, or an unbroken sequence of events.\u000a\u000aIt is important to use the ます-stem correctly. For example, 「食べる」 (taberu) becomes 「食べます」 (tabemasu) -> 「食べ続ける」 (tabetsuzukeru), and 「する」 (suru) becomes 「します」 (shimasu) -> 「し続ける」 (shitsuzukeru).'),'N4',9,'Ongoing and Continuous','[{"ja":"昨日から雨が降り続けている。","romaji":"kinou kara ame ga furitsuzukete iru.","en":"It''s been raining nonstop since yesterday."},{"ja":"父からもらった自転車を今も使い続けています。","romaji":"chichi kara moratta jitensha o ima mo tsukaitsuzukete imasu.","en":"I still use the bicycle that my father gave to me even now."},{"ja":"彼女は彼氏の話をしゃべり続けた。","romaji":"kanojo wa kareshi no hanashi o shaberitsuzuketa.","en":"She continued talking about her boyfriend."},{"ja":"この薬は毎日飲み続ける必要があります。","romaji":"kono kusuri wa mainichi nomitsuzukeru hitsuyou ga arimasu.","en":"You need to keep taking this medicine every day."}]','[]','["compound verb","aspect"]',254);
INSERT INTO grammar_points VALUES(255,'n4-様に言う','様（よう）に言（い）う','you ni iu','To tell/ask someone to do (in such a way); to instruct to',unistr('Verb (Dictionary form) + ように言う\u000aVerb (Negative form) + ように言う'),unistr('「ように言う」 is used to convey an indirect command, request, or instruction. It means "to tell someone to do something" or "to ask someone to do something" in a gentle or indirect manner, rather than a direct order. It is formed by attaching 「ように言う」 to the dictionary form of a verb for affirmative instructions, or the negative form of a verb for negative instructions.\u000a\u000aThis expression is commonly used when reporting what someone said or when giving advice or instructions without being overly forceful. For example, 先生は静かにするように言った (sensei wa shizuka ni suru you ni itta) means "The teacher told us to be quiet."\u000a\u000aIt differs from direct quotes (e.g., 「～と言った」) by focusing on the content of the instruction rather than the exact words used. It implies that the speaker wants the listener to act in a certain way or to make an effort to do so.'),'N4',9,'Ongoing and Continuous','[{"ja":"先生は静かにするように言った。","romaji":"sensei wa shizuka ni suru you ni itta.","en":"The teacher told us to be quiet."},{"ja":"医者は薬を飲むように言いました。","romaji":"isha wa kusuri o nomu you ni iimashita.","en":"The doctor told me to take the medicine."},{"ja":"母は早く家に帰るように言った。","romaji":"haha wa hayaku ie ni kaeru you ni itta.","en":"My mother told me to come home early."},{"ja":"彼は嘘をつかないように私に言った。","romaji":"kare wa uso o tsukanai you ni watashi ni itta.","en":"He told me not to lie."}]','["n4-様にする"]','["indirect speech","expression"]',255);
INSERT INTO grammar_points VALUES(256,'n4-予定だ','予定（よてい）だ','yotei da','Plan to; intend to; scheduled to',unistr('Verb (dictionary form) + 予定だ\u000aNoun + の + 予定だ'),unistr('「予定だ」 (yotei da) is used to express a plan, intention, or schedule. It indicates that something is expected or arranged to happen. It can be used for both personal plans and official schedules.\u000a\u000aThis grammar point is a straightforward way to state future arrangements. While similar to using the plain form of a verb for future actions, 「予定だ」 adds a nuance of a pre-determined plan or schedule. It is often used in slightly more formal contexts than simply stating a future action, but less formal than using specific planning verbs like 「～つもりだ」 when the plan is very firm and personal.'),'N4',9,'Ongoing and Continuous','[{"ja":"来月引っ越す予定です。","romaji":"Raigetsu hikkosu yotei desu.","en":"I plan to move next month."},{"ja":"会議は午後3時に始まる予定です。","romaji":"Kaigi wa gogo san-ji ni hajimaru yotei desu.","en":"The meeting is scheduled to start at 3 PM."},{"ja":"彼は明日日本へ出発する予定だ。","romaji":"Kare wa ashita Nihon e shuppatsu suru yotei da.","en":"He is scheduled to depart for Japan tomorrow."},{"ja":"今週末は友達と映画を見る予定です。","romaji":"Konshūmatsu wa tomodachi to eiga o miru yotei desu.","en":"I plan to watch a movie with my friends this weekend."}]','["n5-つもりだ"]','["noun","expression"]',256);
INSERT INTO grammar_points VALUES(257,'n4-様に祈る','様（よう）に祈（いの）る','you ni inoru','Pray that; hope that; wish for',unistr('Verb (casual form) + ように祈る\u000aNoun + に + なる + ように祈る\u000aい-Adjective (stem) + くなる + ように祈る\u000aな-Adjective (stem) + になる + ように祈る'),unistr('「～ように祈る」 (you ni inoru) is used to express a wish, hope, or prayer for something to happen or for a certain state to be achieved. The 「ように」 part indicates the desired manner or outcome, while 「祈る」 means to pray or wish.\u000a\u000aThis expression is typically used when you want to convey a strong desire or prayer for an outcome that is not entirely within your control, such as someone''s recovery from illness, success in an exam, or good weather. It implies a heartfelt request or hope for a positive result.'),'N4',9,'Ongoing and Continuous','[{"ja":"合格するように祈っています。","romaji":"Goukaku suru you ni inotte imasu.","en":"I''m praying that you pass."},{"ja":"早く病気が治るように祈っています。","romaji":"Hayaku byouki ga naoru you ni inotte imasu.","en":"I''m praying that your illness gets better quickly."},{"ja":"みんなが幸せになるように祈る。","romaji":"Minna ga shiawase ni naru you ni inoru.","en":"I pray for everyone to be happy."},{"ja":"明日、晴れるように祈ろう。","romaji":"Ashita, hareru you ni inorou.","en":"Let''s pray for clear weather tomorrow."}]','["n4-ようにする","n4-ように言う"]','["expression","verb"]',257);
INSERT INTO grammar_points VALUES(258,'n4-たばかり','～たばかり','tabakari','Just did; just finished doing something','Verb (た-form) + ばかり',unistr('「～たばかり」 (ta bakari) indicates that an action has just been completed very recently. It conveys the nuance of "just now" or "a short time ago" from the speaker''s perspective, emphasizing the recency of the event.\u000a\u000aThe exact duration that constitutes "just now" can be subjective and depends on the context. For example, someone who just ate lunch might say 「食べたばかり」, but someone who just moved to Japan a month ago might also say 「日本に来たばかり」. It highlights that the action is still fresh in the speaker''s mind or has immediate relevance.'),'N4',9,'Ongoing and Continuous','[{"ja":"彼は今、家を出たばかりです。","romaji":"Kare wa ima, ie o deta bakari desu.","en":"He just left the house now."},{"ja":"このケーキは焼きたばかりで、まだ温かい。","romaji":"Kono kēki wa yakita bakari de, mada atatakai.","en":"This cake was just baked, so it''s still warm."},{"ja":"日本に来たばかりなので、まだ日本語がよく分かりません。","romaji":"Nihon ni kita bakari nano de, mada Nihongo ga yoku wakarimasen.","en":"Since I just came to Japan, I don''t understand Japanese very well yet."},{"ja":"私は昼ごはんを食べたばかりだから、お腹がいっぱいです。","romaji":"Watashi wa hirugohan o tabeta bakari dakara, onaka ga ippai desu.","en":"I just ate lunch, so I''m full."}]','["n4-たところ"]','["expression","verb"]',258);
INSERT INTO grammar_points VALUES(259,'n4-化する','化（か）する','ka suru','To become; to change into; -ize; -ification','Noun + 化する',unistr('「～化する」 (ka suru) is a suffix that attaches to nouns to form a verb, meaning "to become [Noun]" or "to change into [Noun]". It indicates a process of transformation, development, or a change in state.\u000a\u000aThis grammar point is widely used to describe various kinds of changes, such as urbanization (都市化), industrialization (工業化), or simplification (単純化). It can also be used to describe a negative change, like worsening (悪化). The resulting verb is a する-verb, meaning it conjugates like other する-verbs (e.g., 都市化する, 都市化しない, 都市化した).'),'N4',9,'Ongoing and Continuous','[{"ja":"この地域は都市化している。","romaji":"Kono chiiki wa toshika shite iru.","en":"This area is urbanizing."},{"ja":"環境問題が深刻化している。","romaji":"Kankyō mondai ga shinkokuka shite iru.","en":"Environmental problems are becoming more serious."},{"ja":"彼の病状は悪化してしまった。","romaji":"Kare no byoujou wa akka shite shimatta.","en":"His medical condition has worsened."},{"ja":"最近、仕事が多様化している。","romaji":"Saikin, shigoto ga tayouka shite iru.","en":"Recently, jobs are becoming more diverse."}]','["n4-になる","n4-にする"]','["suffix","verb"]',259);
INSERT INTO grammar_points VALUES(260,'n4-命令形','命令形（めいれいけい）','meireikei','Imperative form; command form',unistr('Group 1 Verbs (う-verbs): Change final う-sound to え-sound (e.g., 飲む → 飲め, 行く → 行け)\u000aGroup 2 Verbs (る-verbs): Replace る with ろ (e.g., 食べる → 食べろ, 見る → 見ろ)\u000aIrregular Verbs: する → しろ (or せよ), 来る (くる) → 来い (こい)'),unistr('命令形 (meireikei) is the imperative or command form of verbs. It is used to give direct, strong orders or commands. This form is generally considered very direct, blunt, and can be rude, especially when used towards superiors or strangers.\u000a\u000aIt is commonly used in specific contexts: by men towards subordinates, children, or close friends (often in casual, rough speech); in emergencies or when giving urgent instructions (e.g., 「止まれ！」 - Stop!); in written instructions, slogans, or signs; and when quoting someone''s command. For more polite commands, 「～てください」 or 「～なさい」 are typically used.'),'N4',9,'Ongoing and Continuous','[{"ja":"早く食べろ！","romaji":"Hayaku tabero!","en":"Eat quickly!"},{"ja":"ここに座れ。","romaji":"Koko ni suware.","en":"Sit here."},{"ja":"静かにしろ！","romaji":"Shizuka ni shiro!","en":"Be quiet!"},{"ja":"あっちへ行け！","romaji":"Acchi e ike!","en":"Go over there!"}]','["n5-てください","n4-なさい"]','["verb conjugation","command"]',260);
INSERT INTO grammar_points VALUES(261,'n4-you-ni','様（よう）に','you ni','So that; in order to; in such a way that',unistr('Verb (dictionary form) + ように\u000aVerb (negative form) + ように\u000aPotential Verb + ように'),unistr('「ように」 is used to express a purpose or goal, often indicating that an action is taken so that a certain state or ability can be achieved, or to prevent something from happening. It focuses on the *result* or *effect* of an action.\u000a\u000aThis grammar point is frequently used with verbs that express potential (e.g., できる, わかる), involuntary actions (e.g., 見える, 聞こえる), or states (e.g., なる, ある). It implies that the action is performed to facilitate or enable the desired outcome.\u000a\u000aWhile similar to 「ために」, 「ように」 is generally used when the desired outcome is not a direct, volitional action of the subject, but rather a state, ability, or a change that occurs. For example, you use 「日本語が話せるように」 (so that I can speak Japanese) rather than 「日本語を話すために」 (in order to speak Japanese) because speaking Japanese is an ability/state.'),'N4',10,'Advanced Expressions','[{"ja":"忘れないように、メモしておきます。","romaji":"Wasurenai you ni, memo shite okimasu.","en":"I''ll make a note so I don''t forget."},{"ja":"日本語が話せるように、毎日勉強しています。","romaji":"Nihongo ga hanaseru you ni, mainichi benkyou shite imasu.","en":"I study every day so that I can speak Japanese."},{"ja":"よく見えるように、眼鏡をかけます。","romaji":"Yoku mieru you ni, megane o kakemasu.","en":"I wear glasses so that I can see well."},{"ja":"遅れないように、早く家を出ました。","romaji":"Okurenai you ni, hayaku ie o demashita.","en":"I left home early so that I wouldn''t be late."}]','["n4-tame-ni"]','["conjunction","purpose"]',261);
INSERT INTO grammar_points VALUES(262,'n4-kashira','かしら','kashira','I wonder (feminine/soft)',unistr('Verb (casual form) + かしら\u000aい-adjective + かしら\u000aな-adjective (stem) + かしら\u000aNoun + かしら'),unistr('「かしら」 is a sentence-ending particle used to express doubt, uncertainty, or a gentle question, often directed to oneself or in a soft, reflective manner. It translates to "I wonder if..." or "I wonder what/who/when...".\u000a\u000aThis particle carries a distinctly feminine or softer tone and is primarily used by women. While men might use it in very specific, gentle contexts, 「かな」 is the more common equivalent for men or for general, less gender-specific use.\u000a\u000aIt can be attached to various word types in their casual forms. For nouns and な-adjectives, the 「だ」 is usually omitted before 「かしら」, though it can sometimes be included for emphasis or a slightly different nuance.'),'N4',10,'Advanced Expressions','[{"ja":"本当かしら。","romaji":"Hontou kashira.","en":"I wonder if that''s true."},{"ja":"彼は来るかしら。","romaji":"Kare wa kuru kashira.","en":"I wonder if he will come."},{"ja":"このケーキ、美味しいかしら。","romaji":"Kono keeki, oishii kashira.","en":"I wonder if this cake is delicious."},{"ja":"明日は晴れるかしら。","romaji":"Ashita wa hareru kashira.","en":"I wonder if it will be sunny tomorrow."}]','["n4-kana"]','["particle","question"]',262);
INSERT INTO grammar_points VALUES(263,'n4-rashii-2','らしい ②','rashii 2','Typical of; -like; appropriate for; becoming of','Noun + らしい',unistr('「らしい」, when used with a noun, indicates that something strongly exhibits the characteristics or qualities typical of that noun. It conveys a sense of "like a Noun," "worthy of being a Noun," or "appropriate for a Noun." It''s often used to express a subjective judgment or impression based on observation, implying that something truly embodies the essence of the noun.\u000a\u000aThis usage of 「らしい」 often carries a positive connotation, suggesting that the subject is a good example of the noun it describes (e.g., 「男らしい」 - manly, 「女性らしい」 - ladylike, 「学生らしい」 - student-like). It emphasizes inherent qualities rather than just a superficial resemblance.\u000a\u000aIt differs from 「みたいだ」 which focuses more on mere resemblance or comparison, and from 「そうだ」 (appearance) which is based on immediate visual cues. 「らしい」 delves deeper into the fundamental nature or expected behavior associated with the noun.'),'N4',10,'Advanced Expressions','[{"ja":"彼女はいつも女性らしい。","romaji":"Kanojo wa itsumo joseirashii.","en":"She is always ladylike."},{"ja":"彼はとても男らしい人だ。","romaji":"Kare wa totemo otokorashii hito da.","en":"He is a very manly person."},{"ja":"今日は春らしい暖かい日だ。","romaji":"Kyou wa harurashii atatakai hi da.","en":"Today is a warm day, typical of spring."},{"ja":"学生らしい服装をしてください。","romaji":"Gakuseirashii fukusou o shite kudasai.","en":"Please wear clothes appropriate for a student."}]','["n4-mitai-da","n4-sou-da-2"]','["adjective","suffix"]',263);
INSERT INTO grammar_points VALUES(264,'n4-ni-mieru','にみえる','ni mieru','To look; to seem; to appear',unistr('Noun + に見える\u000aい-adjective (stem) + に見える\u000a(e.g., 寒く見える)\u000a な-adjective (stem) + に見える\u000a(e.g., 元気にみえる)'),unistr('「に見える」 is a grammar pattern used to express an appearance or impression based on observation. It means "looks like," "seems like," or "appears to be." It''s used when you infer something about a person, object, or situation from their outward appearance or behavior.\u000a\u000aThis pattern is versatile and can be used with nouns to describe what something resembles (e.g., 「先生に見える」 - looks like a teacher) or with adjectives to describe how something appears (e.g., 「楽しそうに見える」 - looks fun, 「疲れて見える」 - looks tired). When used with い-adjectives, the い changes to く (e.g., 寒い → 寒く見える). For な-adjectives, the な is dropped (e.g., 元気な → 元気にみえる).\u000a\u000aIt''s important to note that 「に見える」 describes a visual or sensory impression, not necessarily a confirmed fact. The speaker is making a judgment based on what they perceive.'),'N4',10,'Advanced Expressions','[{"ja":"同じに見える。","romaji":"Onaji ni mieru.","en":"They look the same."},{"ja":"彼はアメリカ人に見える。","romaji":"Kare wa Amerikajin ni mieru.","en":"He looks like he is American."},{"ja":"彼女は先生にみえる。","romaji":"Kanojo wa sensei ni mieru.","en":"She looks like a teacher."},{"ja":"その人はとてもお金持ちにみえる。","romaji":"Sono hito wa totemo okanemochi ni mieru.","en":"That person appears to be very rich."}]','["n4-sou-da-2","n4-mitai-da"]','["verb","expression"]',264);
INSERT INTO grammar_points VALUES(265,'n4-to-mieru','と見（み）える','to mieru','It seems that; it appears that; it can be deduced that',unistr('Verb (casual form) + と見える\u000aい-adjective + と見える\u000a な-adjective (stem) + だ + と見える\u000aNoun + だ + と見える'),unistr('「と見える」 is a grammar pattern used to express a conclusion or inference drawn from observable facts or circumstances. It means "it seems that," "it appears that," or "one can deduce that." Unlike 「そうだ」 (appearance) which is often based on immediate visual cues, 「と見える」 implies a more logical or reasoned deduction.\u000a\u000aThis pattern is used when the speaker has observed certain evidence or a situation and has formed a reasonable conclusion based on that observation. It suggests a higher degree of certainty or a more objective inference compared to other expressions of appearance or hearsay.\u000a\u000aIt can be attached to the casual forms of verbs, い-adjectives, な-adjectives (with 「だ」), and nouns (with 「だ」). It is often accompanied by adverbs like 「どうやら」 (douyara - apparently, it seems) or 「どうも」 (doumo - somehow, it seems) to further emphasize the inferential nature.'),'N4',10,'Advanced Expressions','[{"ja":"どうやら疲れていると見える。","romaji":"Douyara tsukarete iru to mieru.","en":"It seems he is tired."},{"ja":"彼は忙しいと見える。","romaji":"Kare wa isogashii to mieru.","en":"It appears he is busy."},{"ja":"雨が降ったと見える。道が濡れている。","romaji":"Ame ga futta to mieru. Michi ga nurete iru.","en":"It seems it rained. The road is wet."},{"ja":"彼女はもう帰ったと見える。電気が消えている。","romaji":"Kanojo wa mou kaetta to mieru. Denki ga kiete iru.","en":"It appears she has already gone home. The lights are off."}]','["n4-sou-da-2","n4-mitai-da"]','["expression","inference"]',265);
INSERT INTO grammar_points VALUES(266,'n4-fuu','風（ふう）','fuu','-style; -way; -fashion','Noun + 風（ふう）',unistr('「風（ふう）」 is a suffix attached to nouns to indicate a style, manner, or appearance resembling that noun. It means "-style," "-way," or "-fashion."\u000a\u000aIt is often used to describe something that has the characteristics or look of a particular culture, person, or object. For example, 「日本風（にほんふう）」 means "Japanese style," and 「西洋風（せいようふう）」 means "Western style."\u000a\u000aWhen used with a noun, it typically forms a new noun (e.g., 日本風) which can then modify another noun using 「の」 (e.g., 日本風の部屋).'),'N4',10,'Advanced Expressions','[{"ja":"日本風の部屋が好きです。","romaji":"nihonfuu no heya ga suki desu.","en":"I like Japanese-style rooms."},{"ja":"この町にはヨーロッパ風の建物が多い。","romaji":"kono machi ni wa yooroppafuu no tatemono ga ooi.","en":"There are many European-style buildings in this town."},{"ja":"彼女はいつもおしゃれなアメリカ風の服を着ている。","romaji":"kanojo wa itsumo share na amerikafuu no fuku o kiteiru.","en":"She always wears stylish American-style clothes."},{"ja":"この絵はゴッホ風で、とても個性的だ。","romaji":"kono e wa gohho fuu de, totemo koseiteki da.","en":"This painting is in Van Gogh''s style and is very unique."}]','[]','["suffix","noun"]',266);
INSERT INTO grammar_points VALUES(267,'n4-ga-mirareru','が見（み）られる','ga mirareru','can be seen; can observe; is evident','Noun + が見（み）られる',unistr('「が見（み）られる」 is the potential form of the verb 「見る (miru)」 (to see), meaning "can see" or "can be seen." In this specific grammar pattern, it is often used in a more general or impersonal sense to indicate that something is visible, observable, or evident in a particular place, situation, or context.\u000a\u000aIt implies that there is an opportunity or possibility to see something, or that a certain characteristic, trend, or phenomenon is present and noticeable. It''s frequently used when describing natural scenery, cultural aspects, or social trends.'),'N4',10,'Advanced Expressions','[{"ja":"ここから富士山が見られます。","romaji":"koko kara fujisan ga mirareru.","en":"Mt. Fuji can be seen from here."},{"ja":"この地方では珍しい鳥が見られます。","romaji":"kono chihoo de wa mezurashii tori ga mirareru.","en":"Rare birds can be observed in this region."},{"ja":"彼の作品には、日本の伝統的な美しさが見られる。","romaji":"kare no sakuhin ni wa, nihon-teki na utsukushisa ga mirareru.","en":"Traditional Japanese beauty can be seen in his works."},{"ja":"最近、若い人たちの間で新しいトレンドが見られる。","romaji":"saikin, wakai hitotachi no aida de atarashii torendo ga mirareru.","en":"Recently, new trends can be observed among young people."}]','["n5-miru"]','["verb","potential form"]',267);
INSERT INTO grammar_points VALUES(268,'n4-ni-kigatsuku','に気（き）が付（つ）く','ni kigatsuku','to notice; to realize; to become aware of','Noun + に + 気（き）が付（つ）く\nVerb (Casual) + こと + に + 気（き）が付（つ）く',unistr('「に気（き）が付（つ）く」 means "to notice," "to realize," or "to become aware of" something. The particle 「に」 indicates the object or situation that one notices or becomes aware of.\u000a\u000aThis phrase is used when you suddenly become aware of something that was previously unnoticed or when you come to understand a fact or situation. It can be used for both concrete things (like noticing a mistake) and abstract concepts (like realizing someone''s kindness).\u000a\u000aWhen noticing an action or state, the casual form of a verb followed by 「こと」 is used before 「に気（き）が付（つ）く」.'),'N4',10,'Advanced Expressions','[{"ja":"間違いに気がついた。","romaji":"machigai ni ki ga tsuita.","en":"I noticed the mistake."},{"ja":"彼女が髪を切ったことに気がつかなかった。","romaji":"kanojo ga kami o kitta koto ni ki ga tsukanakatta.","en":"I didn''t notice that she had cut her hair."},{"ja":"電車の中に傘を忘れたことに、駅に着いてから気がついた。","romaji":"densha no naka ni kasa o wasureta koto ni, eki ni tsuite kara ki ga tsuita.","en":"I realized I had left my umbrella on the train after arriving at the station."},{"ja":"彼の優しさに、最近になって気がつきました。","romaji":"kare no yasashisa ni, saikin ni natte ki ga tsukimashita.","en":"I only recently became aware of his kindness."}]','[]','["verb phrase","particle"]',268);
INSERT INTO grammar_points VALUES(269,'n4-demo-demo','でも〜でも','demo demo','either ~ or ~; neither ~ nor ~','Noun A + でも + Noun B + でも',unistr('The pattern 「でも〜でも」 is used to list two or more items, indicating that *either* of them is acceptable, possible, or applicable. It conveys a sense of indifference or inclusiveness regarding the choices.\u000a\u000aWhen used with a negative predicate, it means "neither ~ nor ~," indicating that none of the listed items are applicable or chosen. This pattern emphasizes that the distinction between the listed items is not important in the given context.\u000a\u000aIt can also be used to express that something is true regardless of the listed conditions, often implying a broad range of possibilities.'),'N4',10,'Advanced Expressions','[{"ja":"彼はコーヒーでも紅茶でも飲む。","romaji":"kare wa koohii demo koucha demo nomu.","en":"He drinks either coffee or tea."},{"ja":"週末は映画でも買い物でもいいよ。","romaji":"shuumatsu wa eiga demo kaimono demo ii yo.","en":"For the weekend, either a movie or shopping is fine."},{"ja":"彼女は肉でも魚でも食べない。","romaji":"kanojo wa niku demo sakana demo tabenai.","en":"She eats neither meat nor fish."},{"ja":"日本語でも英語でも、彼は話せる。","romaji":"nihongo demo eigo demo, kare wa hanaseru.","en":"He can speak either Japanese or English."}]','[]','["conjunction","particle"]',269);
INSERT INTO grammar_points VALUES(270,'n4-sore-ni','それに','sore ni','besides; in addition; moreover','Sentence A. それに, Sentence B.',unistr('「それに」 is a conjunction used to add further information, a reason, or an additional point to a previously stated sentence or idea. It functions similarly to "and," "in addition," "besides," or "moreover" in English.\u000a\u000aIt connects two sentences or clauses, where the second clause provides supplementary information that reinforces or expands upon the first. It often introduces something positive or negative that adds to the existing situation.\u000a\u000aWhile it can sometimes connect nouns (e.g., listing items), its primary use at the N4 level is to link sentences, indicating an additive relationship between them.'),'N4',10,'Advanced Expressions','[{"ja":"チーズバーガー、それにフライドポテトをお願いします。","romaji":"chiizu baagaa, sore ni furaido poteto o onegaishimasu.","en":"I''d like a cheeseburger, and fries please."},{"ja":"このアニメはとても人気がある。それに、音楽がいい。","romaji":"kono anime wa totemo ninki ga aru. sore ni, ongaku ga ii.","en":"This anime is very popular. In addition, it has good music."},{"ja":"彼は頭がいい。それに、スポーツも得意だ。","romaji":"kare wa atama ga ii. sore ni, supootsu mo tokui da.","en":"He is smart. Moreover, he is also good at sports."},{"ja":"このレストランは美味しい。それに、値段も手頃だ。","romaji":"kono resutoran wa oishii. sore ni, nedan mo tegoroda.","en":"This restaurant is delicious. Besides, the price is reasonable."}]','["n5-soshite"]','["conjunction"]',270);
INSERT INTO grammar_points VALUES(271,'n4-sorede','それで','sorede','Therefore; because of that; and then; so','Sentence 1. それで, Sentence 2.',unistr('「それで」 is a conjunction used to connect two sentences. It indicates that the second sentence is a result or consequence of the first sentence, or that it describes what happened next.\u000a\u000aIt can be translated as "therefore," "because of that," or "so." In casual conversation, it can also be used to prompt someone to continue their story, similar to asking "And then?" or "So what happened?"'),'N4',10,'Advanced Expressions','[{"ja":"雨が降った。それで、試合は中止になった。","romaji":"Ame ga futta. Sore de, shiai wa chuushi ni natta.","en":"It rained. Because of that, the match was cancelled."},{"ja":"宿題が終わった。それで、テレビを見た。","romaji":"Shukudai ga owatta. Sore de, terebi o mita.","en":"I finished my homework. And then, I watched TV."},{"ja":"昨日、田中さんに会ったんだ。それで？","romaji":"Kinou, Tanaka-san ni atta n da. Sore de?","en":"I met Tanaka-san yesterday. And then? (So what happened?)"},{"ja":"電車が遅れた。それで、会社に遅刻した。","romaji":"Densha ga okureta. Sore de, kaisha ni chikoku shita.","en":"The train was delayed. Therefore, I was late for work."}]','["n4-soshite","n4-dakara"]','["conjunction","connector"]',271);
INSERT INTO grammar_points VALUES(272,'n4-embedded-question-ka','(Question-Phrase) + か','question-phrase ka','To embed a question within a sentence',unistr('Verb (plain form) + か\u000aい-Adjective (plain form) + か\u000aな-Adjective (omit な) + か\u000aNoun + か'),unistr('This grammar pattern uses 「か」 to embed a question within a larger sentence. Instead of directly asking a question, you are talking *about* a question or expressing uncertainty regarding a question''s content.\u000a\u000aThe embedded question acts like a noun clause, functioning as the object of verbs like 「知る (shiru - to know)」, 「分かる (wakaru - to understand)」, 「教える (oshieru - to teach/tell)」, 「決める (kimeru - to decide)」, or 「調べる (shiraberu - to investigate)」. The verb or adjective preceding 「か」 must be in its plain (casual) form.'),'N4',10,'Advanced Expressions','[{"ja":"どこに行くか決めましたか？","romaji":"Doko ni iku ka kimemashita ka?","en":"Have you decided where to go?"},{"ja":"この本がおもしろいか教えてください。","romaji":"Kono hon ga omoshiroi ka oshiete kudasai.","en":"Please tell me if this book is interesting."},{"ja":"彼が学生か知りません。","romaji":"Kare ga gakusei ka shirimasen.","en":"I don''t know if he is a student."},{"ja":"新しいレストランが便利か調べています。","romaji":"Atarashii resutoran ga benri ka shirabete imasu.","en":"I am checking if the new restaurant is convenient."}]','["n4-ka-douka"]','["particle","embedded question"]',272);
INSERT INTO grammar_points VALUES(273,'n4-soredemo','それでも','soredemo','Even so; nevertheless; but still','Sentence 1. それでも, Sentence 2.',unistr('「それでも」 is a conjunction used to express a contrasting or unexpected outcome despite a preceding situation. It connects two sentences where the second sentence presents something that happens or is true *in spite of* the first sentence.\u000a\u000aIt conveys a stronger sense of ''even in that situation'' or ''despite that fact'' compared to simpler conjunctions like 「でも (demo)」 or 「しかし (shikashi)」. It emphasizes that the action or state in the second clause occurs regardless of the condition in the first clause.'),'N4',10,'Advanced Expressions','[{"ja":"それでもいいですか？","romaji":"Sore demo ii desu ka?","en":"Is that still okay with you?"},{"ja":"外は大雨だ。それでも出かけないといけない。","romaji":"Soto wa ooame da. Sore demo dekakenai to ikenai.","en":"It''s pouring rain outside, but even so, I still have to go out."},{"ja":"彼はテストの準備をしていなかった。それでも合格した。","romaji":"Kare wa tesuto no junbi o shite inakatta. Sore demo goukaku shita.","en":"He didn''t prepare for the test, but nevertheless, he passed."},{"ja":"彼女は忙しいと言っていた。それでも、私に会いに来てくれた。","romaji":"Kanojo wa isogashii to itte ita. Sore demo, watashi ni ai ni kite kureta.","en":"She said she was busy. Even so, she still came to see me."}]','["n4-demo","n4-keredomo"]','["conjunction","connector"]',273);
INSERT INTO grammar_points VALUES(274,'n4-taradou','たらどう','taradou','Why don''t you...?; How about...?',unistr('Verb (た-form) + らどうですか\u000aVerb (た-form) + らどう？'),unistr('The pattern 「〜たらどうですか」 (or the casual 「〜たらどう？」) is used to offer a suggestion or advice to someone. It literally means "What if you did...?" or "How about doing...?"\u000a\u000aThis is a softer and less direct way to give advice compared to a command or a strong recommendation like 「〜ほうがいい (hou ga ii)」. It invites the listener to consider the suggestion rather than obliging them to follow it. The polite form 「〜たらどうですか」 is generally safer to use, especially with people you don''t know well or who are of higher status.'),'N4',10,'Advanced Expressions','[{"ja":"一緒に来たらどうですか？","romaji":"Issho ni kitara dou desu ka?","en":"How about coming together with us?"},{"ja":"静かにしたらどうですか。","romaji":"Shizuka ni shitara dou desu ka.","en":"How about being quiet?"},{"ja":"先生に聞いてみたらどうですか？","romaji":"Sensei ni kiite mitara dou desu ka?","en":"Why don''t you try asking the teacher?"},{"ja":"彼に電話したらどうですか。","romaji":"Kare ni denwa shitara dou desu ka?","en":"Why don''t you give him a call?"}]','["n4-hougaii"]','["advice","suggestion"]',274);
INSERT INTO grammar_points VALUES(275,'n4-to-kangaerareteiru','と考（かんが）えられている','to kangaerareteiru','It is considered that; it is thought that',unistr('Verb (plain form) + と考えられている\u000aい-Adjective (plain form) + と考えられている\u000aな-Adjective (omit な) + だ + と考えられている\u000aNoun + だ + と考えられている'),unistr('The phrase 「〜と考えられている」 is a passive construction meaning "it is considered that..." or "it is thought that...". It is used to express a widely held belief, opinion, or general understanding without specifying who holds that opinion.\u000a\u000aThis pattern is often used in formal or objective statements, such as news reports, academic papers, or general discussions, to present information as a commonly accepted idea or a prevailing view. It implies that the statement is based on general consensus or observation, rather than a personal opinion.'),'N4',10,'Advanced Expressions','[{"ja":"日本語は難しいと考えられている。","romaji":"Nihongo wa muzukashii to kangaerarete iru.","en":"Japanese is considered to be difficult."},{"ja":"彼は正直な人だと考えられている。","romaji":"Kare wa shoujiki na hito da to kangaerarete iru.","en":"He is considered to be an honest person."},{"ja":"この薬は効果があると考えられている。","romaji":"Kono kusuri wa kouka ga aru to kangaerarete iru.","en":"This medicine is thought to be effective."},{"ja":"運動は健康に良いと考えられている。","romaji":"Undou wa kenkou ni yoi to kangaerarete iru.","en":"Exercise is considered good for health."}]','["n4-to-iwareteiru"]','["passive","expression"]',275);
INSERT INTO grammar_points VALUES(276,'n4-とされている','とされている','to sarete iru','To be considered; To be regarded as',unistr('Noun + とされている\u000aVerb (Casual) + とされている\u000aい-adjective + とされている\u000aな-adjective + だ + とされている'),unistr('「とされている」 is a passive expression derived from 「とする」, meaning "to consider" or "to regard as". It is used to state that something is generally accepted, widely believed, or officially recognized in a certain way.\u000a\u000aThis grammar point often appears in more formal or objective contexts, such as news reports, academic papers, or general statements about established facts or common understanding. It implies a consensus or a prevailing view without necessarily specifying who holds that view.\u000a\u000aWhile similar to 「と言われている」, 「とされている」 often carries a stronger sense of established fact or official designation, whereas 「と言われている」 can sometimes imply more of a rumor or general saying.'),'N4',10,'Advanced Expressions','[{"ja":"富士山は日本の象徴とされている。","romaji":"Fujisan wa Nihon no shouchou to sarete iru.","en":"Mt. Fuji is regarded as a symbol of Japan."},{"ja":"この薬は副作用が少ないとされている。","romaji":"Kono kusuri wa fukusayou ga sukunai to sarete iru.","en":"This medicine is considered to have few side effects."},{"ja":"彼は次期社長の候補とされている。","romaji":"Kare wa jiki shachou no kouho to sarete iru.","en":"He is regarded as a candidate for the next president."},{"ja":"早寝早起きは健康に良いとされている。","romaji":"Hayane hayaoki wa kenkou ni yoi to sarete iru.","en":"Going to bed early and waking up early is considered good for health."}]','["n4-と言われている"]','["passive","expression"]',276);
INSERT INTO grammar_points VALUES(277,'n4-と言われている','と言われている','to iwarete iru','It is said that; People say that',unistr('Noun + だ + と言われている\u000aVerb (Casual) + と言われている\u000aい-adjective + と言われている\u000aな-adjective + だ + と言われている'),unistr('「と言われている」 is a passive expression derived from 「と言う」, meaning "to say". It is used to convey information that is commonly known, rumored, or generally believed by people, without specifying who exactly said it.\u000a\u000aThis phrase is useful when you want to report something that is widely talked about or accepted as common knowledge, but you don''t have a specific source or you want to generalize the source as "people in general". It can be used for facts, rumors, or general opinions.\u000a\u000aIt''s a common way to introduce information that is not necessarily a personal opinion but rather a shared understanding or a piece of information circulating among people. It''s slightly less formal than 「とされている」 and can sometimes imply a rumor.'),'N4',10,'Advanced Expressions','[{"ja":"彼は天才だと言われている。","romaji":"Kare wa tensai da to iwarete iru.","en":"He is said to be a genius."},{"ja":"彼は来月に退職すると言われている。","romaji":"Kare wa raigetsu ni taishoku suru to iwarete iru.","en":"It is said that he will retire next month."},{"ja":"女性は男性より長生きだと言われている。","romaji":"Josei wa dansei yori nagaiki da to iwarete iru.","en":"It is said that women live longer than men."},{"ja":"このレストランのラーメンは美味しいと言われている。","romaji":"Kono resutoran no raamen wa oishii to iwarete iru.","en":"It is said that the ramen at this restaurant is delicious."}]','["n4-とされている"]','["passive","expression"]',277);
INSERT INTO grammar_points VALUES(278,'n4-ば良かった','ば良かった','ba yokatta','Should have; I wish I had; It would have been better if','Verb (ば-form) + よかった',unistr('「ばよかった」 is a grammar pattern used to express regret or a wish that a past action had been different. It literally means "if I had done X, it would have been good," implying that the speaker now regrets not having done X, or having done something else.\u000a\u000aTo form this, you take the ば-form of a verb and attach 「よかった」. For example, 「行く」 becomes 「行けば」, so 「行けばよかった」 means "I should have gone" or "I wish I had gone". For negative actions, use the negative ば-form, e.g., 「行かない」 becomes 「行かなければ」, so 「行かなければよかった」 means "I wish I hadn''t gone".\u000a\u000aThis expression is commonly used when reflecting on past decisions or situations and feeling remorse or a desire for a different outcome. It''s a very natural way to express regret in Japanese.'),'N4',10,'Advanced Expressions','[{"ja":"もっと勉強すればよかった。","romaji":"Motto benkyou sureba yokatta.","en":"I should have studied more."},{"ja":"傘を持っていけばよかった。","romaji":"Kasa o motte ikeba yokatta.","en":"I wish I had brought an umbrella."},{"ja":"彼に会わなければよかった。","romaji":"Kare ni awanakereba yokatta.","en":"I wish I hadn''t met him."},{"ja":"早く寝ればよかったのに、ゲームをしてしまった。","romaji":"Hayaku nereba yokatta noni, geemu o shite shimatta.","en":"I should have gone to bed early, but I ended up playing games."}]','[]','["conditional","regret"]',278);
